const query = new URLSearchParams(window.location.search);
const inlineApiBase = typeof window === 'undefined' ? '' : (window.ENV_API_BASE || '').trim();
const DEFAULT_DEPLOYED_BACKEND = 'https://rg-arls-backend.azurewebsites.net';
const DEFAULT_SENTRIX_APP_BASE_URL = 'https://security-ops-center-prod-002-260227135557.azurewebsites.net';
const DEBUG_LOG_QUERY_KEYS = ['debug_logs', 'debugLogs', 'debug_location', 'debugLocation'];

function isInvalidApiBase(value) {
  const normalized = String(value || '').trim().toLowerCase();
  return !normalized || normalized === 'undefined' || normalized === 'null';
}

function normalizeApiBase(raw) {
  if (!raw) return '';
  const trimmed = raw.replace(/\/$/, '');
  return /\/api\/v1$/.test(trimmed) ? trimmed : `${trimmed}/api/v1`;
}

function resolveApiBase() {
  const queryApi = query.get('api');
  const cleanQueryApi = isInvalidApiBase(queryApi) ? '' : queryApi;
  const cleanInlineApi = isInvalidApiBase(inlineApiBase) ? '' : inlineApiBase;
  const candidate = cleanQueryApi || cleanInlineApi || (
    (window.location.hostname || '').includes('.web.core.windows.net')
      ? DEFAULT_DEPLOYED_BACKEND
      : (window.location.protocol === 'file:'
        ? DEFAULT_DEPLOYED_BACKEND
        : ''
      )
  );
  return candidate ? normalizeApiBase(candidate) : '/api/v1';
}
const API_BASE = resolveApiBase();

function normalizeExternalAppBase(raw) {
  return String(raw || '').trim().replace(/\/+$/, '');
}

function buildSentrixHqSupportSubmissionUrl(context = {}) {
  const baseUrl = normalizeExternalAppBase(DEFAULT_SENTRIX_APP_BASE_URL) || DEFAULT_SENTRIX_APP_BASE_URL;
  const params = new URLSearchParams();
  const month = normalizeMonthKey(context.month || '');
  const siteCode = String(context.site_code || context.site || '').trim().toUpperCase();
  const artifactId = String(context.artifact_id || '').trim();
  const revision = String(context.revision || '').trim();
  const sourceUploadBatchId = String(context.source_upload_batch_id || '').trim();
  const tenantCode = String(context.tenant_code || getTenantCodeForScopedAdminApi() || '').trim();
  params.set('mode', 'hq-submission');
  if (month) params.set('month', month);
  if (siteCode) params.set('site', siteCode);
  if (artifactId) params.set('artifact_id', artifactId);
  if (revision) params.set('revision', revision);
  if (sourceUploadBatchId) params.set('source_upload_batch_id', sourceUploadBatchId);
  if (tenantCode) params.set('tenant_code', tenantCode);
  return `${baseUrl}/#/ops/support?${params.toString()}`;
}

function formatDateLabel(dateStr, fallback = '-') {
  if (!dateStr) return fallback;
  try {
    const d = new Date(dateStr);
    if (Number.isNaN(d.getTime())) {
      const raw = String(dateStr).trim();
      return raw || fallback;
    }
    return d.toLocaleDateString('ko-KR');
  } catch (e) {
    const raw = String(dateStr || '').trim();
    return raw || fallback;
  }
}

function formatHomeHeaderDate(date = new Date()) {
  try {
    return date.toLocaleDateString('ko-KR', {
      year: 'numeric',
      month: 'long',
      day: 'numeric',
      weekday: 'short',
    });
  } catch {
    return formatDateLabel(date, '오늘');
  }
}

function setTextContentIfPresent(selector, value, fallback = '-') {
  const el = $(selector);
  if (!el) return;
  const text = String(value || '').trim();
  el.textContent = text || fallback;
}

function resolveSafeImageSrc(raw) {
  const value = String(raw || '').trim();
  if (!value) return '';
  if (/^https?:\/\//i.test(value)) return value;
  if (/^data:image\//i.test(value)) return value;
  if (/^blob:/i.test(value)) return value;
  if (value.startsWith('/')) return value;
  return '';
}

function resolveDebugLogsEnabled() {
  const queryEnabled = DEBUG_LOG_QUERY_KEYS.some((key) => {
    const value = String(query.get(key) || '').trim().toLowerCase();
    return value === '1' || value === 'true' || value === 'yes' || value === 'on';
  });
  let localEnabled = '';
  try {
    localEnabled = String(localStorage.getItem('rg-arls-debug') || '').trim().toLowerCase();
  } catch {
    localEnabled = '';
  }
  return queryEnabled || localEnabled === '1' || localEnabled === 'true' || localEnabled === 'on';
}

const DEBUG_LOGS_ENABLED = resolveDebugLogsEnabled();
const PERF_DEBUG_QUERY_KEYS = ['perf_debug', 'perfDebug', 'PERF_DEBUG'];
const PERF_DEBUG_STORAGE_KEYS = ['PERF_DEBUG', 'rg-arls-perf-debug'];

function isTruthyDebugFlagValue(value = '') {
  const normalized = String(value || '').trim().toLowerCase();
  return normalized === '1' || normalized === 'true' || normalized === 'yes' || normalized === 'on';
}

function readPerfDebugStorageFlag(storageRef) {
  try {
    if (!storageRef) return false;
    return PERF_DEBUG_STORAGE_KEYS.some((key) => isTruthyDebugFlagValue(storageRef.getItem(key)));
  } catch {
    return false;
  }
}

function isLocalDevelopmentHost() {
  const host = String(window.location?.hostname || '').trim().toLowerCase();
  if (!host) return false;
  return host === 'localhost'
    || host === '127.0.0.1'
    || host === '0.0.0.0'
    || host.endsWith('.local');
}

function resolvePerfDebugEnabled() {
  const queryEnabled = PERF_DEBUG_QUERY_KEYS.some((key) => isTruthyDebugFlagValue(query.get(key)));
  return queryEnabled
    || DEBUG_LOGS_ENABLED
    || readPerfDebugStorageFlag(window.localStorage)
    || readPerfDebugStorageFlag(window.sessionStorage)
    || isLocalDevelopmentHost();
}

function logPerfInfo(message, ...args) {
  if (!resolvePerfDebugEnabled()) return;
  console.info(message, ...args);
}

