function setAuthStatus(nextStatus) {
  const status = String(nextStatus || '').trim().toUpperCase();
  if (!status) return;
  state.authStatus = status;
}

function decodeJwtPayload(token = '') {
  const rawToken = String(token || '').trim();
  if (!rawToken) return null;
  const parts = rawToken.split('.');
  if (parts.length < 2) return null;
  try {
    const base64 = parts[1].replace(/-/g, '+').replace(/_/g, '/');
    const padded = base64.padEnd(base64.length + ((4 - (base64.length % 4)) % 4), '=');
    const json = atob(padded);
    const parsed = JSON.parse(json);
    return parsed && typeof parsed === 'object' ? parsed : null;
  } catch {
    return null;
  }
}

function restoreUserFromAccessToken(token = '') {
  const payload = decodeJwtPayload(token);
  if (!payload) return null;
  const userId = String(payload.sub || payload.user_id || payload.userId || '').trim();
  const username = String(payload.username || payload.preferred_username || payload.upn || '').trim();
  if (!userId && !username) return null;
  const tenantCode = String(payload.tenant_code || payload.tenantCode || '').trim().toUpperCase();
  const tenantId = String(payload.tenant_id || payload.tenantId || '').trim();
  const role = normalizeRoleValue(payload.role || payload.user_role || payload.userRole || 'officer');
  const fullName = String(payload.full_name || payload.name || username || '사용자').trim() || '사용자';
  return {
    id: userId || username,
    username: username || userId || 'user',
    full_name: fullName,
    tenant_id: tenantId,
    tenant_code: tenantCode,
    role,
    employee_id: payload.employee_id || payload.employeeId || null,
  };
}

function showDebug() {
  const origin = window.location.origin || 'unknown';
  console.info(
    '[RG ARLS] API base',
    JSON.stringify(
      {
        activeApiBase: state.activeApiBase,
        source: state.apiBaseResolvedFromQuery ? 'query' : 'inline-or-default',
        inlineApiBase: inlineApiBase || '(unset)',
        queryApi: query.get('api') || '(none)',
        origin,
      },
      null,
      2,
    ),
  );
}

function sanitizeDebugValue(key, value) {
  if (value === null || value === undefined) return value;
  const lowerKey = String(key || '').toLowerCase();
  if (lowerKey.includes('latitude') || lowerKey.includes('longitude') || lowerKey === 'lat' || lowerKey === 'lng') {
    return '[redacted]';
  }
  if (typeof value === 'number') {
    if (!Number.isFinite(value)) return value;
    return Math.round(value * 10) / 10;
  }
  if (Array.isArray(value)) {
    return value.map((item) => sanitizeDebugValue(key, item));
  }
  if (typeof value === 'object') {
    const next = {};
    Object.entries(value).forEach(([k, v]) => {
      next[k] = sanitizeDebugValue(k, v);
    });
    return next;
  }
  return value;
}

function debugAuditLog(scope, payload = {}) {
  if (!DEBUG_LOGS_ENABLED) return;
  try {
    const safePayload = sanitizeDebugValue('', payload);
    console.info(`[RG ARLS][DEBUG][${scope}]`, safePayload);
  } catch {
    // no-op
  }
}

function setAriaBusy(target, busy) {
  if (!target) return;
  target.setAttribute('aria-busy', busy ? 'true' : 'false');
}

function getPerfNowMs() {
  try {
    if (window.performance && typeof window.performance.now === 'function') {
      return window.performance.now();
    }
  } catch {
    // no-op
  }
  return Date.now();
}

function formatPerfDurationMs(value) {
  const num = Number(value);
  if (!Number.isFinite(num)) return 'n/a';
  return `${num.toFixed(1)}ms`;
}

function getIsDesktopViewportForRender() {
  try {
    return window.matchMedia('(min-width: 1024px)').matches;
  } catch {
    return false;
  }
}

function isRenderContainerVisible(node) {
  if (!(node instanceof HTMLElement)) return false;
  const style = window.getComputedStyle(node);
  return style.display !== 'none' && style.visibility !== 'hidden';
}

function resolveResponsiveRenderMode({ desktopContainer = null, mobileContainer = null } = {}) {
  const desktopVisible = isRenderContainerVisible(desktopContainer);
  const mobileVisible = isRenderContainerVisible(mobileContainer);
  if (desktopVisible && !mobileVisible) return 'desktop';
  if (mobileVisible && !desktopVisible) return 'mobile';
  if (desktopVisible && mobileVisible) {
    return getIsDesktopViewportForRender() ? 'desktop' : 'mobile';
  }
  if (desktopContainer && mobileContainer) {
    return 'none';
  }
  if (desktopContainer) return desktopVisible ? 'desktop' : 'none';
  if (mobileContainer) return mobileVisible ? 'mobile' : 'none';
  return 'none';
}

function resolvePerfScreenFromRoute(routePath = '') {
  const route = normalizeRoutePath(parseRouteCandidate(routePath).path);
  if (!route) return '';
  if (route === ROUTE_HOME) return PERF_SCREEN_HOME;
  if (route === ROUTE_MASTER_TENANTS || route === ROUTE_DEV_TENANTS) return PERF_SCREEN_COMPANY_LIST;
  if (route === ROUTE_ADMIN_SITES) return PERF_SCREEN_SITE_LIST;
  if (route === ROUTE_ADMIN_EMPLOYEES_NEW) return PERF_SCREEN_EMPLOYEE_FORM;
  if (route === ROUTE_ADMIN_EMPLOYEES_IMPORT) return PERF_SCREEN_ROSTER;
  if (isScheduleRoutePath(route)) return PERF_SCREEN_SCHEDULE;
  return '';
}

function resolvePerfScreenFromView(viewName = '', routePath = state.currentRoute || '') {
  const byRoute = resolvePerfScreenFromRoute(routePath);
  if (byRoute) return byRoute;
  const view = String(viewName || '').trim().toLowerCase();
  if (view === 'home') return PERF_SCREEN_HOME;
  if (view === 'schedule') return PERF_SCREEN_SCHEDULE;
  if (view === 'org') return PERF_SCREEN_SITE_LIST;
  if (view === 'dev-console') {
    const route = normalizeRoutePath(parseRouteCandidate(routePath).path);
    if (route === ROUTE_MASTER_TENANTS) return PERF_SCREEN_COMPANY_LIST;
  }
  if (view === 'employees') {
    const route = normalizeRoutePath(parseRouteCandidate(routePath).path);
    if (route === ROUTE_ADMIN_EMPLOYEES_IMPORT) return PERF_SCREEN_ROSTER;
    if (route === ROUTE_ADMIN_EMPLOYEES_NEW) return PERF_SCREEN_EMPLOYEE_FORM;
  }
  return '';
}

function ensureViewRuntimeState() {
  if (!state.viewRuntime || typeof state.viewRuntime !== 'object') {
    state.viewRuntime = createInitialViewRuntimeState();
  }
  if (!(state.viewRuntime.loadedByKey instanceof Map)) {
    state.viewRuntime.loadedByKey = new Map();
  }
  if (!(state.viewRuntime.loadingByKey instanceof Map)) {
    state.viewRuntime.loadingByKey = new Map();
  }
  if (!state.viewRuntime.statsByView || typeof state.viewRuntime.statsByView !== 'object') {
    state.viewRuntime.statsByView = {};
  }
  if (!state.viewRuntime.perf || typeof state.viewRuntime.perf !== 'object') {
    state.viewRuntime.perf = createInitialViewPerfState();
  }
  return state.viewRuntime;
}

function ensureViewPerfState() {
  const runtime = ensureViewRuntimeState();
  if (!runtime.perf || typeof runtime.perf !== 'object') {
    runtime.perf = createInitialViewPerfState();
  }
  if (!runtime.perf.lastByScreen || typeof runtime.perf.lastByScreen !== 'object') {
    runtime.perf.lastByScreen = {};
  }
  return runtime.perf;
}

function startViewPerfSession({ routePath = '', viewName = '', trigger = 'tab_click' } = {}) {
  const perfState = ensureViewPerfState();
  const screen = resolvePerfScreenFromRoute(routePath) || resolvePerfScreenFromView(viewName, routePath);
  if (!screen) return null;
  const startedAt = getPerfNowMs();
  const nextSession = {
    id: Number(perfState.seq || 0) + 1,
    screen,
    route: normalizeRoutePath(parseRouteCandidate(routePath).path) || '',
    marks: {
      tab_click: startedAt,
    },
    metrics: {},
    trigger: String(trigger || 'tab_click'),
  };
  perfState.seq = nextSession.id;
  perfState.activeSession = nextSession;
  return nextSession;
}

function getActiveViewPerfSession(screen = '') {
  const perfState = ensureViewPerfState();
  const active = perfState.activeSession;
  if (!active || typeof active !== 'object') return null;
  if (screen && String(active.screen || '').trim() !== String(screen || '').trim()) {
    return null;
  }
  return active;
}

function logViewPerfSession(session) {
  if (!session || typeof session !== 'object') return;
  const screen = String(session.screen || '').trim() || 'UNKNOWN';
  const marks = session.marks || {};
  const clickToMount = Number(marks.route_or_view_mount) - Number(marks.tab_click);
  const mountToFirstUi = Number(marks.first_paintable_ui) - Number(marks.route_or_view_mount);
  const mountToCritical = Number(marks.critical_ui_ready) - Number(marks.route_or_view_mount);
  const totalToInteractive = Number(marks.fully_interactive) - Number(marks.tab_click);

  logPerfInfo(`[PERF][${screen}] click->mount: ${formatPerfDurationMs(clickToMount)}`);
  logPerfInfo(`[PERF][${screen}] mount->first_ui: ${formatPerfDurationMs(mountToFirstUi)}`);
  logPerfInfo(`[PERF][${screen}] mount->critical_ui: ${formatPerfDurationMs(mountToCritical)}`);
  logPerfInfo(`[PERF][${screen}] total_to_interactive: ${formatPerfDurationMs(totalToInteractive)}`);

  const apiMs = Number(session.metrics.api_ms);
  const renderMs = Number(session.metrics.render_ms);
  if (Number.isFinite(apiMs) || Number.isFinite(renderMs)) {
    const dominant = Number.isFinite(apiMs) && Number.isFinite(renderMs)
      ? (renderMs > apiMs ? 'render' : 'api')
      : (Number.isFinite(renderMs) ? 'render' : 'api');
    logPerfInfo(
      `[PERF][${screen}] api_vs_render: api=${formatPerfDurationMs(apiMs)} render=${formatPerfDurationMs(renderMs)} dominant=${dominant}`,
    );
  }
}

function markViewPerfStage(stage, { routePath = '', viewName = '', metrics = null } = {}) {
  const stageName = String(stage || '').trim();
  if (!stageName) return null;
  const perfState = ensureViewPerfState();
  const targetScreen = resolvePerfScreenFromRoute(routePath) || resolvePerfScreenFromView(viewName, routePath);
  if (!targetScreen) return null;

  let session = getActiveViewPerfSession(targetScreen);
  if (!session) {
    session = startViewPerfSession({
      routePath: routePath || state.currentRoute || '',
      viewName: viewName || state.currentView || '',
      trigger: stageName === 'tab_click' ? 'tab_click' : 'implicit',
    });
  }
  if (!session) return null;

  if (!session.marks[stageName]) {
    session.marks[stageName] = getPerfNowMs();
  }
  if (metrics && typeof metrics === 'object') {
    session.metrics = {
      ...(session.metrics || {}),
      ...metrics,
    };
  }

  if (stageName === 'fully_interactive') {
    if (!session.marks.critical_ui_ready) {
      session.marks.critical_ui_ready = session.marks.fully_interactive;
    }
    logViewPerfSession(session);
    perfState.lastByScreen[targetScreen] = {
      ...session,
      marks: { ...(session.marks || {}) },
      metrics: { ...(session.metrics || {}) },
    };
    if (perfState.activeSession && perfState.activeSession.id === session.id) {
      perfState.activeSession = null;
    }
  }
  return session;
}

function renderChunkedNodes(
  target,
  items,
  buildNode,
  {
    chunkSize = 80,
    onComplete = null,
    onCancel = null,
    shouldContinue = null,
  } = {},
) {
  if (!(target instanceof HTMLElement) || typeof buildNode !== 'function') {
    return { cancel: () => {} };
  }
  const rows = Array.isArray(items) ? items : [];
  if (!rows.length) {
    return { cancel: () => {} };
  }
  const token = `${Date.now()}_${Math.random().toString(16).slice(2)}`;
  target.dataset.renderToken = token;
  const normalizedChunkSize = Math.max(20, Number(chunkSize) || 80);
  let cursor = 0;
  let rafId = 0;
  let cancelled = false;

  const clearTokenIfOwned = () => {
    if (target.dataset.renderToken === token) {
      delete target.dataset.renderToken;
    }
  };

  const isCancelled = () => {
    if (cancelled) return true;
    if (target.dataset.renderToken !== token) return true;
    if (typeof shouldContinue === 'function' && !shouldContinue()) return true;
    return false;
  };

  const cancel = () => {
    if (cancelled) return;
    cancelled = true;
    if (rafId) {
      cancelAnimationFrame(rafId);
      rafId = 0;
    }
    clearTokenIfOwned();
    if (typeof onCancel === 'function') {
      onCancel();
    }
  };

  const renderBatch = () => {
    if (isCancelled()) {
      cancel();
      return;
    }
    const frag = document.createDocumentFragment();
    let batchCount = 0;
    while (cursor < rows.length && batchCount < normalizedChunkSize) {
      const node = buildNode(rows[cursor], cursor);
      if (node instanceof Node) {
        frag.appendChild(node);
      }
      cursor += 1;
      batchCount += 1;
    }
    if (frag.childNodes.length > 0) {
      target.appendChild(frag);
    }
    if (cursor < rows.length) {
      rafId = requestAnimationFrame(renderBatch);
      return;
    }
    cancelled = true;
    rafId = 0;
    clearTokenIfOwned();
    if (typeof onComplete === 'function') {
      onComplete();
    }
  };

  renderBatch();
  return { cancel, token };
}

function resolveViewRuntimeCacheKey(viewName = '') {
  const normalizedView = String(viewName || '').trim() || 'unknown';
  const routePath = normalizeRoutePath(state.currentRoute || resolveRouteForView(normalizedView) || '');
  return `${normalizedView}:${routePath || normalizedView}`;
}

function ensureViewRuntimeStats(viewName = '') {
  const runtime = ensureViewRuntimeState();
  const key = String(viewName || '').trim() || 'unknown';
  const current = runtime.statsByView[key];
  if (!current || typeof current !== 'object') {
    runtime.statsByView[key] = {
      activations: 0,
      loads: 0,
      cacheHits: 0,
      loadErrors: 0,
      lastLoadAt: 0,
      lastActivatedAt: 0,
    };
  }
  return runtime.statsByView[key];
}

function markViewActivated(viewName = '') {
  const stats = ensureViewRuntimeStats(viewName);
  stats.activations += 1;
  stats.lastActivatedAt = Date.now();
  if (DEBUG_LOGS_ENABLED || resolvePerfDebugEnabled()) {
    console.debug('[RG ARLS][PERF] view activated', {
      view: viewName,
      activations: stats.activations,
      loads: stats.loads,
      cacheHits: stats.cacheHits,
    });
  }
}

function clearViewRuntimeCache(viewName = '') {
  const runtime = ensureViewRuntimeState();
  const target = String(viewName || '').trim();
  if (!target) {
    runtime.loadedByKey.clear();
    runtime.loadingByKey.clear();
    runtime.statsByView = {};
    runtime.perf = createInitialViewPerfState();
    return;
  }
  const prefix = `${target}:`;
  Array.from(runtime.loadedByKey.keys()).forEach((key) => {
    if (String(key || '').startsWith(prefix)) {
      runtime.loadedByKey.delete(key);
    }
  });
  Array.from(runtime.loadingByKey.keys()).forEach((key) => {
    if (String(key || '').startsWith(prefix)) {
      runtime.loadingByKey.delete(key);
    }
  });
  delete runtime.statsByView[target];
  const perfScreen = resolvePerfScreenFromView(target, state.currentRoute || '');
  if (perfScreen && runtime.perf?.activeSession?.screen === perfScreen) {
    runtime.perf.activeSession = null;
  }
}

async function triggerHaptic(kind = 'tap') {
  try {
    const haptics = window.Capacitor?.Plugins?.Haptics;
    if (haptics) {
      if (kind === 'tap' && typeof haptics.impact === 'function') {
        await haptics.impact({ style: 'LIGHT' });
        return;
      }
      if (kind === 'success' && typeof haptics.notification === 'function') {
        await haptics.notification({ type: 'SUCCESS' });
        return;
      }
      if (kind === 'error' && typeof haptics.notification === 'function') {
        await haptics.notification({ type: 'ERROR' });
        return;
      }
      if (kind === 'warn' && typeof haptics.notification === 'function') {
        await haptics.notification({ type: 'WARNING' });
        return;
      }
    }

    const vibrationMap = {
      tap: 8,
      success: 14,
      error: [18, 20, 18],
      warn: [16, 30, 16],
    };
    if (navigator.vibrate) {
      navigator.vibrate(vibrationMap[kind] || 8);
    }
  } catch {
    // no-op
  }
}

function buildGeneratedTemporaryPassword(length = 12) {
  const size = Math.max(10, Math.min(20, Number(length) || 12));
  const chars = 'ABCDEFGHJKLMNPQRSTUVWXYZabcdefghijkmnopqrstuvwxyz23456789!@#$%^&*';
  const bytes = new Uint32Array(size);
  if (typeof crypto !== 'undefined' && typeof crypto.getRandomValues === 'function') {
    crypto.getRandomValues(bytes);
  } else {
    for (let i = 0; i < size; i += 1) bytes[i] = Math.floor(Math.random() * 1000000);
  }
  let out = '';
  for (let i = 0; i < size; i += 1) {
    out += chars[bytes[i] % chars.length];
  }
  return out;
}

async function copyTextToClipboard(value, successMessage = '복사되었습니다.') {
  const text = String(value || '').trim();
  if (!text) {
    showToast('복사할 값이 없습니다.', 'info', 1800);
    return false;
  }
  try {
    if (navigator.clipboard && typeof navigator.clipboard.writeText === 'function') {
      await navigator.clipboard.writeText(text);
      showToast(successMessage, 'success', 1600);
      return true;
    }
  } catch {
    // no-op
  }

  try {
    const ta = document.createElement('textarea');
    ta.value = text;
    ta.setAttribute('readonly', 'readonly');
    ta.style.position = 'fixed';
    ta.style.left = '-9999px';
    document.body.appendChild(ta);
    ta.select();
    const ok = document.execCommand('copy');
    ta.remove();
    if (ok) {
      showToast(successMessage, 'success', 1600);
      return true;
    }
  } catch {
    // no-op
  }
  showToast('복사에 실패했습니다. 수동으로 복사해 주세요.', 'error', 2200);
  return false;
}

function openGeneratedTempPasswordSheet(password = '') {
  const temp = String(password || '').trim();
  if (!temp) return;
  state.devAdmin.generatedPasswordMemo = temp;
  const node = document.createElement('div');
  node.className = 'stack';
  node.innerHTML = `
    <p class="muted">보안상 이 값은 다시 조회되지 않습니다. 안전 채널로 즉시 전달하세요.</p>
    <div class="master-temp-password-row">
      <input id="generatedTempPasswordDisplay" type="text" value="${temp}" readonly />
      <button class="btn btn-secondary" type="button" data-action="copy-generated-temp-password">복사</button>
      <button class="btn btn-primary" type="button" data-action="close-sheet">확인</button>
    </div>
  `;
  openSheet({
    title: '임시 비밀번호 발급 완료',
    contentNode: node,
    actions: [],
  });
}

function openRiskTwoStepConfirm({
  title = '위험 작업',
  message = '이 작업은 즉시 반영됩니다. 계속하시겠습니까?',
  finalMessage = '최종 확인: 정말 진행하시겠습니까?',
  acceptLabel = '진행',
  triggerEl = null,
  onAccept = null,
} = {}) {
  triggerHaptic('warn');
  openConfirmDialog({
    title,
    message,
    acceptLabel: '다음',
    acceptVariant: 'btn-destructive',
    triggerEl,
    onAccept: async () => {
      triggerHaptic('warn');
      setTimeout(() => {
        openConfirmDialog({
          title: '최종 확인',
          message: finalMessage,
          acceptLabel,
          acceptVariant: 'btn-destructive',
          triggerEl,
          onAccept: async () => {
            if (typeof onAccept === 'function') {
              await onAccept();
            }
          },
        });
      }, 0);
    },
  });
}

function isDesktopViewport() {
  try {
    return window.matchMedia('(min-width: 1024px)').matches;
  } catch {
    return false;
  }
}

function isDestructiveVariant(variant = '') {
  return String(variant || '').trim().toLowerCase().includes('destructive');
}

function normalizeTypedConfirmValue(value = '', normalize = 'exact') {
  const raw = String(value ?? '');
  if (typeof normalize === 'function') {
    return String(normalize(raw) ?? '').trim();
  }
  const mode = String(normalize || 'exact').trim().toLowerCase();
  if (mode === 'upper') return raw.trim().toUpperCase();
  if (mode === 'lower') return raw.trim().toLowerCase();
  if (mode === 'compact-upper') return raw.trim().toUpperCase().replace(/\s+/g, '');
  if (mode === 'employee-code') return normalizeEmployeeDeleteConfirmCode(raw);
  return raw.trim();
}

function createTypedConfirmInputNode({
  intro = '',
  fields = [],
  errorClassName = 'input-helper error',
} = {}) {
  const container = document.createElement('div');
  container.className = 'stack';

  if (String(intro || '').trim()) {
    const introEl = document.createElement('p');
    introEl.className = 'muted';
    introEl.textContent = String(intro).trim();
    container.appendChild(introEl);
  }

  const inputRefs = [];
  fields.forEach((field, index) => {
    const meta = (field && typeof field === 'object') ? field : {};
    const expectedRaw = String(meta.expected ?? '').trim();
    const normalizedExpected = normalizeTypedConfirmValue(expectedRaw, meta.normalize || 'exact');

    if (meta.showExpected) {
      const expectedWrap = document.createElement('div');
      expectedWrap.className = 'master-temp-password-row';

      const expectedInput = document.createElement('input');
      expectedInput.type = 'text';
      expectedInput.readOnly = true;
      expectedInput.className = 'master-temp-password-display';
      expectedInput.value = String(meta.expectedDisplay || expectedRaw || '-').trim();
      expectedInput.setAttribute('aria-label', `${String(meta.label || '확인값')} 표시`);
      expectedWrap.appendChild(expectedInput);

      if (meta.copyExpected) {
        const copyBtn = document.createElement('button');
        copyBtn.type = 'button';
        copyBtn.className = 'btn btn-secondary';
        copyBtn.textContent = '복사';
        copyBtn.addEventListener('click', () => {
          copyTextToClipboard(expectedRaw, '확인값을 복사했습니다.');
        });
        expectedWrap.appendChild(copyBtn);
      }

      container.appendChild(expectedWrap);
    }

    const label = document.createElement('label');
    label.className = 'input-field';
    label.textContent = String(meta.label || `확인 항목 ${index + 1}`);

    const input = document.createElement('input');
    input.type = 'text';
    input.autocomplete = 'off';
    input.spellcheck = false;
    input.autocapitalize = meta.autoCapitalize || 'none';
    input.placeholder = String(meta.placeholder || expectedRaw || '').trim();
    input.dataset.confirmFieldIndex = String(index);
    label.appendChild(input);

    if (String(meta.helper || '').trim()) {
      const helper = document.createElement('span');
      helper.className = 'input-helper';
      helper.textContent = String(meta.helper).trim();
      label.appendChild(helper);
    }

    container.appendChild(label);

    inputRefs.push({
      input,
      expectedRaw,
      normalizedExpected,
      normalize: meta.normalize || 'exact',
      mismatchMessage: String(meta.mismatchMessage || '').trim(),
      requiredLabel: String(meta.label || `확인 항목 ${index + 1}`).trim(),
    });
  });

  const errorEl = document.createElement('p');
  errorEl.className = errorClassName;
  errorEl.style.display = 'none';
  container.appendChild(errorEl);

  const setError = (message = '') => {
    const text = String(message || '').trim();
    if (!text) {
      errorEl.textContent = '';
      errorEl.style.display = 'none';
      return;
    }
    errorEl.textContent = text;
    errorEl.style.display = '';
  };

  const validate = ({ showError = false } = {}) => {
    for (const ref of inputRefs) {
      const actual = normalizeTypedConfirmValue(ref.input?.value || '', ref.normalize);
      if (!actual || actual !== ref.normalizedExpected) {
        if (showError) {
          setError(ref.mismatchMessage || `${ref.requiredLabel} 입력값이 일치하지 않습니다.`);
        }
        return false;
      }
    }
    setError('');
    return true;
  };

  const bindLiveValidation = (onChange) => {
    if (typeof onChange !== 'function') return () => {};
    const handler = () => onChange(validate({ showError: false }));
    inputRefs.forEach((ref) => {
      ref.input.addEventListener('input', handler);
      ref.input.addEventListener('change', handler);
    });
    handler();
    return () => {
      inputRefs.forEach((ref) => {
        ref.input.removeEventListener('input', handler);
        ref.input.removeEventListener('change', handler);
      });
    };
  };

  const focusFirst = () => {
    const first = inputRefs[0]?.input;
    if (!(first instanceof HTMLInputElement)) return;
    first.focus({ preventScroll: true });
    first.select();
  };

  return {
    node: container,
    validate,
    bindLiveValidation,
    focusFirst,
  };
}

function openDestructiveTypedConfirm({
  title = '확인',
  message = '계속 진행하시겠습니까?',
  acceptLabel = '실행',
  triggerEl = null,
  fields = [],
  onAccept = null,
  onClose = null,
} = {}) {
  const controller = createTypedConfirmInputNode({
    intro: message,
    fields,
  });

  openConfirmDialog({
    title,
    message: '',
    acceptLabel,
    acceptVariant: 'btn-destructive',
    triggerEl,
    extraNode: controller.node,
    onClose,
    validateBeforeAccept: ({ showError = false } = {}) => controller.validate({ showError }),
    onMount: ({ setAcceptEnabled }) => {
      const unbind = controller.bindLiveValidation((ok) => {
        setAcceptEnabled(Boolean(ok));
      });
      return () => {
        if (typeof unbind === 'function') {
          unbind();
        }
      };
    },
    onAccept: async () => {
      if (typeof onAccept === 'function') {
        await onAccept();
      }
    },
  });

  setTimeout(() => {
    controller.focusFirst();
  }, 0);
}

function setButtonsBusy(button, busy, busyLabel = '처리 중...') {
  if (!button) return;
  if (!button.dataset.label) {
    button.dataset.label = button.textContent || '';
  }
  button.disabled = busy;
  button.classList.toggle('is-loading', busy);
  button.setAttribute('aria-busy', busy ? 'true' : 'false');
  button.textContent = busy ? busyLabel : button.dataset.label;
}

function extractTextForAriaLabel(node) {
  if (!(node instanceof Element)) return '';
  const clone = node.cloneNode(true);
  clone.querySelectorAll('input, select, textarea, button, svg, img, [aria-hidden="true"]').forEach((child) => child.remove());
  return String(clone.textContent || '').replace(/\s+/g, ' ').trim();
}

function resolveAriaLabelCandidate(el) {
  if (!(el instanceof HTMLElement)) return '';
  if (el instanceof HTMLButtonElement) {
    return String(el.textContent || '').replace(/\s+/g, ' ').trim();
  }

  if ((el instanceof HTMLInputElement || el instanceof HTMLSelectElement || el instanceof HTMLTextAreaElement)) {
    const id = String(el.id || '').trim();
    if (id) {
      const explicitLabel = document.querySelector(`label[for="${CSS.escape ? CSS.escape(id) : id}"]`);
      const explicitText = extractTextForAriaLabel(explicitLabel);
      if (explicitText) return explicitText;
    }
    const wrappedLabel = el.closest('label');
    const wrappedText = extractTextForAriaLabel(wrappedLabel);
    if (wrappedText) return wrappedText;

    const placeholder = String(el.getAttribute('placeholder') || '').trim();
    if (placeholder) return placeholder;
  }

  return '';
}

function applyAccessibilityDefaults(root = document) {
  const scope = (root instanceof Document || root instanceof Element) ? root : document;
  const controls = scope.querySelectorAll('button, input, select, textarea');
  controls.forEach((el) => {
    if (!(el instanceof HTMLElement)) return;
    if (el.hasAttribute('aria-label')) return;
    if (el instanceof HTMLInputElement && el.type === 'hidden') return;
    const label = resolveAriaLabelCandidate(el);
    if (!label) return;
    el.setAttribute('aria-label', label);
  });
}

function statusPillClassFromText(text = '') {
  const v = String(text).toLowerCase();
  if (v.includes('승인') || v.includes('완료') || v.includes('정상') || v.includes('check_in') || v.includes('day')) {
    return 'status-pill status-pill-success';
  }
  if (
    v.includes('대기')
    || v.includes('warn')
    || v.includes('pending')
    || v.includes('night')
    || v.includes('휴가')
    || v.includes('연차')
    || v.includes('반차')
    || v.includes('병가')
    || v.includes('holiday')
  ) {
    return 'status-pill status-pill-warn';
  }
  if (v.includes('거절') || v.includes('오류') || v.includes('error') || v.includes('반경 밖') || v.includes('off')) {
    return 'status-pill status-pill-error';
  }
  return 'status-pill status-pill-warn';
}

function getUiStatusLabel(value = '') {
  const raw = String(value || '').trim();
  if (!raw) return '-';
  const lower = raw.toLowerCase();
  const map = {
    success: '성공',
    fail: '실패',
    failed: '실패',
    error: '오류',
    pending: '대기',
    approved: '승인',
    rejected: '반려',
    cancelled: '취소',
    canceled: '취소',
    applied: '반영',
    validated: '검증완료',
    processed: '처리완료',
    received: '수신',
    skipped: '건너뜀',
    invalid: '유효성오류',
    idle: '대기중',
    off: '비활성',
    active: '활성',
    inactive: '비활성',
    locked: '잠금',
    open: '열림',
    closed: '닫힘',
    unknown: '미확인',
    check_in: '출근',
    check_out: '퇴근',
    day: '주간',
    night: '야간',
    holiday: '공휴일',
  };
  return map[lower] || raw;
}

function getSupportWorkerTypeLabel(value = '') {
  const normalized = String(value || '').trim().toUpperCase();
  if (!normalized) return '-';
  return SUPPORT_WORKER_TYPE_LABELS[normalized] || normalized;
}

function createListRow({ title = '', subtitle = '', pill = '', danger = false, rawText = '' }) {
  const li = document.createElement('li');
  li.classList.add('content-fade-in');
  if (danger) li.classList.add('attendance-outside');

  const row = document.createElement('div');
  row.className = 'list-row';

  const main = document.createElement('div');
  main.className = 'list-row-main';

  const titleEl = document.createElement('div');
  titleEl.className = 'list-row-title';
  titleEl.textContent = title || rawText;

  main.appendChild(titleEl);

  if (subtitle) {
    const subEl = document.createElement('div');
    subEl.className = 'list-row-sub';
    subEl.textContent = subtitle;
    main.appendChild(subEl);
  }

  row.appendChild(main);

  if (pill) {
    const pillEl = document.createElement('span');
    pillEl.className = statusPillClassFromText(pill);
    pillEl.textContent = getUiStatusLabel(pill);
    row.appendChild(pillEl);
  }

  li.appendChild(row);
  return li;
}

// Older desktop workspace paths still call makeListRow().
// Keep the alias so presenter refreshes do not crash at runtime.
const makeListRow = createListRow;

function renderEmptyState(target, text = '표시할 데이터가 없습니다.', ctaText = '') {
  if (!target) return;
  target.innerHTML = '';
  setAriaBusy(target, false);
  const li = document.createElement('li');
  li.classList.add('content-fade-in');
  const box = document.createElement('div');
  box.className = 'empty-state';
  box.innerHTML = `
    <div class="empty-state-icon" aria-hidden="true">□</div>
    <div class="empty-state-title">데이터 없음</div>
    <div class="empty-state-description">${text}</div>
    ${ctaText ? `<div class="empty-state-meta">${ctaText}</div>` : ''}
  `;
  li.appendChild(box);
  target.appendChild(li);
}

function renderSkeleton(target, rows = 3) {
  if (!target) return;
  target.innerHTML = '';
  setAriaBusy(target, true);
  const li = document.createElement('li');
  const wrapper = document.createElement('div');
  wrapper.className = 'skeleton-list';
  for (let i = 0; i < rows; i += 1) {
    const row = document.createElement('div');
    row.className = 'skeleton-row';
    wrapper.appendChild(row);
  }
  li.appendChild(wrapper);
  target.appendChild(li);
}

function clearList(target) {
  if (!target) return;
  target.innerHTML = '';
  setAriaBusy(target, false);
}

function renderAdminTableEmptyState(targetBody, colSpan = 1, message = '표시할 데이터가 없습니다.') {
  if (!(targetBody instanceof HTMLElement)) return;
  targetBody.innerHTML = '';
  const tr = document.createElement('tr');
  tr.className = 'admin-table-empty-row';
  const td = document.createElement('td');
  td.colSpan = Math.max(1, Number(colSpan) || 1);
  td.textContent = message;
  tr.appendChild(td);
  targetBody.appendChild(tr);
}

function normalizeShiftType(value) {
  const shift = String(value || '').trim().toLowerCase();
  if (shift === 'day' || shift === 'overtime' || shift === 'night' || shift === 'off' || shift === 'holiday') {
    return shift;
  }
  return '';
}

function resolveScheduleDisplayType(row = {}) {
  const explicit = String(row?.schedule_display_type || '').trim().toLowerCase();
  if (['day', 'overtime', 'night', 'off', 'holiday', 'annual_leave', 'half_leave'].includes(explicit)) {
    return explicit;
  }
  if (isLeaveScheduleRow(row)) {
    const leaveType = String(row?.leave_type || '').trim().toLowerCase();
    return leaveType === 'half' ? 'half_leave' : 'annual_leave';
  }
  const shiftType = normalizeShiftType(row?.shift_type || '');
  if (shiftType === 'holiday') return 'holiday';
  if (shiftType !== 'off') return shiftType || 'day';
  const note = String(row?.schedule_note || '').trim().toLowerCase();
  const source = String(row?.source || '').trim().toLowerCase();
  if (note.includes('반차') || note.includes('half')) return 'half_leave';
  if (
    note.includes('연차')
    || note.includes('휴가')
    || note.includes('leave')
    || note.includes('vacation')
    || source === 'leave'
    || source === 'annual_leave'
  ) {
    return 'annual_leave';
  }
  return 'off';
}

function isScheduleNonWorkingDisplayType(displayType = '') {
  return ['off', 'holiday', 'annual_leave', 'half_leave'].includes(String(displayType || '').trim().toLowerCase());
}

function toLocalDateKey(value = new Date()) {
  const date = value instanceof Date ? value : new Date(value);
  if (Number.isNaN(date.getTime())) return '';
  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, '0');
  const day = String(date.getDate()).padStart(2, '0');
  return `${year}-${month}-${day}`;
}

function toLocalDatetimeInputValue(value = new Date()) {
  const date = value instanceof Date ? value : new Date(value);
  if (Number.isNaN(date.getTime())) return '';
  const pad = (num) => String(num).padStart(2, '0');
  return `${date.getFullYear()}-${pad(date.getMonth() + 1)}-${pad(date.getDate())}T${pad(date.getHours())}:${pad(date.getMinutes())}`;
}

function getMondayOfWeek(baseDate = new Date()) {
  const date = new Date(baseDate);
  date.setHours(0, 0, 0, 0);
  const day = date.getDay();
  const diff = day === 0 ? -6 : 1 - day;
  date.setDate(date.getDate() + diff);
  return date;
}

function getCurrentWeekDates(baseDate = new Date()) {
  const monday = getMondayOfWeek(baseDate);
  return Array.from({ length: 7 }, (_, idx) => {
    const d = new Date(monday);
    d.setDate(monday.getDate() + idx);
    return d;
  });
}

function toMonthKey(value = new Date()) {
  const date = value instanceof Date ? value : new Date(value);
  if (Number.isNaN(date.getTime())) return '';
  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, '0');
  return `${year}-${month}`;
}

function normalizeMonthKey(value) {
  const month = String(value || '').trim();
  if (!/^\d{4}-\d{2}$/.test(month)) return '';
  return month;
}

function getMonthMeta(month) {
  const normalized = normalizeMonthKey(month);
  if (!normalized) return null;
  const [yearRaw, monthRaw] = normalized.split('-');
  const year = Number(yearRaw);
  const monthIndex = Number(monthRaw) - 1;
  if (!Number.isFinite(year) || !Number.isFinite(monthIndex)) return null;
  const firstDate = new Date(year, monthIndex, 1);
  if (Number.isNaN(firstDate.getTime())) return null;
  const daysInMonth = new Date(year, monthIndex + 1, 0).getDate();
  const firstWeekdayOffset = (firstDate.getDay() + 6) % 7;
  return {
    month: normalized,
    year,
    monthIndex,
    daysInMonth,
    firstWeekdayOffset,
    firstDate,
  };
}

function getMonthFromDateKey(dateKey) {
  const key = String(dateKey || '').trim();
  return /^\d{4}-\d{2}-\d{2}$/.test(key) ? key.slice(0, 7) : '';
}

function formatScheduleShiftLabel(shiftType = '') {
  return getScheduleShiftMeta(shiftType).time;
}

function formatScheduleBoardItemTimeLabel(item = {}) {
  const start = String(item?.start_time || item?.shift_start_time || '').trim().slice(0, 5);
  const end = String(item?.end_time || item?.shift_end_time || '').trim().slice(0, 5);
  if (start && end) {
    return `${start} - ${end}`;
  }
  const displayMeta = getScheduleDisplayMeta(item);
  return String(
    item?.schedule_display_time
    || item?.shift_label
    || displayMeta.time
    || formatScheduleShiftLabel(item?.shift_type || '')
    || '-',
  ).trim() || '-';
}

function normalizeScheduleBoardItem(item = {}) {
  const shiftType = normalizeShiftType(item?.shift_type || '');
  const displayType = resolveScheduleDisplayType(item);
  const status = String(
    item?.status
    || (displayType === 'annual_leave' || displayType === 'half_leave'
      ? 'leave'
      : ((shiftType === 'off' || shiftType === 'holiday') ? 'non_working' : 'scheduled'))
  ).trim().toLowerCase() || 'scheduled';
  const displayMeta = getScheduleDisplayMeta({
    ...item,
    shift_type: shiftType,
    schedule_display_type: displayType,
  });
  return {
    schedule_id: String(item?.schedule_id || item?.id || '').trim(),
    employee_id: String(item?.employee_id || '').trim(),
    employee_code: String(item?.employee_code || '').trim(),
    employee_name: String(item?.employee_name || item?.full_name || '').trim(),
    site_code: String(item?.site_code || '').trim().toUpperCase(),
    site_name: String(item?.site_name || '').trim(),
    shift_type: shiftType,
    shift_label: String(item?.shift_label || '').trim() || displayMeta.time || formatScheduleShiftLabel(shiftType),
    start_time: String(item?.start_time || item?.shift_start_time || '').trim(),
    end_time: String(item?.end_time || item?.shift_end_time || '').trim(),
    schedule_note: String(item?.schedule_note || '').trim(),
    status,
    schedule_display_type: displayType,
    schedule_display_label: String(item?.schedule_display_label || displayMeta.label || '').trim(),
    schedule_display_time: String(item?.schedule_display_time || displayMeta.time || '').trim(),
    source_type: String(item?.source_type || '').trim().toLowerCase(),
    source: String(item?.source || '').trim(),
    display_variant: String(item?.display_variant || '').trim().toLowerCase(),
    display_shift_types: Array.isArray(item?.display_shift_types)
      ? item.display_shift_types.map((value) => normalizeShiftType(value)).filter(Boolean)
      : [],
    combined_schedule_ids: Array.isArray(item?.combined_schedule_ids)
      ? item.combined_schedule_ids.map((value) => String(value || '').trim()).filter(Boolean)
      : [],
  };
}

function formatScheduleComparableMinutesToTimeText(minutes = null) {
  if (!Number.isFinite(minutes)) return '';
  let normalized = Number(minutes) % 1440;
  if (normalized < 0) normalized += 1440;
  const hour = String(Math.floor(normalized / 60)).padStart(2, '0');
  const minute = String(normalized % 60).padStart(2, '0');
  return `${hour}:${minute}`;
}

function getScheduleBoardItemComparableRange(item = {}) {
  return buildScheduleTimeRangeForOverlap(
    item?.start_time || item?.shift_start_time || '',
    item?.end_time || item?.shift_end_time || '',
  );
}

function getScheduleBoardDisplayShiftTypes(item = {}) {
  const variants = Array.isArray(item?.display_shift_types) && item.display_shift_types.length
    ? item.display_shift_types
    : [item?.shift_type || ''];
  return variants
    .map((value) => normalizeShiftType(value))
    .filter(Boolean);
}

function getScheduleBoardEmployeeIdentity(item = {}) {
  return String(
    item?.employee_id
    || item?.employee_code
    || item?.employee_name
    || item?.full_name
    || '',
  ).trim();
}

function getScheduleBoardSiteIdentity(item = {}) {
  return String(item?.site_code || item?.site_name || '').trim().toUpperCase();
}

function getScheduleBoardEmployeeSortKey(item = {}) {
  return String(
    item?.employee_name
    || item?.full_name
    || item?.employee_code
    || item?.employee_id
    || '',
  ).trim().toUpperCase();
}

function getScheduleBoardEmployeeDisplayKey(item = {}) {
  return String(
    item?.employee_name
    || item?.full_name
    || item?.employee_code
    || item?.employee_id
    || '',
  ).trim().toUpperCase();
}

function getScheduleBoardSiteSortKey(item = {}) {
  return String(item?.site_code || item?.site_name || '').trim().toUpperCase();
}

function getScheduleBoardSiteDisplayKey(item = {}) {
  return String(item?.site_name || item?.site_code || '').trim().toUpperCase();
}

function getScheduleBoardComparableTokens(values = []) {
  return Array.from(new Set(
    (Array.isArray(values) ? values : [values])
      .map((value) => String(value || '').trim().toUpperCase())
      .filter(Boolean),
  ));
}

function hasScheduleBoardIdentityOverlap(leftValues = [], rightValues = []) {
  const leftTokens = getScheduleBoardComparableTokens(leftValues);
  const rightTokens = getScheduleBoardComparableTokens(rightValues);
  if (!leftTokens.length || !rightTokens.length) return false;
  return leftTokens.some((token) => rightTokens.includes(token));
}

function isSameScheduleBoardEmployee(left = {}, right = {}) {
  return hasScheduleBoardIdentityOverlap(
    [
      left?.employee_id,
      left?.employee_code,
      left?.employee_name,
      left?.full_name,
    ],
    [
      right?.employee_id,
      right?.employee_code,
      right?.employee_name,
      right?.full_name,
    ],
  );
}

function isSameScheduleBoardSite(left = {}, right = {}) {
  return hasScheduleBoardIdentityOverlap(
    [left?.site_code, left?.site_name],
    [right?.site_code, right?.site_name],
  );
}

function canCombineScheduleBoardItemPair(left = {}, right = {}) {
  if (!left || !right) return false;
  const leftShiftTypes = getScheduleBoardDisplayShiftTypes(left);
  const rightShiftTypes = getScheduleBoardDisplayShiftTypes(right);
  if (leftShiftTypes.length !== 1 || rightShiftTypes.length !== 1) return false;
  const leftShiftType = leftShiftTypes[0];
  const rightShiftType = rightShiftTypes[0];
  if (!['day', 'overtime', 'night'].includes(leftShiftType)) return false;
  if (!['day', 'overtime', 'night'].includes(rightShiftType)) return false;
  if (leftShiftType === rightShiftType) return false;
  const sameEmployee = isSameScheduleBoardEmployee(left, right)
    || (
      getScheduleBoardEmployeeDisplayKey(left)
      && getScheduleBoardEmployeeDisplayKey(left) === getScheduleBoardEmployeeDisplayKey(right)
    );
  if (!sameEmployee) return false;
  const sameSite = isSameScheduleBoardSite(left, right)
    || (
      getScheduleBoardSiteDisplayKey(left)
      && getScheduleBoardSiteDisplayKey(left) === getScheduleBoardSiteDisplayKey(right)
    );
  if (!sameSite) return false;
  const leftStatus = String(left.status || '').trim().toLowerCase();
  const rightStatus = String(right.status || '').trim().toLowerCase();
  if (leftStatus === 'leave' || rightStatus === 'leave') return false;
  const leftRange = getScheduleBoardItemComparableRange(left);
  const rightRange = getScheduleBoardItemComparableRange(right);
  if (!leftRange || !rightRange) return false;
  const rangesDoNotOverlap = leftRange.endMinutes <= rightRange.startMinutes
    || rightRange.endMinutes <= leftRange.startMinutes;
  return rangesDoNotOverlap;
}

function canCombineScheduleBoardItems(items = []) {
  const rows = (Array.isArray(items) ? items : []).filter(Boolean);
  if (rows.length < 2) return false;
  for (let index = 0; index < rows.length; index += 1) {
    for (let nextIndex = index + 1; nextIndex < rows.length; nextIndex += 1) {
      if (!canCombineScheduleBoardItemPair(rows[index], rows[nextIndex])) {
        return false;
      }
    }
  }
  return true;
}

function createCombinedScheduleBoardItemFromItems(items = []) {
  const rows = (Array.isArray(items) ? items : [])
    .filter(Boolean)
    .sort((a, b) => {
      const aRange = getScheduleBoardItemComparableRange(a);
      const bRange = getScheduleBoardItemComparableRange(b);
      const aStart = Number.isFinite(aRange?.startMinutes) ? aRange.startMinutes : Number.MAX_SAFE_INTEGER;
      const bStart = Number.isFinite(bRange?.startMinutes) ? bRange.startMinutes : Number.MAX_SAFE_INTEGER;
      return aStart - bStart;
    });
  if (!rows.length) return null;
  if (rows.length === 1) return rows[0];
  const ranges = rows.map((item) => getScheduleBoardItemComparableRange(item)).filter(Boolean);
  if (ranges.length !== rows.length) return rows[0];
  const shiftTypes = Array.from(new Set(rows.flatMap((item) => getScheduleBoardDisplayShiftTypes(item))));
  const startMinutes = Math.min(...ranges.map((range) => range.startMinutes));
  const endMinutes = Math.max(...ranges.map((range) => range.endMinutes));
  const combinedIds = Array.from(new Set(
    rows.flatMap((item) => {
      const ownId = String(item?.schedule_id || '').trim();
      const nestedIds = Array.isArray(item?.combined_schedule_ids)
        ? item.combined_schedule_ids.map((value) => String(value || '').trim()).filter(Boolean)
        : [];
      return [ownId, ...nestedIds].filter(Boolean);
    }),
  ));
  const base = rows[0];
  return {
    ...base,
    schedule_id: '',
    employee_id: String(base.employee_id || '').trim(),
    start_time: formatScheduleComparableMinutesToTimeText(startMinutes),
    end_time: formatScheduleComparableMinutesToTimeText(endMinutes),
    shift_label: shiftTypes.includes('night') ? '주야' : '복합근무',
    display_variant: 'combined',
    display_shift_types: shiftTypes,
    combined_schedule_ids: combinedIds,
  };
}

function createCombinedScheduleBoardItem(left = {}, right = {}) {
  return createCombinedScheduleBoardItemFromItems([left, right]) || left;
}

function buildScheduleBoardGroupedBuckets(items = []) {
  const groups = [];
  (Array.isArray(items) ? items : []).forEach((item) => {
    const existing = groups.find((group) => {
      const anchor = group?.[0];
      if (!anchor) return false;
      return isSameScheduleBoardEmployee(anchor, item) && isSameScheduleBoardSite(anchor, item);
    });
    if (existing) {
      existing.push(item);
      return;
    }
    groups.push([item]);
  });
  return groups;
}

function buildScheduleBoardMergedGroupItems(group = []) {
  const rows = (Array.isArray(group) ? group : [])
    .filter((item) => item && typeof item === 'object')
    .sort((a, b) => {
      const aRange = getScheduleBoardItemComparableRange(a);
      const bRange = getScheduleBoardItemComparableRange(b);
      const aStart = Number.isFinite(aRange?.startMinutes) ? aRange.startMinutes : Number.MAX_SAFE_INTEGER;
      const bStart = Number.isFinite(bRange?.startMinutes) ? bRange.startMinutes : Number.MAX_SAFE_INTEGER;
      if (aStart !== bStart) return aStart - bStart;
      const aEnd = Number.isFinite(aRange?.endMinutes) ? aRange.endMinutes : Number.MAX_SAFE_INTEGER;
      const bEnd = Number.isFinite(bRange?.endMinutes) ? bRange.endMinutes : Number.MAX_SAFE_INTEGER;
      return aEnd - bEnd;
    });

  const combinable = [];
  const passthrough = [];

  rows.forEach((item) => {
    if (String(item?.display_variant || '').trim().toLowerCase() === 'combined') {
      passthrough.push(item);
      return;
    }
    const shiftTypes = getScheduleBoardDisplayShiftTypes(item);
    if (shiftTypes.length === 1 && ['day', 'overtime', 'night'].includes(shiftTypes[0])) {
      combinable.push(item);
      return;
    }
    passthrough.push(item);
  });

  const merged = [];
  let cluster = [];
  const flushCluster = () => {
    if (!cluster.length) return;
    if (canCombineScheduleBoardItems(cluster)) {
      const combinedItem = createCombinedScheduleBoardItemFromItems(cluster);
      if (combinedItem) {
        merged.push(combinedItem);
      } else {
        merged.push(...cluster);
      }
    } else {
      merged.push(...cluster);
    }
    cluster = [];
  };

  combinable.forEach((item) => {
    if (!cluster.length) {
      cluster = [item];
      return;
    }
    const nextCluster = [...cluster, item];
    if (canCombineScheduleBoardItems(nextCluster)) {
      cluster = nextCluster;
      return;
    }
    flushCluster();
    cluster = [item];
  });
  flushCluster();

  merged.push(...passthrough);
  return merged.sort((a, b) => {
    const aRange = getScheduleBoardItemComparableRange(a);
    const bRange = getScheduleBoardItemComparableRange(b);
    const aStart = Number.isFinite(aRange?.startMinutes) ? aRange.startMinutes : Number.MAX_SAFE_INTEGER;
    const bStart = Number.isFinite(bRange?.startMinutes) ? bRange.startMinutes : Number.MAX_SAFE_INTEGER;
    if (aStart !== bStart) return aStart - bStart;
    const aEnd = Number.isFinite(aRange?.endMinutes) ? aRange.endMinutes : Number.MAX_SAFE_INTEGER;
    const bEnd = Number.isFinite(bRange?.endMinutes) ? bRange.endMinutes : Number.MAX_SAFE_INTEGER;
    return aEnd - bEnd;
  });
}

function getScheduleMonthGridDateKeys(month) {
  const monthMeta = getMonthMeta(month);
  if (!monthMeta) return [];
  const firstDate = new Date(monthMeta.year, monthMeta.monthIndex, 1);
  const leadingDays = firstDate.getDay();
  const gridStart = new Date(firstDate);
  gridStart.setDate(gridStart.getDate() - leadingDays);
  const slotCount = Math.ceil((leadingDays + monthMeta.daysInMonth) / 7) * 7;
  return Array.from({ length: slotCount }, (_, index) => {
    const value = new Date(gridStart);
    value.setDate(gridStart.getDate() + index);
    return toLocalDateKey(value);
  });
}

function buildScheduleBoardDisplayItems(items = []) {
  const rows = (Array.isArray(items) ? items : [])
    .filter((item) => item && typeof item === 'object')
    .sort((a, b) => {
      const siteCompare = getScheduleBoardSiteDisplayKey(a).localeCompare(getScheduleBoardSiteDisplayKey(b))
        || getScheduleBoardSiteSortKey(a).localeCompare(getScheduleBoardSiteSortKey(b));
      if (siteCompare !== 0) return siteCompare;
      const employeeCompare = getScheduleBoardEmployeeDisplayKey(a).localeCompare(getScheduleBoardEmployeeDisplayKey(b))
        || getScheduleBoardEmployeeSortKey(a).localeCompare(getScheduleBoardEmployeeSortKey(b));
      if (employeeCompare !== 0) return employeeCompare;
      const aRange = getScheduleBoardItemComparableRange(a);
      const bRange = getScheduleBoardItemComparableRange(b);
      const aStart = Number.isFinite(aRange?.startMinutes) ? aRange.startMinutes : Number.MAX_SAFE_INTEGER;
      const bStart = Number.isFinite(bRange?.startMinutes) ? bRange.startMinutes : Number.MAX_SAFE_INTEGER;
      if (aStart !== bStart) return aStart - bStart;
      const aEnd = Number.isFinite(aRange?.endMinutes) ? aRange.endMinutes : Number.MAX_SAFE_INTEGER;
      const bEnd = Number.isFinite(bRange?.endMinutes) ? bRange.endMinutes : Number.MAX_SAFE_INTEGER;
      return aEnd - bEnd;
    });

  const groups = buildScheduleBoardGroupedBuckets(rows);
  return groups.flatMap((group) => buildScheduleBoardMergedGroupItems(group));
}

function buildScheduleBoardRenderItemsForCell(items = []) {
  const normalizedItems = (Array.isArray(items) ? items : [])
    .map((item) => normalizeScheduleBoardItem(item))
    .filter((item) => item && typeof item === 'object');
  const mergedItems = buildScheduleBoardDisplayItems(normalizedItems);
  if (mergedItems.some((item) => String(item?.display_variant || '').trim().toLowerCase() === 'combined')) {
    return mergedItems;
  }

  const groups = new Map();
  normalizedItems.forEach((item) => {
    const employeeKey = String(
      item?.employee_id
      || item?.employee_code
      || item?.employee_name
      || item?.full_name
      || ''
    ).trim().toUpperCase();
    const siteKey = String(item?.site_code || item?.site_name || '').trim().toUpperCase();
    if (!employeeKey || !siteKey) return;
    const key = `${employeeKey}::${siteKey}`;
    if (!groups.has(key)) groups.set(key, []);
    groups.get(key).push(item);
  });

  if (!groups.size) return mergedItems;

  const forcedItems = [];
  groups.forEach((group) => {
    forcedItems.push(...buildScheduleBoardMergedGroupItems(group));
  });

  return forcedItems.sort((a, b) => {
    const aRange = getScheduleBoardItemComparableRange(a);
    const bRange = getScheduleBoardItemComparableRange(b);
    const aStart = Number.isFinite(aRange?.startMinutes) ? aRange.startMinutes : Number.MAX_SAFE_INTEGER;
    const bStart = Number.isFinite(bRange?.startMinutes) ? bRange.startMinutes : Number.MAX_SAFE_INTEGER;
    if (aStart !== bStart) return aStart - bStart;
    const aEnd = Number.isFinite(aRange?.endMinutes) ? aRange.endMinutes : Number.MAX_SAFE_INTEGER;
    const bEnd = Number.isFinite(bRange?.endMinutes) ? bRange.endMinutes : Number.MAX_SAFE_INTEGER;
    return aEnd - bEnd;
  });
}

function buildScheduleBoardDaysFromRows(month, rows = [], seedDays = []) {
  const monthKey = normalizeMonthKey(month);
  if (!monthKey) return [];
  const visibleDateKeys = getScheduleMonthGridDateKeys(monthKey);
  const seedMap = new Map(
    (Array.isArray(seedDays) ? seedDays : [])
      .map((day) => [String(day?.date || '').trim(), day]),
  );
  const dayMap = new Map();
  visibleDateKeys.forEach((dateKey) => {
    const seed = seedMap.get(dateKey);
    const isOutsideMonth = getMonthFromDateKey(dateKey) !== monthKey;
    dayMap.set(dateKey, {
      date: dateKey,
      holiday_name: String(seed?.holiday_name || '').trim(),
      items: isOutsideMonth
        ? buildScheduleBoardDisplayItems(
          (Array.isArray(seed?.items) ? seed.items : [])
            .map((item) => normalizeScheduleBoardItem(item))
            .filter((item) => item.employee_code && item.shift_type),
        )
        : [],
      support_request_count: Number(seed?.support_request_count || 0),
    });
  });

  (Array.isArray(rows) ? rows : []).forEach((row) => {
    const dateKey = String(row?.schedule_date || row?.date || '').trim();
    if (!dayMap.has(dateKey)) return;
    const dayBucket = dayMap.get(dateKey);
    const normalizedItem = normalizeScheduleBoardItem({
      ...row,
      schedule_id: row?.id || row?.schedule_id,
      employee_name: row?.employee_name || row?.full_name,
      status: isLeaveScheduleRow(row)
        ? 'leave'
        : (normalizeShiftType(row?.shift_type || '') === 'holiday' ? 'non_working' : 'scheduled'),
      source_type: row?.source_type || '',
    });
    dayBucket.items.push(normalizedItem);
    if (!dayBucket.holiday_name && normalizeShiftType(row?.shift_type || '') === 'holiday') {
      dayBucket.holiday_name = '공휴일';
    }
  });

  dayMap.forEach((dayBucket) => {
    dayBucket.items = buildScheduleBoardDisplayItems(dayBucket.items);
  });

  return visibleDateKeys.map((dateKey) => dayMap.get(dateKey));
}

function normalizeScheduleBoardDays(month, days = []) {
  const monthKey = normalizeMonthKey(month);
  if (!monthKey) return [];
  const fallback = buildScheduleBoardDaysFromRows(monthKey, []);
  const fallbackMap = new Map(fallback.map((day) => [day.date, day]));

  (Array.isArray(days) ? days : []).forEach((day) => {
    const dateKey = String(day?.date || '').trim();
    if (!fallbackMap.has(dateKey)) return;
    const bucket = fallbackMap.get(dateKey);
    bucket.holiday_name = String(day?.holiday_name || bucket.holiday_name || '').trim();
    bucket.support_request_count = Number(day?.support_request_count || bucket.support_request_count || 0);
    bucket.items = buildScheduleBoardDisplayItems((Array.isArray(day?.items) ? day.items : [])
      .map((item) => normalizeScheduleBoardItem(item))
      .filter((item) => item.employee_code && item.shift_type));
  });

  return Array.from(fallbackMap.values());
}

function buildScheduleRowsFromBoardDays(days = []) {
  const rows = [];
  (Array.isArray(days) ? days : []).forEach((day) => {
    const dateKey = String(day?.date || '').trim();
    if (!/^\d{4}-\d{2}-\d{2}$/.test(dateKey)) return;
    (Array.isArray(day?.items) ? day.items : []).forEach((item) => {
      const normalized = normalizeScheduleBoardItem(item);
      if (!normalized.employee_code) return;
      rows.push({
        id: normalized.schedule_id || '',
        employee_id: normalized.employee_id || '',
        employee_code: normalized.employee_code,
        employee_name: normalized.employee_name,
        site_code: normalized.site_code,
        site_name: normalized.site_name,
        schedule_date: dateKey,
        shift_type: normalized.shift_type,
        schedule_note: normalized.schedule_note || '',
        source: normalized.source || '',
        schedule_display_type: normalized.schedule_display_type || '',
        schedule_display_label: normalized.schedule_display_label || '',
        schedule_display_time: normalized.schedule_display_time || '',
      });
    });
  });
  return rows;
}

function toDateLabel(dateKey) {
  const value = String(dateKey || '').trim();
  if (!/^\d{4}-\d{2}-\d{2}$/.test(value)) return '날짜 미정';
  const date = new Date(`${value}T00:00:00`);
  if (Number.isNaN(date.getTime())) return value;
  const weekday = SCHEDULE_WEEKDAY_LABELS[(date.getDay() + 6) % 7];
  return `${value} (${weekday})`;
}

function getScheduleProviderModeFromQuery() {
  for (const key of SCHEDULE_PROVIDER_QUERY_KEYS) {
    const value = String(query.get(key) || '').trim().toLowerCase();
    if (!value) continue;
    if (value === 'mock' || value === '1' || value === 'true' || value === 'yes') {
      return 'mock';
    }
  }
  return 'real';
}

function createRealScheduleProvider() {
  return {
    mode: 'real',
    async listMonthlySchedulesLite({ month, tenantCode }) {
      const normalizedMonth = normalizeMonthKey(month);
      if (!normalizedMonth) return { rows: [], employees: [], days: [], metrics: null };
      const tenant = String(tenantCode || '').trim().toLowerCase();
      const queryString = tenant
        ? `?month=${encodeURIComponent(normalizedMonth)}&tenant_code=${encodeURIComponent(tenant)}`
        : `?month=${encodeURIComponent(normalizedMonth)}`;
      try {
        const payload = await apiRequest(`/schedules/monthly-board-lite${queryString}`);
        const days = Array.isArray(payload?.days) ? payload.days : [];
        const rows = Array.isArray(payload?.rows) && payload.rows.length
          ? payload.rows
          : buildScheduleRowsFromBoardDays(days);
        const employees = Array.isArray(payload?.employees) && payload.employees.length
          ? payload.employees
          : buildScheduleEmployeesFromRows(rows).map((item) => ({
            id: String(item?.employee_id || item?.id || item?.employee_code || '').trim(),
            employee_code: String(item?.employee_code || '').trim(),
            employee_name: String(item?.full_name || item?.employee_name || '').trim(),
          }));
        return {
          rows,
          employees,
          days,
          metrics: payload?.metrics && typeof payload.metrics === 'object' ? payload.metrics : null,
        };
      } catch (error) {
        const statusCode = Number(error?.status || error?.response?.status || 0);
        const code = String(error?.code || error?.response?.code || '').trim().toUpperCase();
        if (statusCode !== 404 && statusCode !== 405 && code !== 'HTTP_404' && code !== 'HTTP_405') {
          throw error;
        }
        const payload = await apiRequest(`/schedules/monthly-lite${queryString}`);
        const rows = Array.isArray(payload?.rows) ? payload.rows : [];
        const employees = Array.isArray(payload?.employees) ? payload.employees : [];
        return {
          rows,
          employees,
          days: buildScheduleBoardDaysFromRows(normalizedMonth, rows),
          metrics: null,
        };
      }
    },
    async listMonthlySchedules({ month, tenantCode }) {
      const normalizedMonth = normalizeMonthKey(month);
      if (!normalizedMonth) return [];
      const tenant = String(tenantCode || '').trim().toLowerCase();
      const queryString = tenant
        ? `?month=${encodeURIComponent(normalizedMonth)}&tenant_code=${encodeURIComponent(tenant)}`
        : `?month=${encodeURIComponent(normalizedMonth)}`;
      const rows = await apiRequest(`/schedules/monthly${queryString}`);
      return Array.isArray(rows) ? rows : [];
    },
    async listEmployees({ search = '' } = {}) {
      const employeesPath = appendTenantCodeQuery('/employees?limit=500', getTenantCodeForScopedAdminApi());
      const rows = await fetchPagedApiRows(employeesPath, { pageLimit: 500, maxPages: 20 });
      const list = Array.isArray(rows) ? rows : [];
      const keyword = String(search || '').trim().toLowerCase();
      if (!keyword) return list;
      return list.filter((item) => {
        const code = String(item?.employee_code || '').toLowerCase();
        const name = String(item?.full_name || '').toLowerCase();
        return code.includes(keyword) || name.includes(keyword);
      });
    },
    async listAttendanceByDate({ date, force = false }) {
      const dateKey = String(date || '').trim();
      if (!dateKey) return [];
      const tenantScope = getHeavyApiTenantScope();
      const cacheKey = `attendance-records:${tenantScope}:${dateKey}`;
      if (!force) {
        const cached = getCachedHeavyApiValue(cacheKey);
        if (Array.isArray(cached)) {
          return cached;
        }
      }
      const rows = await apiRequest(`/attendance/records?date=${encodeURIComponent(dateKey)}`);
      const list = Array.isArray(rows) ? rows : [];
      setCachedHeavyApiValue(cacheKey, list, HEAVY_CACHE_TTL_RECORDS_MS);
      return list;
    },
  };
}

function createMockScheduleProvider() {
  const mockEmployees = [
    {
      employee_code: 'E001',
      full_name: '홍길동',
      company_code: 'C001',
      site_code: 'S001',
      site_name: '테스트현장',
    },
    {
      employee_code: 'E002',
      full_name: '김샘플',
      company_code: 'C001',
      site_code: 'S001',
      site_name: '테스트현장',
    },
    {
      employee_code: 'E003',
      full_name: '이데모',
      company_code: 'C001',
      site_code: 'S002',
      site_name: '보조현장',
    },
  ];
  const shiftPattern = ['day', 'day', 'night', 'off', 'off', 'holiday', 'day'];

  const shiftByDate = (dateKey, employeeIndex) => {
    const date = new Date(`${dateKey}T00:00:00`);
    const day = Number.isNaN(date.getTime()) ? 1 : date.getDate();
    return shiftPattern[(day + employeeIndex) % shiftPattern.length];
  };

  return {
    mode: 'mock',
    async listMonthlySchedulesLite({ month, tenantCode }) {
      const rows = await this.listMonthlySchedules({ month, tenantCode });
      return {
        rows,
        employees: buildScheduleEmployeesFromRows(rows).map((item) => ({
          id: String(item?.employee_code || '').trim(),
          employee_code: String(item?.employee_code || '').trim(),
          employee_name: String(item?.full_name || item?.employee_name || '').trim(),
        })),
        days: buildScheduleBoardDaysFromRows(month, rows),
        metrics: null,
      };
    },
    async listMonthlySchedules({ month, tenantCode }) {
      const meta = getMonthMeta(month);
      if (!meta) return [];
      const tenant = String(tenantCode || state.user?.tenant_code || 'T001').trim() || 'T001';
      const rows = [];

      mockEmployees.forEach((employee, employeeIndex) => {
        for (let day = 1; day <= meta.daysInMonth; day += 1) {
          const dateKey = `${meta.month}-${String(day).padStart(2, '0')}`;
          const shiftType = shiftByDate(dateKey, employeeIndex);
          rows.push({
            id: `mock-${meta.month}-${employee.employee_code}-${String(day).padStart(2, '0')}`,
            tenant_code: tenant,
            company_code: employee.company_code,
            site_code: employee.site_code,
            site_name: employee.site_name,
            employee_code: employee.employee_code,
            employee_name: employee.full_name,
            schedule_date: dateKey,
            shift_type: shiftType,
            memo: shiftType === 'night' ? '야간 교대' : '',
            support_worker: employeeIndex === 0 && shiftType === 'day' ? 'E099' : '',
          });
        }
      });

      return rows;
    },
    async listEmployees({ search = '' } = {}) {
      const keyword = String(search || '').trim().toLowerCase();
      if (!keyword) return [...mockEmployees];
      return mockEmployees.filter((item) => {
        const code = String(item.employee_code).toLowerCase();
        const name = String(item.full_name).toLowerCase();
        return code.includes(keyword) || name.includes(keyword);
      });
    },
    async listAttendanceByDate({ date }) {
      const dateKey = String(date || '').trim();
      if (!/^\d{4}-\d{2}-\d{2}$/.test(dateKey)) return [];
      const today = toLocalDateKey(new Date());
      if (dateKey > today) return [];

      const rows = [];
      mockEmployees.forEach((employee, index) => {
        const shiftType = shiftByDate(dateKey, index);
        if (shiftType === 'off' || shiftType === 'holiday') return;
        rows.push({
          id: `mock-att-in-${employee.employee_code}-${dateKey}`,
          employee_code: employee.employee_code,
          event_type: 'check_in',
          event_at: `${dateKey}T09:00:00+09:00`,
          is_within_radius: true,
          distance_meters: 25 + index * 4,
        });
        rows.push({
          id: `mock-att-out-${employee.employee_code}-${dateKey}`,
          employee_code: employee.employee_code,
          event_type: 'check_out',
          event_at: `${dateKey}T18:00:00+09:00`,
          is_within_radius: true,
          distance_meters: 24 + index * 3,
        });
      });
      return rows;
    },
  };
}

function getScheduleDataProvider() {
  if (scheduleDataProvider) return scheduleDataProvider;
  const mode = getScheduleProviderModeFromQuery();
  scheduleDataProvider = mode === 'mock'
    ? createMockScheduleProvider()
    : createRealScheduleProvider();
  state.schedule.usingMockProvider = scheduleDataProvider.mode === 'mock';
  return scheduleDataProvider;
}

function normalizeScheduleRows(rows = []) {
  const list = Array.isArray(rows) ? rows : [];
  return list
    .map((row) => {
      const dateKey = String(row?.schedule_date || '').trim().slice(0, 10);
      const shiftType = normalizeShiftType(row?.shift_type || '');
      const displayType = resolveScheduleDisplayType({ ...row, shift_type: shiftType });
      const displayMeta = getScheduleDisplayMeta({
        ...row,
        shift_type: shiftType,
        schedule_display_type: displayType,
      });
      return {
        ...row,
        schedule_date: /^\d{4}-\d{2}-\d{2}$/.test(dateKey) ? dateKey : '',
        shift_type: shiftType,
        schedule_note: String(row?.schedule_note || '').trim(),
        source: String(row?.source || '').trim(),
        schedule_display_type: displayType,
        schedule_display_label: String(row?.schedule_display_label || displayMeta.label || '').trim(),
        schedule_display_time: String(row?.schedule_display_time || displayMeta.time || '').trim(),
      };
    })
    .filter((row) => row.schedule_date)
    .sort((a, b) => {
      const dateCompare = String(a.schedule_date).localeCompare(String(b.schedule_date));
      if (dateCompare !== 0) return dateCompare;
      return String(a.employee_code || '').localeCompare(String(b.employee_code || ''));
    });
}

function ensureScheduleTenantCode(value = '') {
  const inputTenant = String(value || '').trim().toLowerCase();
  if (inputTenant) return inputTenant;
  const workingTenant = String(getWorkingTenantDisplayCode() || '').trim().toLowerCase();
  if (workingTenant && workingTenant !== 'master') return workingTenant;
  const activeTenant = String(getActiveTenantContext().code || '').trim().toLowerCase();
  if (activeTenant && activeTenant !== 'master') return activeTenant;
  return String(state.user?.tenant_code || '').trim().toLowerCase();
}

function getScheduleCacheKey(month, tenantCode) {
  const normalizedMonth = normalizeMonthKey(month);
  const tenant = String(tenantCode || '').trim().toUpperCase();
  const providerMode = getScheduleDataProvider().mode;
  return `${providerMode}:${tenant}:${normalizedMonth}`;
}

function invalidateScheduleCache() {
  if (!(state.schedule.liteCacheByMonth instanceof Map)) {
    state.schedule.liteCacheByMonth = new Map();
  } else {
    state.schedule.liteCacheByMonth.clear();
  }
  if (!(state.schedule.cacheByMonth instanceof Map)) {
    state.schedule.cacheByMonth = new Map();
    return;
  }
  state.schedule.cacheByMonth.clear();
}

function getScheduleRowMergeKey(row = {}) {
  const id = String(row?.id || row?.schedule_id || '').trim();
  if (id) return `id:${id}`;
  return [
    'row',
    String(row?.employee_id || '').trim(),
    String(row?.employee_code || '').trim(),
    String(row?.schedule_date || '').trim(),
    normalizeShiftType(row?.shift_type || ''),
    String(row?.shift_start_time || row?.start_time || '').trim(),
    String(row?.shift_end_time || row?.end_time || '').trim(),
    String(row?.site_code || '').trim().toUpperCase(),
  ].join('|');
}

function mergeScheduleRowsForState(existingRows = [], incomingRows = []) {
  const mergedMap = new Map();
  normalizeScheduleRows(existingRows).forEach((row) => {
    mergedMap.set(getScheduleRowMergeKey(row), row);
  });
  normalizeScheduleRows(incomingRows).forEach((row) => {
    mergedMap.set(getScheduleRowMergeKey(row), row);
  });
  return normalizeScheduleRows(Array.from(mergedMap.values()));
}

function syncScheduleCurrentMonthCaches(month, tenantCode) {
  const normalizedMonth = normalizeMonthKey(month || state.schedule.month);
  const normalizedTenant = ensureScheduleTenantCode(tenantCode || state.schedule.tenantCode);
  if (!normalizedMonth) return;
  const cacheKey = getScheduleCacheKey(normalizedMonth, normalizedTenant);
  const rows = normalizeScheduleRows(state.schedule.rows);
  const employees = normalizeScheduleEmployees(Array.isArray(state.schedule.employees) ? state.schedule.employees : []);
  const days = normalizeScheduleBoardDays(
    normalizedMonth,
    Array.isArray(state.schedule.boardDays) ? state.schedule.boardDays : [],
  );
  state.schedule.cacheByMonth.set(cacheKey, {
    rows,
    cachedAt: Date.now(),
  });
  state.schedule.liteCacheByMonth.set(cacheKey, {
    rows,
    employees,
    days,
    metrics: null,
    cachedAt: Date.now(),
  });
}

function applyCreatedScheduleRowsToCurrentView(createdRows = [], { month = '', tenantCode = '' } = {}) {
  const normalizedMonth = normalizeMonthKey(month || state.schedule.month);
  if (!normalizedMonth) return false;
  const visibleDateKeys = new Set(
    (Array.isArray(state.schedule.boardDays) ? state.schedule.boardDays : [])
      .map((row) => String(row?.date || '').trim())
      .filter((value) => /^\d{4}-\d{2}-\d{2}$/.test(value)),
  );
  const visibleRows = normalizeScheduleRows(createdRows).filter((row) => {
    const dateKey = String(row?.schedule_date || '').trim();
    if (!dateKey) return false;
    if (visibleDateKeys.size > 0) {
      return visibleDateKeys.has(dateKey);
    }
    return getMonthFromDateKey(dateKey) === normalizedMonth;
  });
  if (!visibleRows.length) return false;
  state.schedule.rows = mergeScheduleRowsForState(state.schedule.rows, visibleRows);
  state.schedule.employees = normalizeScheduleEmployees([
    ...(Array.isArray(state.schedule.employees) ? state.schedule.employees : []),
    ...buildScheduleEmployeesFromRows(visibleRows),
  ]);
  ensureScheduleSelectedEmployee();
  ensureScheduleSelectedDate();
  state.schedule.boardDays = buildScheduleBoardDaysFromRows(
    normalizedMonth,
    getScheduleCombinedRows(),
    state.schedule.boardDays,
  );
  syncScheduleCurrentMonthCaches(normalizedMonth, tenantCode || state.schedule.tenantCode);
  renderScheduleAll();
  return true;
}

function queueScheduleRefreshAfterMutation({ force = true, deferDetailHydration = true } = {}) {
  window.setTimeout(() => {
    loadSchedule({ force, deferDetailHydration, background: true })
      .catch((error) => {
        console.error('[RG ARLS] schedule background refresh failed after mutation', error);
      });
  }, 0);
}

function ensureHeavyApiCacheMap() {
  if (!(state.heavyApiCache instanceof Map)) {
    state.heavyApiCache = new Map();
  }
  return state.heavyApiCache;
}

function getCachedHeavyApiValue(key = '') {
  const cacheKey = String(key || '').trim();
  if (!cacheKey) return null;
  const cache = ensureHeavyApiCacheMap();
  const entry = cache.get(cacheKey);
  if (!entry || typeof entry !== 'object') return null;
  const expiresAt = Number(entry.expiresAt || 0);
  if (!Number.isFinite(expiresAt) || expiresAt <= Date.now()) {
    cache.delete(cacheKey);
    return null;
  }
  return entry.value;
}

function setCachedHeavyApiValue(key = '', value = null, ttlMs = 0) {
  const cacheKey = String(key || '').trim();
  const ttl = Number(ttlMs || 0);
  if (!cacheKey || !Number.isFinite(ttl) || ttl <= 0) return;
  const cache = ensureHeavyApiCacheMap();
  cache.set(cacheKey, {
    value,
    expiresAt: Date.now() + ttl,
  });
}

function clearHeavyApiCache(prefix = '') {
  const cache = ensureHeavyApiCacheMap();
  const normalizedPrefix = String(prefix || '').trim();
  if (!normalizedPrefix) {
    cache.clear();
    return;
  }
  Array.from(cache.keys()).forEach((key) => {
    if (String(key || '').startsWith(normalizedPrefix)) {
      cache.delete(key);
    }
  });
}

function getHeavyApiTenantScope() {
  return String(getActiveTenantHeaderValue() || state.user?.tenant_code || '')
    .trim()
    .toLowerCase();
}

function splitApiPath(path = '') {
  const raw = String(path || '').trim();
  const idx = raw.indexOf('?');
  if (idx < 0) {
    return { basePath: raw, params: new URLSearchParams() };
  }
  return {
    basePath: raw.slice(0, idx),
    params: new URLSearchParams(raw.slice(idx + 1)),
  };
}

function buildApiPath(basePath = '', params = null) {
  const query = params instanceof URLSearchParams ? params.toString() : '';
  return query ? `${String(basePath || '').trim()}?${query}` : String(basePath || '').trim();
}

async function fetchPagedApiRows(path, { headers = null, pageLimit = PAGED_FETCH_LIMIT, maxPages = PAGED_FETCH_MAX_PAGES } = {}) {
  const { basePath, params } = splitApiPath(path);
  if (!basePath) return [];

  const normalizedLimit = Math.max(1, Math.min(2000, Number(pageLimit) || PAGED_FETCH_LIMIT));
  let offset = Math.max(0, Number(params.get('offset')) || 0);
  params.set('limit', String(normalizedLimit));

  const rows = [];
  for (let page = 0; page < Math.max(1, Number(maxPages) || PAGED_FETCH_MAX_PAGES); page += 1) {
    params.set('offset', String(offset));
    const pagePath = buildApiPath(basePath, params);
    const pageRows = await apiRequest(pagePath, headers ? { headers } : {});
    if (!Array.isArray(pageRows)) {
      return rows;
    }
    rows.push(...pageRows);
    if (pageRows.length < normalizedLimit) {
      break;
    }
    offset += pageRows.length;
  }
  return rows;
}

function clearListCaches({ clearStorage = true, resetFilters = true } = {}) {
  state.sites = [];
  state.siteCatalog = [];
  state.home.sites = [];
  state.employeeAdmin.rows = [];
  state.employeeAdmin.siteRows = [];
  state.employeeAdmin.siteRowsScopeKey = '';
  if (resetFilters) {
    state.siteTenantFilterValue = '';
    state.employeeAdmin.tenantFilterId = '';
    state.employeeAdmin.siteFilterCode = 'all';
  }
  state.devAdmin.usersByTenant = {};
  clearHeavyApiCache();
  clearViewRuntimeCache();
  if (Array.isArray(state.attendanceView?.sites)) state.attendanceView.sites = [];
  if (Array.isArray(state.attendanceView?.employees)) state.attendanceView.employees = [];
  employeesPresenterLastRefreshAt = 0;
  orgPresenterLastRefreshAt = 0;

  if (!clearStorage || typeof localStorage === 'undefined') return;
  const exactKeys = new Set([
    'sitesCache',
    'employeesCache',
    'cachedSites',
    'cachedEmployees',
    'rg-arls-sites-cache',
    'rg-arls-employees-cache',
    'rg-arls-tenants-cache',
    'RG_ARLS_TENANTS_CACHE',
    'RG_ARLS_SITES_CACHE',
    'RG_ARLS_EMPLOYEES_CACHE',
  ]);
  const deleteKeys = [];
  for (let i = 0; i < localStorage.length; i += 1) {
    const key = localStorage.key(i);
    if (!key) continue;
    if (exactKeys.has(key)) {
      deleteKeys.push(key);
      continue;
    }
    const upper = key.toUpperCase();
    if (
      upper.startsWith('RG_ARLS_')
      && (upper.includes('SITE') || upper.includes('EMPLOYEE') || upper.includes('TENANT') || upper.includes('CACHE'))
    ) {
      deleteKeys.push(key);
    }
  }
  deleteKeys.forEach((key) => {
    try {
      localStorage.removeItem(key);
    } catch {
      // ignore storage cleanup failures
    }
  });
}

async function loadMonthlyScheduleRowsWithCache({ month, tenantCode, force = false } = {}) {
  const normalizedMonth = normalizeMonthKey(month);
  if (!normalizedMonth) return [];
  const normalizedTenant = ensureScheduleTenantCode(tenantCode);
  if (!(state.schedule.cacheByMonth instanceof Map)) {
    state.schedule.cacheByMonth = new Map();
  }
  const cacheKey = getScheduleCacheKey(normalizedMonth, normalizedTenant);
  if (!force && state.schedule.cacheByMonth.has(cacheKey)) {
    const cached = state.schedule.cacheByMonth.get(cacheKey);
    if (Array.isArray(cached)) {
      state.schedule.cacheByMonth.set(cacheKey, {
        rows: cached,
        cachedAt: Date.now(),
      });
      return cached;
    }
    const cachedRows = Array.isArray(cached?.rows) ? cached.rows : [];
    const cachedAt = Number(cached?.cachedAt || 0);
    const isFresh = Number.isFinite(cachedAt) && (Date.now() - cachedAt) < HEAVY_CACHE_TTL_MONTHLY_MS;
    if (isFresh) {
      return cachedRows;
    }
  }

  const provider = getScheduleDataProvider();
  const fetched = await provider.listMonthlySchedules({
    month: normalizedMonth,
    tenantCode: normalizedTenant,
  });
  const rows = normalizeScheduleRows(fetched);
  state.schedule.cacheByMonth.set(cacheKey, {
    rows,
    cachedAt: Date.now(),
  });
  return rows;
}

async function loadMonthlyScheduleLiteWithCache({ month, tenantCode, force = false } = {}) {
  const normalizedMonth = normalizeMonthKey(month);
  if (!normalizedMonth) return {
    rows: [],
    employees: [],
    days: [],
    metrics: null,
  };
  const normalizedTenant = ensureScheduleTenantCode(tenantCode);
  if (!(state.schedule.liteCacheByMonth instanceof Map)) {
    state.schedule.liteCacheByMonth = new Map();
  }
  const cacheKey = getScheduleCacheKey(normalizedMonth, normalizedTenant);
  if (!force && state.schedule.liteCacheByMonth.has(cacheKey)) {
    const cached = state.schedule.liteCacheByMonth.get(cacheKey);
    const cachedRows = Array.isArray(cached?.rows) ? cached.rows : [];
    const cachedEmployees = Array.isArray(cached?.employees) ? cached.employees : [];
    const cachedDays = Array.isArray(cached?.days) ? cached.days : [];
    const cachedMetrics = cached?.metrics && typeof cached.metrics === 'object' ? cached.metrics : null;
    const cachedAt = Number(cached?.cachedAt || 0);
    const isFresh = Number.isFinite(cachedAt) && (Date.now() - cachedAt) < HEAVY_CACHE_TTL_MONTHLY_MS;
    if (isFresh) {
      return {
        rows: cachedRows,
        employees: cachedEmployees,
        days: cachedDays,
        metrics: cachedMetrics,
      };
    }
  }

  const provider = getScheduleDataProvider();
  const fetched = await provider.listMonthlySchedulesLite({
    month: normalizedMonth,
    tenantCode: normalizedTenant,
  });
  const rows = normalizeScheduleRows(Array.isArray(fetched?.rows) ? fetched.rows : fetched);
  const employees = normalizeScheduleEmployees(
    Array.isArray(fetched?.employees) && fetched.employees.length
      ? fetched.employees.map((item) => ({
        employee_code: item?.employee_code,
        full_name: item?.employee_name || item?.full_name || '',
        company_code: '',
        site_code: '',
      }))
      : buildScheduleEmployeesFromRows(rows),
  );
  const days = normalizeScheduleBoardDays(
    normalizedMonth,
    Array.isArray(fetched?.days) && fetched.days.length
      ? fetched.days
      : buildScheduleBoardDaysFromRows(normalizedMonth, rows),
  );
  const payload = {
    rows,
    employees,
    days,
    metrics: fetched?.metrics && typeof fetched.metrics === 'object' ? fetched.metrics : null,
    cachedAt: Date.now(),
  };
  state.schedule.liteCacheByMonth.set(cacheKey, payload);
  return {
    rows,
    employees,
    days,
    metrics: payload.metrics,
  };
}

async function loadMonthlySchedulesForMonths(months = [], { tenantCode, force = false } = {}) {
  const normalizedMonths = Array.from(
    new Set(
      (Array.isArray(months) ? months : [])
        .map((item) => normalizeMonthKey(item))
        .filter(Boolean),
    ),
  );
  if (!normalizedMonths.length) return [];

  const settled = await Promise.allSettled(
    normalizedMonths.map((month) => loadMonthlyScheduleRowsWithCache({ month, tenantCode, force })),
  );

  const rows = [];
  let firstError = null;
  settled.forEach((result) => {
    if (result.status === 'fulfilled') {
      rows.push(...(Array.isArray(result.value) ? result.value : []));
    } else if (!firstError) {
      firstError = result.reason instanceof Error ? result.reason : new Error('스케줄 데이터를 불러오지 못했습니다.');
    }
  });

  if (!rows.length && firstError) {
    throw firstError;
  }
  return normalizeScheduleRows(rows);
}

function formatDistanceMeters(value) {
  const num = Number(value);
  if (!Number.isFinite(num)) return '-';
  if (num >= 1000) return `${(num / 1000).toFixed(2)}km`;
  return `${Math.round(num)}m`;
}

function normalizeSiteActiveFilter(value) {
  const raw = String(value || SITE_ACTIVE_ALL).trim().toLowerCase();
  if (raw === SITE_ACTIVE_TRUE) return SITE_ACTIVE_TRUE;
  if (raw === SITE_ACTIVE_FALSE) return SITE_ACTIVE_FALSE;
  return SITE_ACTIVE_ALL;
}

function isToggleChecked(selector) {
  const input = $(selector);
  return input instanceof HTMLInputElement ? Boolean(input.checked) : false;
}

function buildSiteListQuery() {
  const params = new URLSearchParams();
  params.set('detail', 'true');
  const active = normalizeSiteActiveFilter($('#siteActiveFilter')?.value || SITE_ACTIVE_ALL);
  const allowAdvancedToggles = getNavigationRole() === 'DEV';
  if (active !== SITE_ACTIVE_ALL) params.set('active', active);
  if (allowAdvancedToggles && isToggleChecked('#siteIncludeInactive')) params.set('include_inactive', 'true');
  if (allowAdvancedToggles && isToggleChecked('#siteIncludeDeleted')) params.set('include_deleted', 'true');
  const query = params.toString();
  return query ? `?${query}` : '';
}

function getSiteTenantFilterSelection() {
  const navRole = getNavigationRole();
  const uiTenantId = String(state.uiContext?.activeTenantId || '').trim();
  const uiTenantCode = normalizeTenantCode(state.uiContext?.activeTenantCode || '');
  const fallbackTenantId = String(
    uiTenantId
    ||
    getTenantIdForScopedAdminApi()
    || state.user?.tenant_id
    || '',
  ).trim();
  const fallbackTenantCode = String(
    uiTenantCode
    ||
    getTenantCodeForScopedAdminApi()
    || state.user?.tenant_code
    || '',
  ).trim().toUpperCase();
  const select = $('#siteTenantFilter');
  if (!(select instanceof HTMLSelectElement)) {
    return {
      tenantId: fallbackTenantId,
      tenantCode: fallbackTenantCode,
      tenantName: '',
      isAll: false,
    };
  }
  const rawTenantId = String(select.value || '').trim();
  if (navRole === 'DEV' && rawTenantId.toLowerCase() === 'all') {
    return {
      tenantId: '',
      tenantCode: 'ALL',
      tenantName: '전체',
      isAll: true,
    };
  }
  const tenantId = rawTenantId.toLowerCase() === 'all' ? fallbackTenantId : (rawTenantId || fallbackTenantId);
  const option = select.options[select.selectedIndex];
  const rawTenantCode = String(option?.dataset?.tenantCode || '').trim().toUpperCase();
  return {
    tenantId,
    tenantCode: rawTenantCode === 'ALL' ? fallbackTenantCode : (rawTenantCode || fallbackTenantCode),
    tenantName: String(option?.dataset?.tenantName || '').trim(),
    isAll: false,
  };
}

function getSiteScopedTenantHeaderValue(site = null) {
  const row = site && typeof site === 'object' ? site : {};
  const rowHeader = String(row?.tenant_code || row?.tenant_id || '').trim().toLowerCase();
  if (rowHeader && rowHeader !== 'all') return rowHeader;
  const selection = getSiteTenantFilterSelection();
  const filterHeader = String(selection.tenantCode || selection.tenantId || '').trim().toLowerCase();
  if (filterHeader && filterHeader !== 'all') return filterHeader;
  return String(getActiveTenantHeaderValue() || '').trim().toLowerCase();
}

function buildScopedSiteCatalogQuery() {
  const params = new URLSearchParams();
  const tenantCode = String(getTenantCodeForScopedAdminApi() || '').trim().toLowerCase();
  if (tenantCode) params.set('tenant_code', tenantCode);
  params.set('limit', '500');
  const query = params.toString();
  return query ? `?${query}` : '';
}

async function refreshSiteCatalog({ force = false } = {}) {
  if (!force && Array.isArray(state.siteCatalog) && state.siteCatalog.length) {
    return state.siteCatalog;
  }
  try {
    const rows = await fetchPagedApiRows(`/sites${buildScopedSiteCatalogQuery()}`, {
      pageLimit: 500,
      maxPages: 20,
    });
    state.siteCatalog = Array.isArray(rows) ? rows : [];
  } catch {
    state.siteCatalog = Array.isArray(state.siteCatalog) ? state.siteCatalog : [];
  }
  return state.siteCatalog;
}

function parseNumberInput(value) {
  const num = Number(value);
  return Number.isFinite(num) ? num : NaN;
}

function isValidLatLng(latitude, longitude) {
  return Number.isFinite(latitude)
    && Number.isFinite(longitude)
    && latitude >= -90
    && latitude <= 90
    && longitude >= -180
    && longitude <= 180;
}

function haversineMetersClient(lat1, lon1, lat2, lon2) {
  const toRad = (deg) => (deg * Math.PI) / 180;
  const dLat = toRad(lat2 - lat1);
  const dLon = toRad(lon2 - lon1);
  const a = Math.sin(dLat / 2) ** 2
    + Math.cos(toRad(lat1)) * Math.cos(toRad(lat2)) * Math.sin(dLon / 2) ** 2;
  const c = 2 * Math.asin(Math.sqrt(a));
  return 6371000 * c;
}

function getSelectedHomeSite() {
  const code = state.home.selectedSiteCode;
  if (!code) return null;
  return state.home.sites.find((site) => site.site_code === code) || null;
}

function setHomeSitePickerExpanded(expanded) {
  const pickerBtn = $('#homeSitePickerBtn');
  if (!pickerBtn) return;
  pickerBtn.setAttribute('aria-expanded', expanded ? 'true' : 'false');
}

function getHomeSiteDisplayName(site) {
  if (!site) return '';
  const code = String(site.site_code || '').trim();
  const name = String(site.site_name || '').trim();
  if (code && name) return `${code} · ${name}`;
  return code || name || '현장';
}

function renderHomeSitePickerSummary() {
  const pickerBtn = $('#homeSitePickerBtn');
  const metaEl = $('#homeSelectedSiteMeta');
  if (!pickerBtn || !metaEl) return;

  const sites = Array.isArray(state.home.sites) ? state.home.sites : [];
  if (!sites.length) {
    pickerBtn.textContent = '등록된 현장 없음';
    pickerBtn.disabled = true;
    pickerBtn.setAttribute('aria-label', '등록된 현장 없음');
    metaEl.textContent = '관리자가 현장를 등록하면 선택할 수 있습니다.';
    renderHomePolicySkeleton();
    return;
  }

  pickerBtn.disabled = false;
  const site = getSelectedHomeSite();
  if (!site) {
    pickerBtn.textContent = '현장 선택';
    pickerBtn.setAttribute('aria-label', '근무 현장 선택');
    metaEl.textContent = '근무 현장를 선택해 주세요.';
    renderHomePolicySkeleton();
    return;
  }

  const displayName = getHomeSiteDisplayName(site);
  const radius = Number(site.radius_meters);
  pickerBtn.textContent = displayName;
  pickerBtn.setAttribute('aria-label', `근무 현장 선택 (현재 ${displayName})`);
  metaEl.textContent = `선택: ${displayName} · 반경 ${Number.isFinite(radius) ? Math.round(radius) : '-'}m`;
  renderHomePolicySkeleton();
}

function renderHomePolicySkeleton() {
  const workType = $('#homeWorkType');
  const policyHint = $('#homeWorkTypePolicyHint');
  const wifiStatus = $('#homeWifiStatusPill');
  const wifiDetail = $('#homeWifiStatusText');
  const site = getSelectedHomeSite();
  const canEdit = can('attendanceWrite');

  if (workType instanceof HTMLSelectElement) {
    if (!workType.value) workType.value = 'onsite';
    workType.disabled = !canEdit || !site;
  }

  if (policyHint) {
    if (!site) {
      policyHint.textContent = '현장 선택 후 근무 타입 정책을 확인할 수 있습니다.';
    } else if (!canEdit) {
      policyHint.textContent = '읽기 전용 계정은 근무 타입을 변경할 수 없습니다.';
    } else {
      policyHint.textContent = 'P1 골격: 정책 연동 전까지 선택값은 UI에서만 유지됩니다.';
    }
  }

  if (!wifiStatus || !wifiDetail) return;
  if (!site) {
    wifiStatus.className = 'status-pill status-pill-warn';
    wifiStatus.textContent = '확인 대기';
    wifiDetail.textContent = '현장를 선택하면 와이파이 인증 상태를 확인합니다.';
    return;
  }

  const siteCode = String(site.site_code || '').trim();
  const ssid = getSiteWifiSsid(siteCode);
  if (ssid) {
    wifiStatus.className = 'status-pill status-pill-success';
    wifiStatus.textContent = 'SSID 등록';
    wifiDetail.textContent = `${siteCode} · ${ssid}`;
    return;
  }

  wifiStatus.className = 'status-pill status-pill-warn';
  wifiStatus.textContent = 'SSID 미등록';
  wifiDetail.textContent = `${siteCode} · P1 골격: 현장 편집에서 SSID를 입력하면 상태가 연결됩니다.`;
}

function renderHomeWorkStatusCard() {
  const textEl = $('#homeWorkStatusText');
  const pillEl = $('#homeWorkStatusPill');
  const autoCheckoutBadgeEl = $('#homeAutoCheckoutBadge');
  const dateEl = $('#homeTodayDate');
  const siteEl = $('#homeTodaySite');
  const shiftTimeEl = $('#homeTodayShiftTime');
  if (!textEl || !pillEl) return;

  const today = new Date();
  const todayKey = toLocalDateKey(today);
  const todayEntry = (Array.isArray(state.home.weekEntries) ? state.home.weekEntries : [])
    .find((item) => String(item?.dateKey || '') === todayKey);
  const shiftType = normalizeShiftType(todayEntry?.shiftType || '');
  const shiftMeta = HOME_SHIFT_META[shiftType] || { label: '미정', time: '-' };
  const selectedSite = getSelectedHomeSite();
  const hasSelectedSite = Boolean(selectedSite);
  const statusSiteLabel = getHomeStatusSiteDisplayName();
  const hasStatusSite = Boolean(statusSiteLabel);
  const siteDisplayText = hasSelectedSite
    ? getHomeSiteDisplayName(selectedSite)
    : (statusSiteLabel || '현장 선택 필요');
  const hasPendingRequest = Boolean(state.attendanceRequest.pendingId);
  const todayStatus = normalizeHomeAttendanceStatus(state.home.todayStatus || '');
  const checkInTime = formatAttendanceTime(state.home.todayCheckInAt || '');
  const checkOutTime = formatAttendanceTime(state.home.todayCheckOutAt || '');
  const isAutoCheckout = todayStatus === 'DONE' && Boolean(state.home.todayAutoCheckout);

  let statusText = '미출근';
  let detailText = '오늘 출근 기록이 없습니다.';
  let pillClass = 'status-pill status-pill-warn';

  if (todayStatus === 'DONE') {
    statusText = '퇴근완료';
    detailText = `출근 ${checkInTime} · 퇴근 ${checkOutTime}`;
    pillClass = 'status-pill status-pill-success';
  } else if (todayStatus === 'WORKING') {
    statusText = '출근중';
    detailText = checkInTime !== '-'
      ? `출근 시간 ${checkInTime}`
      : '출근 기록이 있습니다. 근무 종료 시 퇴근하기를 눌러주세요.';
    pillClass = 'status-pill status-pill-success';
  } else if (hasPendingRequest) {
    detailText = '범위 밖 출근요청이 승인 대기중입니다.';
  } else if (shiftType === 'off' || shiftType === 'holiday') {
    detailText = '오늘 스케줄은 휴무/휴가로 표시됩니다.';
  } else if (!hasSelectedSite && !hasStatusSite) {
    detailText = '근무 현장를 선택하면 오늘 상태가 갱신됩니다.';
  }

  pillEl.className = pillClass;
  pillEl.textContent = statusText;
  textEl.textContent = detailText;
  if (autoCheckoutBadgeEl) {
    autoCheckoutBadgeEl.classList.toggle('hidden', !isAutoCheckout);
  }
  if (dateEl) {
    dateEl.textContent = today.toLocaleDateString('ko-KR', {
      month: '2-digit',
      day: '2-digit',
      weekday: 'short',
    });
  }
  if (siteEl) {
    siteEl.textContent = siteDisplayText;
  }
  if (shiftTimeEl) {
    if (todayStatus === 'DONE') {
      shiftTimeEl.textContent = `출근 ${checkInTime} · 퇴근 ${checkOutTime}`;
    } else if (todayStatus === 'WORKING') {
      shiftTimeEl.textContent = checkInTime !== '-' ? `출근 ${checkInTime}` : '출근중';
    } else if (!hasSelectedSite && !hasStatusSite) {
      shiftTimeEl.textContent = '-';
    } else {
      shiftTimeEl.textContent = `${shiftMeta.label} · ${shiftMeta.time}`;
    }
  }
}

function setOpsStatusPill(elementId, label, variant = 'warn') {
  const el = $(elementId);
  if (!el) return;
  if (variant === 'success') {
    el.className = 'status-pill status-pill-success';
  } else if (variant === 'error') {
    el.className = 'status-pill status-pill-error';
  } else {
    el.className = 'status-pill status-pill-warn';
  }
  el.textContent = getUiStatusLabel(label);
}

function formatOpsDateTime(rawValue = '') {
  const text = String(rawValue || '').trim();
  if (!text) return '';
  const parsed = new Date(text);
  if (Number.isNaN(parsed.getTime())) return text;
  return parsed.toLocaleString('ko-KR');
}

function setTextToSelectors(selectors = [], text = '') {
  (Array.isArray(selectors) ? selectors : []).forEach((selector) => {
    const el = $(selector);
    if (el) el.textContent = text;
  });
}

function setOpsPillToSelectors(selectors = [], label = '', variant = 'warn') {
  (Array.isArray(selectors) ? selectors : []).forEach((selector) => {
    setOpsStatusPill(selector, label, variant);
  });
}

function getOpsActiveDate() {
  return normalizeAttendanceDate(state.ops?.selectedDate || '') || toLocalDateKey(new Date());
}

function setOpsActiveDate(nextDate, { syncInput = true } = {}) {
  const normalized = normalizeAttendanceDate(nextDate) || toLocalDateKey(new Date());
  if (!state.ops) {
    state.ops = createInitialOpsState();
  }
  state.ops.selectedDate = normalized;
  if (syncInput) {
    const input = $('#opsDateInput');
    if (input instanceof HTMLInputElement) {
      input.value = normalized;
    }
  }
  return normalized;
}

function getOpsSelectedSiteCode() {
  return String(state.ops?.selectedSiteCode || '').trim().toUpperCase();
}

function setOpsSelectedSiteCode(siteCode = '', { syncInput = true } = {}) {
  if (!state.ops) {
    state.ops = createInitialOpsState();
  }
  if (state.ops.siteContextSetting) {
    return String(state.ops.selectedSiteCode || '').trim().toUpperCase();
  }
  const normalized = String(siteCode || '').trim().toUpperCase();
  if (String(state.ops.selectedSiteCode || '').trim().toUpperCase() === normalized) {
    if (syncInput) {
      const select = $('#opsSiteSelect');
      if (select instanceof HTMLSelectElement) {
        select.value = normalized;
      }
    }
    return normalized;
  }
  state.ops.siteContextSetting = true;
  try {
    state.ops.selectedSiteCode = normalized;
    if (syncInput) {
      const select = $('#opsSiteSelect');
      if (select instanceof HTMLSelectElement) {
        select.value = normalized;
      }
    }
  } finally {
    state.ops.siteContextSetting = false;
  }
  return normalized;
}

function isAppleTenantCode(tenantCode = '') {
  return String(tenantCode || '').trim().toLowerCase() === 'apple';
}

function getReportsTenantCode() {
  const navRole = getNavigationRole();
  if (navRole === 'DEV') {
    const ctx = getActiveTenantContext();
    const code = String(ctx?.code || '').trim().toUpperCase();
    return code === 'MASTER' ? '' : code;
  }
  return String(state.user?.tenant_code || '').trim().toUpperCase();
}

function isAppleReportPackEnabled() {
  const reportsTenantCode = getReportsTenantCode();
  return isAppleTenantCode(reportsTenantCode);
}

function buildReportsApiPath(path = '') {
  const basePath = String(path || '').trim();
  if (!basePath) return basePath;
  const tenantCode = getReportsTenantCode();
  if (!tenantCode) return basePath;
  return appendTenantCodeQuery(basePath, tenantCode);
}

function buildDefaultReportPacksForTenant() {
  const packs = [
    {
      key: 'DEFAULT_REPORT_PACK',
      title: '기본 리포트',
      description: '내부 월표/근태 기본 리포트',
      route: '/reports?pack=default',
      type: 'default',
      enabled: true,
    },
  ];
  if (isAppleReportPackEnabled()) {
    packs.unshift({
      key: 'APPLE_REPORT_PACK',
      title: '전용 보고',
      description: '월별 전용 보고 자동화/동기화',
      route: '/reports/apple',
      type: 'apple',
      enabled: true,
    });
  }
  return packs;
}

function renderOpsHeaderMeta() {
  const headerEl = $('#opsHeaderMeta');
  const filterEl = $('#opsFilterMeta');
  const navRole = getNavigationRole();
  const dateKey = getOpsActiveDate();
  const selectedSiteCode = getOpsSelectedSiteCode();
  const siteRows = Array.isArray(state.home?.sites) ? state.home.sites : [];
  const selectedSite = siteRows.find((site) => String(site?.site_code || '').trim().toUpperCase() === selectedSiteCode);
  const tenantLabel = navRole === 'DEV'
    ? `조회 테넌트 ${getWorkingTenantDisplayCode() || '미선택'}`
    : `회사 ${String(state.user?.tenant_code || '-').trim().toUpperCase() || '-'}`;
  const siteLabel = selectedSiteCode
    ? `${selectedSiteCode}${selectedSite?.site_name ? ` · ${selectedSite.site_name}` : ''}`
    : '전체 현장';

  if (headerEl) {
    headerEl.textContent = `${tenantLabel} · 기준일 ${dateKey}`;
  }
  if (filterEl) {
    filterEl.textContent = `현재 필터: ${siteLabel}`;
  }
}

function renderOpsWorkspaceScopeHint() {
  const hintEl = $('#opsWorkspaceScopeHint');
  if (!hintEl) return;
  const tab = normalizeOpsViewTab(state.ops?.viewTab || 'overview');
  const copyByTab = {
    overview: '개요는 오늘 바로 실행할 작업과 즉시 조치할 blocker를 먼저 정리하는 실행 화면입니다.',
    soc: 'SOC 탭은 최근 이벤트, 실패, 재시도 대상을 빠르게 확인하는 운영 화면입니다.',
    sheets: '사이트 동기화 탭은 시트 반영, 엑셀 실행, reconciliation 이슈를 함께 확인하는 실행 화면입니다.',
    logs: '작업 로그 탭은 최근 실행 이력과 오류 메시지를 추적하는 기록 화면입니다.',
  };
  hintEl.textContent = copyByTab[tab] || copyByTab.overview;
}

function createOpsAttentionRow({
  title = '',
  subtitle = '',
  pillLabel = '',
  pillVariant = 'neutral',
  action = '',
  route = '',
  focus = '',
  tab = '',
} = {}) {
  const li = document.createElement('li');
  const button = document.createElement('button');
  button.type = 'button';
  button.className = `ops-attention-row ops-attention-row-${pillVariant || 'neutral'}`;
  if (action) button.dataset.action = action;
  if (route) button.dataset.route = route;
  if (focus) button.dataset.focus = focus;
  if (tab) button.dataset.tab = tab;
  button.dataset.variant = String(pillVariant || 'neutral');

  const main = document.createElement('div');
  main.className = 'list-row-main';

  const titleEl = document.createElement('div');
  titleEl.className = 'list-row-title';
  titleEl.textContent = String(title || '-').trim() || '-';
  main.appendChild(titleEl);

  if (String(subtitle || '').trim()) {
    const subEl = document.createElement('div');
    subEl.className = 'list-row-sub';
    subEl.textContent = String(subtitle || '').trim();
    main.appendChild(subEl);
  }

  const pill = document.createElement('span');
  pill.className = `status-pill ${pillVariant === 'success'
    ? 'status-pill-success'
    : (pillVariant === 'error' ? 'status-pill-error' : (pillVariant === 'warn' ? 'status-pill-warn' : 'status-pill-neutral'))}`;
  pill.textContent = String(pillLabel || '-').trim() || '-';

  button.appendChild(main);
  button.appendChild(pill);
  li.appendChild(button);
  return li;
}

function buildOpsAttentionItems() {
  const dashboard = getHomeManagerDashboardState();
  const scheduleSummary = dashboard.scheduleSummary || {};
  const items = [];
  const vacancyCount = Number(state.ops?.vacancyCount || 0);
  const scheduleGapCount = Number(scheduleSummary.scheduleGapCount || 0);
  const vacancySiteCount = Number(scheduleSummary.vacancySiteCount || 0);

  if (vacancyCount > 0) {
    items.push({
      title: '결원/미출근 우선 확인',
      subtitle: `오늘 결원 ${vacancyCount}명 · 출퇴근 기록 확인`,
      pillLabel: `${vacancyCount}건`,
      pillVariant: 'error',
      action: 'ops-open-attendance',
      focus: 'vacancy',
    });
  }

  if (scheduleGapCount > 0 || vacancySiteCount > 0) {
    items.push({
      title: '현장 배정/스케줄 누락',
      subtitle: `현장 누락 ${scheduleGapCount}건 · 결원 지점 ${vacancySiteCount}개`,
      pillLabel: '확인 필요',
      pillVariant: 'warn',
      action: 'ops-open-schedule-today',
    });
  }

  if (!state.ops?.closerAssigned) {
    items.push({
      title: '오늘 마감자 미지정',
      subtitle: '오늘 스케줄에서 먼저 지정 필요',
      pillLabel: '미지정',
      pillVariant: 'error',
      action: 'ops-open-schedule-today',
    });
  }

  if (!state.ops?.leaderAssigned) {
    items.push({
      title: '현장 리더 미지정',
      subtitle: '현장 리더 배정 확인 필요',
      pillLabel: '미지정',
      pillVariant: 'error',
      action: 'ops-open-schedule-today',
    });
  }

  const sheetsStatus = normalizeOpsRunStatus(state.ops?.sheetsStatus || '');
  const socStatus = normalizeOpsRunStatus(state.ops?.socStatus || '');
  const excelStatus = normalizeOpsRunStatus(state.ops?.excelImportStatus || '');
  if (sheetsStatus === 'FAIL' || socStatus === 'FAIL' || excelStatus === 'FAIL') {
    const failedTargets = [];
    if (sheetsStatus === 'FAIL') failedTargets.push('사이트 동기화');
    if (socStatus === 'FAIL') failedTargets.push('SOC');
    if (excelStatus === 'FAIL') failedTargets.push('엑셀 가져오기');
    items.push({
      title: '자동화/연동 실패',
      subtitle: `${failedTargets.join(', ')} 최근 실패`,
      pillLabel: `${failedTargets.length}건`,
      pillVariant: 'warn',
      action: 'ops-view-tab',
      tab: sheetsStatus === 'FAIL' ? 'sheets' : (socStatus === 'FAIL' ? 'soc' : 'logs'),
    });
  }

  if (!items.length) {
    items.push({
      title: '즉시 조치할 운영 이슈 없음',
      subtitle: '오늘 즉시 처리할 blocker 없음',
      pillLabel: '정상',
      pillVariant: 'success',
      action: 'ops-open-attendance',
      focus: 'present',
    });
  }

  return items.slice(0, 4);
}

function renderOpsOverviewAttention() {
  const list = $('#opsAttentionList');
  const pill = $('#opsAttentionCountPill');
  const meta = $('#opsAttentionMeta');
  if (!list) return;

  clearList(list);
  if (state.ops?.loading) {
    if (pill) {
      pill.className = 'status-pill status-pill-neutral';
      pill.textContent = '조회 중';
    }
    if (meta) {
      meta.textContent = '결원, 미지정, 연동 이슈를 계산하는 중입니다.';
    }
    renderEmptyState(list, '운영 우선 조치를 계산하는 중입니다.');
    return;
  }
  if (state.ops?.error) {
    if (pill) {
      pill.className = 'status-pill status-pill-error';
      pill.textContent = '오류';
    }
    if (meta) {
      meta.textContent = '운영 이슈를 정상적으로 불러오지 못했습니다.';
    }
    renderEmptyState(list, '운영 이슈를 불러오지 못했습니다.', state.ops.error);
    return;
  }

  const items = buildOpsAttentionItems();
  const issueCount = items.filter((item) => item.pillVariant !== 'success' && item.pillVariant !== 'neutral').length;

  if (pill) {
    pill.className = `status-pill ${issueCount > 0 ? 'status-pill-warn' : 'status-pill-success'}`;
    pill.textContent = issueCount > 0 ? `${issueCount}건` : '정상';
  }
  if (meta) {
    meta.textContent = issueCount > 0
      ? '오늘 바로 확인할 이슈만 상단에 정리합니다.'
      : '오늘 즉시 조치가 필요한 blocker는 없습니다.';
  }

  if (!items.length) {
    renderEmptyState(list, '오늘 우선 확인 항목이 없습니다.');
    return;
  }

  items.forEach((item) => {
    list.appendChild(createOpsAttentionRow(item));
  });
}

function renderOpsSiteOptions() {
  const select = $('#opsSiteSelect');
  if (!(select instanceof HTMLSelectElement)) {
    renderOpsHeaderMeta();
    return;
  }

  const rows = Array.isArray(state.home?.sites) ? state.home.sites : [];
  const selectedSiteCode = getOpsSelectedSiteCode();
  select.innerHTML = '';

  const allOption = document.createElement('option');
  allOption.value = '';
  allOption.textContent = '전체 현장';
  select.appendChild(allOption);

  rows.forEach((site) => {
    const code = String(site?.site_code || '').trim().toUpperCase();
    if (!code) return;
    const option = document.createElement('option');
    option.value = code;
    option.textContent = `${code} · ${String(site?.site_name || '-').trim() || '-'}`;
    select.appendChild(option);
  });

  const hasSelected = rows.some((site) => String(site?.site_code || '').trim().toUpperCase() === selectedSiteCode);
  const resolvedSite = hasSelected ? selectedSiteCode : '';
  setOpsSelectedSiteCode(resolvedSite, { syncInput: false });
  select.value = resolvedSite;
  renderOpsHeaderMeta();
}

function normalizeOpsRunStatus(rawStatus = '') {
  const value = String(rawStatus || '').trim().toUpperCase();
  if (!value) return 'PENDING';
  if (['SUCCESS', 'OK', 'DONE', 'PROCESSED', 'APPROVED', 'COMPLETED'].includes(value)) return 'SUCCESS';
  if (['FAIL', 'FAILED', 'ERROR', 'REJECTED', 'ABORTED', 'DENIED'].includes(value)) return 'FAIL';
  if (['APPLIED', 'VALIDATED', 'IDLE', 'PENDING', 'OFF'].includes(value)) return value;
  return value;
}

function getOpsStatusVariant(status = '') {
  const normalized = normalizeOpsRunStatus(status);
  if (normalized === 'SUCCESS' || normalized === 'APPLIED' || normalized === 'VALIDATED') return 'success';
  if (normalized === 'FAIL') return 'error';
  return 'warn';
}

function pickLatestRowByTimestamp(rows = [], timestampKeys = []) {
  if (!Array.isArray(rows) || !rows.length) return null;
  const keys = Array.isArray(timestampKeys) ? timestampKeys : [];
  const sorted = [...rows].sort((a, b) => {
    const toMillis = (row) => {
      for (const key of keys) {
        const candidate = String(row?.[key] || '').trim();
        if (!candidate) continue;
        const millis = new Date(candidate).getTime();
        if (Number.isFinite(millis)) return millis;
      }
      return 0;
    };
    return toMillis(b) - toMillis(a);
  });
  return sorted[0] || null;
}

function renderOpsAutomationStatus() {
  const flags = state.integration.flags || {};
  const socEnabled = Boolean(flags.soc_ingest_enabled);
  const socRows = Array.isArray(state.integration.socEvents) ? state.integration.socEvents : [];
  const latestSoc = pickLatestRowByTimestamp(socRows, ['received_at', 'occurred_at', 'created_at']);
  const socRawStatus = latestSoc ? normalizeOpsRunStatus(latestSoc?.status || '') : 'PENDING';
  const socStatus = !socEnabled && !latestSoc
    ? 'OFF'
    : (socRawStatus === 'FAIL' ? 'FAIL' : (socRawStatus === 'SUCCESS' ? 'SUCCESS' : 'PENDING'));
  const socAt = String(
    latestSoc?.received_at
    || latestSoc?.occurred_at
    || latestSoc?.created_at
    || state.ops.socLastSyncedAt
    || '',
  ).trim();
  const socEventType = String(latestSoc?.event_type || '').trim();
  const socTicket = String(latestSoc?.ticket_id || '').trim();
  const socMetaText = latestSoc
    ? `${socEventType || 'SOC 이벤트'}${socTicket ? ` #${socTicket}` : ''} · ${formatOpsDateTime(socAt) || '시간 정보 없음'}`
    : (!socEnabled ? 'SOC 연동이 비활성화되어 있습니다.' : '최근 이벤트 없음');

  const sheetsEnabled = Boolean(flags.google_sheets_sync_enabled);
  const latestSheetFail = pickLatestRowByTimestamp(state.integration.sheetLogs || [], ['created_at']);
  let sheetsStatus = normalizeOpsRunStatus(state.ops.sheetsStatus || (sheetsEnabled ? 'PENDING' : 'OFF'));
  let sheetsAt = String(state.ops.sheetsLastSyncedAt || '').trim();
  let sheetsMessage = String(state.ops.sheetsMessage || '').trim();
  if (latestSheetFail && sheetsStatus !== 'SUCCESS') {
    sheetsStatus = 'FAIL';
    sheetsAt = String(latestSheetFail.created_at || sheetsAt).trim();
    if (!sheetsMessage) {
      sheetsMessage = String(latestSheetFail.error_message || '최근 시트 동기화 실패').trim();
    }
  }
  if (!sheetsEnabled && sheetsStatus === 'PENDING') {
    sheetsStatus = 'OFF';
  }

  const excelStatus = normalizeOpsRunStatus(state.ops.excelImportStatus || 'IDLE');
  const excelAt = String(state.ops.excelImportAt || '').trim();
  const excelMessage = String(state.ops.excelImportMessage || '').trim();

  state.ops.socStatus = socStatus;
  state.ops.socLastSyncedAt = socAt;
  state.ops.sheetsStatus = sheetsStatus;
  state.ops.sheetsLastSyncedAt = sheetsAt;
  state.ops.sheetsMessage = sheetsMessage;
  state.ops.excelImportStatus = excelStatus;
  state.ops.excelImportAt = excelAt;
  state.ops.excelImportMessage = excelMessage;

  setOpsPillToSelectors(['#opsSocStatusPill', '#opsViewSocStatusPill', '#opsOverviewSocStatusPill'], socStatus, getOpsStatusVariant(socStatus));
  setOpsPillToSelectors(['#opsSheetsStatusPill', '#opsViewSheetsStatusPill', '#opsOverviewSheetsStatusPill'], sheetsStatus, getOpsStatusVariant(sheetsStatus));
  setOpsPillToSelectors(['#opsExcelStatusPill', '#opsViewExcelStatusPill', '#opsOverviewExcelStatusPill'], excelStatus, getOpsStatusVariant(excelStatus));

  setTextToSelectors(['#opsSocMeta', '#opsViewSocMeta', '#opsOverviewSocMeta'], socMetaText);

  let sheetsMetaText = '최근 동기화 없음';
  if (sheetsStatus === 'OFF') {
    sheetsMetaText = '시트 동기화가 비활성화되어 있습니다.';
  } else if (sheetsMessage && sheetsAt) {
    sheetsMetaText = `${sheetsMessage} · ${formatOpsDateTime(sheetsAt)}`;
  } else if (sheetsMessage) {
    sheetsMetaText = sheetsMessage;
  } else if (sheetsAt) {
    sheetsMetaText = `마지막 동기화 ${formatOpsDateTime(sheetsAt)}`;
  }
  setTextToSelectors(['#opsSheetsMeta', '#opsViewSheetsMeta', '#opsOverviewSheetsMeta'], sheetsMetaText);

  let excelMetaText = '최근 실행 없음';
  if (excelMessage && excelAt) {
    excelMetaText = `${excelMessage} · ${formatOpsDateTime(excelAt)}`;
  } else if (excelMessage) {
    excelMetaText = excelMessage;
  } else if (excelAt) {
    excelMetaText = `마지막 실행 ${formatOpsDateTime(excelAt)}`;
  }
  setTextToSelectors(['#opsExcelMeta', '#opsViewExcelMeta', '#opsOverviewExcelMeta'], excelMetaText);

  const latestTimes = [socAt, sheetsAt, excelAt]
    .map((value) => new Date(String(value || '').trim()).getTime())
    .filter((value) => Number.isFinite(value) && value > 0);
  let summaryText = '마지막 자동화 동기화 정보가 없습니다.';
  if (latestTimes.length) {
    summaryText = `마지막 자동화 갱신 ${new Date(Math.max(...latestTimes)).toLocaleString('ko-KR')}`;
  }
  setTextToSelectors(['#opsAutomationMeta', '#opsViewAutomationMeta', '#opsOverviewAutomationMeta'], summaryText);
  renderOpsOverviewAttention();
  renderOpsWorkspacePanels();
}

function getHomeManagerDashboardState() {
  if (!state.home) {
    state.home = createInitialHomeState();
  }
  if (!state.home.managerDashboard) {
    state.home.managerDashboard = createInitialHomeManagerDashboardState();
  }
  return state.home.managerDashboard;
}

function setHomeDashboardPill(selector, label = '', variant = 'neutral') {
  const el = $(selector);
  if (!el) return;
  if (variant === 'success') {
    el.className = 'status-pill status-pill-success';
  } else if (variant === 'error') {
    el.className = 'status-pill status-pill-error';
  } else if (variant === 'warn') {
    el.className = 'status-pill status-pill-warn';
  } else {
    el.className = 'status-pill status-pill-neutral';
  }
  el.textContent = String(label || '-').trim() || '-';
}

function createHomeDashboardListRow({
  title = '',
  subtitle = '',
  pillLabel = '',
  pillVariant = 'neutral',
  danger = false,
} = {}) {
  const li = document.createElement('li');
  li.className = 'content-fade-in';
  if (danger) li.classList.add('attendance-outside');

  const row = document.createElement('div');
  row.className = 'list-row';

  const main = document.createElement('div');
  main.className = 'list-row-main';

  const titleEl = document.createElement('div');
  titleEl.className = 'list-row-title';
  titleEl.textContent = String(title || '-').trim() || '-';
  main.appendChild(titleEl);

  if (String(subtitle || '').trim()) {
    const subEl = document.createElement('div');
    subEl.className = 'list-row-sub';
    subEl.textContent = String(subtitle || '').trim();
    main.appendChild(subEl);
  }

  row.appendChild(main);

  if (String(pillLabel || '').trim()) {
    const pillEl = document.createElement('span');
    pillEl.className = `status-pill ${pillVariant === 'success'
      ? 'status-pill-success'
      : (pillVariant === 'error' ? 'status-pill-error' : (pillVariant === 'warn' ? 'status-pill-warn' : 'status-pill-neutral'))}`;
    pillEl.textContent = String(pillLabel || '').trim();
    row.appendChild(pillEl);
  }

  li.appendChild(row);
  return li;
}

function renderHomeDashboardList(listSelector, rows = [], emptyText = '표시할 데이터가 없습니다.', emptyMeta = '') {
  const listEl = $(listSelector);
  if (!listEl) return;
  clearList(listEl);
  const items = Array.isArray(rows) ? rows : [];
  if (!items.length) {
    renderEmptyState(listEl, emptyText, emptyMeta);
    listEl.querySelector('.empty-state')?.classList.add('home-compact-empty');
    return;
  }
  items.forEach((row) => {
    listEl.appendChild(createHomeDashboardListRow(row));
  });
}

function buildHomeManagerPointRows() {
  const dashboard = getHomeManagerDashboardState();
  const unreadItems = (Array.isArray(state.notificationItems) ? state.notificationItems : [])
    .filter((item) => !item?.read)
    .slice(0, 3);
  if (unreadItems.length) {
    return {
      title: '공지사항',
      meta: '오늘 확인이 필요한 알림만 간단히 표시합니다.',
      rows: unreadItems.map((item) => ({
        title: normalizeInAppNotificationMessage(item),
        subtitle: String(item?.createdAt || '').trim()
          ? new Date(String(item.createdAt)).toLocaleString('ko-KR', { month: '2-digit', day: '2-digit', hour: '2-digit', minute: '2-digit' })
          : '시간 정보 없음',
        pillLabel: item?.read ? '읽음' : '미읽음',
        pillVariant: item?.read ? 'neutral' : 'warn',
      })),
    };
  }

  const pointRows = [];
  if (Number(state.ops?.vacancyCount || 0) > 0) {
    pointRows.push({
      title: '결원 확인 필요',
      subtitle: `오늘 결원(미출근) ${Number(state.ops.vacancyCount || 0)}명을 먼저 확인하세요.`,
      pillLabel: '주의',
      pillVariant: 'warn',
    });
  }
  if (!state.ops?.closerAssigned) {
    pointRows.push({
      title: '오늘 마감자 미지정',
      subtitle: '오늘 스케줄에서 마감자를 먼저 지정해야 합니다.',
      pillLabel: '미지정',
      pillVariant: 'error',
    });
  }
  if (!state.ops?.leaderAssigned) {
    pointRows.push({
      title: '리더 지정 필요',
      subtitle: '현장 리더가 비어 있습니다. 스케줄에서 지정해 주세요.',
      pillLabel: '미지정',
      pillVariant: 'error',
    });
  }
  if (Number(dashboard.scheduleSummary?.scheduleGapCount || 0) > 0) {
    pointRows.push({
      title: '스케줄 누락 확인',
      subtitle: `현장/배정 누락 ${Number(dashboard.scheduleSummary.scheduleGapCount || 0)}건이 있습니다.`,
      pillLabel: '확인',
      pillVariant: 'warn',
    });
  }
  if (!pointRows.length) {
    pointRows.push({
      title: '오늘 특이사항 없음',
      subtitle: '핵심 운영 지표상 즉시 확인이 필요한 이슈는 없습니다.',
      pillLabel: '정상',
      pillVariant: 'success',
    });
  }

  return {
    title: '오늘 포인트',
    meta: '공지 데이터가 없을 때 오늘 우선 확인 포인트를 대신 표시합니다.',
    rows: pointRows.slice(0, 3),
  };
}

function renderHomeManagerDashboard() {
  if (!isManagerShellRole()) return;

  const dashboard = getHomeManagerDashboardState();
  const leaveSummary = dashboard.leaveSummary || {};
  const reportSummary = dashboard.reportSummary || {};
  const scheduleSummary = dashboard.scheduleSummary || {};
  const attendanceIssues = Array.isArray(dashboard.attendanceIssues) ? dashboard.attendanceIssues : [];

  const leaveCount = Number(leaveSummary.todayLeaveCount || 0);
  const overnightCount = Number(reportSummary.overnightCount || state.ops?.overnightCount || 0);
  let leaveOrNightText = '없음';
  if (leaveCount > 0 && overnightCount > 0) {
    leaveOrNightText = `휴가 ${leaveCount} · 야간 ${overnightCount}`;
  } else if (leaveCount > 0) {
    leaveOrNightText = `휴가 ${leaveCount}명`;
  } else if (overnightCount > 0) {
    leaveOrNightText = `야간 ${overnightCount}건`;
  }
  setTextToSelectors(['#homeManagerLeaveOrNightLabel'], leaveOrNightText);

  let briefingMeta = '오늘 운영 상태를 집계하고 있습니다.';
  if (state.ops.loading) {
    briefingMeta = '오늘 운영 상태를 집계하는 중입니다.';
  } else if (state.ops.error) {
    briefingMeta = state.ops.error;
  } else {
    const metaParts = [
      `출근 ${Number(state.ops?.presentCount || 0)}/${Number(state.ops?.scheduledCount || 0)}`,
    ];
    if (Number(state.ops?.vacancyCount || 0) > 0) {
      metaParts.push(`결원 ${Number(state.ops.vacancyCount || 0)}명`);
    }
    if (Number(dashboard.approvalPendingCount || 0) > 0) {
      metaParts.push(`승인 대기 ${Number(dashboard.approvalPendingCount || 0)}건`);
    }
    if (state.ops?.lastSyncedAt) {
      metaParts.push(`최근 ${new Date(state.ops.lastSyncedAt).toLocaleTimeString('ko-KR', { hour: '2-digit', minute: '2-digit' })}`);
    }
    briefingMeta = metaParts.join(' · ');
  }
  setTextToSelectors(['#homeManagerOpsMeta'], briefingMeta);

  const attendanceRows = attendanceIssues.slice(0, 5).map((row) => ({
    title: row.employeeName ? `${row.employeeName} (${row.employeeCode})` : row.employeeCode,
    subtitle: `${row.dateLabel || toDateLabel(getOpsActiveDate())} · ${row.siteName || '-'} · ${row.statusLabel || '확인 필요'}`,
    pillLabel: row.statusLabel || '확인 필요',
    pillVariant: row.pillVariant || 'warn',
    danger: Boolean(row.danger),
  }));
  const attendanceIssueCount = attendanceIssues.length;
  setHomeDashboardPill(
    '#homeManagerAttendanceIssuePill',
    state.ops?.loading ? '조회 중' : `${attendanceIssueCount}건`,
    state.ops?.loading ? 'neutral' : (attendanceIssueCount > 0 ? 'warn' : 'success'),
  );
  renderHomeDashboardList(
    '#homeManagerAttendanceIssueList',
    attendanceRows,
    '오늘 표시할 누락/미퇴근 기록이 없습니다.',
    '자세한 확인은 출퇴근 화면에서 진행하세요.',
  );

  const attentionRows = [];
  if (Number(scheduleSummary.scheduleGapCount || 0) > 0 || Number(scheduleSummary.vacancySiteCount || 0) > 0) {
    attentionRows.push({
      title: '스케줄 누락 / 결원 지점',
      subtitle: `현장 누락 ${Number(scheduleSummary.scheduleGapCount || 0)}건 · 결원 지점 ${Number(scheduleSummary.vacancySiteCount || 0)}개`,
      pillLabel: '확인 필요',
      pillVariant: 'warn',
    });
  }
  if (!state.ops?.leaderAssigned) {
    attentionRows.push({
      title: '리더 지정 필요',
      subtitle: '오늘 스케줄에서 현장 리더를 지정해야 합니다.',
      pillLabel: '미지정',
      pillVariant: 'error',
    });
  }
  if (!state.ops?.closerAssigned) {
    attentionRows.push({
      title: '마감자 지정 필요',
      subtitle: '오늘 스케줄에서 마감자를 먼저 지정해야 합니다.',
      pillLabel: '미지정',
      pillVariant: 'error',
    });
  }
  const pointRows = buildHomeManagerPointRows();
  const priorityRows = [
    ...attendanceRows.slice(0, 3),
    ...attentionRows,
    ...(Array.isArray(pointRows.rows) ? pointRows.rows : []),
  ].slice(0, 5);
  const priorityCount = priorityRows.filter((row) => row?.pillVariant && row.pillVariant !== 'success' && row.pillVariant !== 'neutral').length;
  setHomeDashboardPill('#homeManagerPriorityPill', priorityCount > 0 ? `${priorityCount}건` : '정상', priorityCount > 0 ? 'warn' : 'success');
  renderHomeDashboardList('#homeManagerPriorityList', priorityRows, '지금 바로 확인할 운영 이슈가 없습니다.', '세부 처리는 출퇴근, 스케줄, 요청 탭에서 이어집니다.');

  setTextToSelectors(['#homeManagerTodayScheduleCount'], Number(scheduleSummary.todayScheduledCount || 0) > 0 ? `${Number(scheduleSummary.todayScheduledCount || 0)}명` : '0명');
  setTextToSelectors(['#homeManagerWeekScheduleCount'], Number(scheduleSummary.weekScheduledCount || 0) > 0 ? `${Number(scheduleSummary.weekScheduledCount || 0)}건` : '0건');
  setTextToSelectors(['#homeManagerVacancySiteCount'], Number(scheduleSummary.vacancySiteCount || 0) > 0 ? `${Number(scheduleSummary.vacancySiteCount || 0)}개` : '없음');
  setTextToSelectors(['#homeManagerScheduleGapCount'], Number(scheduleSummary.scheduleGapCount || 0) > 0 ? `${Number(scheduleSummary.scheduleGapCount || 0)}건` : '없음');
  const scheduleRows = [
    {
      title: '결원 발생 지점',
      subtitle: Array.isArray(scheduleSummary.vacancySiteLabels) && scheduleSummary.vacancySiteLabels.length
        ? scheduleSummary.vacancySiteLabels.slice(0, 3).join(', ')
        : '오늘 결원 지점이 없습니다.',
      pillLabel: Number(scheduleSummary.vacancySiteCount || 0) > 0 ? '주의' : '정상',
      pillVariant: Number(scheduleSummary.vacancySiteCount || 0) > 0 ? 'warn' : 'success',
    },
    {
      title: '스케줄 누락 여부',
      subtitle: Number(scheduleSummary.scheduleGapCount || 0) > 0
        ? `현장/배정 누락 ${Number(scheduleSummary.scheduleGapCount || 0)}건`
        : '오늘 스케줄 누락은 확인되지 않았습니다.',
      pillLabel: Number(scheduleSummary.scheduleGapCount || 0) > 0 ? '확인 필요' : '정상',
      pillVariant: Number(scheduleSummary.scheduleGapCount || 0) > 0 ? 'warn' : 'success',
    },
  ];
  renderHomeDashboardList('#homeManagerScheduleList', scheduleRows);

  setHomeDashboardPill(
    '#homeManagerApprovalPendingPill',
    `대기 ${Number(dashboard.approvalPendingCount || 0)}건`,
    Number(dashboard.approvalPendingCount || 0) > 0 ? 'warn' : 'success',
  );
  setTextToSelectors(['#homeManagerTodayLeaveCount'], Number(leaveSummary.todayLeaveCount || 0) > 0 ? `${Number(leaveSummary.todayLeaveCount || 0)}명` : '0명');
  setTextToSelectors(['#homeManagerWeekLeaveCount'], Number(leaveSummary.weekLeaveCount || 0) > 0 ? `${Number(leaveSummary.weekLeaveCount || 0)}명` : '0명');
  setTextToSelectors(['#homeManagerApprovedOtCount'], Number(reportSummary.approvedOtCount || 0) > 0 ? `${Number(reportSummary.approvedOtCount || 0)}건` : '0건');
  setTextToSelectors(['#homeManagerReportOvernightCount'], Number(reportSummary.overnightCount || 0) > 0 ? `${Number(reportSummary.overnightCount || 0)}건` : '0건');
  renderHomeDashboardList('#homeManagerLeaveReportList', [
    {
      title: '휴가 승인 대기',
      subtitle: `오늘 휴가 ${Number(leaveSummary.todayLeaveCount || 0)}명 · 이번 주 휴가 ${Number(leaveSummary.weekLeaveCount || 0)}명`,
      pillLabel: Number(leaveSummary.pendingCount || 0) > 0 ? `${Number(leaveSummary.pendingCount || 0)}건` : '없음',
      pillVariant: Number(leaveSummary.pendingCount || 0) > 0 ? 'warn' : 'success',
    },
    {
      title: '리포트 요약',
      subtitle: String(reportSummary.latestLogLabel || '최근 실행 없음').trim() || '최근 실행 없음',
      pillLabel: Number(reportSummary.approvedOtCount || 0) > 0 || Number(reportSummary.overnightCount || 0) > 0 ? '집계됨' : '기본',
      pillVariant: Number(reportSummary.approvedOtCount || 0) > 0 || Number(reportSummary.overnightCount || 0) > 0 ? 'success' : 'neutral',
    },
  ]);
}

async function loadHomeManagerSupplementaryData({ force = false } = {}) {
  if (!isManagerShellRole()) {
    return createInitialHomeManagerDashboardState();
  }

  const dashboard = getHomeManagerDashboardState();
  let pendingApprovalCount = Number(getCorrectionRowsByStatuses(['pending']).length || 0);

  let leaveRows = [];
  if (can('leaveReview')) {
    try {
      leaveRows = await fetchManagerLeaveRequests(['pending', 'approved']);
      pendingApprovalCount += leaveRows.filter((row) => String(row?.status || '').trim().toLowerCase() === 'pending').length;
    } catch {
      leaveRows = [];
    }
  }

  if (can('attendanceReview')) {
    try {
      const attendanceRows = await fetchManagerAttendanceRequests(['pending']);
      pendingApprovalCount += Array.isArray(attendanceRows) ? attendanceRows.length : 0;
    } catch {
      // no-op
    }
  }

  const leaveSummary = buildLeaveSummary(leaveRows, { scope: 'team' });
  dashboard.leaveSummary = {
    todayLeaveCount: Number(leaveSummary?.todayLeaveCount || 0),
    weekLeaveCount: Number(leaveSummary?.weekLeaveCount || 0),
    pendingCount: Number(leaveSummary?.pendingCount || 0),
  };
  dashboard.approvalPendingCount = pendingApprovalCount;

  let approvedOtCount = 0;
  let overnightCount = Number(state.ops?.overnightCount || 0);
  let latestLogLabel = '최근 실행 없음';
  if (isAppleReportPackEnabled()) {
    try {
      await loadAppleReportStatus({ force });
    } catch {
      // no-op
    }
    try {
      await loadAppleReportLogs({ force });
    } catch {
      // no-op
    }
    const metrics = state.reports?.appleStatus?.metrics || {};
    approvedOtCount = Number(metrics?.approved_ot_rows || 0);
    overnightCount = Number(metrics?.overnight_rows || overnightCount || 0);
    const latestLog = buildReportsHistoryRows()[0] || null;
    if (latestLog) {
      latestLogLabel = `${latestLog.title} · ${latestLog.subtitle}`;
    }
  }

  dashboard.reportSummary = {
    approvedOtCount,
    overnightCount,
    latestLogLabel,
    latestLogStatus: '',
  };

  renderHomeManagerDashboard();
  return dashboard;
}

function renderOpsRoleStatus() {
  const closerPills = ['#homeManagerCloserStatusPill', '#opsCloserStatusPill', '#opsViewCloserStatusPill'];
  const leaderPills = ['#homeManagerLeaderStatusPill', '#opsLeaderStatusPill', '#opsViewLeaderStatusPill'];

  if (state.ops.loading) {
    setOpsPillToSelectors(closerPills, '확인 중', 'warn');
    setOpsPillToSelectors(leaderPills, '확인 중', 'warn');
    setTextToSelectors(['#homeManagerCloserMeta', '#opsCloserMeta', '#opsViewCloserMeta'], '오늘 마감자 지정 상태를 확인 중입니다.');
    setTextToSelectors(['#homeManagerLeaderMeta', '#opsLeaderMeta', '#opsViewLeaderMeta'], '오늘 리더 지정 상태를 확인 중입니다.');
    return;
  }

  const closerAssigned = Boolean(state.ops.closerAssigned);
  const leaderAssigned = Boolean(state.ops.leaderAssigned);
  setOpsPillToSelectors(closerPills, closerAssigned ? '지정됨' : '미지정', closerAssigned ? 'success' : 'error');
  setOpsPillToSelectors(leaderPills, leaderAssigned ? '지정됨' : '미지정', leaderAssigned ? 'success' : 'error');
  setTextToSelectors(
    ['#homeManagerCloserMeta', '#opsCloserMeta', '#opsViewCloserMeta'],
    closerAssigned
      ? `현재 마감자: ${state.ops.closerLabel || '-'}`
      : '오늘 마감자가 지정되지 않았습니다. 오늘 스케줄에서 지정해 주세요.',
  );
  setTextToSelectors(
    ['#homeManagerLeaderMeta', '#opsLeaderMeta', '#opsViewLeaderMeta'],
    leaderAssigned
      ? `현재 리더: ${state.ops.leaderLabel || '-'}`
      : '오늘 리더가 지정되지 않았습니다. 오늘 스케줄에서 지정해 주세요.',
  );
}

function renderOpsSummary() {
  const scheduledText = Number.isFinite(state.ops.scheduledCount) ? String(state.ops.scheduledCount) : '-';
  const presentText = Number.isFinite(state.ops.presentCount) ? String(state.ops.presentCount) : '-';
  const vacancyText = Number.isFinite(state.ops.vacancyCount) ? String(state.ops.vacancyCount) : '-';
  const overnightText = Number.isFinite(state.ops.overnightCount)
    ? (state.ops.overnightCount > 0 ? `있음 (${state.ops.overnightCount})` : '없음')
    : '-';
  setTextToSelectors(['#homeManagerScheduledCount', '#opsScheduledCount', '#opsViewScheduledCount'], scheduledText);
  setTextToSelectors(['#homeManagerPresentCount', '#opsPresentCount', '#opsViewPresentCount'], presentText);
  setTextToSelectors(['#homeManagerVacancyCount', '#opsVacancyCount', '#opsViewVacancyCount'], vacancyText);
  setTextToSelectors(['#homeManagerOvernightLabel', '#opsOvernightLabel', '#opsViewOvernightLabel'], overnightText);

  let summaryText = '운영 집계 대기중';
  if (state.ops.loading) {
    summaryText = '운영 집계 중...';
  } else if (state.ops.error) {
    summaryText = state.ops.error;
  } else if (state.ops.lastSyncedAt) {
    summaryText = `마지막 집계: ${new Date(state.ops.lastSyncedAt).toLocaleString('ko-KR')}`;
  }
  setTextToSelectors(['#homeManagerOpsMeta', '#opsSummaryMeta', '#opsViewSummaryMeta'], summaryText);

  renderOpsOverviewAttention();
  renderOpsRoleStatus();
  renderOpsAutomationStatus();
  renderOpsHeaderMeta();
  renderOpsWorkspacePanels();
  updateOpsAppleActionVisibility();
  renderHomeManagerDashboard();
}

function buildOpsWorkspaceLogRows() {
  const rows = [];
  const socEvents = Array.isArray(state.integration?.socEvents) ? state.integration.socEvents : [];
  socEvents.forEach((row, index) => {
    const key = `soc:${String(row?.id || row?.ticket_id || index).trim() || index}`;
    const at = String(row?.received_at || row?.occurred_at || row?.created_at || '').trim();
    const status = String(row?.status || 'pending').trim();
    const eventType = String(row?.event_type || 'SOC 이벤트').trim();
    const ticket = String(row?.ticket_id || '').trim();
    const detail = String(row?.message || row?.detail || '').trim();
    rows.push({
      key,
      channel: 'soc',
      at,
      title: `${eventType}${ticket ? ` #${ticket}` : ''}`,
      subtitle: `${formatOpsDateTime(at) || '-'} · ${getUiStatusLabel(status)}`,
      pill: status || 'pending',
      detail: detail || '상세 메시지 없음',
    });
  });

  const sheetLogs = Array.isArray(state.integration?.sheetLogs) ? state.integration.sheetLogs : [];
  sheetLogs.forEach((row, index) => {
    const key = `sheets:${String(row?.id || row?.log_id || index).trim() || index}`;
    const at = String(row?.created_at || row?.updated_at || '').trim();
    const status = String(row?.status || 'fail').trim();
    const profile = String(row?.profile_name || row?.profile_id || '시트 동기화').trim();
    const direction = String(row?.direction || '').trim();
    const detail = String(row?.error_message || row?.message || '').trim();
    rows.push({
      key,
      channel: 'sheets',
      at,
      title: profile,
      subtitle: `${formatOpsDateTime(at) || '-'}${direction ? ` · ${direction}` : ''} · ${getUiStatusLabel(status)}`,
      pill: status || 'fail',
      detail: detail || '상세 메시지 없음',
    });
  });

  if (String(state.ops?.excelImportAt || '').trim() || String(state.ops?.excelImportMessage || '').trim()) {
    const at = String(state.ops?.excelImportAt || '').trim();
    const status = String(state.ops?.excelImportStatus || 'idle').trim();
    rows.push({
      key: 'excel:latest',
      channel: 'excel',
      at,
      title: '엑셀 가져오기',
      subtitle: `${formatOpsDateTime(at) || '-'} · ${getUiStatusLabel(status)}`,
      pill: status || 'idle',
      detail: String(state.ops?.excelImportMessage || '상세 메시지 없음').trim(),
    });
  }

  return rows.sort((a, b) => {
    const aTime = new Date(String(a.at || '')).getTime();
    const bTime = new Date(String(b.at || '')).getTime();
    const safeA = Number.isFinite(aTime) ? aTime : 0;
    const safeB = Number.isFinite(bTime) ? bTime : 0;
    if (safeA !== safeB) return safeB - safeA;
    return String(a.key || '').localeCompare(String(b.key || ''));
  });
}

function renderOpsWorkspaceLogs() {
  const list = $('#opsLogList');
  const detailTitle = $('#opsLogDetailTitle');
  const detailBody = $('#opsLogDetailBody');
  if (!list || !detailTitle || !detailBody) return;

  const rows = buildOpsWorkspaceLogRows();
  clearList(list);
  if (!rows.length) {
    renderEmptyState(list, '표시할 로그가 없습니다.');
    list.querySelector('.empty-state')?.classList.add('ops-compact-empty-state');
    detailTitle.textContent = '항목 선택';
    detailBody.textContent = '로그를 선택하면 상세를 확인할 수 있습니다.';
    renderOpsLogsSummary();
    return;
  }

  const selected = rows.find((row) => row.key === String(state.ops?.selectedLogKey || '').trim()) || rows[0];
  state.ops.selectedLogKey = selected.key;

  rows.forEach((row) => {
    const li = document.createElement('li');
    const item = makeListRow({
      title: row.title,
      subtitle: row.subtitle,
      pill: row.pill,
      danger: String(row.pill || '').trim().toUpperCase() === 'FAIL',
    });
    item.dataset.action = 'ops-log-select';
    item.dataset.logKey = row.key;
    item.classList.add('ops-log-row');
    item.classList.toggle('active', row.key === selected.key);
    li.appendChild(item);
    list.appendChild(li);
  });

  detailTitle.textContent = `${selected.title}`;
  detailBody.textContent = `${selected.subtitle} · ${selected.detail}`;
  renderOpsLogsSummary();
}

function renderOpsWorkspacePanels() {
  const tabs = $('#opsWorkspaceTabs');
  const tabbarRow = tabs?.closest('.workspace-tabbar-row');
  const automationTitle = $('#opsAutomationCardTitle');
  const isDesktop = isDesktopViewport();
  const tab = normalizeOpsViewTab(state.ops?.viewTab || 'overview');
  state.ops.viewTab = tab;

  if (tabs) {
    tabs.classList.toggle('hidden', !isDesktop);
    if (tabbarRow instanceof HTMLElement) {
      tabbarRow.classList.toggle('hidden', !isDesktop);
    }
    tabs.querySelectorAll('[data-action="ops-view-tab"]').forEach((button) => {
      const buttonTab = normalizeOpsViewTab(button?.dataset?.tab || '');
      button.classList.toggle('active', buttonTab === tab);
      button.setAttribute('aria-pressed', buttonTab === tab ? 'true' : 'false');
    });
  }

  renderOpsWorkspaceScopeHint();

  const panels = Array.from(document.querySelectorAll('#view-ops [data-ops-panel]'));
  const showPanel = (panelType) => {
    if (!isDesktop) {
      return panelType !== 'logs';
    }
    if (tab === 'logs') return panelType === 'logs';
    if (tab === 'soc') return panelType === 'automation';
    if (tab === 'sheets') return panelType === 'automation';
    return panelType === 'overview';
  };
  panels.forEach((panel) => {
    const panelType = String(panel?.dataset?.opsPanel || '').trim();
    panel.classList.toggle('hidden', !showPanel(panelType));
  });

  const socRow = $('#opsAutomationRowSoc');
  const sheetsRow = $('#opsAutomationRowSheets');
  const excelRow = $('#opsAutomationRowExcel');
  if (socRow) socRow.classList.toggle('hidden', isDesktop && tab === 'sheets');
  if (sheetsRow) sheetsRow.classList.toggle('hidden', isDesktop && tab === 'soc');
  if (excelRow) excelRow.classList.toggle('hidden', isDesktop && tab === 'soc');

  if (automationTitle) {
    if (tab === 'soc') automationTitle.textContent = 'SOC 동기화 상태';
    else if (tab === 'sheets') automationTitle.textContent = '사이트 동기화 상태';
    else automationTitle.textContent = '자동화 상태';
  }

  renderOpsAutomationWorkspace();
  renderOpsWorkspaceLogs();
}

async function loadOpsSummary({ force = false } = {}) {
  if (!state.user || !state.token || !isManagerShellRole()) {
    state.ops = createInitialOpsState();
    renderOpsSummary();
    return state.ops;
  }
  if (!hasRuntimeTenantContext()) {
    state.ops = {
      ...createInitialOpsState(),
      error: '작업회사를 먼저 선택해 주세요.',
    };
    renderOpsSummary();
    return state.ops;
  }
  if (state.ops.loading && !force) {
    return state.ops;
  }

  const activeDate = setOpsActiveDate(state.ops.selectedDate || toLocalDateKey(new Date()), { syncInput: true });
  const activeSiteCode = getOpsSelectedSiteCode();
  const month = activeDate.slice(0, 7);
  const tenantCode = getTenantCodeForScopedAdminApi() || ensureScheduleTenantCode(state.user?.tenant_code || '');
  const summaryCacheKey = `${tenantCode}:${activeDate}:${String(activeSiteCode || '').toUpperCase()}`;
  const summaryFetchedAt = Number(state.ops.summaryFetchedAt || 0);
  const hasCachedSnapshot = !force
    && !state.ops.error
    && state.ops.summaryCacheKey === summaryCacheKey
    && summaryFetchedAt > 0
    && (Date.now() - summaryFetchedAt) < OPS_SUMMARY_CACHE_TTL_MS
    && Number.isFinite(Number(state.ops.scheduledCount))
    && Number.isFinite(Number(state.ops.presentCount))
    && Number.isFinite(Number(state.ops.vacancyCount));
  if (hasCachedSnapshot) {
    renderOpsSummary();
    return state.ops;
  }

  state.ops.loading = true;
  state.ops.error = '';
  renderOpsSummary();

  try {
    const [attendanceResult, scheduleResult] = await Promise.allSettled([
      getScheduleDataProvider().listAttendanceByDate({ date: activeDate, force }),
      loadMonthlyScheduleRowsWithCache({ month, tenantCode, force }),
    ]);

    if (scheduleResult.status !== 'fulfilled') {
      throw scheduleResult.reason instanceof Error
        ? scheduleResult.reason
        : new Error('스케줄 조회 실패');
    }

    let attendanceRows = attendanceResult.status === 'fulfilled' && Array.isArray(attendanceResult.value)
      ? attendanceResult.value
      : [];
    if (activeSiteCode) {
      attendanceRows = attendanceRows.filter((row) => String(row?.site_code || '').trim().toUpperCase() === activeSiteCode);
    }
    const checkInSet = new Set();
    attendanceRows.forEach((row) => {
      const eventType = String(row?.event_type || '').trim().toLowerCase();
      if (eventType !== 'check_in') return;
      const key = String(row?.employee_code || row?.employee_id || '').trim();
      if (key) checkInSet.add(key);
    });

    const scheduleRows = Array.isArray(scheduleResult.value) ? scheduleResult.value : [];
    const todayScheduleRows = scheduleRows.filter((row) => {
      const dateKey = String(row?.schedule_date || '').trim();
      const shiftType = normalizeShiftType(row?.shift_type || '');
      const siteMatch = !activeSiteCode || String(row?.site_code || '').trim().toUpperCase() === activeSiteCode;
      return dateKey === activeDate && shiftType !== 'off' && shiftType !== 'holiday' && siteMatch;
    });
    const weekDateKeys = new Set(
      getCurrentWeekDates(new Date(`${activeDate}T00:00:00`))
        .map((date) => toLocalDateKey(date)),
    );
    const weekScheduleRows = scheduleRows.filter((row) => {
      const dateKey = String(row?.schedule_date || '').trim();
      const shiftType = normalizeShiftType(row?.shift_type || '');
      const siteMatch = !activeSiteCode || String(row?.site_code || '').trim().toUpperCase() === activeSiteCode;
      return weekDateKeys.has(dateKey) && shiftType !== 'off' && shiftType !== 'holiday' && siteMatch;
    });

    const scheduledSet = new Set(
      todayScheduleRows
        .map((row) => String(row?.employee_code || row?.employee_id || '').trim())
        .filter(Boolean),
    );
    const overnightCount = todayScheduleRows
      .filter((row) => normalizeShiftType(row?.shift_type || '') === 'night')
      .length;
    const closerCandidate = todayScheduleRows.find((row) => {
      const closer = String(
        row?.closer_employee_code
        || row?.closer_name
        || '',
      ).trim();
      return Boolean(closer);
    });
    const leaderCandidate = todayScheduleRows.find((row) => {
      const leader = String(
        row?.leader_employee_code
        || row?.leader_full_name
        || row?.leader_username
        || row?.leader_name
        || '',
      ).trim();
      return Boolean(leader);
    });

    const scheduleByEmployee = new Map();
    const recordsByEmployee = new Map();
    const vacancySiteMap = new Map();
    const scheduleGapEmployees = new Set();

    todayScheduleRows.forEach((row) => {
      const employeeCode = String(row?.employee_code || row?.employee_id || '').trim();
      if (!employeeCode) return;
      if (!scheduleByEmployee.has(employeeCode)) {
        scheduleByEmployee.set(employeeCode, row);
      }
      const siteCode = String(row?.site_code || '').trim().toUpperCase();
      const siteName = String(row?.site_name || '').trim();
      if (!siteCode || !siteName) {
        scheduleGapEmployees.add(employeeCode);
      }
    });

    attendanceRows.forEach((row) => {
      const employeeCode = String(row?.employee_code || row?.employee_id || '').trim();
      if (!employeeCode) return;
      if (!recordsByEmployee.has(employeeCode)) {
        recordsByEmployee.set(employeeCode, []);
      }
      recordsByEmployee.get(employeeCode).push(row);
    });

    const attendanceIssues = [];
    scheduleByEmployee.forEach((scheduleRow, employeeCode) => {
      const rows = recordsByEmployee.get(employeeCode) || [];
      const checkInRows = rows.filter((row) => String(row?.event_type || '').trim() === 'check_in');
      const checkOutRows = rows.filter((row) => String(row?.event_type || '').trim() === 'check_out');
      let statusCode = '';
      if (!checkInRows.length) {
        statusCode = 'missing_in';
      } else if (!checkOutRows.length) {
        statusCode = 'missing_out';
      } else if (checkInRows.length > 1 || checkOutRows.length > 1) {
        statusCode = 'duplicate';
      }
      if (!statusCode) return;

      const statusMeta = getAttendanceStatusMeta(statusCode);
      const siteCode = String(scheduleRow?.site_code || '').trim().toUpperCase();
      const siteName = String(scheduleRow?.site_name || scheduleRow?.site_code || '').trim() || '-';
      if (statusCode === 'missing_in' && siteName) {
        vacancySiteMap.set(siteCode || siteName, siteName);
      }
      attendanceIssues.push({
        employeeCode,
        employeeName: String(scheduleRow?.employee_name || scheduleRow?.full_name || '').trim(),
        siteName,
        dateLabel: toDateLabel(activeDate),
        statusLabel: statusMeta.label,
        pillVariant: statusCode === 'duplicate' ? 'warn' : 'error',
        danger: Boolean(statusMeta.danger),
      });
    });
    attendanceIssues.sort((a, b) => {
      const rank = (item) => {
        if (String(item?.statusLabel || '').includes('출근')) return 0;
        if (String(item?.statusLabel || '').includes('퇴근')) return 1;
        return 2;
      };
      return rank(a) - rank(b) || String(a.employeeCode).localeCompare(String(b.employeeCode));
    });

    const presentCount = checkInSet.size;
    const scheduledCount = scheduledSet.size;
    state.ops.scheduledCount = scheduledCount;
    state.ops.presentCount = presentCount;
    state.ops.vacancyCount = Math.max(scheduledCount - presentCount, 0);
    state.ops.overnightCount = overnightCount;
    state.ops.overnightActive = overnightCount > 0;
    state.ops.closerAssigned = Boolean(closerCandidate);
    state.ops.closerLabel = String(
      closerCandidate?.closer_employee_code
      || closerCandidate?.closer_name
      || '미지정',
    );
    state.ops.leaderAssigned = Boolean(leaderCandidate);
    state.ops.leaderLabel = String(
      leaderCandidate?.leader_employee_code
      || leaderCandidate?.leader_full_name
      || leaderCandidate?.leader_username
      || leaderCandidate?.leader_name
      || '미지정',
    );
    state.ops.selectedDate = activeDate;
    state.ops.selectedSiteCode = activeSiteCode;
    state.ops.lastSyncedAt = new Date().toISOString();
    state.ops.summaryFetchedAt = Date.now();
    state.ops.summaryCacheKey = summaryCacheKey;
    state.ops.error = '';

    const dashboard = getHomeManagerDashboardState();
    dashboard.attendanceIssues = attendanceIssues;
    dashboard.scheduleSummary = {
      todayScheduledCount: scheduledCount,
      weekScheduledCount: weekScheduleRows.length,
      vacancySiteCount: vacancySiteMap.size,
      scheduleGapCount: scheduleGapEmployees.size,
      siteCount: new Set(
        todayScheduleRows
          .map((row) => String(row?.site_code || row?.site_name || '').trim())
          .filter(Boolean),
      ).size,
      vacancySiteLabels: Array.from(vacancySiteMap.values()),
    };
  } catch (error) {
    state.ops.error = normalizeActionError(error, '운영 집계를 불러오지 못했습니다.');
    const dashboard = getHomeManagerDashboardState();
    dashboard.attendanceIssues = [];
    dashboard.scheduleSummary = createInitialHomeManagerDashboardState().scheduleSummary;
  } finally {
    state.ops.loading = false;
    renderOpsSummary();
  }

  return state.ops;
}

async function refreshOpsAutomationSnapshot({ force = false } = {}) {
  if (!isManagerShellRole() || !canManageIntegrations()) {
    renderOpsAutomationStatus();
    return;
  }
  if (!hasRuntimeTenantContext()) {
    renderOpsAutomationStatus();
    return;
  }

  const jobs = [];
  jobs.push(loadIntegrationFlags({ force }));
  jobs.push(loadSocEvents({ force }));
  // 홈 최초 진입 배경 동기화 실패는 카드 상태로만 반영하고 전역 오류 토스트는 억제한다.
  jobs.push(loadGoogleSheetSyncLogs({ notifyOnError: force, force }));

  await Promise.allSettled(jobs);
  renderOpsAutomationStatus();
}

async function onOpsRetrySheetsSync() {
  if (!canManageIntegrations()) {
    showToast('연동 설정 권한이 없습니다.', 'error', 2600);
    return;
  }

  if (!Array.isArray(state.integration.profiles) || !state.integration.profiles.length) {
    await loadGoogleSheetProfiles();
  }
  const selected = getSelectedGoogleSheetProfile();
  if (!selected?.id) {
    await navigateToRoute(ROUTE_PROFILE);
    showToast('동기화할 구글 시트 프로파일을 먼저 선택해 주세요.', 'info', 3000);
    return;
  }

  await syncGoogleSheetProfileNow();
  await refreshOpsAutomationSnapshot();
}

async function onOpsOpenScheduleToday() {
  const moved = await navigateToRoute(ROUTE_SCHEDULE_CALENDAR);
  if (!moved) return;
  await onScheduleJumpToday();
}

async function onOpsOpenAttendance(focus = 'scheduled') {
  if (!state.attendanceView) {
    state.attendanceView = createInitialAttendanceViewState();
  }
  const activeDate = getOpsActiveDate();
  const siteCode = getOpsSelectedSiteCode();
  setAttendanceActiveDate(activeDate, { syncInput: true });
  state.attendanceView.siteCode = siteCode;
  const moved = await navigateToRoute(ROUTE_ATTENDANCE);
  if (!moved) return;
  if (canUseAttendanceManagerFilter()) {
    if (focus === 'vacancy') {
      state.attendanceView.statusFilter = 'missing_in';
      syncAttendanceManagerFilterInputs();
      renderAttendanceFilterMeta();
      scrollToSelector('#attendanceManagerTableCard');
      showToast('결원/누락 기준으로 출퇴근 화면을 열었습니다.', 'info', 2200);
      return;
    }
    if (focus === 'present') {
      scrollToSelector('#attendanceManagerTableCard');
      return;
    }
    scrollToSelector('#attendanceManagerKpiCard');
    return;
  }
  if (focus === 'vacancy') {
    scrollToSelector('#attendanceTimelineList');
    showToast('결원/누락 기준으로 출퇴근 화면을 열었습니다.', 'info', 2200);
    return;
  }
  if (focus === 'present') {
    scrollToSelector('#attendanceTimelineList');
    return;
  }
  scrollToSelector('#attendanceSummaryHint');
}

async function onOpsOpenOvernightReport() {
  const targetRoute = isAppleReportPackEnabled() ? ROUTE_REPORTS_APPLE : ROUTE_REPORTS;
  const moved = await navigateToRoute(targetRoute);
  if (!moved) return;
  scrollToSelector('#reportsPackList');
  if (isAppleReportPackEnabled()) {
    showToast('전용 보고로 이동했습니다.', 'info', 2200);
  } else {
    showToast('기본 리포트 팩으로 이동했습니다.', 'info', 2200);
  }
}

function buildOpsRetryScope() {
  const dateKey = getOpsActiveDate();
  const siteCode = getOpsSelectedSiteCode();
  return {
    date: dateKey,
    month: String(dateKey || '').slice(0, 7),
    site_code: siteCode || null,
  };
}

async function onOpsRetryTarget(target = '') {
  const normalizedTarget = String(target || '').trim().toLowerCase();
  if (!normalizedTarget) return;
  if (!canManageIntegrations()) {
    showToast('연동 상태 재시도 권한이 없습니다.', 'error', 2600);
    return;
  }

  const payload = {
    target: normalizedTarget,
    scope: buildOpsRetryScope(),
  };
  let apiRetried = false;
  try {
    await apiRequest('/integrations/retry', {
      method: 'POST',
      body: payload,
    });
    apiRetried = true;
    showToast(`${normalizedTarget.toUpperCase()} 재시도를 요청했습니다.`, 'success', 2200);
  } catch (error) {
    const statusCode = Number(error?.status || 0);
    if (statusCode !== 404 && statusCode !== 405) {
      throw error;
    }
  }

    if (!apiRetried) {
      if (normalizedTarget === 'sheets') {
        await onOpsRetrySheetsSync();
        return;
      }
      if (normalizedTarget === 'soc') {
      await loadSocEvents({ force: true });
        showToast('SOC 상태를 다시 조회했습니다.', 'info', 2200);
      } else if (normalizedTarget === 'excel') {
        await navigateToRoute(ROUTE_ADMIN_SCHEDULE_TOOLS);
        showToast('엑셀 가져오기 화면으로 이동했습니다.', 'info', 2200);
      }
  }

  await refreshOpsAutomationSnapshot({ force: true });
}

function buildOpsLogRows(target = '') {
  const normalizedTarget = String(target || '').trim().toLowerCase();
  if (normalizedTarget === 'soc') {
    const socRows = Array.isArray(state.integration.socEvents) ? state.integration.socEvents : [];
    return socRows.slice(0, 20).map((row) => ({
      title: `${String(row?.event_type || 'SOC 이벤트').trim()} · ${getUiStatusLabel(String(row?.status || 'pending').trim())}`,
      subtitle: `${String(row?.ticket_id || '-')} · ${formatOpsDateTime(row?.received_at || row?.occurred_at || row?.created_at || '') || '-'}`,
      pill: String(row?.status || 'pending').trim(),
    }));
  }
  if (normalizedTarget === 'sheets') {
    const sheetRows = Array.isArray(state.integration.sheetLogs) ? state.integration.sheetLogs : [];
    return sheetRows.slice(0, 20).map((row) => ({
      title: `${String(row?.profile_name || row?.profile_id || '시트 프로파일').trim()} · ${String(row?.status || 'FAIL').trim()}`,
      subtitle: `${String(row?.direction || 'DB_TO_SHEET').trim()} · ${formatOpsDateTime(row?.created_at || '') || '-'} · ${String(row?.error_message || '오류 메시지 없음').trim()}`,
      pill: String(row?.status || 'FAIL').trim(),
    }));
  }
  return [{
    title: '엑셀 가져오기',
    subtitle: `${String(state.ops.excelImportMessage || '최근 실행 정보 없음').trim()} · ${formatOpsDateTime(state.ops.excelImportAt || '') || '-'}`,
    pill: String(state.ops.excelImportStatus || 'IDLE').trim() || 'IDLE',
  }];
}

function createOpsCompactActionRow({
  title = '',
  subtitle = '',
  pill = '',
  action = '',
  tab = '',
  target = '',
} = {}) {
  const li = document.createElement('li');
  const button = document.createElement('button');
  button.type = 'button';
  button.className = 'ops-attention-row ops-compact-action-row';
  if (action) button.dataset.action = action;
  if (tab) button.dataset.tab = tab;
  if (target) button.dataset.target = target;

  const main = document.createElement('div');
  main.className = 'list-row-main';

  const titleEl = document.createElement('div');
  titleEl.className = 'list-row-title';
  titleEl.textContent = String(title || '-').trim() || '-';
  main.appendChild(titleEl);

  if (String(subtitle || '').trim()) {
    const subtitleEl = document.createElement('div');
    subtitleEl.className = 'list-row-sub';
    subtitleEl.textContent = String(subtitle || '').trim();
    main.appendChild(subtitleEl);
  }

  button.appendChild(main);
  if (String(pill || '').trim()) {
    const pillEl = document.createElement('span');
    pillEl.className = 'status-pill status-pill-neutral';
    pillEl.textContent = String(pill || '').trim();
    button.appendChild(pillEl);
  }

  li.appendChild(button);
  return li;
}

function createOpsCompactLogRow({
  title = '',
  subtitle = '',
  pill = '',
  danger = false,
} = {}) {
  const li = document.createElement('li');
  const row = document.createElement('div');
  row.className = 'ops-attention-row ops-compact-log-row';
  if (danger) row.classList.add('ops-row-danger');

  const main = document.createElement('div');
  main.className = 'list-row-main';

  const titleEl = document.createElement('div');
  titleEl.className = 'list-row-title';
  titleEl.textContent = String(title || '-').trim() || '-';
  main.appendChild(titleEl);

  if (String(subtitle || '').trim()) {
    const subtitleEl = document.createElement('div');
    subtitleEl.className = 'list-row-sub';
    subtitleEl.textContent = String(subtitle || '').trim();
    main.appendChild(subtitleEl);
  }

  row.appendChild(main);
  if (String(pill || '').trim()) {
    const pillEl = document.createElement('span');
    const normalized = normalizeOpsRunStatus(pill);
    pillEl.className = `status-pill ${normalized === 'FAIL'
      ? 'status-pill-error'
      : (normalized === 'SUCCESS' ? 'status-pill-success' : 'status-pill-neutral')}`;
    pillEl.textContent = getUiStatusLabel(String(pill || '').trim());
    row.appendChild(pillEl);
  }

  li.appendChild(row);
  return li;
}

function renderOpsCompactList(listEl, rows = [], emptyTitle = '', emptyMeta = '') {
  if (!listEl) return;
  clearList(listEl);
  const items = Array.isArray(rows) ? rows : [];
  if (!items.length) {
    renderEmptyState(listEl, emptyTitle, emptyMeta);
    listEl.querySelector('.empty-state')?.classList.add('ops-compact-empty-state');
    return;
  }
  items.forEach((row) => listEl.appendChild(row));
}

function getOpsAutomationRelatedRows(tab = '') {
  const normalizedTab = normalizeOpsViewTab(tab || state.ops?.viewTab || 'overview');
  if (normalizedTab === 'soc') {
    return buildOpsLogRows('soc').slice(0, 8);
  }
  if (normalizedTab === 'sheets') {
    const excelRows = String(state.ops?.excelImportAt || '').trim() || String(state.ops?.excelImportMessage || '').trim()
      ? buildOpsLogRows('excel').map((row) => ({ ...row, channel: 'excel' }))
      : [];
    return [
      ...buildOpsLogRows('sheets').map((row) => ({ ...row, channel: 'sheets' })),
      ...excelRows,
    ].slice(0, 8);
  }
  return buildOpsWorkspaceLogRows().slice(0, 8);
}

function buildOpsAutomationActionRows(tab = '') {
  const normalizedTab = normalizeOpsViewTab(tab || state.ops?.viewTab || 'overview');
  if (normalizedTab === 'soc') {
    return [
      createOpsCompactActionRow({
        title: 'SOC 상태 다시 확인',
        subtitle: '최근 이벤트와 상태를 즉시 새로 조회합니다.',
        pill: '새로고침',
        action: 'refresh-ops-automation',
      }),
      createOpsCompactActionRow({
        title: 'SOC 재시도',
        subtitle: '실패한 SOC 연동을 다시 시도합니다.',
        pill: '재시도',
        action: 'ops-retry-target',
        target: 'soc',
      }),
      createOpsCompactActionRow({
        title: '관련 로그 보기',
        subtitle: '최근 SOC 실행 기록을 로그 화면에서 추적합니다.',
        pill: '로그',
        action: 'ops-view-logs',
        target: 'soc',
      }),
    ];
  }
  if (normalizedTab === 'sheets') {
    return [
      createOpsCompactActionRow({
        title: '시트 동기화 재시도',
        subtitle: '최근 실패한 시트 반영을 다시 실행합니다.',
        pill: '재시도',
        action: 'ops-retry-target',
        target: 'sheets',
      }),
      createOpsCompactActionRow({
        title: '엑셀 실행 확인',
        subtitle: '엑셀 가져오기 결과와 최근 실행 상태를 확인합니다.',
        pill: '실행',
        action: 'ops-view-logs',
        target: 'excel',
      }),
      createOpsCompactActionRow({
        title: '작업 로그 열기',
        subtitle: '동기화와 실행 이력을 한곳에서 검토합니다.',
        pill: '로그',
        action: 'ops-view-tab',
        tab: 'logs',
      }),
    ];
  }
  return [
    createOpsCompactActionRow({
      title: '작업 로그 새로고침',
      subtitle: '가장 최근 실행 결과를 다시 불러옵니다.',
      pill: '새로고침',
      action: 'refresh-ops-automation',
    }),
    createOpsCompactActionRow({
      title: '사이트 동기화 보기',
      subtitle: '시트 반영 상태와 실패를 확인합니다.',
      pill: '동기화',
      action: 'ops-view-tab',
      tab: 'sheets',
    }),
    createOpsCompactActionRow({
      title: 'SOC 상태 보기',
      subtitle: 'SOC 이벤트와 재시도 대상을 확인합니다.',
      pill: 'SOC',
      action: 'ops-view-tab',
      tab: 'soc',
    }),
  ];
}

function renderOpsAutomationWorkspace() {
  const tab = normalizeOpsViewTab(state.ops?.viewTab || 'overview');
  const scopeMeta = $('#opsAutomationScopeMeta');
  const primaryStatusLabel = $('#opsAutomationPrimaryStatusLabel');
  const lastRunLabel = $('#opsAutomationLastRunLabel');
  const issueLabel = $('#opsAutomationIssueLabel');
  const recentList = $('#opsAutomationRecentList');
  const actionList = $('#opsAutomationActionList');
  if (!scopeMeta || !primaryStatusLabel || !lastRunLabel || !issueLabel || !recentList || !actionList) return;

  const tabCopy = {
    soc: 'SOC 관련 상태, 최근 이벤트, 재시도 대상을 한 번에 확인합니다.',
    sheets: '시트 반영과 엑셀 실행 상태를 함께 점검하고 바로 재시도할 수 있습니다.',
    logs: '최근 실행 기록과 오류를 추적하고 다음 조치를 정합니다.',
    overview: '운영 자동화 상태를 요약해 보여줍니다.',
  };
  scopeMeta.textContent = tabCopy[tab] || tabCopy.overview;

  let primaryStatus = 'PENDING';
  let lastRun = '';
  let issueCount = 0;
  if (tab === 'soc') {
    primaryStatus = normalizeOpsRunStatus(state.ops?.socStatus || 'PENDING');
    lastRun = String(state.ops?.socLastSyncedAt || '').trim();
    issueCount = getOpsAutomationRelatedRows(tab).filter((row) => normalizeOpsRunStatus(row?.pill || '') === 'FAIL').length;
  } else if (tab === 'sheets') {
    const sheetStatus = normalizeOpsRunStatus(state.ops?.sheetsStatus || 'PENDING');
    const excelStatus = normalizeOpsRunStatus(state.ops?.excelImportStatus || 'IDLE');
    primaryStatus = sheetStatus === 'FAIL' || excelStatus === 'FAIL'
      ? 'FAIL'
      : (sheetStatus === 'SUCCESS' || excelStatus === 'SUCCESS' ? 'SUCCESS' : sheetStatus);
    lastRun = String(state.ops?.sheetsLastSyncedAt || state.ops?.excelImportAt || '').trim();
    issueCount = getOpsAutomationRelatedRows(tab).filter((row) => normalizeOpsRunStatus(row?.pill || '') === 'FAIL').length;
  } else {
    const rows = buildOpsWorkspaceLogRows();
    primaryStatus = rows.some((row) => normalizeOpsRunStatus(row?.pill || '') === 'FAIL')
      ? 'FAIL'
      : (rows.length ? 'SUCCESS' : 'PENDING');
    lastRun = rows[0]?.at || '';
    issueCount = rows.filter((row) => normalizeOpsRunStatus(row?.pill || '') === 'FAIL').length;
  }

  primaryStatusLabel.textContent = getUiStatusLabel(primaryStatus || 'PENDING');
  lastRunLabel.textContent = formatOpsDateTime(lastRun) || '최근 기록 없음';
  issueLabel.textContent = issueCount > 0 ? `${issueCount}건` : '없음';

  const recentRows = getOpsAutomationRelatedRows(tab).slice(0, 4).map((row) => createOpsCompactLogRow({
    title: row.title,
    subtitle: row.subtitle,
    pill: row.pill,
    danger: normalizeOpsRunStatus(row?.pill || '') === 'FAIL',
  }));
  renderOpsCompactList(recentList, recentRows, '최근 관련 실행이 없습니다.', '이 탭과 연결된 최근 실행 기록이 여기에 표시됩니다.');
  renderOpsCompactList(actionList, buildOpsAutomationActionRows(tab), '바로 실행할 작업이 없습니다.');
}

function renderOpsLogsSummary() {
  const metaEl = $('#opsLogsSummaryMeta');
  const totalEl = $('#opsLogsTotalCount');
  const failureEl = $('#opsLogsFailureCount');
  if (!metaEl || !totalEl || !failureEl) return;
  const rows = buildOpsWorkspaceLogRows();
  const failureCount = rows.filter((row) => normalizeOpsRunStatus(row?.pill || '') === 'FAIL').length;
  totalEl.textContent = String(rows.length);
  failureEl.textContent = String(failureCount);
  if (!rows.length) {
    metaEl.textContent = '최근 실행 기록이 없습니다.';
    return;
  }
  const latestAt = rows[0]?.at || '';
  metaEl.textContent = `최근 ${formatOpsDateTime(latestAt) || '-'} 기준 실행 ${rows.length}건을 확인할 수 있습니다.`;
}

function openOpsLogsSheet(target = '') {
  const normalizedTarget = String(target || '').trim().toLowerCase();
  const titleMap = {
    soc: 'SOC 연동 로그',
    sheets: '구글 시트 동기화 로그',
    excel: '엑셀 가져오기 로그',
  };
  const rows = buildOpsLogRows(normalizedTarget);
  const wrapper = document.createElement('div');
  wrapper.className = 'stack';
  const list = document.createElement('ul');
  list.className = 'list';
  if (!rows.length) {
    renderEmptyState(list, '표시할 로그가 없습니다.');
  } else {
    rows.forEach((row) => {
      const li = document.createElement('li');
      li.appendChild(makeListRow({
        title: row.title,
        subtitle: row.subtitle,
        pill: row.pill,
      }));
      list.appendChild(li);
    });
  }
  wrapper.appendChild(list);
  openSheet({
    title: titleMap[normalizedTarget] || '연동 로그',
    contentNode: wrapper,
    actions: [
      { label: '닫기', variant: 'btn-secondary', action: 'sheet-close' },
    ],
  });
}

async function onOpsViewLogs(target = '') {
  const normalizedTarget = String(target || '').trim().toLowerCase();
  if (normalizedTarget === 'soc') {
    await loadSocEvents({ force: true });
  } else if (normalizedTarget === 'sheets') {
    await loadGoogleSheetSyncLogs({ notifyOnError: false, force: true });
  }
  openOpsLogsSheet(normalizedTarget);
}

async function onOpsRunAppleReport() {
  if (!canManageIntegrations()) {
    showToast('자동화 실행 권한이 없습니다.', 'error', 2600);
    return;
  }
  if (!isAppleReportPackEnabled()) {
    await navigateToRoute(ROUTE_REPORTS);
    showToast('이 회사에 해당 보고서가 없습니다.', 'error', 2800);
    return;
  }
  await onReportsAppleRun({ retry: false });
}

async function onOpsOpenSupportWorkers() {
  const workspace = ensureSupportStatusState();
  const opsSiteCode = getOpsSelectedSiteCode();
  if (opsSiteCode) {
    workspace.selectedSiteCode = opsSiteCode;
  }
  workspace.drawerOpen = false;
  workspace.selectedRowKey = '';
  await navigateToRoute(ROUTE_SUPPORT_STATUS);
}

function ensureSupportStatusState() {
  if (!state.supportStatus || typeof state.supportStatus !== 'object') {
    state.supportStatus = createInitialSupportStatusState();
  }
  return state.supportStatus;
}

function ensureSupportStatusHqWorkspaceState() {
  const workspace = ensureSupportStatusState();
  if (!workspace.hqWorkspace || typeof workspace.hqWorkspace !== 'object') {
    workspace.hqWorkspace = createInitialSupportStatusHqWorkspaceState();
  }
  return workspace.hqWorkspace;
}

function ensureScheduleSupportHqWorkspaceState() {
  if (!state.schedule?.supportHqWorkspace || typeof state.schedule.supportHqWorkspace !== 'object') {
    state.schedule.supportHqWorkspace = createInitialScheduleSupportHqWorkspaceState();
  }
  return state.schedule.supportHqWorkspace;
}

function normalizeSupportStatusMode(value = '') {
  const normalized = String(value || '').trim().toLowerCase();
  if (normalized === 'day') return 'day';
  if (normalized === 'night') return 'night';
  return 'all';
}

function normalizeSupportStatusSortKey(value = '') {
  const normalized = String(value || '').trim().toLowerCase();
  if (normalized === 'date_asc') return 'date_asc';
  if (normalized === 'site') return 'site';
  if (normalized === 'request_desc') return 'request_desc';
  if (normalized === 'assigned_desc') return 'assigned_desc';
  return 'date_desc';
}

function normalizeSupportStatusWorkspaceTab(value = '') {
  return String(value || '').trim().toLowerCase() === 'hq' ? 'hq' : 'status';
}

function normalizeSupportStatusHqScope(value = '') {
  return String(value || '').trim().toLowerCase() === 'site' ? 'site' : 'all';
}

function normalizeSupportStatusFilterStatus(value = '') {
  const normalized = String(value || '').trim().toLowerCase();
  if (normalized === 'approved') return 'approved';
  if (normalized === 'auto_approved') return 'auto_approved';
  if (normalized === 'approval_pending') return 'approval_pending';
  if (normalized === 'active') return 'active';
  if (normalized === 'retracted') return 'retracted';
  return 'all';
}

function canUseSupportStatusHqWorkspace() {
  return canUseScheduleSupportRoundtripHq();
}

function getSupportStatusAccessibleSites() {
  const rows = Array.isArray(state.home?.sites) ? state.home.sites : [];
  const siteMap = new Map();
  rows.forEach((site) => {
    const code = String(site?.site_code || '').trim().toUpperCase();
    if (!code || siteMap.has(code)) return;
    siteMap.set(code, {
      code,
      name: String(site?.site_name || code).trim() || code,
    });
  });
  return Array.from(siteMap.values()).sort((a, b) => {
    const nameCompare = String(a.name || '').localeCompare(String(b.name || ''), 'ko');
    if (nameCompare !== 0) return nameCompare;
    return String(a.code || '').localeCompare(String(b.code || ''), 'ko');
  });
}

function getSupportStatusSiteLabel(siteCode = '', siteName = '') {
  const normalizedCode = String(siteCode || '').trim().toUpperCase();
  const normalizedName = String(siteName || '').trim();
  if (normalizedName && normalizedCode && normalizedName !== normalizedCode) {
    return `${normalizedName} (${normalizedCode})`;
  }
  if (normalizedName) return normalizedName;
  if (normalizedCode) {
    const site = getSiteByCode(normalizedCode);
    const lookupName = String(site?.site_name || '').trim();
    if (lookupName && lookupName !== normalizedCode) {
      return `${lookupName} (${normalizedCode})`;
    }
  }
  return normalizedCode || '전체 현장';
}

function getSupportStatusShiftLabel(value = '') {
  return String(value || '').trim().toLowerCase() === 'night' ? '야간' : '주간';
}

function getSupportStatusShiftClass(value = '') {
  return String(value || '').trim().toLowerCase() === 'night'
    ? 'status-pill status-pill-warn'
    : 'status-pill status-pill-success';
}

function getSupportStatusRequestStatusLabel(value = '') {
  const normalized = String(value || '').trim().toLowerCase();
  if (normalized === 'upload_blocked') return '업로드 차단';
  if (normalized === 'approved') return '승인';
  if (normalized === 'auto_approved') return '자동승인';
  if (normalized === 'approval_pending') return '승인대기';
  if (normalized === 'active') return '활성';
  if (normalized === 'retracted') return '철회';
  return '-';
}

function getSupportStatusRequestStatusClass(value = '') {
  const normalized = String(value || '').trim().toLowerCase();
  if (normalized === 'upload_blocked') return 'status-pill status-pill-error';
  if (normalized === 'approved') return 'status-pill status-pill-success';
  if (normalized === 'auto_approved') return 'status-pill status-pill-success';
  if (normalized === 'approval_pending') return 'status-pill status-pill-warn';
  if (normalized === 'active') return 'status-pill status-pill-success';
  if (normalized === 'retracted') return 'status-pill status-pill-neutral';
  return 'status-pill status-pill-neutral';
}

function getSupportStatusSourceLabels(row = {}) {
  const labels = Array.isArray(row?.source_labels) ? row.source_labels : [];
  return labels
    .map((item) => String(item || '').trim())
    .filter(Boolean);
}

function getSupportStatusWorkerValues(row = {}) {
  const values = Array.isArray(row?.worker_display_values) ? row.worker_display_values : [];
  return values
    .map((item) => String(item || '').trim())
    .filter(Boolean);
}

function getSupportStatusSearchText(row = {}) {
  return [
    row?.work_date,
    row?.site_code,
    row?.site_name,
    row?.shift_kind,
    row?.work_purpose,
    row?.request_status,
    ...(getSupportStatusWorkerValues(row)),
    ...(getSupportStatusSourceLabels(row)),
  ]
    .map((item) => String(item || '').trim().toLowerCase())
    .filter(Boolean)
    .join(' ');
}

function getSupportStatusRowByKey(rowKey = '') {
  const key = String(rowKey || '').trim();
  if (!key) return null;
  const workspace = ensureSupportStatusState();
  return (Array.isArray(workspace.rows) ? workspace.rows : [])
    .find((row) => String(row?.row_key || '').trim() === key) || null;
}

function getFilteredSupportStatusRows() {
  const workspace = ensureSupportStatusState();
  const mode = normalizeSupportStatusMode(workspace.selectedMode || 'all');
  const siteCode = String(workspace.selectedSiteCode || '').trim().toUpperCase();
  const requestStatus = normalizeSupportStatusFilterStatus(workspace.selectedStatus || 'all');
  const queryText = String(workspace.searchQuery || '').trim().toLowerCase();
  const sortKey = normalizeSupportStatusSortKey(workspace.sortKey || 'date_desc');
  let rows = Array.isArray(workspace.rows) ? [...workspace.rows] : [];

  if (mode !== 'all') {
    rows = rows.filter((row) => String(row?.shift_kind || '').trim().toLowerCase() === mode);
  }
  if (siteCode) {
    rows = rows.filter((row) => String(row?.site_code || '').trim().toUpperCase() === siteCode);
  }
  if (requestStatus !== 'all') {
    rows = rows.filter((row) => String(row?.request_status || '').trim().toLowerCase() === requestStatus);
  }
  if (queryText) {
    rows = rows.filter((row) => getSupportStatusSearchText(row).includes(queryText));
  }

  rows.sort((a, b) => {
    const aDate = String(a?.work_date || '').trim();
    const bDate = String(b?.work_date || '').trim();
    const aTime = aDate ? new Date(`${aDate}T00:00:00`).getTime() : 0;
    const bTime = bDate ? new Date(`${bDate}T00:00:00`).getTime() : 0;
    const aShiftOrder = String(a?.shift_kind || '').trim().toLowerCase() === 'night' ? 1 : 0;
    const bShiftOrder = String(b?.shift_kind || '').trim().toLowerCase() === 'night' ? 1 : 0;
    const aSite = getSupportStatusSiteLabel(a?.site_code, a?.site_name);
    const bSite = getSupportStatusSiteLabel(b?.site_code, b?.site_name);
    const aRequest = Number(a?.request_count || 0);
    const bRequest = Number(b?.request_count || 0);
    const aAssigned = Number(a?.assigned_count || 0);
    const bAssigned = Number(b?.assigned_count || 0);

    if (sortKey === 'date_asc') {
      if (aTime !== bTime) return aTime - bTime;
      if (aShiftOrder !== bShiftOrder) return aShiftOrder - bShiftOrder;
      return aSite.localeCompare(bSite, 'ko');
    }
    if (sortKey === 'site') {
      const siteCompare = aSite.localeCompare(bSite, 'ko');
      if (siteCompare !== 0) return siteCompare;
      if (aTime !== bTime) return bTime - aTime;
      return aShiftOrder - bShiftOrder;
    }
    if (sortKey === 'request_desc') {
      if (aRequest !== bRequest) return bRequest - aRequest;
      if (aTime !== bTime) return bTime - aTime;
      return aShiftOrder - bShiftOrder;
    }
    if (sortKey === 'assigned_desc') {
      if (aAssigned !== bAssigned) return bAssigned - aAssigned;
      if (aTime !== bTime) return bTime - aTime;
      return aShiftOrder - bShiftOrder;
    }
    if (aTime !== bTime) return bTime - aTime;
    if (aShiftOrder !== bShiftOrder) return aShiftOrder - bShiftOrder;
    return aSite.localeCompare(bSite, 'ko');
  });

  return rows;
}

function buildSupportStatusCounts() {
  const workspace = ensureSupportStatusState();
  const allRows = Array.isArray(workspace.rows) ? workspace.rows : [];
  const filteredRows = getFilteredSupportStatusRows();
  return {
    total: allRows.length,
    day: allRows.filter((row) => String(row?.shift_kind || '').trim().toLowerCase() === 'day').length,
    night: allRows.filter((row) => String(row?.shift_kind || '').trim().toLowerCase() === 'night').length,
    filtered: filteredRows.length,
  };
}

function renderSupportStatusSiteOptions() {
  const workspace = ensureSupportStatusState();
  const select = $('#supportStatusSiteFilter');
  const hint = $('#supportStatusSiteHint');
  if (!(select instanceof HTMLSelectElement)) return;

  const siteRows = getSupportStatusAccessibleSites();
  if (siteRows.length === 1 && !String(workspace.selectedSiteCode || '').trim()) {
    workspace.selectedSiteCode = siteRows[0].code;
  }

  const currentCode = String(workspace.selectedSiteCode || '').trim().toUpperCase();
  select.innerHTML = '';
  const allOption = document.createElement('option');
  allOption.value = '';
  allOption.textContent = '전체 현장';
  select.appendChild(allOption);
  siteRows.forEach((site) => {
    const option = document.createElement('option');
    option.value = site.code;
    option.textContent = getSupportStatusSiteLabel(site.code, site.name);
    if (site.code === currentCode) {
      option.selected = true;
    }
    select.appendChild(option);
  });

  if (currentCode && !siteRows.some((site) => site.code === currentCode)) {
    workspace.selectedSiteCode = '';
    select.value = '';
  } else if (!currentCode) {
    select.value = '';
  }

  select.disabled = workspace.loading || siteRows.length <= 1;
  if (hint) {
    if (!siteRows.length) {
      hint.textContent = '조회 가능한 현장 정보를 확인하는 중입니다.';
    } else if (siteRows.length === 1) {
      hint.textContent = `${getSupportStatusSiteLabel(siteRows[0].code, siteRows[0].name)} 범위만 확인할 수 있습니다.`;
    } else {
      hint.textContent = '전체 현장 또는 개별 현장 범위로 바로 전환할 수 있습니다.';
    }
  }
}

function createSupportStatusEmptyTableRow(title = '', meta = '') {
  const tr = document.createElement('tr');
  const td = document.createElement('td');
  td.colSpan = 9;
  const wrap = document.createElement('div');
  wrap.className = 'empty-state support-status-empty-state';
  const strong = document.createElement('strong');
  strong.textContent = String(title || '표시할 지원근무 항목이 없습니다.').trim();
  wrap.appendChild(strong);
  if (String(meta || '').trim()) {
    const p = document.createElement('p');
    p.textContent = String(meta || '').trim();
    wrap.appendChild(p);
  }
  td.appendChild(wrap);
  tr.appendChild(td);
  return tr;
}

function getSupportStatusEmptyStateCopy() {
  const workspace = ensureSupportStatusState();
  const rawRows = Array.isArray(workspace.rows) ? workspace.rows : [];
  const mode = normalizeSupportStatusMode(workspace.selectedMode || 'all');
  const siteCode = String(workspace.selectedSiteCode || '').trim().toUpperCase();
  const requestStatus = normalizeSupportStatusFilterStatus(workspace.selectedStatus || 'all');
  const queryText = String(workspace.searchQuery || '').trim();

  if (!rawRows.length) {
    return {
      title: '표시할 지원근무 항목이 없습니다.',
      meta: `${formatScheduleMonthTitle(workspace.month)} 기준 요청/배정 데이터가 아직 없습니다.`,
    };
  }
  if (queryText) {
    return {
      title: '검색 결과가 없습니다.',
      meta: '검색어를 바꾸거나 현장/모드 필터를 조정해 주세요.',
    };
  }
  if (siteCode && requestStatus !== 'all') {
    return {
      title: '선택한 조건에 맞는 현장 항목이 없습니다.',
      meta: `${getSupportStatusSiteLabel(siteCode)} · ${getSupportStatusRequestStatusLabel(requestStatus)} 상태 기준입니다.`,
    };
  }
  if (siteCode && mode === 'day') {
    return {
      title: '선택한 현장에 주간 지원 항목이 없습니다.',
      meta: `${getSupportStatusSiteLabel(siteCode)} · ${formatScheduleMonthTitle(workspace.month)} 기준입니다.`,
    };
  }
  if (siteCode && mode === 'night') {
    return {
      title: '선택한 현장에 야간 지원 항목이 없습니다.',
      meta: `${getSupportStatusSiteLabel(siteCode)} · ${formatScheduleMonthTitle(workspace.month)} 기준입니다.`,
    };
  }
  if (mode === 'day') {
    return {
      title: '주간 지원 항목이 없습니다.',
      meta: `${formatScheduleMonthTitle(workspace.month)} 기준 전체 현장을 확인했습니다.`,
    };
  }
  if (mode === 'night') {
    return {
      title: '야간 지원 항목이 없습니다.',
      meta: `${formatScheduleMonthTitle(workspace.month)} 기준 전체 현장을 확인했습니다.`,
    };
  }
  if (siteCode) {
    return {
      title: '선택한 현장에 표시할 지원근무 항목이 없습니다.',
      meta: `${getSupportStatusSiteLabel(siteCode)} · ${formatScheduleMonthTitle(workspace.month)} 기준입니다.`,
    };
  }
  return {
    title: '현재 필터에 맞는 지원근무 항목이 없습니다.',
    meta: '현장 필터를 바꾸거나 새로고침으로 최신 상태를 확인해 주세요.',
  };
}

function renderSupportStatusTable() {
  const workspace = ensureSupportStatusState();
  const body = $('#supportStatusTableBody');
  if (!body) return;
  body.innerHTML = '';

  if (workspace.loading) {
    body.appendChild(createSupportStatusEmptyTableRow('지원근무자 현황을 불러오는 중입니다.', '기존 support request / assignment 데이터를 다시 조회하고 있습니다.'));
    return;
  }

  if (workspace.error && !(Array.isArray(workspace.rows) && workspace.rows.length)) {
    body.appendChild(createSupportStatusEmptyTableRow('지원근무자 현황을 불러오지 못했습니다.', workspace.error));
    return;
  }

  const rows = getFilteredSupportStatusRows();
  if (!rows.length) {
    const empty = getSupportStatusEmptyStateCopy();
    body.appendChild(createSupportStatusEmptyTableRow(empty.title, empty.meta));
    return;
  }

  rows.forEach((row) => {
    const tr = document.createElement('tr');
    const isSelected = workspace.drawerOpen && String(workspace.selectedRowKey || '').trim() === String(row?.row_key || '').trim();
    tr.className = `support-status-table-row${isSelected ? ' active' : ''}`;
    tr.dataset.action = 'support-status-open-detail';
    tr.dataset.rowKey = String(row?.row_key || '').trim();

    const workerValues = getSupportStatusWorkerValues(row);
    const visibleWorkers = workerValues.slice(0, 3);
    const hiddenCount = Math.max(workerValues.length - visibleWorkers.length, 0);
    const sourceLabels = getSupportStatusSourceLabels(row);
    const requestCount = Math.max(Number(row?.request_count || 0), 0);
    const assignedCount = Math.max(Number(row?.assigned_count || 0), 0);

    const dateCell = document.createElement('td');
    dateCell.textContent = formatDateLabel(row?.work_date || '', '-');
    tr.appendChild(dateCell);

    const siteCell = document.createElement('td');
    siteCell.textContent = getSupportStatusSiteLabel(row?.site_code, row?.site_name);
    tr.appendChild(siteCell);

    const shiftCell = document.createElement('td');
    const shiftPill = document.createElement('span');
    shiftPill.className = getSupportStatusShiftClass(row?.shift_kind || '');
    shiftPill.textContent = getSupportStatusShiftLabel(row?.shift_kind || '');
    shiftCell.appendChild(shiftPill);
    tr.appendChild(shiftCell);

    const requestCell = document.createElement('td');
    requestCell.textContent = requestCount > 0 ? `${requestCount}명` : '-';
    tr.appendChild(requestCell);

    const assignedCell = document.createElement('td');
    assignedCell.textContent = requestCount > 0 ? `${assignedCount} / ${requestCount}` : `${assignedCount}`;
    tr.appendChild(assignedCell);

    const workersCell = document.createElement('td');
    workersCell.className = 'support-status-workers-cell';
    if (visibleWorkers.length) {
      const wrap = document.createElement('div');
      wrap.className = 'support-status-worker-list';
      visibleWorkers.forEach((value) => {
        const item = document.createElement('span');
        item.className = 'support-status-worker-token';
        item.textContent = value;
        wrap.appendChild(item);
      });
      if (hiddenCount > 0) {
        const more = document.createElement('span');
        more.className = 'support-status-worker-more';
        more.textContent = `+${hiddenCount}`;
        wrap.appendChild(more);
      }
      workersCell.appendChild(wrap);
    } else {
      workersCell.textContent = '-';
    }
    tr.appendChild(workersCell);

    const statusCell = document.createElement('td');
    const statusPill = document.createElement('span');
    statusPill.className = getSupportStatusRequestStatusClass(row?.request_status || '');
    statusPill.textContent = getSupportStatusRequestStatusLabel(row?.request_status || '');
    statusCell.appendChild(statusPill);
    tr.appendChild(statusCell);

    const metaCell = document.createElement('td');
    metaCell.className = 'support-status-source-cell';
    const metaWrap = document.createElement('div');
    metaWrap.className = 'support-status-source-stack';
    if (sourceLabels.length) {
      const sourceWrap = document.createElement('div');
      sourceWrap.className = 'support-status-source-list';
      sourceLabels.forEach((label) => {
        const token = document.createElement('span');
        token.className = 'support-status-source-token';
        token.textContent = label;
        sourceWrap.appendChild(token);
      });
      metaWrap.appendChild(sourceWrap);
    }
    const purposeText = String(row?.work_purpose || '').trim();
    if (purposeText) {
      const purpose = document.createElement('div');
      purpose.className = 'support-status-purpose';
      purpose.textContent = purposeText;
      metaWrap.appendChild(purpose);
    }
    if (!sourceLabels.length && !purposeText) {
      metaWrap.textContent = '-';
    }
    metaCell.appendChild(metaWrap);
    tr.appendChild(metaCell);

    const actionCell = document.createElement('td');
    const detailBtn = document.createElement('button');
    detailBtn.type = 'button';
    detailBtn.className = 'btn btn-secondary';
    detailBtn.textContent = '상세';
    detailBtn.dataset.action = 'support-status-open-detail';
    detailBtn.dataset.rowKey = String(row?.row_key || '');
    actionCell.appendChild(detailBtn);
    tr.appendChild(actionCell);

    body.appendChild(tr);
  });
}

function createSupportStatusDetailSection(title = '') {
  const section = document.createElement('section');
  section.className = 'support-status-detail-section';
  const heading = document.createElement('h4');
  heading.textContent = String(title || '').trim() || '-';
  section.appendChild(heading);
  return section;
}

function appendSupportStatusMetaRow(section, label = '', value = '') {
  if (!(section instanceof HTMLElement)) return;
  const row = document.createElement('div');
  row.className = 'support-status-detail-meta-row';
  const labelEl = document.createElement('span');
  labelEl.className = 'support-status-detail-meta-label';
  labelEl.textContent = String(label || '').trim() || '-';
  const valueEl = document.createElement('strong');
  valueEl.className = 'support-status-detail-meta-value';
  valueEl.textContent = String(value || '').trim() || '-';
  row.appendChild(labelEl);
  row.appendChild(valueEl);
  section.appendChild(row);
}

function renderSupportStatusDetailDrawer() {
  const workspace = ensureSupportStatusState();
  if (normalizeSupportStatusWorkspaceTab(workspace.workspaceTab || 'status') !== 'status') {
    const backdrop = $('#supportStatusDetailBackdrop');
    const drawer = $('#supportStatusDetailDrawer');
    if (backdrop) backdrop.classList.add('hidden');
    if (drawer) {
      drawer.classList.add('hidden');
      drawer.setAttribute('aria-hidden', 'true');
    }
    return;
  }
  const backdrop = $('#supportStatusDetailBackdrop');
  const drawer = $('#supportStatusDetailDrawer');
  const title = $('#supportStatusDetailTitle');
  const meta = $('#supportStatusDetailMeta');
  const pill = $('#supportStatusDetailPill');
  const body = $('#supportStatusDetailBody');
  if (!backdrop || !drawer || !title || !meta || !pill || !body) return;

  const selected = workspace.drawerOpen ? getSupportStatusRowByKey(workspace.selectedRowKey) : null;
  const open = Boolean(selected);
  backdrop.classList.toggle('hidden', !open);
  drawer.classList.toggle('hidden', !open);
  drawer.setAttribute('aria-hidden', open ? 'false' : 'true');
  if (!open) {
    title.textContent = '항목 선택';
    meta.textContent = '리스트에서 상세를 열면 지원근무자, 요청 수, 상태를 확인할 수 있습니다.';
    pill.className = 'status-pill status-pill-neutral';
    pill.textContent = '상세 대기';
    body.innerHTML = '';
    return;
  }

  const row = selected || {};
  title.textContent = `${formatDateLabel(row?.work_date || '', '-')} · ${getSupportStatusSiteLabel(row?.site_code, row?.site_name)}`;
  meta.textContent = `${getSupportStatusShiftLabel(row?.shift_kind || '')} 지원 · ${formatScheduleMonthTitle(workspace.month)}`;
  pill.className = getSupportStatusRequestStatusClass(row?.request_status || '');
  pill.textContent = getSupportStatusRequestStatusLabel(row?.request_status || '');

  body.innerHTML = '';

  const summarySection = createSupportStatusDetailSection('기본 정보');
  appendSupportStatusMetaRow(summarySection, '현장', getSupportStatusSiteLabel(row?.site_code, row?.site_name));
  appendSupportStatusMetaRow(summarySection, '근무 구분', getSupportStatusShiftLabel(row?.shift_kind || ''));
  appendSupportStatusMetaRow(summarySection, '요청 인원', `${Number(row?.request_count || 0)}명`);
  appendSupportStatusMetaRow(summarySection, '배정 인원', `${Number(row?.assigned_count || 0)}명`);
  appendSupportStatusMetaRow(summarySection, '요청 상태', getSupportStatusRequestStatusLabel(row?.request_status || ''));
  if (String(row?.work_purpose || '').trim()) {
    appendSupportStatusMetaRow(summarySection, '작업 목적', String(row?.work_purpose || '').trim());
  }
  const sourceLabels = getSupportStatusSourceLabels(row);
  if (sourceLabels.length) {
    appendSupportStatusMetaRow(summarySection, '출처', sourceLabels.join(' · '));
  }
  body.appendChild(summarySection);

  const workersSection = createSupportStatusDetailSection('배정 인원');
  const assignments = Array.isArray(row?.assignments) ? row.assignments : [];
  if (!assignments.length) {
    const empty = document.createElement('p');
    empty.className = 'muted';
    empty.textContent = '등록된 지원근무자가 없습니다.';
    workersSection.appendChild(empty);
  } else {
    const list = document.createElement('ul');
    list.className = 'list compact-list support-status-detail-worker-list';
    assignments.forEach((item) => {
      const li = document.createElement('li');
      const container = document.createElement('div');
      container.className = 'list-row';
      const main = document.createElement('div');
      main.className = 'list-row-main';
      const itemTitle = document.createElement('div');
      itemTitle.className = 'list-row-title';
      itemTitle.textContent = String(item?.display_value || item?.worker_name || '-').trim() || '-';
      const subtitle = document.createElement('div');
      subtitle.className = 'list-row-sub';
      subtitle.textContent = [
        `슬롯 ${Number(item?.slot_index || 0)}`,
        getSupportWorkerTypeLabel(item?.worker_type || ''),
        String(item?.source || '').trim() || '-',
      ]
        .filter(Boolean)
        .join(' · ');
      main.appendChild(itemTitle);
      main.appendChild(subtitle);
      container.appendChild(main);
      li.appendChild(container);
      list.appendChild(li);
    });
    workersSection.appendChild(list);
  }
  body.appendChild(workersSection);
}

function getSupportStatusHqScopeLabel(value = '') {
  return normalizeSupportStatusHqScope(value) === 'site' ? '지점별 다운로드' : '전체 다운로드';
}

function getSupportStatusHqLatestStatusLabel(value = '') {
  const normalized = String(value || '').trim().toLowerCase();
  if (normalized === 'latest') return '최신';
  if (normalized === 'outdated') return '구버전';
  if (normalized === 'source_missing') return '원본 대기';
  if (normalized === 'sheet_name_invalid') return '시트명 확인 필요';
  if (normalized === 'invalid') return '검토 필요';
  return '확인 전';
}

function getSupportStatusHqLatestStatusClass(value = '') {
  const normalized = String(value || '').trim().toLowerCase();
  if (normalized === 'latest') return 'status-pill status-pill-success';
  if (normalized === 'outdated') return 'status-pill status-pill-warn';
  if (normalized === 'invalid' || normalized === 'sheet_name_invalid') return 'status-pill status-pill-error';
  return 'status-pill status-pill-neutral';
}

function getSupportStatusHqReviewRowStatusLabel(value = '') {
  const normalized = String(value || '').trim().toLowerCase();
  if (normalized === 'blocking') return '차단';
  if (normalized === 'over_capacity') return '인원 초과';
  if (normalized === 'parsed') return '유효 입력';
  if (normalized === 'auto_approved') return '자동승인';
  if (normalized === 'approval_pending') return '승인대기';
  if (normalized === 'empty') return '입력 없음';
  if (normalized === 'applied') return '적용 완료';
  return '검토 대기';
}

function getSupportStatusHqReviewRowStatusClass(value = '') {
  const normalized = String(value || '').trim().toLowerCase();
  if (normalized === 'blocking' || normalized === 'over_capacity') return 'status-pill status-pill-error';
  if (normalized === 'parsed' || normalized === 'auto_approved' || normalized === 'applied') return 'status-pill status-pill-success';
  if (normalized === 'approval_pending') return 'status-pill status-pill-warn';
  return 'status-pill status-pill-neutral';
}

function getSupportStatusHqWorkspaceSites() {
  const hqWorkspace = ensureSupportStatusHqWorkspaceState();
  const rows = Array.isArray(hqWorkspace.contract?.sites) ? hqWorkspace.contract.sites : [];
  return rows
    .map((row) => ({
      siteCode: String(row?.site_code || '').trim().toUpperCase(),
      siteName: String(row?.site_name || '').trim(),
      sheetName: String(row?.sheet_name || '').trim(),
      downloadReady: Boolean(row?.download_ready),
      latestStatus: String(row?.latest_status || '').trim().toLowerCase() || 'source_missing',
    }))
    .filter((row) => row.siteCode);
}

function getSupportStatusHqSelectedSite() {
  const hqWorkspace = ensureSupportStatusHqWorkspaceState();
  const selectedSiteCode = String(hqWorkspace.selectedSiteCode || '').trim().toUpperCase();
  if (!selectedSiteCode) return null;
  return getSupportStatusHqWorkspaceSites().find((site) => site.siteCode === selectedSiteCode) || null;
}

function renderSupportStatusWorkspaceTabs() {
  const workspace = ensureSupportStatusState();
  const activeTab = normalizeSupportStatusWorkspaceTab(workspace.workspaceTab || 'status');
  const tabWrap = $('#supportStatusWorkspaceTabs');
  if (!(tabWrap instanceof HTMLElement)) return;
  tabWrap.querySelectorAll('[data-action="support-status-workspace-tab"]').forEach((button) => {
    const tab = normalizeSupportStatusWorkspaceTab(button?.dataset?.tab || 'status');
    const hqTab = tab === 'hq';
    const allowed = !hqTab || canUseSupportStatusHqWorkspace();
    const active = tab === activeTab;
    button.classList.toggle('active', active);
    button.setAttribute('aria-pressed', active ? 'true' : 'false');
    button.disabled = !allowed;
    button.setAttribute('aria-disabled', allowed ? 'false' : 'true');
    button.title = allowed ? '' : 'HQ/Admin만 사용할 수 있습니다.';
  });
  setTextContentIfPresent(
    '#supportStatusWorkspaceScopeHint',
    canUseSupportStatusHqWorkspace()
      ? '지원근무 현황과 HQ 엑셀 워크스페이스를 같은 화면에서 전환합니다.'
      : 'HQ 엑셀 워크스페이스는 HQ/Admin만 사용할 수 있습니다.',
    '',
  );
}

function createSupportStatusHqMetaItem(label = '', value = '') {
  const item = document.createElement('div');
  item.className = 'schedule-upload-meta-item';
  const labelEl = document.createElement('span');
  labelEl.textContent = String(label || '').trim() || '-';
  const valueEl = document.createElement('strong');
  valueEl.textContent = String(value || '').trim() || '-';
  item.appendChild(labelEl);
  item.appendChild(valueEl);
  return item;
}

function renderSupportStatusHqMetaGrid(container, items = []) {
  if (!(container instanceof HTMLElement)) return;
  container.innerHTML = '';
  items.forEach((item) => {
    container.appendChild(createSupportStatusHqMetaItem(item.label, item.value));
  });
}

function renderSupportStatusHqSiteOptions() {
  const hqWorkspace = ensureSupportStatusHqWorkspaceState();
  hqWorkspace.scope = normalizeSupportStatusHqScope(hqWorkspace.scope || 'all');
  const select = $('#supportStatusHqSiteSelect');
  if (!(select instanceof HTMLSelectElement)) return;
  const sites = getSupportStatusHqWorkspaceSites();
  const selectedSiteCode = String(hqWorkspace.selectedSiteCode || '').trim().toUpperCase();
  select.innerHTML = '';
  const emptyOption = document.createElement('option');
  emptyOption.value = '';
  emptyOption.textContent = '지점 선택';
  select.appendChild(emptyOption);
  sites.forEach((site) => {
    const option = document.createElement('option');
    option.value = site.siteCode;
    option.textContent = `${site.siteName}${site.downloadReady ? '' : ' · 원본 대기'}`;
    option.disabled = !site.downloadReady;
    if (site.siteCode === selectedSiteCode) option.selected = true;
    select.appendChild(option);
  });
  if (selectedSiteCode && !sites.some((site) => site.siteCode === selectedSiteCode && site.downloadReady)) {
    hqWorkspace.selectedSiteCode = '';
    select.value = '';
  }
  select.disabled = hqWorkspace.loading || hqWorkspace.scope !== 'site';
}

function renderSupportStatusHqReviewSummary() {
  const hqWorkspace = ensureSupportStatusHqWorkspaceState();
  const container = $('#supportStatusHqReviewSummary');
  if (!(container instanceof HTMLElement)) return;
  container.innerHTML = '';
  const inspectResult = hqWorkspace.inspectResult && typeof hqWorkspace.inspectResult === 'object'
    ? hqWorkspace.inspectResult
    : null;
  const summaryItems = inspectResult
    ? [
      {
        label: 'workbook 유효성',
        value: inspectResult.workbook_valid ? '검토 가능' : '검토 필요',
      },
      {
        label: 'ticket scope',
        value: `${Number(inspectResult.total_scope_count || 0)}건`,
      },
      {
        label: '적용 가능',
        value: `${Number(inspectResult.valid_scope_count || 0)}건`,
      },
      {
        label: '자동승인 예상',
        value: `${Number(inspectResult.summary?.auto_approved || 0)}건`,
      },
      {
        label: '승인대기 예상',
        value: `${Number(inspectResult.summary?.approval_pending || 0)}건`,
      },
      {
        label: '차단',
        value: `${Number(inspectResult.summary?.blocking || 0)}건`,
      },
      {
        label: 'worker row',
        value: `${Number(inspectResult.summary?.worker_rows || 0)}건`,
      },
    ]
    : [
      { label: 'workbook 유효성', value: '파일 선택 대기' },
      { label: 'ticket scope', value: '-' },
      { label: '적용 가능', value: '-' },
      { label: '자동승인 예상', value: '-' },
      { label: '승인대기 예상', value: '-' },
      { label: '차단', value: '-' },
      { label: 'worker row', value: '-' },
    ];
  summaryItems.forEach((item) => {
    const card = document.createElement('div');
    card.className = 'schedule-upload-summary-card';
    const labelEl = document.createElement('span');
    labelEl.textContent = item.label;
    const valueEl = document.createElement('strong');
    valueEl.textContent = item.value;
    card.appendChild(labelEl);
    card.appendChild(valueEl);
    container.appendChild(card);
  });
}

function renderSupportStatusHqIssueGroups() {
  const hqWorkspace = ensureSupportStatusHqWorkspaceState();
  const container = $('#supportStatusHqIssueGroups');
  if (!(container instanceof HTMLElement)) return;
  container.innerHTML = '';
  const inspectResult = hqWorkspace.inspectResult && typeof hqWorkspace.inspectResult === 'object'
    ? hqWorkspace.inspectResult
    : null;
  const issues = Array.isArray(inspectResult?.issues) ? inspectResult.issues : [];
  if (!issues.length) {
    const placeholder = document.createElement('div');
    placeholder.className = 'schedule-upload-placeholder support-status-hq-placeholder';
    const strong = document.createElement('strong');
    strong.textContent = inspectResult ? '현재 검토 이슈가 없습니다.' : '검토를 시작하면 workbook validity와 revision 상태가 여기에 표시됩니다.';
    placeholder.appendChild(strong);
    if (inspectResult?.next_step_message) {
      const meta = document.createElement('p');
      meta.textContent = String(inspectResult.next_step_message || '').trim();
      placeholder.appendChild(meta);
    }
    container.appendChild(placeholder);
    return;
  }
  issues.forEach((issue) => {
    const card = document.createElement('article');
    card.className = 'schedule-upload-issue-card';
    const head = document.createElement('div');
    head.className = 'schedule-upload-issue-card-head';
    const copy = document.createElement('strong');
    copy.textContent = String(issue?.title || issue?.code || '검토 이슈').trim();
    const count = document.createElement('span');
    count.className = issue?.severity === 'blocking' ? 'status-pill status-pill-error' : 'status-pill status-pill-neutral';
    count.textContent = `${Number(issue?.count || 0)}건`;
    head.appendChild(copy);
    head.appendChild(count);
    card.appendChild(head);
    const message = document.createElement('p');
    message.textContent = String(issue?.message || '').trim();
    card.appendChild(message);
    if (String(issue?.guidance || '').trim()) {
      const guidance = document.createElement('span');
      guidance.textContent = String(issue?.guidance || '').trim();
      card.appendChild(guidance);
    }
    container.appendChild(card);
  });
}

function renderSupportStatusHqReviewTable() {
  const hqWorkspace = ensureSupportStatusHqWorkspaceState();
  const tableWrap = $('#supportStatusHqReviewTableWrap');
  const tableBody = $('#supportStatusHqReviewTableBody');
  const placeholder = $('#supportStatusHqReviewPlaceholder');
  if (!(tableWrap instanceof HTMLElement) || !(tableBody instanceof HTMLElement) || !(placeholder instanceof HTMLElement)) return;
  tableBody.innerHTML = '';
  const inspectResult = hqWorkspace.inspectResult && typeof hqWorkspace.inspectResult === 'object'
    ? hqWorkspace.inspectResult
    : null;
  const reviewRows = Array.isArray(inspectResult?.review_rows) ? inspectResult.review_rows : [];
  if (!reviewRows.length) {
    tableWrap.classList.add('hidden');
    placeholder.classList.remove('hidden');
    const strong = placeholder.querySelector('strong');
    const meta = placeholder.querySelector('p');
    if (strong) strong.textContent = hqWorkspace.uploadFileName ? '업로드 파일 검토를 실행하면 scope별 상태와 근무자 셀 결과가 표시됩니다.' : '업로드할 지원근무 workbook 파일을 선택하세요.';
    if (meta) {
      meta.textContent = inspectResult?.next_step_message
        ? String(inspectResult.next_step_message || '').trim()
        : '지원요청 scope, 유효 입력 수, 근무자 셀 파싱 결과를 이 구역에서 검토합니다.';
    }
    return;
  }
  tableWrap.classList.remove('hidden');
  placeholder.classList.add('hidden');
  reviewRows.forEach((row) => {
    const tr = document.createElement('tr');
    const sheetCell = document.createElement('td');
    sheetCell.textContent = String(row?.sheet_name || '-').trim() || '-';
    tr.appendChild(sheetCell);

    const siteCell = document.createElement('td');
    siteCell.textContent = getSupportStatusSiteLabel(row?.site_code || '', row?.site_name || '');
    tr.appendChild(siteCell);

    const dateCell = document.createElement('td');
    dateCell.textContent = formatDateLabel(row?.work_date || '', '-');
    tr.appendChild(dateCell);

    const shiftCell = document.createElement('td');
    if (String(row?.shift_kind || '').trim()) {
      const shiftPill = document.createElement('span');
      shiftPill.className = getSupportStatusShiftClass(row?.shift_kind || '');
      shiftPill.textContent = getSupportStatusShiftLabel(row?.shift_kind || '');
      shiftCell.appendChild(shiftPill);
    } else {
      shiftCell.textContent = '-';
    }
    tr.appendChild(shiftCell);

    const slotCell = document.createElement('td');
    slotCell.textContent = row?.row_kind === 'scope_summary'
      ? 'scope'
      : `근무자 ${Math.max(Number(row?.slot_index || 0), 1)}`;
    tr.appendChild(slotCell);

    const workerCell = document.createElement('td');
    workerCell.textContent = String(
      row?.parsed_display_value
      || row?.raw_cell_text
      || (row?.row_kind === 'scope_summary' ? 'scope summary' : '-')
      || '-'
    ).trim() || '-';
    tr.appendChild(workerCell);

    const countCell = document.createElement('td');
    if (row?.row_kind === 'scope_summary') {
      const ticketCount = Number(row?.request_count || 0);
      const workbookCount = row?.workbook_required_count === null || row?.workbook_required_count === undefined
        ? null
        : Number(row.workbook_required_count || 0);
      const workbookLabel = workbookCount === null
        ? (String(row?.workbook_required_raw || '').trim() || '-')
        : String(workbookCount);
      countCell.textContent = `${Number(row?.valid_filled_count || 0)} / ${ticketCount} · 파일 ${workbookLabel}`;
    } else {
      countCell.textContent = `${Number(row?.request_count || 0)}명 요청`;
    }
    tr.appendChild(countCell);

    const targetCell = document.createElement('td');
    const targetStatus = String(row?.target_status || '').trim();
    if (targetStatus) {
      const targetPill = document.createElement('span');
      targetPill.className = getSupportStatusRequestStatusClass(targetStatus);
      targetPill.textContent = getSupportStatusRequestStatusLabel(targetStatus);
      targetCell.appendChild(targetPill);
    } else {
      targetCell.textContent = '-';
    }
    tr.appendChild(targetCell);

    const statusCell = document.createElement('td');
    const statusPill = document.createElement('span');
    statusPill.className = getSupportStatusHqReviewRowStatusClass(row?.status || '');
    statusPill.textContent = getSupportStatusHqReviewRowStatusLabel(row?.status || '');
    statusCell.appendChild(statusPill);
    tr.appendChild(statusCell);

    const reasonCell = document.createElement('td');
    reasonCell.textContent = String(row?.reason || '-').trim() || '-';
    tr.appendChild(reasonCell);
    tableBody.appendChild(tr);
  });
}

function renderSupportStatusHqWorkspace() {
  const workspace = ensureSupportStatusState();
  const hqWorkspace = ensureSupportStatusHqWorkspaceState();
  hqWorkspace.scope = normalizeSupportStatusHqScope(hqWorkspace.scope || 'all');
  const panel = $('#supportStatusHqPanel');
  const accessBlocked = $('#supportStatusHqAccessBlocked');
  const body = $('#supportStatusHqWorkspaceBody');
  if (!(panel instanceof HTMLElement) || !(accessBlocked instanceof HTMLElement) || !(body instanceof HTMLElement)) return;

  const allowed = canUseSupportStatusHqWorkspace();
  accessBlocked.classList.toggle('hidden', allowed);
  body.classList.toggle('hidden', !allowed);
  if (!allowed) {
    setTextContentIfPresent('#supportStatusHqAccessMeta', 'HQ/Admin만 이 엑셀 워크스페이스에 접근할 수 있습니다.', 'HQ/Admin만 이 엑셀 워크스페이스에 접근할 수 있습니다.');
    return;
  }

  const monthInput = $('#supportStatusHqMonthInput');
  if (monthInput instanceof HTMLInputElement && monthInput.value !== String(hqWorkspace.month || '')) {
    monthInput.value = String(hqWorkspace.month || '');
  }

  const scopeSwitch = $('#supportStatusHqScopeSwitch');
  if (scopeSwitch) {
    scopeSwitch.querySelectorAll('[data-action="support-status-hq-set-scope"]').forEach((button) => {
      const scope = normalizeSupportStatusHqScope(button?.dataset?.scope || 'all');
      const active = scope === hqWorkspace.scope;
      button.classList.toggle('active', active);
      button.setAttribute('aria-pressed', active ? 'true' : 'false');
    });
  }

  renderSupportStatusHqSiteOptions();
  setTextContentIfPresent(
    '#supportStatusHqContractHint',
    hqWorkspace.error
      ? hqWorkspace.error
      : hqWorkspace.loading
        ? '다운로드 가능한 workbook 범위를 불러오는 중입니다.'
        : '전체 다운로드는 기본값이며, 지점별 다운로드는 지점을 명시적으로 선택해야 합니다.',
    '다운로드 가능한 workbook 범위를 불러오는 중입니다.',
  );

  const downloadMetaItems = (() => {
    const sites = getSupportStatusHqWorkspaceSites();
    const readyCount = sites.filter((site) => site.downloadReady).length;
    const selectedSite = getSupportStatusHqSelectedSite();
    return [
      { label: '대상월', value: formatScheduleMonthTitle(hqWorkspace.month) },
      { label: '다운로드 범위', value: getSupportStatusHqScopeLabel(hqWorkspace.scope) },
      { label: hqWorkspace.scope === 'site' ? '대상 지점' : '전체 시트 수', value: hqWorkspace.scope === 'site' ? (selectedSite ? getSupportStatusSiteLabel(selectedSite.siteCode, selectedSite.siteName) : '지점 선택') : `${readyCount}개` },
      { label: 'workbook family', value: String(hqWorkspace.contract?.workbook_family || SUPPORT_STATUS_HQ_WORKBOOK_FAMILY).trim() || SUPPORT_STATUS_HQ_WORKBOOK_FAMILY },
      { label: 'revision/build', value: String(hqWorkspace.contract?.template_version || SUPPORT_STATUS_HQ_TEMPLATE_VERSION).trim() || SUPPORT_STATUS_HQ_TEMPLATE_VERSION },
      { label: 'latest 상태', value: readyCount > 0 ? '시스템 최신 기준본' : '원본 대기' },
    ];
  })();
  renderSupportStatusHqMetaGrid($('#supportStatusHqDownloadMeta'), downloadMetaItems);

  const inspectResult = hqWorkspace.inspectResult && typeof hqWorkspace.inspectResult === 'object'
    ? hqWorkspace.inspectResult
    : null;
  const uploadMeta = inspectResult?.upload_meta && typeof inspectResult.upload_meta === 'object'
    ? inspectResult.upload_meta
    : null;
  const uploadMetaItems = [
    { label: '파일명', value: String(uploadMeta?.file_name || hqWorkspace.uploadFileName || '선택 전').trim() || '선택 전' },
    { label: '대상월', value: formatScheduleMonthTitle(String(uploadMeta?.month || hqWorkspace.month || '')) },
    { label: '범위', value: getSupportStatusHqScopeLabel(uploadMeta?.download_scope || hqWorkspace.scope) },
    { label: 'workbook family', value: String(uploadMeta?.workbook_family || (hqWorkspace.uploadFileName ? '검토 전' : '선택 전')).trim() || (hqWorkspace.uploadFileName ? '검토 전' : '선택 전') },
    { label: 'revision', value: String(uploadMeta?.revision || (hqWorkspace.uploadFileName ? '검토 전' : '선택 전')).trim() || (hqWorkspace.uploadFileName ? '검토 전' : '선택 전') },
    { label: 'latest 상태', value: uploadMeta ? getSupportStatusHqLatestStatusLabel(uploadMeta.latest_status || '') : (hqWorkspace.uploadFileName ? '검토 전' : '선택 전') },
    {
      label: '지점 범위',
      value: uploadMeta
        ? (
          Number(uploadMeta.site_count || 0) > 1
            ? `${Number(uploadMeta.site_count || 0)}개 지점`
            : (String(uploadMeta.selected_site_name || '').trim()
              ? getSupportStatusSiteLabel(uploadMeta.selected_site_code || '', uploadMeta.selected_site_name || '')
              : `${Math.max(Number(uploadMeta.site_count || 0), 1)}개 지점`)
        )
        : (hqWorkspace.uploadFileName ? '검토 전' : '선택 전'),
    },
  ];
  renderSupportStatusHqMetaGrid($('#supportStatusHqUploadMeta'), uploadMetaItems);

  const downloadBtn = $('#supportStatusHqDownloadBtn');
  const selectedSite = getSupportStatusHqSelectedSite();
  if (downloadBtn instanceof HTMLButtonElement) {
    downloadBtn.disabled = hqWorkspace.loading
      || (hqWorkspace.scope === 'site' && !selectedSite)
      || !getSupportStatusHqWorkspaceSites().some((site) => site.downloadReady);
  }

  const inspectBtn = $('#supportStatusHqInspectBtn');
  const reinspectBtn = $('#supportStatusHqReinspectBtn');
  const applyBtn = $('#supportStatusHqApplyBtn');
  const fileInput = $('#supportStatusHqUploadFile');
  const hasFile = fileInput instanceof HTMLInputElement && Boolean(fileInput.files?.length);
  if (inspectBtn instanceof HTMLButtonElement) inspectBtn.disabled = !hasFile || hqWorkspace.inspectLoading;
  if (reinspectBtn instanceof HTMLButtonElement) reinspectBtn.disabled = !hasFile || hqWorkspace.inspectLoading;
  if (applyBtn instanceof HTMLButtonElement) {
    applyBtn.disabled = !Boolean(inspectResult?.can_apply) || !inspectResult?.batch_id || hqWorkspace.inspectLoading || hqWorkspace.applyLoading;
    applyBtn.textContent = hqWorkspace.applyLoading ? 'Sentrix 이동 준비 중...' : 'Sentrix에서 적용';
  }

  renderSupportStatusHqReviewSummary();
  renderSupportStatusHqIssueGroups();
  renderSupportStatusHqReviewTable();

  const reviewTitle = $('#supportStatusHqReviewStateTitle');
  const reviewText = $('#supportStatusHqReviewStateText');
  const applyResult = hqWorkspace.applyResult && typeof hqWorkspace.applyResult === 'object'
    ? hqWorkspace.applyResult
    : null;
  if (reviewTitle) {
    reviewTitle.textContent = applyResult?.applied
      ? '적용 완료'
      : (
        inspectResult
          ? (inspectResult.can_apply ? '적용 가능' : '검토 보완 필요')
          : '적용 전 검토 영역'
      );
  }
  if (reviewText) {
    if (applyResult?.applied) {
      reviewText.textContent = `적용 완료: ticket ${Number(applyResult.tickets_updated || 0)}건 갱신, 자동승인 ${Number(applyResult.tickets_auto_approved || 0)}건, 승인대기 ${Number(applyResult.tickets_pending || 0)}건, 알림 ${Number(applyResult.notifications_created || 0)}건, ARLS bridge ${Number(applyResult.bridge_actions_created || 0)}건`;
    } else if (applyResult?.blocked && Array.isArray(applyResult.blocked_reasons) && applyResult.blocked_reasons.length) {
      reviewText.textContent = String(applyResult.blocked_reasons[0] || '').trim() || '차단 사유를 해결한 뒤 다시 검토하세요.';
    } else if (hqWorkspace.applyError) {
      reviewText.textContent = String(hqWorkspace.applyError || '').trim();
    } else {
      reviewText.textContent = inspectResult
        ? String(inspectResult.next_step_message || '검토 결과를 확인한 뒤 적용 여부를 결정하세요.').trim()
        : '지원요청 scope, 유효 입력 수, 근무자 셀 파싱 결과를 검토한 뒤 적용합니다.';
    }
  }
}

async function loadSupportStatusHqWorkspaceContract({ force = false } = {}) {
  const hqWorkspace = ensureSupportStatusHqWorkspaceState();
  if (!canUseSupportStatusHqWorkspace()) {
    hqWorkspace.loading = false;
    hqWorkspace.error = '';
    hqWorkspace.contract = null;
    renderSupportStatusHqWorkspace();
    return null;
  }
  hqWorkspace.loading = true;
  hqWorkspace.error = '';
  renderSupportStatusHqWorkspace();
  const tenantCode = getTenantCodeForScopedAdminApi();
  const params = new URLSearchParams();
  params.set('month', String(hqWorkspace.month || toMonthKey(new Date())).trim() || toMonthKey(new Date()));
  const path = appendTenantCodeQuery(`/schedules/support-roundtrip/hq-workspace?${params.toString()}`, tenantCode);
  try {
    const payload = await apiRequest(path, { force });
    hqWorkspace.contract = payload && typeof payload === 'object' ? payload : null;
    hqWorkspace.loading = false;
    if (hqWorkspace.scope === 'site') {
      const selectedSite = getSupportStatusHqSelectedSite();
      if (!selectedSite) {
        hqWorkspace.selectedSiteCode = '';
      }
    }
    renderSupportStatusHqWorkspace();
    return hqWorkspace.contract;
  } catch (error) {
    hqWorkspace.loading = false;
    hqWorkspace.error = normalizeActionError(error, 'HQ workbook 계약 정보를 불러오지 못했습니다.');
    renderSupportStatusHqWorkspace();
    throw error;
  }
}

async function onSupportStatusHqDownload() {
  const hqWorkspace = ensureSupportStatusHqWorkspaceState();
  if (!canUseSupportStatusHqWorkspace()) {
    showToast('HQ workbook 다운로드 권한이 없습니다.', 'error');
    return;
  }
  const params = new URLSearchParams();
  params.set('month', String(hqWorkspace.month || toMonthKey(new Date())).trim() || toMonthKey(new Date()));
  params.set('scope', normalizeSupportStatusHqScope(hqWorkspace.scope || 'all'));
  if (normalizeSupportStatusHqScope(hqWorkspace.scope || 'all') === 'site') {
    const selectedSite = getSupportStatusHqSelectedSite();
    if (!selectedSite) {
      showToast('지점별 다운로드는 지점을 먼저 선택해 주세요.', 'error');
      return;
    }
    params.set('site_code', selectedSite.siteCode);
  }
  const requestUrl = appendTenantCodeQuery(
    `${state.activeApiBase}/schedules/support-roundtrip/hq-roster-workbook?${params.toString()}`,
    getTenantCodeForScopedAdminApi(),
  );
  const fallbackName = `${String(hqWorkspace.month || '').trim()}_support_roster_${normalizeSupportStatusHqScope(hqWorkspace.scope || 'all')}.xlsx`;
  await downloadScheduleWorkbookWithAuth(requestUrl, fallbackName);
  showToast('HQ 지원근무 workbook을 다운로드했습니다.', 'success', 2200);
}

async function onSupportStatusHqInspect() {
  const hqWorkspace = ensureSupportStatusHqWorkspaceState();
  if (!canUseSupportStatusHqWorkspace()) {
    showToast('HQ workbook 업로드 권한이 없습니다.', 'error');
    return;
  }
  const fileInput = $('#supportStatusHqUploadFile');
  if (!(fileInput instanceof HTMLInputElement) || !fileInput.files?.length) {
    showToast('검토할 workbook 파일을 먼저 선택해 주세요.', 'error');
    return;
  }
  const file = fileInput.files[0];
  hqWorkspace.inspectLoading = true;
  hqWorkspace.inspectError = '';
  hqWorkspace.applyError = '';
  hqWorkspace.applyResult = null;
  hqWorkspace.uploadFileName = String(file?.name || '').trim();
  renderSupportStatusHqWorkspace();
  const body = new FormData();
  body.append('file', file);
  body.append('month', String(hqWorkspace.month || toMonthKey(new Date())).trim() || toMonthKey(new Date()));
  body.append('tenant_code', getTenantCodeForScopedAdminApi());
  try {
    const result = await apiRequest('/schedules/support-roundtrip/hq-roster-upload/inspect', {
      method: 'POST',
      body,
    });
    hqWorkspace.inspectResult = result && typeof result === 'object' ? result : null;
    hqWorkspace.inspectLoading = false;
    hqWorkspace.applyResult = null;
    renderSupportStatusHqWorkspace();
    const issueCount = Number(result?.issue_count || 0);
    if (issueCount > 0) {
      showToast(`workbook 검토 완료: ${issueCount}건 확인 필요`, 'error', 2800);
    } else {
      showToast('workbook 검토 완료', 'success', 2200);
    }
  } catch (error) {
    hqWorkspace.inspectLoading = false;
    hqWorkspace.inspectError = normalizeActionError(error, 'workbook 검토에 실패했습니다.');
    hqWorkspace.inspectResult = null;
    renderSupportStatusHqWorkspace();
    throw error;
  }
}

async function onSupportStatusHqApply() {
  const hqWorkspace = ensureSupportStatusHqWorkspaceState();
  const batchId = String(hqWorkspace.inspectResult?.batch_id || '').trim();
  if (!canUseSupportStatusHqWorkspace()) {
    showToast('HQ workbook 적용 권한이 없습니다.', 'error');
    return;
  }
  if (!batchId) {
    showToast('먼저 workbook 검토를 완료해 주세요.', 'error');
    return;
  }
  if (!hqWorkspace.inspectResult?.can_apply) {
    showToast('차단 이슈를 해결한 뒤 다시 검토해 주세요.', 'error');
    return;
  }
  hqWorkspace.applyLoading = true;
  hqWorkspace.applyError = '';
  hqWorkspace.applyResult = null;
  renderSupportStatusHqWorkspace();
  try {
    const uploadMeta = hqWorkspace.inspectResult?.upload_meta && typeof hqWorkspace.inspectResult.upload_meta === 'object'
      ? hqWorkspace.inspectResult.upload_meta
      : {};
    const targetUrl = buildSentrixHqSupportSubmissionUrl({
      tenant_code: getTenantCodeForScopedAdminApi(),
      month: String(uploadMeta?.month || hqWorkspace.month || '').trim(),
      site_code: String(uploadMeta?.selected_site_code || '').trim(),
      artifact_id: String(hqWorkspace.inspectResult?.artifact_context?.artifact_id || '').trim() || `sentrix-hq:${String(getTenantCodeForScopedAdminApi() || '').trim()}:${String(uploadMeta?.month || hqWorkspace.month || '').trim()}:${String(uploadMeta?.selected_site_code || 'ALL').trim()}:${String(uploadMeta?.revision || 'latest').trim()}`,
      revision: String(uploadMeta?.revision || '').trim(),
      source_upload_batch_id: batchId,
    });
    hqWorkspace.applyLoading = false;
    hqWorkspace.applyResult = {
      redirected: true,
      target_url: targetUrl,
      source_upload_batch_id: batchId,
    };
    renderSupportStatusHqWorkspace();
    window.open(targetUrl, '_blank', 'noopener,noreferrer');
    showToast('HQ roster apply 흐름을 Sentrix 워크스페이스로 넘겼습니다.', 'success', 2600);
  } catch (error) {
    hqWorkspace.applyLoading = false;
    hqWorkspace.applyError = normalizeActionError(error, 'Sentrix HQ submission workspace 이동에 실패했습니다.');
    hqWorkspace.applyResult = null;
    renderSupportStatusHqWorkspace();
    throw error;
  }
}

function renderSupportStatusWorkspace() {
  const workspace = ensureSupportStatusState();
  workspace.selectedMode = normalizeSupportStatusMode(workspace.selectedMode || 'all');
  workspace.sortKey = normalizeSupportStatusSortKey(workspace.sortKey || 'date_desc');
  workspace.selectedStatus = normalizeSupportStatusFilterStatus(workspace.selectedStatus || 'all');
  workspace.workspaceTab = normalizeSupportStatusWorkspaceTab(workspace.workspaceTab || 'status');

  renderSupportStatusWorkspaceTabs();
  const statusPanel = $('#supportStatusStatusPanel');
  const hqPanel = $('#supportStatusHqPanel');
  const showStatusPanel = workspace.workspaceTab === 'status';
  if (statusPanel) statusPanel.classList.toggle('hidden', !showStatusPanel);
  if (hqPanel) hqPanel.classList.toggle('hidden', showStatusPanel);

  const modeSwitch = $('#supportStatusModeSwitch');
  if (modeSwitch) {
    modeSwitch.querySelectorAll('[data-action="support-status-set-mode"]').forEach((button) => {
      const mode = normalizeSupportStatusMode(button?.dataset?.mode || 'all');
      const active = mode === workspace.selectedMode;
      button.classList.toggle('active', active);
      button.setAttribute('aria-pressed', active ? 'true' : 'false');
    });
  }

  const searchInput = $('#supportStatusSearchInput');
  if (searchInput instanceof HTMLInputElement && searchInput.value !== String(workspace.searchQuery || '')) {
    searchInput.value = String(workspace.searchQuery || '');
  }
  const sortSelect = $('#supportStatusSortSelect');
  if (sortSelect instanceof HTMLSelectElement && sortSelect.value !== workspace.sortKey) {
    sortSelect.value = workspace.sortKey;
  }
  const statusSelect = $('#supportStatusStatusFilter');
  if (statusSelect instanceof HTMLSelectElement && statusSelect.value !== workspace.selectedStatus) {
    statusSelect.value = workspace.selectedStatus;
  }

  renderSupportStatusSiteOptions();
  const counts = buildSupportStatusCounts();
  const scopeMeta = $('#supportStatusScopeMeta');
  if (scopeMeta) {
    const siteLabel = workspace.selectedSiteCode
      ? getSupportStatusSiteLabel(workspace.selectedSiteCode)
      : '전체 현장';
    if (workspace.error) {
      scopeMeta.textContent = workspace.error;
    } else {
      scopeMeta.textContent = `${formatScheduleMonthTitle(workspace.month)} 기준 · ${siteLabel} · ${workspace.loading ? '조회 중' : `${counts.filtered}건 표시`}`;
    }
  }
  setTextContentIfPresent('#supportStatusCountTotal', `${counts.total}건`, '0건');
  setTextContentIfPresent('#supportStatusCountDay', `${counts.day}건`, '0건');
  setTextContentIfPresent('#supportStatusCountNight', `${counts.night}건`, '0건');
  setTextContentIfPresent('#supportStatusCountFiltered', `${counts.filtered}건`, '0건');
  renderSupportStatusTable();
  renderSupportStatusDetailDrawer();
  renderSupportStatusHqWorkspace();
}

async function loadSupportStatusWorkspace({ force = false } = {}) {
  const workspace = ensureSupportStatusState();
  workspace.loading = true;
  workspace.error = '';
  renderSupportStatusWorkspace();

  const month = String(workspace.month || toMonthKey(new Date())).trim() || toMonthKey(new Date());
  const tenantCode = getTenantCodeForScopedAdminApi();
  const params = new URLSearchParams();
  params.set('month', month);
  const path = appendTenantCodeQuery(`/schedules/support-status-workspace?${params.toString()}`, tenantCode);

  try {
    const payload = await apiRequest(path, { force });
    workspace.month = String(payload?.month || month).trim() || month;
    workspace.rows = Array.isArray(payload?.rows) ? payload.rows : [];
    workspace.fetchedAt = Date.now();
    workspace.loading = false;

    const siteRows = getSupportStatusAccessibleSites();
    const currentSite = String(workspace.selectedSiteCode || '').trim().toUpperCase();
    if (currentSite && !siteRows.some((site) => site.code === currentSite)) {
      workspace.selectedSiteCode = '';
    }
    if (!String(workspace.selectedSiteCode || '').trim()) {
      const preferredSiteCode = String(getOpsSelectedSiteCode() || state.home?.selectedSiteCode || '').trim().toUpperCase();
      if (preferredSiteCode && siteRows.some((site) => site.code === preferredSiteCode)) {
        workspace.selectedSiteCode = preferredSiteCode;
      } else if (siteRows.length === 1) {
        workspace.selectedSiteCode = siteRows[0].code;
      }
    }
    renderSupportStatusWorkspace();
    return workspace.rows;
  } catch (error) {
    workspace.loading = false;
    workspace.error = normalizeActionError(error, '지원근무자 현황을 불러오지 못했습니다.');
    renderSupportStatusWorkspace();
    throw error;
  }
}

async function loadSupportStatusViewPresenter() {
  if (!isManagerShellRole()) return;
  renderSupportStatusWorkspace();
  await loadHomeSites({ activeOnly: true, notifyOnError: false, force: false });
  renderSupportStatusWorkspace();
  const tasks = [
    loadSupportStatusWorkspace({ force: false }),
  ];
  if (canUseSupportStatusHqWorkspace()) {
    tasks.push(loadSupportStatusHqWorkspaceContract({ force: false }));
  }
  await Promise.allSettled(tasks);
  renderSupportStatusWorkspace();
}

function queueOpsViewPresenterRefresh() {
  if (pendingOpsViewPresenterRefresh) {
    return null;
  }
  const task = (async () => {
    const tasks = [
      loadHomeSites({ activeOnly: true, notifyOnError: false, force: false }).catch(() => []),
      loadOpsSummary({ force: false }),
    ];
    if (canManageIntegrations()) {
      tasks.push(refreshOpsAutomationSnapshot({ force: false }));
    }
    await Promise.allSettled(tasks);
    renderOpsSiteOptions();
    renderOpsSummary();
  })();
  pendingOpsViewPresenterRefresh = task;
  task.finally(() => {
    if (pendingOpsViewPresenterRefresh === task) {
      pendingOpsViewPresenterRefresh = null;
    }
  });
  return task;
}

async function loadOpsViewPresenter() {
  if (!isManagerShellRole()) return;
  setOpsActiveDate(state.ops.selectedDate || toLocalDateKey(new Date()), { syncInput: true });
  renderOpsSiteOptions();
  renderOpsSummary();
  const task = queueOpsViewPresenterRefresh();
  if (task) {
    task.catch((error) => {
      console.error('[RG ARLS] ops presenter refresh failed', error);
    });
  }
}

function queueScheduleViewPresenterRefresh() {
  if (pendingScheduleViewPresenterRefresh) {
    return null;
  }
  const task = loadSchedule({ force: false });
  pendingScheduleViewPresenterRefresh = task;
  task.finally(() => {
    if (pendingScheduleViewPresenterRefresh === task) {
      pendingScheduleViewPresenterRefresh = null;
    }
  });
  return task;
}

function updateOpsAppleActionVisibility() {
  const isAppleTenant = isAppleReportPackEnabled();
  document.querySelectorAll('[data-action="ops-run-apple-report"]').forEach((node) => {
    node.classList.toggle('hidden', !isAppleTenant);
  });
}

function applyAppleTenantScopedUiVisibility() {
  const isAppleTenant = isAppleReportPackEnabled();
  ['flagAppleDaytime', 'flagAppleOt', 'flagAppleTotalLate'].forEach((id) => {
    const input = document.getElementById(id);
    const row = input?.closest('.notification-toggle-row');
    if (row) {
      row.classList.toggle('hidden', !isAppleTenant);
    }
  });

  const scopeSelect = $('#gsProfileScope');
  if (scopeSelect instanceof HTMLSelectElement) {
    Array.from(scopeSelect.options || []).forEach((option) => {
      const isAppleScope = String(option.value || '').trim().toUpperCase().startsWith('APPLE_');
      option.hidden = !isAppleTenant && isAppleScope;
      option.disabled = !isAppleTenant && isAppleScope;
    });
    const selected = String(scopeSelect.value || '').trim().toUpperCase();
    if (!isAppleTenant && selected.startsWith('APPLE_')) {
      scopeSelect.value = 'PAYROLL_LEAVE_OVERTIME';
    }
  }

  updateOpsAppleActionVisibility();
}

function normalizeReportPackValue(value = '') {
  const raw = String(value || '').trim().toLowerCase();
  if (raw === 'apple' || raw === 'apple_report_pack') return 'apple';
  return 'default';
}

function getSelectedReportsPack() {
  return normalizeReportPackValue(state.reports?.selectedPack || 'default');
}

function setSelectedReportsPack(value = '') {
  const next = normalizeReportPackValue(value);
  if (!state.reports) {
    state.reports = createInitialReportsState();
  }
  state.reports.selectedPack = next;
  return next;
}

function getReportsMonthValue() {
  const monthFromInput = normalizeMonthKey($('#reportsAppleMonth')?.value || '');
  if (monthFromInput) return monthFromInput;
  const monthFromState = normalizeMonthKey(state.reports?.month || '');
  return monthFromState || toMonthKey(new Date());
}

function setReportsMonthValue(monthValue, { syncInput = true } = {}) {
  const normalized = normalizeMonthKey(monthValue) || toMonthKey(new Date());
  if (!state.reports) {
    state.reports = createInitialReportsState();
  }
  state.reports.month = normalized;
  if (syncInput) {
    const monthInput = $('#reportsAppleMonth');
    if (monthInput instanceof HTMLInputElement) {
      monthInput.value = normalized;
    }
  }
  return normalized;
}

function renderReportsScopeHint() {
  const hint = $('#reportsScopeHint');
  if (!hint) return;
  const navRole = getNavigationRole();
  const tenantCode = getReportsTenantCode();
  if (!tenantCode) {
    hint.textContent = navRole === 'DEV'
      ? '개발자 계정은 상단 회사 배지에서 작업 회사를 선택하면 리포트 팩이 표시됩니다.'
      : '리포트 대상 회사를 확인할 수 없습니다.';
    return;
  }
  hint.textContent = `현재 회사: ${tenantCode}`;
}

function renderReportsPackList() {
  const list = $('#reportsPackList');
  const hint = $('#reportsPackHint');
  if (!list || !hint) return;
  clearList(list);

  const rows = Array.isArray(state.reports?.packs) ? state.reports.packs : [];
  if (!rows.length) {
    renderEmptyState(list, '이 회사에 설정된 보고서 양식이 없습니다.');
    hint.textContent = '리포트 팩이 없는 회사입니다.';
    return;
  }

  const selectedPack = getSelectedReportsPack();
  rows.forEach((pack) => {
    const li = document.createElement('li');
    const key = normalizeReportPackValue(pack?.type || pack?.key || '');
    const isSelected = key === selectedPack;
    const row = makeListRow({
      title: String(pack?.title || '-').trim() || '-',
      subtitle: String(pack?.description || '').trim() || '설명 없음',
      pill: isSelected ? '선택됨' : (pack?.enabled === false ? '비활성' : '사용 가능'),
      danger: pack?.enabled === false,
    });
    const actions = document.createElement('div');
    actions.className = 'inline-actions';
    const openBtn = document.createElement('button');
    openBtn.type = 'button';
    openBtn.className = isSelected ? 'btn btn-primary' : 'btn btn-secondary';
    openBtn.dataset.action = 'reports-select-pack';
    openBtn.dataset.pack = key;
    openBtn.textContent = isSelected ? '선택됨' : '열기';
    actions.appendChild(openBtn);
    row.appendChild(actions);
    li.appendChild(row);
    list.appendChild(li);
  });

  hint.textContent = selectedPack === 'apple'
    ? '전용 보고가 선택되었습니다.'
    : '기본 리포트 팩이 선택되었습니다.';
  renderReportsWorkspacePanels();
}

function renderReportsAppleCard() {
  const selectedPack = getSelectedReportsPack();
  const isApplePack = selectedPack === 'apple';
  const appleEnabled = isAppleReportPackEnabled();
  const appleCard = $('#reportsAppleCard');
  const emptyPackCard = $('#reportsPackEmptyCard');
  const emptyPackMessage = $('#reportsPackEmptyMessage');
  const defaultCard = $('#reportsDefaultCard');
  const appleHint = $('#reportsAppleHint');
  const sheetsMeta = $('#reportsAppleSheetsMeta');
  const sheetsPill = $('#reportsAppleSheetsPill');
  const showPackEmpty = !isApplePack || !appleEnabled;

  if (appleCard) appleCard.classList.toggle('hidden', !isApplePack || !appleEnabled);
  if (emptyPackCard) emptyPackCard.classList.toggle('hidden', !showPackEmpty);
  if (defaultCard) defaultCard.classList.toggle('hidden', isApplePack);
  if (emptyPackMessage) {
    emptyPackMessage.textContent = appleEnabled
      ? '전용 팩을 선택하면 실행/로그를 확인할 수 있습니다.'
      : '현재 회사에는 전용 팩이 연결되어 있지 않습니다.';
  }

  if (!appleEnabled) {
    if (appleHint) appleHint.textContent = '이 회사에 해당 보고서가 없습니다.';
    if (sheetsMeta) sheetsMeta.textContent = '사용할 수 없음';
    if (sheetsPill) {
      sheetsPill.className = 'status-pill status-pill-warn';
      sheetsPill.textContent = '비대상';
    }
    renderReportsWorkspacePanels();
    return;
  }

  const status = state.reports?.appleStatus || null;
  if (!status) {
    $('#reportsAppleDaytimeStatus').textContent = '-';
    $('#reportsAppleOvertimeStatus').textContent = '-';
    $('#reportsAppleOvernightStatus').textContent = '-';
    $('#reportsAppleLateEventStatus').textContent = '-';
    if (sheetsPill) {
      sheetsPill.className = 'status-pill status-pill-warn';
      sheetsPill.textContent = '확인 중';
    }
    if (sheetsMeta) {
      sheetsMeta.textContent = '최근 동기화 정보를 불러오는 중입니다.';
    }
    if (appleHint) {
      appleHint.textContent = '전용 보고 상태를 확인하세요.';
    }
    renderReportsWorkspacePanels();
    return;
  }

  const statusMap = status.status || {};
  const daytimeStatus = String(statusMap.daytime?.status || '-').trim().toUpperCase();
  const overtimeStatus = String(statusMap.overtime?.status || '-').trim().toUpperCase();
  const overnightStatus = String(statusMap.overnight?.status || '-').trim().toUpperCase();
  const lateEventStatus = String(statusMap.late_event_additional?.status || '-').trim().toUpperCase();
  const sheetsStatus = String(statusMap.sheets?.status || '-').trim().toUpperCase();
  const sheetsLastAt = formatOpsDateTime(statusMap.sheets?.last_at || '');
  const sheetsError = String(statusMap.sheets?.error || '').trim();

  $('#reportsAppleDaytimeStatus').textContent = getUiStatusLabel(daytimeStatus);
  $('#reportsAppleOvertimeStatus').textContent = getUiStatusLabel(overtimeStatus);
  $('#reportsAppleOvernightStatus').textContent = getUiStatusLabel(overnightStatus);
  $('#reportsAppleLateEventStatus').textContent = getUiStatusLabel(lateEventStatus);

  if (sheetsPill) {
    const variant = getOpsStatusVariant(sheetsStatus);
    if (variant === 'success') sheetsPill.className = 'status-pill status-pill-success';
    else if (variant === 'error') sheetsPill.className = 'status-pill status-pill-error';
    else sheetsPill.className = 'status-pill status-pill-warn';
    sheetsPill.textContent = getUiStatusLabel(sheetsStatus);
  }

  if (sheetsMeta) {
    if (sheetsError) {
      sheetsMeta.textContent = `${sheetsError}${sheetsLastAt ? ` · ${sheetsLastAt}` : ''}`;
    } else if (sheetsLastAt) {
      sheetsMeta.textContent = `마지막 동기화 ${sheetsLastAt}`;
    } else {
      sheetsMeta.textContent = '최근 동기화 이력이 없습니다.';
    }
  }

  if (appleHint) {
    const metrics = status.metrics || {};
    appleHint.textContent = `월 집계: Overnight ${Number(metrics.overnight_rows || 0)}건 · OT ${Number(metrics.approved_ot_rows || 0)}건 · Late/Event ${Number(metrics.late_rows || 0) + Number(metrics.event_rows || 0) + Number(metrics.additional_rows || 0)}건`;
  }
  renderReportsWorkspacePanels();
}

function buildReportsHistoryRows() {
  const rows = [];
  const appleLogs = Array.isArray(state.reports?.appleLogs) ? state.reports.appleLogs : [];
  appleLogs.forEach((row, index) => {
    const key = `apple:${String(row?.id || row?.log_id || index).trim() || index}`;
    const at = String(row?.created_at || row?.updated_at || '').trim();
    const status = String(row?.status || 'pending').trim();
    const title = String(row?.profile_name || row?.profile_scope || '전용 보고').trim();
    const detail = String(row?.error_message || row?.message || '').trim();
    rows.push({
      key,
      at,
      title,
      subtitle: `${formatOpsDateTime(at) || '-'} · ${getUiStatusLabel(status)}`,
      pill: status || 'pending',
      detail: detail || '상세 메시지 없음',
    });
  });
  return rows.sort((a, b) => {
    const aTime = new Date(String(a.at || '')).getTime();
    const bTime = new Date(String(b.at || '')).getTime();
    const safeA = Number.isFinite(aTime) ? aTime : 0;
    const safeB = Number.isFinite(bTime) ? bTime : 0;
    return safeB - safeA;
  });
}

function renderReportsHistoryPanel() {
  const list = $('#reportsHistoryList');
  const detailTitle = $('#reportsHistoryDetailTitle');
  const detailBody = $('#reportsHistoryDetailBody');
  if (!list || !detailTitle || !detailBody) return;

  const rows = buildReportsHistoryRows();
  clearList(list);
  if (!rows.length) {
    renderEmptyState(list, '실행 이력이 없습니다.');
    detailTitle.textContent = '항목 선택';
    detailBody.textContent = '실행 이력을 선택하면 상세 로그를 확인할 수 있습니다.';
    return;
  }

  const selected = rows.find((row) => row.key === String(state.reports?.selectedHistoryLogKey || '').trim()) || rows[0];
  state.reports.selectedHistoryLogKey = selected.key;

  rows.forEach((row) => {
    const li = document.createElement('li');
    const item = makeListRow({
      title: row.title,
      subtitle: row.subtitle,
      pill: row.pill,
      danger: String(row.pill || '').trim().toUpperCase() === 'FAIL',
    });
    item.classList.add('reports-history-row');
    item.classList.toggle('active', row.key === selected.key);
    item.dataset.action = 'reports-history-select';
    item.dataset.logKey = row.key;
    li.appendChild(item);
    list.appendChild(li);
  });

  detailTitle.textContent = selected.title;
  detailBody.textContent = `${selected.subtitle} · ${selected.detail}`;
}

function renderReportsWorkspacePanels() {
  const tabs = $('#reportsWorkspaceTabs');
  const tabbarRow = tabs?.closest('.workspace-tabbar-row');
  const isDesktop = isDesktopViewport();
  let tab = normalizeReportsViewTab(state.reports?.viewTab || 'catalog');
  if (!state.reports) state.reports = createInitialReportsState();
  state.reports.viewTab = tab;

  if (tabs) {
    tabs.classList.toggle('hidden', !isDesktop);
    if (tabbarRow instanceof HTMLElement) {
      tabbarRow.classList.toggle('hidden', !isDesktop);
    }
    tabs.querySelectorAll('[data-action="reports-view-tab"]').forEach((button) => {
      const buttonTab = normalizeReportsViewTab(button?.dataset?.tab || '');
      button.classList.toggle('active', buttonTab === tab);
      button.setAttribute('aria-pressed', buttonTab === tab ? 'true' : 'false');
    });
  }

  const panels = Array.from(document.querySelectorAll('#view-reports [data-reports-panel]'));
  panels.forEach((panel) => {
    const panelType = normalizeReportsViewTab(panel?.dataset?.reportsPanel || 'catalog');
    if (!isDesktop) {
      panel.classList.toggle('hidden', panelType === 'history');
      return;
    }
    panel.classList.toggle('hidden', panelType !== tab);
  });

  renderReportsHistoryPanel();
}

async function loadReportsPacks({ force = false } = {}) {
  if (!state.user || !state.token) return [];
  if (!state.reports) state.reports = createInitialReportsState();

  if (!force && Array.isArray(state.reports.packs) && state.reports.packs.length) {
    renderReportsScopeHint();
    renderReportsPackList();
    renderReportsAppleCard();
    return state.reports.packs;
  }

  const fallback = buildDefaultReportPacksForTenant();
  try {
    const rows = await apiRequest(buildReportsApiPath('/reports/packs'));
    const packs = Array.isArray(rows?.packs) ? rows.packs : (Array.isArray(rows) ? rows : []);
    state.reports.packs = packs.length ? packs : fallback;
    state.reports.tenantCode = String(rows?.tenant_code || getReportsTenantCode() || '').trim().toUpperCase();
  } catch (error) {
    state.reports.packs = fallback;
    state.reports.tenantCode = getReportsTenantCode();
    state.reports.error = normalizeActionError(error, '리포트 팩을 불러오지 못했습니다.');
    showToast(state.reports.error, 'error', 2800);
  }

  const appleEnabled = state.reports.packs.some((pack) => normalizeReportPackValue(pack?.type || pack?.key || '') === 'apple');
  if (!appleEnabled && getSelectedReportsPack() === 'apple') {
    setSelectedReportsPack('default');
  }

  renderReportsScopeHint();
  renderReportsPackList();
  renderReportsAppleCard();
  return state.reports.packs;
}

async function loadAppleReportStatus({ force = false } = {}) {
  if (!state.user || !state.token) return null;
  if (!isAppleReportPackEnabled()) {
    state.reports.appleStatus = null;
    renderReportsAppleCard();
    return null;
  }

  const month = setReportsMonthValue(getReportsMonthValue(), { syncInput: true });
  if (!force && state.reports.appleStatus && state.reports.appleStatus.month === month) {
    renderReportsAppleCard();
    return state.reports.appleStatus;
  }

  try {
    const basePath = buildReportsApiPath('/reports/apple/status');
    const path = `${basePath}${basePath.includes('?') ? '&' : '?'}month=${encodeURIComponent(month)}`;
    const payload = await apiRequest(path);
    state.reports.appleStatus = payload || null;
    state.reports.lastSyncedAt = new Date().toISOString();
    renderReportsAppleCard();
    return state.reports.appleStatus;
  } catch (error) {
    state.reports.appleStatus = null;
    renderReportsAppleCard();
    throw error;
  }
}

async function loadAppleReportLogs({ force = false } = {}) {
  if (!state.user || !state.token) return [];
  if (!isAppleReportPackEnabled()) {
    state.reports.appleLogs = [];
    return [];
  }
  if (!force && Array.isArray(state.reports.appleLogs) && state.reports.appleLogs.length) {
    return state.reports.appleLogs;
  }

  const month = setReportsMonthValue(getReportsMonthValue(), { syncInput: true });
  const basePath = buildReportsApiPath('/reports/apple/logs');
  const path = `${basePath}${basePath.includes('?') ? '&' : '?'}month=${encodeURIComponent(month)}&limit=30`;
  const payload = await apiRequest(path);
  const logs = Array.isArray(payload?.logs) ? payload.logs : [];
  state.reports.appleLogs = logs;
  return logs;
}

function openAppleReportLogsSheet() {
  const logs = Array.isArray(state.reports?.appleLogs) ? state.reports.appleLogs : [];
  const content = document.createElement('div');
  content.className = 'stack';
  const list = document.createElement('ul');
  list.className = 'list';
  if (!logs.length) {
    renderEmptyState(list, '표시할 전용 보고 로그가 없습니다.');
  } else {
    logs.forEach((row) => {
      const li = document.createElement('li');
      li.appendChild(makeListRow({
        title: `${row.profile_name || row.profile_scope || '전용 보고'} · ${getUiStatusLabel(row.status || '-')}`,
        subtitle: `${formatOpsDateTime(row.created_at || '') || '-'}${row.error_message ? ` · ${row.error_message}` : ''}`,
        pill: row.status || 'PENDING',
        danger: String(row.status || '').toUpperCase() === 'FAIL',
      }));
      list.appendChild(li);
    });
  }
  content.appendChild(list);
  openSheet({
    title: '전용 보고 동기화 로그',
    contentNode: content,
    actions: [{ label: '닫기', variant: 'btn-secondary', action: 'sheet-close' }],
  });
}

async function onReportsAppleRun({ retry = false } = {}) {
  if (!isAppleReportPackEnabled()) {
    showToast('이 회사에 해당 보고서가 없습니다.', 'error', 3000);
    return;
  }
  const month = setReportsMonthValue(getReportsMonthValue(), { syncInput: true });
  const basePath = buildReportsApiPath('/reports/apple/run');
  const path = `${basePath}${basePath.includes('?') ? '&' : '?'}month=${encodeURIComponent(month)}`;
  const result = await apiRequest(path, { method: 'POST' });
  const summary = result?.summary || {};
  const success = Number(summary.success || 0);
  const fail = Number(summary.fail || 0);
  const skipped = Number(summary.skipped || 0);
  const message = retry
    ? `재시도 완료: 성공 ${success}건, 실패 ${fail}건, 건너뜀 ${skipped}건`
    : `업데이트 완료: 성공 ${success}건, 실패 ${fail}건, 건너뜀 ${skipped}건`;
  showToast(message, fail > 0 ? 'error' : 'success', 3200);
  await Promise.allSettled([
    loadAppleReportStatus({ force: true }),
    loadAppleReportLogs({ force: true }),
    refreshOpsAutomationSnapshot({ force: true }),
  ]);
}

async function loadReportsViewPresenter() {
  if (!state.reports) state.reports = createInitialReportsState();
  setReportsMonthValue(state.reports.month || toMonthKey(new Date()), { syncInput: true });
  applyAppleTenantScopedUiVisibility();
  await loadReportsPacks({ force: true });
  updateOpsAppleActionVisibility();

  const selectedPack = getSelectedReportsPack();
  if (selectedPack === 'apple' && isAppleReportPackEnabled()) {
    await Promise.allSettled([
      loadAppleReportStatus({ force: true }),
      loadAppleReportLogs({ force: true }),
    ]);
    renderReportsAppleCard();
    renderReportsWorkspacePanels();
    return;
  }
  renderReportsAppleCard();
  renderReportsWorkspacePanels();
}

function applyHomeSelectedSite(siteCode, { announce = false, closePicker = false, refresh = true } = {}) {
  const sites = Array.isArray(state.home.sites) ? state.home.sites : [];
  const select = $('#homeSiteSelect');
  if (!sites.length) {
    state.home.selectedSiteCode = '';
    if (select) {
      select.disabled = true;
      select.value = '';
    }
    renderHomeSitePickerSummary();
    if (refresh) {
      evaluateHomeGeofence();
      updateAttendanceRequestMetaUI();
      checkAttendanceRequestReadiness();
    }
    if (closePicker) closeSheet();
    return false;
  }

  const requested = String(siteCode || '').trim();
  const hasRequested = Boolean(requested) && sites.some((site) => String(site.site_code || '') === requested);
  const nextCode = hasRequested ? requested : String(sites[0].site_code || '').trim();
  const previous = String(state.home.selectedSiteCode || '').trim();
  state.home.selectedSiteCode = nextCode;

  if (select) {
    select.disabled = false;
    select.value = nextCode;
  }

  renderHomeSitePickerSummary();
  const changed = nextCode !== previous;
  if (refresh) {
    evaluateHomeGeofence();
    updateAttendanceRequestMetaUI();
    checkAttendanceRequestReadiness();
  }

  if (announce && changed) {
    const site = getSelectedHomeSite();
    showToast(`근무 현장 변경: ${getHomeSiteDisplayName(site)}`, 'info', 1800);
  }
  if (closePicker) closeSheet();
  return changed;
}

function buildOpenStreetMapEmbedUrl(latitude, longitude, radiusMeters = 120) {
  const lat = Number(latitude);
  const lng = Number(longitude);
  if (!isValidLatLng(lat, lng)) return '';

  const radius = Number(radiusMeters);
  const safeRadius = Number.isFinite(radius) ? Math.max(radius, 120) : 120;
  const latDelta = Math.max((safeRadius * 2.2) / 111320, 0.0035);
  const lonDelta = latDelta / Math.max(Math.cos((lat * Math.PI) / 180), 0.2);
  const minLat = Math.max(-85, lat - latDelta);
  const maxLat = Math.min(85, lat + latDelta);
  const minLng = Math.max(-180, lng - lonDelta);
  const maxLng = Math.min(180, lng + lonDelta);
  const bbox = `${minLng},${minLat},${maxLng},${maxLat}`;
  return `https://www.openstreetmap.org/export/embed.html?bbox=${encodeURIComponent(bbox)}&layer=mapnik&marker=${encodeURIComponent(`${lat},${lng}`)}`;
}

function estimateMapZoomByRadius(radiusMeters) {
  const radius = Number(radiusMeters);
  if (!Number.isFinite(radius) || radius <= 0) return 16;
  if (radius <= 60) return 18;
  if (radius <= 120) return 17;
  if (radius <= 250) return 16;
  if (radius <= 500) return 15;
  if (radius <= 1000) return 14;
  return 13;
}

function buildGoogleMapsEmbedUrl(latitude, longitude, radiusMeters = 120) {
  const lat = Number(latitude);
  const lng = Number(longitude);
  if (!isValidLatLng(lat, lng)) return '';
  const zoom = estimateMapZoomByRadius(radiusMeters);
  return `https://maps.google.com/maps?q=${encodeURIComponent(`${lat},${lng}`)}&z=${zoom}&output=embed`;
}

function buildSiteMapPreviewUrl(latitude, longitude, radiusMeters = 120) {
  return buildGoogleMapsEmbedUrl(latitude, longitude, radiusMeters) || '';
}

const scheduleTabPanelRefs = {
  host: null,
  board: null,
  upload: null,
  reports: null,
  templates: null,
};
const scheduleDetachedNodeCache = new Map();

function bootstrapScheduleTabPanelRefs() {
  const host = document.getElementById('scheduleTabContent');
  const board = document.getElementById('scheduleMonthlyPanel');
  const upload = document.getElementById('scheduleUploadPanel');
  const reports = document.getElementById('scheduleReportsPanel');
  const templates = document.getElementById('scheduleTemplatePanel');
  if (host instanceof HTMLElement) scheduleTabPanelRefs.host = host;
  if (board instanceof HTMLElement) scheduleTabPanelRefs.board = board;
  if (upload instanceof HTMLElement) scheduleTabPanelRefs.upload = upload;
  if (reports instanceof HTMLElement) scheduleTabPanelRefs.reports = reports;
  if (templates instanceof HTMLElement) scheduleTabPanelRefs.templates = templates;
}

function indexScheduleDetachedNodes(root) {
  if (!(root instanceof HTMLElement)) return;
  if (root.id) {
    scheduleDetachedNodeCache.set(root.id, root);
  }
  root.querySelectorAll('[id]').forEach((node) => {
    if (node instanceof HTMLElement && node.id) {
      scheduleDetachedNodeCache.set(node.id, node);
    }
  });
}

function ensureScheduleDetachedNodeCache() {
  bootstrapScheduleTabPanelRefs();
  scheduleDetachedNodeCache.clear();
  indexScheduleDetachedNodes(scheduleTabPanelRefs.host);
  indexScheduleDetachedNodes(scheduleTabPanelRefs.board);
  indexScheduleDetachedNodes(scheduleTabPanelRefs.upload);
  indexScheduleDetachedNodes(scheduleTabPanelRefs.reports);
  indexScheduleDetachedNodes(scheduleTabPanelRefs.templates);
}

function getScheduleTabPanelRoot(tab = '') {
  bootstrapScheduleTabPanelRefs();
  const normalized = normalizeScheduleHqTab(tab);
  if (normalized === SCHEDULE_TAB_UPLOAD) return scheduleTabPanelRefs.upload;
  if (normalized === SCHEDULE_TAB_REPORTS) return scheduleTabPanelRefs.reports;
  if (normalized === SCHEDULE_TAB_TEMPLATES) return scheduleTabPanelRefs.templates;
  return scheduleTabPanelRefs.board;
}

function resolveScheduleDetachedElement(selector = '') {
  const raw = String(selector || '').trim();
  if (!raw.startsWith('#')) return null;
  const id = raw.slice(1).trim();
  if (!id) return null;
  ensureScheduleDetachedNodeCache();
  return scheduleDetachedNodeCache.get(id) || null;
}

const $ = (sel) => document.querySelector(sel) || resolveScheduleDetachedElement(sel);

function normalizeUiTheme(rawTheme = '') {
  return String(rawTheme || '').trim().toLowerCase() === 'dark' ? 'dark' : 'light';
}

function readStoredUiTheme() {
  try {
    const stored = localStorage.getItem(UI_THEME_KEY);
    if (stored) return normalizeUiTheme(stored);
  } catch {
    // ignore storage access errors
  }
  return normalizeUiTheme(document.documentElement?.dataset?.uiTheme || 'light');
}

function syncUiThemeButtons(theme = state.uiTheme || 'light') {
  document.querySelectorAll('[data-action="ui-theme-set"]').forEach((btn) => {
    const active = normalizeUiTheme(btn.dataset.theme || 'light') === theme;
    btn.classList.toggle('is-active', active);
    btn.setAttribute('aria-pressed', active ? 'true' : 'false');
  });
}

function applyUiTheme(nextTheme = 'light', { persist = false } = {}) {
  const normalizedTheme = normalizeUiTheme(nextTheme);
  state.uiTheme = normalizedTheme;
  if (persist) {
    try {
      localStorage.setItem(UI_THEME_KEY, normalizedTheme);
    } catch {
      // ignore storage access errors
    }
  }
  if (document.documentElement) {
    document.documentElement.dataset.uiTheme = normalizedTheme;
  }
  if (document.body) {
    document.body.dataset.uiTheme = normalizedTheme;
  }
  const metaTheme = document.querySelector('meta[name="theme-color"]');
  if (metaTheme) {
    metaTheme.setAttribute('content', normalizedTheme === 'dark' ? '#20242c' : '#f97316');
  }
  syncUiThemeButtons(normalizedTheme);
}

