function normalizeRoleValue(rawRole) {
  const normalized = String(rawRole || '').trim().toLowerCase();
  if (!normalized) return 'officer';
  return ROLE_ALIASES[normalized] || normalized;
}

function getRoleDisplayLabel(rawRole) {
  const normalized = normalizeRoleValue(rawRole);
  return ROLE_DISPLAY_LABELS[normalized] || normalized.toUpperCase();
}

function resolvePermissionGroup(rawRole) {
  const normalized = normalizeRoleValue(rawRole);
  if (normalized === 'developer') return PERMISSION_GROUP_LABELS.DEV;
  if (normalized === 'hq_admin') return PERMISSION_GROUP_LABELS.ADMIN;
  return PERMISSION_GROUP_LABELS.STAFF;
}

