function readStoredAuthTokenValue(key) {
  try {
    const value = String(localStorage.getItem(key) || '').trim();
    return value || '';
  } catch {
    return '';
  }
}

function normalizeStoredJwtToken(rawToken) {
  const token = String(rawToken || '').trim();
  if (!token) return '';
  const lowered = token.toLowerCase();
  if (lowered === 'undefined' || lowered === 'null' || lowered === '[object object]') return '';
  // JWT format guard: header.payload.signature
  if (token.split('.').length !== 3) return '';
  return token;
}

function parseJwtPayloadUnsafe(token) {
  const normalized = normalizeStoredJwtToken(token);
  if (!normalized) return null;
  const parts = normalized.split('.');
  if (parts.length < 2) return null;
  const payloadSeg = parts[1].replace(/-/g, '+').replace(/_/g, '/');
  const padded = payloadSeg + '='.repeat((4 - (payloadSeg.length % 4)) % 4);
  try {
    const json = atob(padded);
    const payload = JSON.parse(json);
    if (!payload || typeof payload !== 'object') return null;
    return payload;
  } catch {
    return null;
  }
}

function isAccessTokenNearExpiry(token, leadSeconds = 90) {
  const payload = parseJwtPayloadUnsafe(token);
  const exp = Number(payload?.exp || 0);
  if (!Number.isFinite(exp) || exp <= 0) return false;
  const nowSec = Math.floor(Date.now() / 1000);
  return nowSec >= (exp - Math.max(0, Number(leadSeconds) || 0));
}

function getActiveAccessToken() {
  const memoryToken = normalizeStoredJwtToken(state.token);
  if (memoryToken) return memoryToken;
  const storedToken = normalizeStoredJwtToken(readStoredAuthTokenValue(ACCESS_TOKEN_KEY));
  if (storedToken) {
    state.token = storedToken;
  } else {
    state.token = '';
  }
  return storedToken;
}

function getActiveRefreshToken() {
  const memoryToken = normalizeStoredJwtToken(state.refreshToken);
  if (memoryToken) return memoryToken;
  const storedToken = normalizeStoredJwtToken(readStoredAuthTokenValue(REFRESH_TOKEN_KEY));
  if (storedToken) {
    state.refreshToken = storedToken;
  } else {
    state.refreshToken = '';
  }
  return storedToken;
}

function persistStoredAuthTokens(accessToken = '', refreshToken = '') {
  try {
    const access = String(accessToken || '').trim();
    const refresh = String(refreshToken || '').trim();
    if (access) {
      localStorage.setItem(ACCESS_TOKEN_KEY, access);
    } else {
      localStorage.removeItem(ACCESS_TOKEN_KEY);
    }
    if (refresh) {
      localStorage.setItem(REFRESH_TOKEN_KEY, refresh);
    } else {
      localStorage.removeItem(REFRESH_TOKEN_KEY);
    }
  } catch {
    // no-op
  }
}

async function requestTokenRefresh() {
  if (tokenRefreshPromise) return tokenRefreshPromise;
  tokenRefreshPromise = (async () => {
    const refreshToken = getActiveRefreshToken();
    if (!refreshToken) return false;

    try {
      const response = await fetch(`${state.activeApiBase}/auth/refresh`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ refresh_token: refreshToken }),
        credentials: 'omit',
        mode: 'cors',
      });
      const text = await response.text();
      let payload = null;
      try { payload = text ? JSON.parse(text) : null; } catch { payload = text; }
      const envelope = normalizeApiEnvelope(payload, response.ok);

      if (!response.ok) {
        console.warn('[RG ARLS][Auth] refresh failed', {
          status: response.status,
          message: getApiErrorMessage(envelope, 'refresh failed'),
        });
        return false;
      }

      const data = envelope?.data || {};
      const nextAccessToken = String(data?.access_token || '').trim();
      const nextRefreshToken = String(data?.refresh_token || refreshToken).trim();
      if (!nextAccessToken) return false;

      state.token = nextAccessToken;
      state.refreshToken = nextRefreshToken;
      if (data?.user && typeof data.user === 'object') {
        state.user = data.user;
      }
      persistSession();
      return true;
    } catch (error) {
      console.warn('[RG ARLS][Auth] refresh error', error);
      return false;
    } finally {
      tokenRefreshPromise = null;
    }
  })();

  return tokenRefreshPromise;
}

function apiRequest(path, options = {}) {
  const normalizedPath = stripLegacyTenantCodeQuery(path);
  const key = `${options.method || 'GET'}:${normalizedPath}:${JSON.stringify(options.body || {})}`;
  if (state.inFlight.has(key)) {
    return state.inFlight.get(key);
  }

  const controller = new AbortController();
  const request = (async () => {
    const method = options.method || 'GET';
    const baseHeaders = { ...(options.headers || {}) };
    const contextTenantHeader = String(
      options.ctxTenantId
      || options.contextTenantId
      || '',
    ).trim();
    const activeTenantHeader = String(getActiveTenantHeaderValue() || '').trim();
    const resolvedTenantHeader = contextTenantHeader || activeTenantHeader;
    if (resolvedTenantHeader && !baseHeaders['X-Tenant-Id'] && !baseHeaders['x-tenant-id']) {
      baseHeaders['X-Tenant-Id'] = resolvedTenantHeader;
    }
    const requestBody = options.body instanceof FormData ? options.body : options.body ? JSON.stringify(options.body) : undefined;
    if (!baseHeaders['Content-Type'] && options.body && !(options.body instanceof FormData)) {
      baseHeaders['Content-Type'] = 'application/json';
    }
    if (method !== 'GET' && method !== 'HEAD' && !baseHeaders['Idempotency-Key']) {
      baseHeaders['Idempotency-Key'] = crypto.randomUUID();
    }

    const createNetworkError = (lastError) => {
      const details = lastError && lastError.message ? lastError.message : '네트워크 오류';
      const origin = window.location.origin || '미확인';
      const originHint = (origin === 'null' || window.location.protocol === 'file:')
        ? '현재 file:// 또는 알 수 없는 출처에서 실행 중입니다. file:// 실행은 CORS로 막힙니다. 로컬은 http://localhost 로 실행하거나 배포 주소로 접속하세요.'
        : '브라우저 네트워크/CORS 또는 DNS 제한일 가능성이 있습니다.';
      const networkError = new Error(`요청 실패: API_BASE=${state.activeApiBase}, path=${normalizedPath}, origin=${origin}. 백엔드가 실행 중인지 확인하세요. (${details}) ${originHint}`);
      networkError.code = 'NETWORK_ERROR';
      networkError.status = 0;
      return networkError;
    };

    const sendRequest = async (authToken = '') => {
      let response;
      let lastError;
      const headers = { ...baseHeaders };
      if (authToken) {
        headers.Authorization = `Bearer ${authToken}`;
      }
      try {
        response = await fetch(`${state.activeApiBase}${normalizedPath}`, {
          method,
          headers,
          body: requestBody,
          signal: controller.signal,
          credentials: 'omit',
          mode: 'cors',
        });
      } catch (error) {
        lastError = error;
      }

      if (!response) {
        throw createNetworkError(lastError);
      }

      const text = await response.text();
      let payload = null;
      try { payload = text ? JSON.parse(text) : null; } catch { payload = text; }
      const envelope = normalizeApiEnvelope(payload, response.ok);
      return { response, text, payload, envelope };
    };

    const isLoginRequest = normalizedPath.startsWith('/auth/login');
    const isRefreshRequest = normalizedPath.startsWith('/auth/refresh');
    const allowRefreshRetry = !options.skipRefreshRetry && !isLoginRequest && !isRefreshRequest;

    let authToken = getActiveAccessToken();
    let result = await sendRequest(authToken);
    if (result.response.status === 401 && allowRefreshRetry) {
      const refreshed = await requestTokenRefresh();
      if (refreshed) {
        authToken = getActiveAccessToken();
        result = await sendRequest(authToken);
      }
    }

    const { response, text, payload, envelope } = result;

    if (response.status === 401) {
      const detail = getApiErrorMessage(envelope, '세션이 만료되었습니다. 다시 로그인해 주세요.');
      const authError = new Error(detail);
      authError.code = 'UNAUTHORIZED';
      authError.status = 401;

      if (!isLoginRequest && !isRefreshRequest && getActiveAccessToken()) {
        clearSession();
        stopPolling();
        if (!options.suppressUnauthorizedRedirect) {
          showAuthPanel();
        }
        const sessionExpiredError = new Error('세션이 만료되었습니다. 다시 로그인해 주세요.');
        sessionExpiredError.code = 'UNAUTHORIZED';
        sessionExpiredError.status = 401;
        throw sessionExpiredError;
      }
      throw authError;
    }

    if (!response.ok) {
      const isObject = (value) => Boolean(value && typeof value === 'object' && !Array.isArray(value));
      const payloadDetail = isObject(payload?.detail) ? payload.detail : null;
      const envelopeDataDetail = isObject(envelope?.data?.detail) ? envelope.data.detail : null;
      const envelopeErrorDetail = isObject(envelope?.error?.detail) ? envelope.error.detail : null;
      const detailObject = payloadDetail || envelopeDataDetail || envelopeErrorDetail;

      const code = String(
        detailObject?.error
        || detailObject?.code
        || detailObject?.error_code
        || envelope?.error?.code
        || envelope?.error?.error
        || envelope?.data?.code
        || envelope?.data?.error
        || '',
      ).trim().toUpperCase();
      const detailMessage = String(
        detailObject?.message
        || detailObject?.detail
        || '',
      ).trim();
      const message = detailMessage || getApiErrorMessage(envelope, `요청 실패 (${response.status})`);
      const responseData = envelope?.data ?? payload ?? null;
      const responseError = envelope?.error ?? null;
      console.error('[RG ARLS][API] request failed', {
        method,
        path: normalizedPath,
        status: response.status,
        code: code || null,
        message,
        detail: detailObject,
        response: responseData,
        error: responseError,
      });
      const requestError = new Error(message);
      requestError.status = response.status;
      requestError.code = code || (response.status === 403 ? 'FORBIDDEN' : (response.status >= 500 ? 'SERVER_ERROR' : 'REQUEST_FAILED'));
      requestError.response = responseData || responseError;
      requestError.error = responseError;
      requestError.envelope = envelope;
      requestError.detail = detailObject
        || (responseError && typeof responseError === 'object' ? (responseError.detail ?? null) : null);
      requestError.responseText = text;
      requestError.path = normalizedPath;
      requestError.method = method;
      throw requestError;
    }

    return envelope.data;
  })();

  state.inFlight.set(key, request);
  request
    .finally(() => state.inFlight.delete(key))
    .catch(() => {});
  return request;
}

function isApiEnvelope(payload) {
  return Boolean(
    payload
      && typeof payload === 'object'
      && !Array.isArray(payload)
      && Object.prototype.hasOwnProperty.call(payload, 'success')
      && Object.prototype.hasOwnProperty.call(payload, 'data')
      && Object.prototype.hasOwnProperty.call(payload, 'error'),
  );
}

function normalizeApiEnvelope(payload, fallbackSuccess = true) {
  if (isApiEnvelope(payload)) {
    return payload;
  }
  return {
    success: Boolean(fallbackSuccess),
    data: payload,
    error: fallbackSuccess ? null : payload,
  };
}

function getApiErrorMessage(envelope, fallbackMessage = '요청 처리 중 오류가 발생했습니다.') {
  if (!envelope || typeof envelope !== 'object') return fallbackMessage;

  const error = envelope.error;
  if (typeof error === 'string' && error.trim()) {
    return error.trim();
  }
  if (error && typeof error === 'object') {
    const message = error.message || error.detail || error.code;
    if (typeof message === 'string' && message.trim()) {
      return message.trim();
    }
  }

  const data = envelope.data;
  if (data && typeof data === 'object') {
    const detail = data.detail || data.message;
    if (typeof detail === 'string' && detail.trim()) {
      return detail.trim();
    }
  }

  return fallbackMessage;
}

function formatInt(value) {
  return (Number(value) || 0).toLocaleString('ko-KR');
}

function isModalToastContext() {
  if (document.body.classList.contains('sheet-modal-open')) return true;
  const overlaySelectors = [
    '#sheetBackdrop',
    '#confirmBackdrop',
    '#requestsUnifiedDetailBackdrop',
    '#leaveWorkspaceDetailBackdrop',
    '#attendanceAdminDrawerBackdrop',
    '#employeeDirectoryDetailBackdrop',
    '#scheduleDetailBackdrop',
  ];
  return overlaySelectors.some((selector) => {
    const el = $(selector);
    return el && !el.classList.contains('hidden');
  });
}

function showToast(message, level = 'info', ttl = 2500) {
  const toastEl = $('#globalToast') || $('#scheduleToast');
  if (!toastEl) return;

  if (state.toastTimer) {
    clearTimeout(state.toastTimer);
    state.toastTimer = null;
  }

  toastEl.classList.remove('toast-info', 'toast-success', 'toast-error', 'toast-modal-overlay');
  toastEl.classList.add('toast');
  toastEl.classList.add(`toast-${level}`);
  if (isModalToastContext()) toastEl.classList.add('toast-modal-overlay');
  toastEl.textContent = message || '';
  if (level === 'success') triggerHaptic('success');
  if (level === 'error') triggerHaptic('error');

  state.toastTimer = setTimeout(() => {
    toastEl.textContent = '';
    toastEl.classList.remove('toast');
    toastEl.classList.remove('toast-info', 'toast-success', 'toast-error', 'toast-modal-overlay');
    state.toastTimer = null;
  }, ttl);
}

function setAuthMessage(message = '', level = 'info') {
  const el = $('#authMessage');
  if (!el) return;

  el.classList.remove('auth-error', 'auth-success', 'auth-info');
  el.textContent = message || '';
  if (!message) return;

  if (level === 'error') {
    el.classList.add('auth-error');
  } else if (level === 'success') {
    el.classList.add('auth-success');
  } else {
    el.classList.add('auth-info');
  }
}

function setFieldError(selector, message = '') {
  const el = $(selector);
  if (!el) return;
  el.textContent = message || '';
  el.classList.toggle('hidden', !message);
}

function clearLoginFieldErrors() {
  setFieldError('#tenantError', '');
  setFieldError('#usernameError', '');
  setFieldError('#passwordError', '');
}

function clearSiteFormFieldErrors() {
  setFieldError('#siteTenantError', '');
  setFieldError('#siteIdError', '');
  setFieldError('#siteNameError', '');
  setFieldError('#siteLocationError', '');
  setFieldError('#siteRadiusError', '');

  ['#siteTenantSelect', '#siteCode', '#siteName', '#siteLatitude', '#siteLongitude', '#siteRadius'].forEach((selector) => {
    const el = $(selector);
    if (el) el.classList.remove('input-invalid');
  });
}

function getSiteFormFieldErrorText(fieldKey, message) {
  const key = String(fieldKey || '').trim().toLowerCase();
  const raw = String(message || '').trim();
  const normalizedMessageKey = raw.toLowerCase();
  if (normalizedMessageKey === 'required') {
    if (key === 'tenant_id' || key === 'tenant_code') return '회사 선택 필요';
    if (key === 'company_code') return '회사 선택 필요';
    if (key === 'site_id' || key === 'site_code') return '현장 번호 확인 필요';
    if (key === 'name' || key === 'site_name') return '현장명 입력 필요';
    if (
      key === 'latitude'
      || key === 'longitude'
      || key === 'lat'
      || key === 'lng'
      || key === 'radius_meters'
      || key === 'radius_m'
      || key === 'radius'
    ) return '위치/반경을 설정해주세요';
  }
  if (normalizedMessageKey === 'invalid') {
    if (key === 'site_id' || key === 'site_code') return '현장 번호를 확인해 주세요.';
    if (
      key === 'latitude'
      || key === 'longitude'
      || key === 'lat'
      || key === 'lng'
      || key === 'radius_meters'
      || key === 'radius_m'
      || key === 'radius'
    ) return '위치/반경을 설정해주세요';
  }
  if (normalizedMessageKey === 'not_found' && (key === 'tenant_id' || key === 'tenant_code')) {
    return '선택한 회사를 찾을 수 없습니다.';
  }
  if (normalizedMessageKey === 'not_found' && key === 'company_code') {
    return '회사 선택을 확인해 주세요.';
  }
  return raw;
}

function setSiteFormFieldError(fieldKey, message) {
  const key = String(fieldKey || '').trim().toLowerCase();
  const text = getSiteFormFieldErrorText(key, message);
  if (!text) return;

  const register = (errorSelector, inputSelectors = []) => {
    setFieldError(errorSelector, text);
    inputSelectors.forEach((selector) => {
      const el = $(selector);
      if (el) el.classList.add('input-invalid');
    });
  };

  if (key === 'tenant_id' || key === 'tenant_code') {
    register('#siteTenantError', ['#siteTenantSelect']);
    return;
  }
  if (key === 'company_code') {
    register('#siteTenantError', ['#siteTenantSelect']);
    return;
  }
  if (key === 'site_id' || key === 'site_code') {
    register('#siteIdError', ['#siteCode']);
    return;
  }
  if (key === 'name' || key === 'site_name') {
    register('#siteNameError', ['#siteName']);
    return;
  }
  if (key === 'latitude' || key === 'longitude') {
    register('#siteLocationError', ['#siteLatitude', '#siteLongitude']);
    return;
  }
  if (key === 'lat' || key === 'lng') {
    register('#siteLocationError', ['#siteLatitude', '#siteLongitude']);
    return;
  }
  if (key === 'radius_meters' || key === 'radius') {
    register('#siteRadiusError', ['#siteRadius']);
    return;
  }
  if (key === 'radius_m') {
    register('#siteRadiusError', ['#siteRadius']);
    return;
  }
}

function extractValidationFields(err) {
  const candidates = [
    err?.error?.fields,
    err?.error?.detail?.fields,
    err?.detail?.fields,
    err?.response?.fields,
    err?.response?.detail?.fields,
    err?.envelope?.error?.fields,
    err?.envelope?.error?.detail?.fields,
  ];
  for (const candidate of candidates) {
    if (candidate && typeof candidate === 'object' && !Array.isArray(candidate)) {
      return candidate;
    }
  }
  return null;
}

function setInlineStatus(selector, message, level = 'info') {
  const el = $(selector);
  if (!el) return;
  el.classList.remove('inline-status', 'state-info', 'state-success', 'state-error', 'state-warning');
  el.classList.add('inline-status');
  if (level === 'success') {
    el.classList.add('state-success');
  } else if (level === 'error') {
    el.classList.add('state-error');
  } else if (level === 'warning' || level === 'warn') {
    el.classList.add('state-warning');
  } else {
    el.classList.add('state-info');
  }
  el.textContent = message || '';
}

function safeText(selector) {
  const el = $(selector);
  return el ? el.textContent : '';
}

