function persistScheduleHqWizardResume() {
  const workspace = ensureScheduleSupportHqWorkspaceState();
  const payload = {
    month: buildScheduleSupportHqContext().month || getScheduleMonthValue(),
    siteCode: buildScheduleSupportHqContext().siteCode || '',
    step: getScheduleHqWizardStep(),
    artifactId: String(workspace.inspectResult?.artifact_id || workspace.contract?.latest_artifact_id || '').trim(),
    revision: String(workspace.inspectResult?.upload_meta?.revision || workspace.contract?.template_version || '').trim(),
    fileName: String(workspace.uploadFileName || '').trim(),
    savedAt: Date.now(),
  };
  writeLocalJSON(SCHEDULE_HQ_WIZARD_RESUME_KEY, payload);
}

function maybeResumeScheduleHqWizard() {
  if (state.schedule?.hqWizardResumePromptShown) return;
  state.schedule.hqWizardResumePromptShown = true;
  const saved = readLocalJSON(SCHEDULE_HQ_WIZARD_RESUME_KEY, null);
  if (!saved || typeof saved !== 'object') return;
  const month = normalizeMonthKey(saved.month || '');
  const step = normalizeScheduleHqWizardStep(saved.step || '');
  const siteCode = String(saved.siteCode || '').trim().toUpperCase();
  if (!month || !step || (!siteCode && siteCode !== 'ALL')) return;
  const shouldResume = window.confirm('마지막 종료 시점에서 다시 시작하시겠습니까?');
  if (!shouldResume) return;
  const monthInput = $('#scheduleImportMonth');
  if (monthInput instanceof HTMLInputElement) monthInput.value = month;
  state.schedule.pendingHqWizardResume = {
    month,
    step,
    siteCode,
    artifactId: String(saved.artifactId || '').trim(),
    revision: String(saved.revision || '').trim(),
    fileName: String(saved.fileName || '').trim(),
  };
  applyPendingScheduleHqWizardResume();
  state.schedule.hqWizardStep = step;
}

function applyPendingScheduleHqWizardResume() {
  const pending = state.schedule?.pendingHqWizardResume;
  if (!pending || typeof pending !== 'object') return;
  const month = normalizeMonthKey(pending.month || '');
  const siteCode = String(pending.siteCode || '').trim().toUpperCase();
  const step = normalizeScheduleHqWizardStep(pending.step || '');
  const monthInput = $('#scheduleImportMonth');
  if (monthInput instanceof HTMLInputElement && month) {
    monthInput.value = month;
  }
  const siteSelect = $('#scheduleImportSite');
  const hasMatchingSite = siteSelect instanceof HTMLSelectElement
    && Array.from(siteSelect.options).some((option) => String(option.value || '').trim().toUpperCase() === siteCode);
  if (siteSelect instanceof HTMLSelectElement && siteCode && hasMatchingSite) {
    siteSelect.value = siteCode;
  }
  const workspace = ensureScheduleSupportHqWorkspaceState();
  if (pending.fileName && !workspace.uploadFileName) {
    workspace.uploadFileName = pending.fileName;
  }
  if (siteCode === 'ALL' || hasMatchingSite) {
    state.schedule.hqWizardStep = step;
    state.schedule.pendingHqWizardResume = null;
  }
}

function renderScheduleUploadWorkflowContext() {
  const uploadUi = getScheduleUploadUiState();
  const supportHqWorkspace = ensureScheduleSupportHqWorkspaceState();
  const mode = getScheduleUploadWorkspaceMode();
  const selectedSite = String($('#scheduleImportSite')?.value || '').trim().toUpperCase();
  const selectedMonth = normalizeMonthKey($('#scheduleImportMonth')?.value || '') || getScheduleMonthValue();
  const tenantLabel = getCurrentTenantDisplayName();
  let fileName = '파일 선택 전';
  let revision = '-';
  let stepLabel = '-';
  if (mode === SCHEDULE_UPLOAD_MODE_HQ) {
    fileName = String(supportHqWorkspace.uploadFileName || '파일 선택 전').trim() || '파일 선택 전';
    revision = String(
      supportHqWorkspace.inspectResult?.upload_meta?.revision
      || supportHqWorkspace.contract?.template_version
      || '-',
    ).trim() || '-';
    stepLabel = getScheduleHqWizardSteps().find((item) => item.key === getScheduleHqWizardStep())?.label || '-';
  } else {
    fileName = String($('#scheduleImportFile')?.files?.[0]?.name || '파일 선택 전').trim() || '파일 선택 전';
    revision = String(state.preview?.metadata?.template_version || state.preview?.metadata?.export_revision || '-').trim() || '-';
    stepLabel = getScheduleBaseWizardSteps().find((item) => item.key === getScheduleBaseWizardStep())?.label || '-';
  }
  setTextContentIfPresent('#scheduleExcelWorkflowContextTenant', tenantLabel, '테넌트 확인');
  setTextContentIfPresent('#scheduleExcelWorkflowContextSite', getScheduleImportSiteLabel(selectedSite), '지점 선택');
  setTextContentIfPresent('#scheduleExcelWorkflowContextMonth', formatScheduleMonthTitle(selectedMonth), '월 선택');
  setTextContentIfPresent('#scheduleExcelWorkflowContextFile', fileName, '파일 선택 전');
  setTextContentIfPresent('#scheduleExcelWorkflowContextRevision', revision, '-');
  setTextContentIfPresent('#scheduleExcelWorkflowContextStage', stepLabel, '-');
  const tenantReadonly = $('#scheduleImportTenantReadonly');
  if (tenantReadonly instanceof HTMLInputElement) {
    tenantReadonly.value = tenantLabel;
    tenantReadonly.readOnly = true;
  }
}

function renderScheduleUploadModeTabs() {
  const wrap = $('#scheduleUploadOwnerTabs');
  if (!(wrap instanceof HTMLElement)) return;
  const canUseHq = canUseScheduleUploadHqWizard();
  const mode = canUseHq ? getScheduleUploadWorkspaceMode() : SCHEDULE_UPLOAD_MODE_BASE;
  if (state.schedule) state.schedule.uploadWorkspaceMode = mode;
  wrap.querySelectorAll('[data-action="schedule-upload-mode-tab"]').forEach((button) => {
    const buttonMode = normalizeScheduleUploadWorkspaceMode(button?.dataset?.mode || '');
    const visible = buttonMode !== SCHEDULE_UPLOAD_MODE_HQ || canUseHq;
    button.classList.toggle('hidden', !visible);
    const active = buttonMode === mode;
    button.classList.toggle('active', active);
    button.setAttribute('aria-pressed', active ? 'true' : 'false');
  });
}

function renderScheduleWizardProgress(containerSelector, steps, activeStep) {
  const wrap = document.querySelector(containerSelector);
  if (!(wrap instanceof HTMLElement)) return;
  wrap.querySelectorAll('.schedule-wizard-step').forEach((button) => {
    const step = String(button?.dataset?.step || '').trim().toLowerCase();
    const active = step === activeStep;
    const activeIndex = steps.findIndex((item) => item.key === activeStep);
    const buttonIndex = steps.findIndex((item) => item.key === step);
    const completed = buttonIndex >= 0 && activeIndex > buttonIndex;
    button.classList.toggle('active', active);
    button.classList.toggle('is-complete', completed);
    button.setAttribute('aria-pressed', active ? 'true' : 'false');
    button.disabled = !(active || completed);
  });
}

function renderScheduleBaseWizardPages() {
  const step = getScheduleBaseWizardStep();
  toggleVisibility('#scheduleExcelWorkflowMappingSection', step === SCHEDULE_BASE_WIZARD_STEP_MAPPING);
  toggleVisibility('#scheduleExcelWorkflowBaseSection', step !== SCHEDULE_BASE_WIZARD_STEP_MAPPING);
  toggleVisibility('#scheduleBaseContextStage', step === SCHEDULE_BASE_WIZARD_STEP_CONTEXT);
  toggleVisibility('#scheduleBaseFileStage', step === SCHEDULE_BASE_WIZARD_STEP_FILE);
  toggleVisibility('#scheduleBaseReviewStage', step === SCHEDULE_BASE_WIZARD_STEP_REVIEW);
  toggleVisibility('#scheduleBaseApplyStage', step === SCHEDULE_BASE_WIZARD_STEP_APPLY);
  toggleVisibility('#scheduleUploadApplyBar', step === SCHEDULE_BASE_WIZARD_STEP_REVIEW || step === SCHEDULE_BASE_WIZARD_STEP_APPLY);
  renderScheduleWizardProgress('#scheduleBaseWizardProgress', getScheduleBaseWizardSteps(), step);
}

function renderScheduleHqWizardPages() {
  const step = getScheduleHqWizardStep();
  toggleVisibility('#scheduleExcelWorkflowExportSection', step === SCHEDULE_HQ_WIZARD_STEP_EXPORT);
  toggleVisibility('#scheduleExcelWorkflowHandoffSection', step !== SCHEDULE_HQ_WIZARD_STEP_EXPORT);
  toggleVisibility('#scheduleSupportUploadSection', step === SCHEDULE_HQ_WIZARD_STEP_UPLOAD);
  toggleVisibility('#scheduleHqWizardPreviewStage', step === SCHEDULE_HQ_WIZARD_STEP_PREVIEW);
  toggleVisibility('#scheduleHqWizardCompleteStage', step === SCHEDULE_HQ_WIZARD_STEP_COMPLETE);
  toggleVisibility('#scheduleHqWizardProgress', true);
  renderScheduleWizardProgress('#scheduleHqWizardProgress', getScheduleHqWizardSteps(), step);
  persistScheduleHqWizardResume();
}

function renderScheduleUploadWorkflowSections() {
  renderScheduleUploadModeTabs();
  const mode = getScheduleUploadWorkspaceMode();
  toggleVisibility('#scheduleBaseWizardProgress', mode === SCHEDULE_UPLOAD_MODE_BASE);
  toggleVisibility('#scheduleHqWizardProgress', mode === SCHEDULE_UPLOAD_MODE_HQ);
  if (mode === SCHEDULE_UPLOAD_MODE_HQ) {
    renderScheduleHqWizardPages();
    toggleVisibility('#scheduleExcelWorkflowMappingSection', false);
    toggleVisibility('#scheduleExcelWorkflowBaseSection', false);
  } else {
    renderScheduleBaseWizardPages();
    toggleVisibility('#scheduleExcelWorkflowExportSection', false);
    toggleVisibility('#scheduleExcelWorkflowHandoffSection', false);
  }
  renderScheduleUploadWorkflowContext();
}

function setScheduleUploadWorkspaceMode(mode = SCHEDULE_UPLOAD_MODE_BASE, { scroll = true } = {}) {
  const normalizedMode = normalizeScheduleUploadWorkspaceMode(mode);
  if (state.schedule) state.schedule.uploadWorkspaceMode = normalizedMode;
  if (normalizedMode === SCHEDULE_UPLOAD_MODE_HQ) {
    maybeResumeScheduleHqWizard();
  }
  if (getScheduleActiveTopTab() !== SCHEDULE_TAB_UPLOAD) {
    onScheduleHqTabChange(SCHEDULE_TAB_UPLOAD);
  }
  requestAnimationFrame(() => {
    renderScheduleUploadWorkflowSections();
    if (!scroll) return;
    const target = document.querySelector('#scheduleUploadPanel');
    if (target instanceof HTMLElement) target.scrollIntoView({ behavior: 'smooth', block: 'start' });
  });
}

function setScheduleBaseWizardStep(step = SCHEDULE_BASE_WIZARD_STEP_MAPPING, { scroll = true } = {}) {
  if (state.schedule) {
    state.schedule.uploadWorkspaceMode = SCHEDULE_UPLOAD_MODE_BASE;
    state.schedule.baseWizardStep = normalizeScheduleBaseWizardStep(step);
  }
  setScheduleUploadWorkspaceMode(SCHEDULE_UPLOAD_MODE_BASE, { scroll });
}

function setScheduleHqWizardStep(step = SCHEDULE_HQ_WIZARD_STEP_EXPORT, { scroll = true } = {}) {
  if (state.schedule) {
    state.schedule.uploadWorkspaceMode = SCHEDULE_UPLOAD_MODE_HQ;
    state.schedule.hqWizardStep = normalizeScheduleHqWizardStep(step);
  }
  setScheduleUploadWorkspaceMode(SCHEDULE_UPLOAD_MODE_HQ, { scroll });
}

function openScheduleUploadWorkflowSection(section = SCHEDULE_UPLOAD_WORKFLOW_MAPPING, { scroll = true } = {}) {
  const normalizedSection = normalizeScheduleUploadWorkflowSection(section);
  if (normalizedSection === SCHEDULE_UPLOAD_WORKFLOW_MAPPING) {
    setScheduleBaseWizardStep(SCHEDULE_BASE_WIZARD_STEP_MAPPING, { scroll });
    return;
  }
  if (normalizedSection === SCHEDULE_UPLOAD_WORKFLOW_BASE) {
    setScheduleBaseWizardStep(SCHEDULE_BASE_WIZARD_STEP_CONTEXT, { scroll });
    return;
  }
  if (normalizedSection === SCHEDULE_UPLOAD_WORKFLOW_EXPORT) {
    setScheduleHqWizardStep(SCHEDULE_HQ_WIZARD_STEP_EXPORT, { scroll });
    return;
  }
  setScheduleHqWizardStep(SCHEDULE_HQ_WIZARD_STEP_UPLOAD, { scroll });
}

function renderScheduleUploadWorkspace() {
  const permissionSummary = $('#scheduleImportPermissionSummary');
  const siteHint = $('#scheduleImportSiteHint');
  const analysisEmpty = $('#scheduleImportAnalysisEmpty');
  const analysisWorkspace = $('#scheduleImportAnalysisWorkspace');
  const previewBtn = $('#schedulePreviewBtn');
  const mappingNextBtn = $('#scheduleMappingNextBtn');
  const contextNextBtn = $('#scheduleBaseContextNextBtn');
  const reviewNextBtn = $('#scheduleBaseReviewNextBtn');
  const hqExportNextBtn = $('#scheduleHqExportNextBtn');
  const latestBaseBtn = $('#scheduleLatestBaseBtn');
  const blankTemplateBtn = $('#scheduleBlankTemplateBtn');
  const mappingEditBtn = document.querySelector('[data-action="schedule-import-mapping-edit"]');
  const siteSelect = $('#scheduleImportSite');
  const fileInput = $('#scheduleImportFile');
  const monthInput = $('#scheduleImportMonth');
  const monthValue = syncScheduleImportMonthInput();
  const selectedSite = String(siteSelect?.value || '').trim().toUpperCase();
  const hasFile = Boolean(fileInput?.files?.length);
  const mappingEntryCount = Number(state.schedule?.importMappingProfile?.entry_count || 0);
  const uploadUi = getScheduleUploadUiState();
  const supportHqWorkspace = ensureScheduleSupportHqWorkspaceState();
  const uploadWorkspaceBooting = Boolean(state.schedule.uploadWorkspaceBooting);
  const supportHqBusy = Boolean(
    supportHqWorkspace.loading
    || supportHqWorkspace.inspectLoading
    || supportHqWorkspace.applyLoading
  );
  const siteOptionsLoading = Boolean(state.schedule.importSiteOptionsLoading);

  syncScheduleImportStaleState();
  renderScheduleImportMappingProfileSummary();
  renderScheduleUploadWorkflowSections();

  if (permissionSummary) {
    permissionSummary.textContent = isScheduleUploadTenantWideUser()
      ? '현재 계정은 tenant 전체 지점을 업로드할 수 있습니다.'
      : '현재 계정은 본인 지점만 업로드 가능합니다.';
  }
  if (siteHint) {
    if (uploadWorkspaceBooting) {
      siteHint.textContent = 'Excel workflow 초기 상태를 준비하는 중입니다. 준비가 끝나면 지점과 월을 선택할 수 있습니다.';
    } else if (siteOptionsLoading) {
      siteHint.textContent = '지점 목록을 불러오는 중입니다. 로딩이 끝나면 선택할 수 있습니다.';
    } else {
      siteHint.textContent = isScheduleUploadTenantWideUser()
        ? 'HQ 계정은 같은 tenant의 모든 지점을 선택할 수 있습니다.'
        : `지점 범위가 ${getScheduleImportSiteLabel(state.user?.site_code || selectedSite)}로 고정됩니다.`;
    }
  }
  if (siteSelect instanceof HTMLSelectElement) {
    siteSelect.disabled = uploadWorkspaceBooting || siteOptionsLoading || uploadUi.analysisInFlight || supportHqBusy || !isScheduleUploadTenantWideUser();
  }
  if (monthInput instanceof HTMLInputElement) {
    monthInput.disabled = uploadWorkspaceBooting || uploadUi.analysisInFlight || supportHqBusy;
  }
  if (fileInput instanceof HTMLInputElement) {
    fileInput.disabled = uploadWorkspaceBooting || uploadUi.analysisInFlight || supportHqBusy;
  }
  if (previewBtn) {
    previewBtn.disabled = uploadWorkspaceBooting || siteOptionsLoading || uploadUi.analysisInFlight || supportHqBusy || !(hasFile && selectedSite && monthValue);
    previewBtn.textContent = uploadUi.analysisInFlight ? '분석 중...' : '분석 시작';
  }
  if (mappingNextBtn instanceof HTMLButtonElement) {
    mappingNextBtn.disabled = uploadWorkspaceBooting || mappingEntryCount <= 0;
  }
  if (contextNextBtn instanceof HTMLButtonElement) {
    contextNextBtn.disabled = uploadWorkspaceBooting || siteOptionsLoading || supportHqBusy || !(selectedSite && monthValue);
  }
  if (reviewNextBtn instanceof HTMLButtonElement) {
    reviewNextBtn.disabled = !Boolean(state.preview);
  }
  if (hqExportNextBtn instanceof HTMLButtonElement) {
    hqExportNextBtn.disabled = !Boolean(buildScheduleSupportArtifactContext(state.schedule.supportStatus && typeof state.schedule.supportStatus === 'object' ? state.schedule.supportStatus : null, getScheduleSupportSelectedSiteCode()).artifact_id);
  }
  if (latestBaseBtn) {
    latestBaseBtn.disabled = uploadWorkspaceBooting || siteOptionsLoading || uploadUi.analysisInFlight || supportHqBusy || !(selectedSite && monthValue);
  }
  if (blankTemplateBtn) {
    blankTemplateBtn.disabled = uploadWorkspaceBooting || uploadUi.analysisInFlight || supportHqBusy;
  }
  if (mappingEditBtn instanceof HTMLButtonElement) {
    mappingEditBtn.disabled = uploadWorkspaceBooting || uploadUi.analysisInFlight || supportHqBusy || !canMutateScheduleData();
  }

  renderScheduleUploadProgress();
  renderScheduleUploadFileMeta();
  renderScheduleImportSummaryStrip(state.preview);
  renderScheduleImportIssueGroups(state.preview);
  renderScheduleImportTechnicalDetails(state.preview);

  if (analysisEmpty instanceof HTMLElement) {
    analysisEmpty.classList.toggle('hidden', Boolean(state.preview));
  }
  if (analysisWorkspace instanceof HTMLElement) {
    analysisWorkspace.classList.toggle('hidden', !state.preview);
  }

  const applyResultEl = $('#scheduleApplyResult');
  if (applyResultEl) {
    applyResultEl.textContent = getScheduleUploadUiState().applyResult || '분석이 완료되면 적용 상태가 여기에 표시됩니다.';
  }

  renderScheduleUploadApplyBar();
  renderScheduleSupportHqWorkspace();
}

function renderSchedulePreviewTable(previewRows = []) {
  const wrap = $('#schedulePreviewTableWrap');
  const body = $('#schedulePreviewTableBody');
  const modeSwitch = $('#schedulePreviewModeSwitch');
  if (!wrap || !body) return;

  body.innerHTML = '';
  const rows = Array.isArray(previewRows) ? previewRows : [];
  const previewMode = normalizeScheduleImportPreviewMode(getScheduleUploadUiState().previewMode);
  const visibleRows = filterScheduleImportPreviewRows(rows, previewMode);

  if (modeSwitch instanceof HTMLElement) {
    modeSwitch.querySelectorAll('[data-action="schedule-preview-mode"]').forEach((button) => {
      const buttonMode = normalizeScheduleImportPreviewMode(button?.dataset?.mode || '');
      button.classList.toggle('active', buttonMode === previewMode);
      button.setAttribute('aria-pressed', buttonMode === previewMode ? 'true' : 'false');
    });
  }

  if (!rows.length) {
    wrap.classList.add('hidden');
    return;
  }

  wrap.classList.remove('hidden');
  if (!visibleRows.length) {
    const tr = document.createElement('tr');
    const td = document.createElement('td');
    td.colSpan = 8;
    td.appendChild(createScheduleUploadStackCell(
      previewMode === 'actionable' ? '기본 보기에서는 검토/차단 대상만 표시됩니다.' : '표시할 행이 없습니다.',
      previewMode === 'actionable'
        ? '전체 보기로 전환하면 반영 예정과 보호/요약 메타데이터를 포함한 전체 분석 행을 볼 수 있습니다.'
        : '현재 검토 결과에서 표시할 행이 없습니다.',
    ));
    tr.appendChild(td);
    body.appendChild(tr);
    return;
  }

  visibleRows.forEach((row) => {
    const tr = document.createElement('tr');
    const rowState = getScheduleImportRowState(row);
    if (rowState.key === 'blocked') tr.classList.add('schedule-preview-row-invalid');
    else if (rowState.key === 'protected') tr.classList.add('schedule-preview-row-protected');
    else if (rowState.key === 'apply') tr.classList.add('schedule-upload-preview-row-apply');
    else tr.classList.add('schedule-upload-preview-row-neutral');

    const dateLabel = String(row?.schedule_date || '-').trim() || '-';
    const sectionLabel = String(row?.section_label || row?.source_block || '-').trim() || '-';
    const sourceBlock = String(row?.source_block || '').trim();
    const dutyLabel = formatScheduleImportDutyLabel(row?.duty_type || row?.shift_type || '-');
    const employeeLabel = String(row?.employee_name || row?.employee_code || '-').trim() || '-';
    const workValue = String(row?.work_value || '-').trim() || '-';
    const currentValueLabel = String(row?.current_work_value || '-').trim() || '-';
    const resultLabel = String(row?.status_label || getScheduleImportRowActionLabel(row)).trim() || '-';
    const reasonLabel = String(
      row?.validation_error
      || row?.protected_reason
      || row?.validation_code
      || '-',
    ).trim() || '-';

    const cells = [
      { primary: row?.row_no ?? '-', secondary: '' },
      { primary: dateLabel, secondary: '' },
      { primary: sectionLabel, secondary: sourceBlock && sourceBlock !== sectionLabel ? sourceBlock : '' },
      { primary: dutyLabel, secondary: row?.template_name || row?.mapping_key || '' },
      { primary: employeeLabel, secondary: `셀 값 ${workValue}` },
      { primary: currentValueLabel, secondary: '' },
      null,
      { primary: reasonLabel, secondary: '' },
    ];

    cells.forEach((cell, index) => {
      const td = document.createElement('td');
      if (index === 6) {
        const resultCell = document.createElement('div');
        resultCell.className = 'schedule-upload-preview-cell';
        const chip = document.createElement('span');
        chip.className = rowState.chipClass;
        chip.textContent = rowState.chipLabel;
        const resultStrong = document.createElement('strong');
        resultStrong.textContent = resultLabel;
        const sub = document.createElement('span');
        sub.className = 'muted';
        sub.textContent = getScheduleImportRowActionLabel(row);
        resultCell.appendChild(chip);
        resultCell.appendChild(resultStrong);
        resultCell.appendChild(sub);
        td.appendChild(resultCell);
      } else {
        td.appendChild(createScheduleUploadStackCell(cell?.primary, cell?.secondary));
      }
      tr.appendChild(td);
    });
    body.appendChild(tr);
  });
}

function normalizeScheduleImportPreviewMode(value = '') {
  return String(value || '').trim().toLowerCase() === 'all' ? 'all' : 'actionable';
}

function isScheduleImportPreviewRowActionable(row = {}) {
  if (typeof row?.actionable === 'boolean') return row.actionable;
  const diffCategory = String(row?.diff_category || '').trim().toLowerCase();
  const isProtected = Boolean(row?.is_protected) || diffCategory === 'ignored_protected';
  const isBlocking = Boolean(row?.is_blocking) || (!isProtected && row?.is_valid === false);
  return isBlocking || diffCategory === 'review';
}

function isScheduleImportPreviewRowProtectedInfoOnly(row = {}) {
  const diffCategory = String(row?.diff_category || '').trim().toLowerCase();
  const isProtected = Boolean(row?.is_protected) || diffCategory === 'ignored_protected';
  const isBlocking = Boolean(row?.is_blocking) || (!isProtected && row?.is_valid === false);
  if (isBlocking) return false;
  if (typeof row?.protected_info_only === 'boolean') return row.protected_info_only;
  const sourceBlock = String(row?.source_block || '').trim().toLowerCase();
  const parsedSemanticType = String(row?.parsed_semantic_type || '').trim().toLowerCase();
  if (sourceBlock === 'sentrix_support_ticket') return true;
  if (sourceBlock.startsWith('day_support') || sourceBlock.startsWith('night_support')) return true;
  if (parsedSemanticType.startsWith('protected_') || parsedSemanticType === 'support_demand') return true;
  if ((diffCategory === 'ignored_protected' || diffCategory === 'ignored_no_demand') && sourceBlock !== 'body') return true;
  return false;
}

function filterScheduleImportPreviewRows(rows = [], previewMode = 'actionable') {
  const normalizedMode = normalizeScheduleImportPreviewMode(previewMode);
  const normalizedRows = Array.isArray(rows) ? rows : [];
  if (normalizedMode === 'all') return normalizedRows;
  return normalizedRows.filter((row) => {
    if (isScheduleImportPreviewRowProtectedInfoOnly(row)) return false;
    return isScheduleImportPreviewRowActionable(row);
  });
}

function scheduleApplyStatusClass(status = '') {
  const value = String(status || '').trim().toLowerCase();
  if (value === 'applied') return 'status-pill status-pill-success';
  if (value === 'skipped' || value === 'invalid') return 'status-pill status-pill-error';
  return 'status-pill status-pill-warn';
}

function renderScheduleApplyDetails(appliedRows = [], skippedRows = []) {
  const list = $('#scheduleApplyDetails');
  if (!list) return;

  list.innerHTML = '';
  const applied = Array.isArray(appliedRows) ? appliedRows : [];
  const skipped = Array.isArray(skippedRows) ? skippedRows : [];
  const all = [...applied, ...skipped].sort((a, b) => Number(a?.row_no || 0) - Number(b?.row_no || 0));
  if (!all.length) {
    list.classList.add('hidden');
    return;
  }

  all.forEach((row) => {
    const li = document.createElement('li');
    li.classList.add('content-fade-in');

    const container = document.createElement('div');
    container.className = 'list-row';

    const main = document.createElement('div');
    main.className = 'list-row-main';

    const title = document.createElement('div');
    title.className = 'list-row-title';
    const employee = String(row?.employee_code || '-').trim() || '-';
    const date = String(row?.schedule_date || '-').trim() || '-';
    const site = String(row?.site_code || '-').trim() || '-';
    title.textContent = `행 ${row?.row_no || '-'} · ${employee} · ${date} · ${site}`;
    main.appendChild(title);

    const sub = document.createElement('div');
    sub.className = 'list-row-sub';
    const shift = String(row?.shift_type || '-').trim() || '-';
    const reason = String(row?.reason || '').trim() || '-';
    sub.textContent = `근무유형=${getUiStatusLabel(shift)} · ${reason}`;
    main.appendChild(sub);

    const pill = document.createElement('span');
    const statusText = String(row?.status || '').trim() || 'unknown';
    pill.className = scheduleApplyStatusClass(statusText);
    pill.textContent = getUiStatusLabel(statusText);

    container.appendChild(main);
    container.appendChild(pill);
    li.appendChild(container);
    list.appendChild(li);
  });

  list.classList.remove('hidden');
}

function setScheduleImportUI({
  batchInfo = '',
  issues = [],
  applyResult = '',
  canApply = false,
  previewRows = null,
  clearPreviewRows = false,
  applyRows = null,
  skippedRows = null,
  clearApplyDetails = false,
} = {}) {
  const infoEl = $('#scheduleBatchInfo');
  const issuesEl = $('#scheduleBatchIssues');
  const uploadUi = getScheduleUploadUiState();

  if (infoEl) infoEl.textContent = batchInfo;
  uploadUi.batchInfo = batchInfo;
  uploadUi.applyResult = applyResult;
  uploadUi.canApply = Boolean(canApply);

  if (issuesEl) {
    issuesEl.innerHTML = '';
    if (!issues.length) {
      issuesEl.classList.add('hidden');
    } else {
      issuesEl.classList.remove('hidden');
      issues.forEach((item) => {
        const li = document.createElement('li');
        li.textContent = item;
        issuesEl.appendChild(li);
      });
    }
  }

  if (clearPreviewRows) {
    renderSchedulePreviewTable([]);
  } else if (previewRows !== null) {
    renderSchedulePreviewTable(previewRows);
  }

  if (clearApplyDetails) {
    renderScheduleApplyDetails([], []);
  } else if (applyRows !== null || skippedRows !== null) {
    renderScheduleApplyDetails(applyRows || [], skippedRows || []);
  }

  renderScheduleUploadWorkspace();
}

function invalidateScheduleImportAnalysis(fields = []) {
  const uploadUi = getScheduleUploadUiState();
  clearScheduleImportProgressTimer(uploadUi);
  uploadUi.analysisInFlight = false;
  uploadUi.requestContext = null;
  uploadUi.requestClientContext = '';
  uploadUi.requestToken = '';
  uploadUi.canApply = false;
  uploadUi.stale = Boolean(state.preview || uploadUi.analyzedClientContext);
  uploadUi.staleFields = Array.from(new Set((Array.isArray(fields) ? fields : []).filter(Boolean)));
  state.previewBatchId = '';

  if (!uploadUi.stale) {
    setScheduleImportUI({
      batchInfo: '',
      applyResult: '',
      canApply: false,
      clearPreviewRows: true,
      clearApplyDetails: true,
    });
    return;
  }

  const labels = formatScheduleImportContextFields(uploadUi.staleFields);
  setScheduleImportUI({
    batchInfo: labels ? `${labels} 변경으로 기존 분석 결과가 stale 상태가 되었습니다.` : '기존 분석 결과가 stale 상태가 되었습니다.',
    applyResult: labels ? `${labels} 변경으로 다시 분석해야 합니다.` : '다시 분석해야 적용할 수 있습니다.',
    canApply: false,
  });
}

function parseContentDispositionFilename(disposition = '', fallbackName = '') {
  const raw = String(disposition || '').trim();
  const fallback = String(fallbackName || '').trim() || 'download.xlsx';
  const utf8Match = raw.match(/filename\*\s*=\s*UTF-8''([^;]+)/i);
  const basicMatch = raw.match(/filename="?([^"]+)"?/i);
  if (utf8Match?.[1]) {
    try {
      return decodeURIComponent(String(utf8Match[1]).trim()) || fallback;
    } catch (_) {
      return fallback;
    }
  }
  if (basicMatch?.[1]) return String(basicMatch[1]).trim() || fallback;
  return fallback;
}

function formatScheduleSupportHqContextFields(fields = []) {
  const labels = {
    site: '업로드 지점',
    month: '대상 월',
    file: '업로드 파일',
  };
  return Array.from(new Set((Array.isArray(fields) ? fields : []).filter(Boolean)))
    .map((field) => labels[String(field || '').trim()] || String(field || '').trim())
    .filter(Boolean)
    .join(', ');
}

function buildScheduleSupportHqContext() {
  const month = normalizeMonthKey($('#scheduleImportMonth')?.value || getScheduleMonthValue()) || getScheduleMonthValue();
  const siteCode = getScheduleSupportSelectedSiteCode();
  return {
    month,
    siteCode,
    contextKey: `${month}::${siteCode || 'NONE'}`,
  };
}

function getScheduleSupportHqWorkspaceSites() {
  const workspace = ensureScheduleSupportHqWorkspaceState();
  const sites = Array.isArray(workspace.contract?.sites) ? workspace.contract.sites : [];
  return sites.map((site) => ({
    siteCode: String(site?.site_code || '').trim().toUpperCase(),
    siteName: String(site?.site_name || '').trim() || String(site?.site_code || '').trim().toUpperCase() || '-',
    sheetName: String(site?.sheet_name || site?.site_name || site?.site_code || '').trim() || '-',
    downloadReady: Boolean(site?.download_ready),
    sourceState: String(site?.source_state || '').trim() || 'source_missing',
    sourceRevision: String(site?.source_revision || '').trim(),
    latestHqRevision: String(site?.latest_hq_revision || '').trim(),
    latestStatus: String(site?.latest_status || '').trim() || 'source_missing',
  })).filter((site) => site.siteCode);
}

function getScheduleSupportHqSelectedSiteContext() {
  const currentSiteCode = String(buildScheduleSupportHqContext().siteCode || '').trim().toUpperCase();
  if (!currentSiteCode || currentSiteCode === 'ALL') {
    return currentSiteCode === 'ALL'
      ? {
        siteCode: 'ALL',
        siteName: '전체 지점',
        sheetName: 'ALL',
        downloadReady: getScheduleSupportHqWorkspaceSites().some((site) => site.downloadReady),
      }
      : null;
  }
  return getScheduleSupportHqWorkspaceSites().find((site) => site.siteCode === currentSiteCode) || null;
}

function resetScheduleSupportHqWorkspace({
  preserveFile = true,
  preserveContract = true,
  staleFields = [],
} = {}) {
  const workspace = ensureScheduleSupportHqWorkspaceState();
  const fileInput = $('#scheduleSupportHqUploadFile');
  const currentFile = fileInput instanceof HTMLInputElement && fileInput.files?.length
    ? fileInput.files[0]
    : null;
  const fileName = preserveFile
    ? (
      workspace.uploadFileName
      || (currentFile ? String(currentFile.name || '').trim() : '')
    )
    : '';
  const fileSize = preserveFile ? (workspace.uploadFileSize || Number(currentFile?.size || 0)) : 0;
  const fileLastModified = preserveFile
    ? (
      workspace.uploadFileLastModified
      || (
        currentFile?.lastModified
          ? new Date(currentFile.lastModified).toLocaleString('ko-KR')
          : ''
      )
    )
    : '';
  if (!preserveFile && fileInput instanceof HTMLInputElement) {
    fileInput.value = '';
  }
  const nextContract = preserveContract ? workspace.contract : null;
  const nextError = preserveContract ? workspace.error : '';
  const nextLoading = preserveContract ? workspace.loading : false;
  const nextMonth = buildScheduleSupportHqContext().month || toMonthKey(new Date());
  const staleFieldList = Array.from(new Set((Array.isArray(staleFields) ? staleFields : []).filter(Boolean)));
  workspace.month = nextMonth;
  workspace.loading = nextLoading;
  workspace.error = nextError;
  workspace.contract = nextContract;
  workspace.uploadFileName = fileName;
  workspace.uploadFileSize = fileSize;
  workspace.uploadFileLastModified = fileLastModified;
  workspace.inspectLoading = false;
  workspace.inspectError = '';
  workspace.inspectResult = null;
  workspace.applyLoading = false;
  workspace.applyError = '';
  workspace.applyResult = null;
  workspace.previewMode = 'actionable';
  workspace.stale = Boolean(staleFieldList.length && fileName);
  workspace.staleFields = staleFieldList;
}

function renderScheduleSupportHqReviewSummary() {
  const workspace = ensureScheduleSupportHqWorkspaceState();
  const container = $('#scheduleSupportHqReviewSummary');
  if (!(container instanceof HTMLElement)) return;
  container.innerHTML = '';
  const inspectResult = workspace.inspectResult && typeof workspace.inspectResult === 'object'
    ? workspace.inspectResult
    : null;
  const summaryItems = inspectResult
    ? [
      { label: 'workbook 유효성', value: inspectResult.workbook_valid ? '검토 가능' : '검토 필요' },
      { label: 'ticket scope', value: `${Number(inspectResult.total_scope_count || 0)}건` },
      { label: '적용 가능', value: `${Number(inspectResult.valid_scope_count || 0)}건` },
      { label: '자동승인 예상', value: `${Number(inspectResult.summary?.auto_approved || 0)}건` },
      { label: '승인대기 예상', value: `${Number(inspectResult.summary?.approval_pending || 0)}건` },
      { label: '차단', value: `${Number(inspectResult.summary?.blocking || 0)}건` },
      { label: 'worker row', value: `${Number(inspectResult.summary?.worker_rows || 0)}건` },
    ]
    : [
      { label: 'workbook 유효성', value: workspace.stale ? '재검토 필요' : '파일 선택 대기' },
      { label: 'ticket scope', value: '-' },
      { label: '적용 가능', value: '-' },
      { label: '자동승인 예상', value: '-' },
      { label: '승인대기 예상', value: '-' },
      { label: '차단', value: '-' },
      { label: 'worker row', value: '-' },
    ];
  summaryItems.forEach((item) => {
    const card = document.createElement('div');
    card.className = 'schedule-upload-summary-card';
    const labelEl = document.createElement('span');
    labelEl.textContent = item.label;
    const valueEl = document.createElement('strong');
    valueEl.textContent = item.value;
    card.appendChild(labelEl);
    card.appendChild(valueEl);
    container.appendChild(card);
  });
}

function renderScheduleSupportHqIssueGroups() {
  const workspace = ensureScheduleSupportHqWorkspaceState();
  const container = $('#scheduleSupportHqIssueGroups');
  if (!(container instanceof HTMLElement)) return;
  container.innerHTML = '';
  const inspectResult = workspace.inspectResult && typeof workspace.inspectResult === 'object'
    ? workspace.inspectResult
    : null;
  const issues = Array.isArray(inspectResult?.issues) ? inspectResult.issues : [];
  if (!issues.length) {
    const placeholder = document.createElement('div');
    placeholder.className = 'schedule-upload-placeholder support-status-hq-placeholder';
    const strong = document.createElement('strong');
    if (workspace.inspectError) {
      strong.textContent = '검토 중 오류가 발생했습니다.';
    } else if (workspace.stale) {
      strong.textContent = '현재 검토 결과가 stale 상태입니다.';
    } else {
      strong.textContent = inspectResult ? '현재 검토 이슈가 없습니다.' : '검토를 시작하면 workbook validity와 revision 상태가 여기에 표시됩니다.';
    }
    placeholder.appendChild(strong);
    const meta = document.createElement('p');
    if (workspace.inspectError) {
      meta.textContent = String(workspace.inspectError || '').trim();
    } else if (workspace.stale) {
      meta.textContent = `${formatScheduleSupportHqContextFields(workspace.staleFields)} 변경으로 다시 검토해야 합니다.`;
    } else {
      meta.textContent = String(inspectResult?.next_step_message || 'scope별 요청 수(ticket 기준), 유효 입력 수, 업로드 workbook 근무자 셀 파싱 결과가 여기에 묶여 표시됩니다.').trim();
    }
    placeholder.appendChild(meta);
    container.appendChild(placeholder);
    return;
  }
  issues.forEach((issue) => {
    const card = document.createElement('article');
    card.className = 'schedule-upload-issue-card';
    const head = document.createElement('div');
    head.className = 'schedule-upload-issue-card-head';
    const copy = document.createElement('strong');
    copy.textContent = String(issue?.title || issue?.code || '검토 이슈').trim();
    const count = document.createElement('span');
    count.className = issue?.severity === 'blocking' ? 'status-pill status-pill-error' : 'status-pill status-pill-neutral';
    count.textContent = `${Number(issue?.count || 0)}건`;
    head.appendChild(copy);
    head.appendChild(count);
    card.appendChild(head);
    const message = document.createElement('p');
    message.textContent = String(issue?.message || '').trim();
    card.appendChild(message);
    if (String(issue?.guidance || '').trim()) {
      const guidance = document.createElement('span');
      guidance.textContent = String(issue?.guidance || '').trim();
      card.appendChild(guidance);
    }
    container.appendChild(card);
  });
}

function renderScheduleSupportHqReviewTable() {
  const workspace = ensureScheduleSupportHqWorkspaceState();
  const tableWrap = $('#scheduleSupportHqReviewTableWrap');
  const tableBody = $('#scheduleSupportHqReviewTableBody');
  const placeholder = $('#scheduleSupportHqReviewPlaceholder');
  const modeSwitch = $('#scheduleSupportHqPreviewModeSwitch');
  if (!(tableWrap instanceof HTMLElement) || !(tableBody instanceof HTMLElement) || !(placeholder instanceof HTMLElement)) return;
  tableBody.innerHTML = '';
  const inspectResult = workspace.inspectResult && typeof workspace.inspectResult === 'object'
    ? workspace.inspectResult
    : null;
  const aggregatedRows = buildScheduleSupportHqAggregatedPreviewRows(inspectResult);
  const previewMode = normalizeScheduleSupportHqPreviewMode(workspace.previewMode);
  workspace.previewMode = previewMode;
  if (modeSwitch instanceof HTMLElement) {
    modeSwitch.querySelectorAll('[data-action="schedule-support-hq-preview-mode"]').forEach((button) => {
      const buttonMode = normalizeScheduleSupportHqPreviewMode(button instanceof HTMLElement ? button.dataset.mode || '' : '');
      button.classList.toggle('active', buttonMode === previewMode);
      button.setAttribute('aria-pressed', buttonMode === previewMode ? 'true' : 'false');
    });
  }
  const visibleRows = filterScheduleSupportHqAggregatedPreviewRows(aggregatedRows, previewMode);
  if (!visibleRows.length) {
    tableWrap.classList.add('hidden');
    placeholder.classList.remove('hidden');
    const strong = placeholder.querySelector('strong');
    const meta = placeholder.querySelector('p');
    if (strong) {
      if (workspace.stale) {
        strong.textContent = '현재 검토 결과는 stale 상태입니다.';
      } else if (workspace.uploadFileName) {
        strong.textContent = previewMode === 'actionable'
          ? '기본 보기에서는 검토 필요/업로드 차단 scope만 표시됩니다.'
          : '업로드 파일 검토를 실행하면 scope별 상태와 근무자 셀 결과가 표시됩니다.';
      } else {
        strong.textContent = '업로드할 HQ 작성본 workbook 파일을 선택하세요.';
      }
    }
    if (meta) {
      if (workspace.stale) {
        meta.textContent = `${formatScheduleSupportHqContextFields(workspace.staleFields)} 변경으로 다시 검토해야 합니다.`;
      } else if (workspace.inspectError) {
        meta.textContent = String(workspace.inspectError || '').trim();
      } else {
        meta.textContent = previewMode === 'actionable'
          ? '전체 보기로 전환하면 승인 scope를 포함한 모든 support scope를 볼 수 있습니다.'
          : (
            inspectResult?.next_step_message
              ? String(inspectResult.next_step_message || '').trim()
              : '지원요청 scope, 유효 입력 수, 업로드 workbook 근무자 셀 파싱 결과를 이 구역에서 검토합니다. 요청 수는 기존 Sentrix ticket 기준입니다.'
          );
      }
    }
    return;
  }
  tableWrap.classList.remove('hidden');
  placeholder.classList.add('hidden');
  visibleRows.forEach((row) => {
    const tr = document.createElement('tr');
    const sheetCell = document.createElement('td');
    sheetCell.textContent = String(row?.sheet_name || '-').trim() || '-';
    tr.appendChild(sheetCell);

    const siteCell = document.createElement('td');
    siteCell.textContent = getSupportStatusSiteLabel(row?.site_code || '', row?.site_name || '');
    tr.appendChild(siteCell);

    const dateCell = document.createElement('td');
    dateCell.textContent = formatDateLabel(row?.work_date || '', '-');
    tr.appendChild(dateCell);

    const shiftCell = document.createElement('td');
    if (String(row?.shift_kind || '').trim()) {
      const shiftPill = document.createElement('span');
      shiftPill.className = getSupportStatusShiftClass(row?.shift_kind || '');
      shiftPill.textContent = getSupportStatusShiftLabel(row?.shift_kind || '');
      shiftCell.appendChild(shiftPill);
    } else {
      shiftCell.textContent = '-';
    }
    tr.appendChild(shiftCell);

    const requestCountCell = document.createElement('td');
    requestCountCell.textContent = `${Number(row?.request_count || 0)}`;
    tr.appendChild(requestCountCell);

    const enteredCountCell = document.createElement('td');
    enteredCountCell.textContent = `${Number(row?.entered_count || 0)}`;
    tr.appendChild(enteredCountCell);

    const workerCell = document.createElement('td');
    workerCell.textContent = String(row?.worker_names || '').trim() || '-';
    tr.appendChild(workerCell);

    const targetCell = document.createElement('td');
    const targetStatus = String(row?.display_status || row?.target_status || '').trim();
    if (targetStatus) {
      const targetPill = document.createElement('span');
      targetPill.className = getSupportStatusRequestStatusClass(targetStatus);
      targetPill.textContent = getSupportStatusRequestStatusLabel(targetStatus);
      targetCell.appendChild(targetPill);
    } else {
      targetCell.textContent = '-';
    }
    tr.appendChild(targetCell);

    const reasonCell = document.createElement('td');
    reasonCell.textContent = String(row?.reason || '-').trim() || '-';
    tr.appendChild(reasonCell);
    tableBody.appendChild(tr);
  });
}

function normalizeScheduleSupportHqPreviewMode(value = '') {
  return String(value || '').trim().toLowerCase() === 'all' ? 'all' : 'actionable';
}

function isScheduleSupportHqAggregatedRowActionable(row = {}) {
  const displayStatus = String(row?.display_status || row?.target_status || '').trim().toLowerCase();
  if (displayStatus === 'upload_blocked') return true;
  if (displayStatus === 'approval_pending') return true;
  return Number(row?.blocking_issue_count || 0) > 0;
}

function filterScheduleSupportHqAggregatedPreviewRows(rows = [], previewMode = 'actionable') {
  const normalizedMode = normalizeScheduleSupportHqPreviewMode(previewMode);
  if (normalizedMode === 'all') return Array.isArray(rows) ? rows : [];
  return (Array.isArray(rows) ? rows : []).filter((row) => isScheduleSupportHqAggregatedRowActionable(row));
}

function buildScheduleSupportHqAggregatedPreviewRows(inspectResult) {
  const reviewRows = Array.isArray(inspectResult?.review_rows) ? inspectResult.review_rows : [];
  const scopeSummaries = Array.isArray(inspectResult?.scope_summaries) ? inspectResult.scope_summaries : [];
  const scopeSummaryMap = new Map();
  scopeSummaries.forEach((summary) => {
    const key = buildScheduleSupportHqScopeAggregateKey(summary);
    if (key) scopeSummaryMap.set(key, summary);
  });
  const grouped = new Map();
  reviewRows.forEach((row) => {
    const key = buildScheduleSupportHqScopeAggregateKey(row);
    if (!key) return;
    if (!grouped.has(key)) {
      grouped.set(key, {
        scope_key: key,
        sheet_name: String(row?.sheet_name || '').trim() || '-',
        site_name: String(row?.site_name || '').trim() || null,
        site_code: String(row?.site_code || '').trim() || null,
        work_date: row?.work_date || null,
        shift_kind: String(row?.shift_kind || '').trim() || null,
        request_count: Number(row?.request_count || 0),
        entered_count: Number(row?.valid_filled_count || 0),
        worker_names_list: [],
        target_status: String(row?.target_status || '').trim() || null,
        display_status: String(row?.status || '').trim() || null,
        reason: String(row?.reason || '').trim() || '',
        review_status: String(row?.status || '').trim() || '',
        blocking_issue_count: 0,
        warning_issue_count: 0,
      });
    }
    const aggregate = grouped.get(key);
    if (!aggregate) return;
    if (String(row?.row_kind || '').trim() === 'scope_summary') {
      aggregate.request_count = Number(row?.request_count || 0);
      aggregate.entered_count = Number(row?.valid_filled_count || 0);
      aggregate.target_status = String(row?.target_status || '').trim() || aggregate.target_status || null;
      aggregate.display_status = String(row?.status || '').trim() || aggregate.display_status || null;
      aggregate.reason = String(row?.reason || '').trim() || aggregate.reason || '';
      aggregate.review_status = String(row?.status || '').trim() || aggregate.review_status || '';
      return;
    }
    const normalizedStatus = String(row?.status || '').trim().toLowerCase();
    if (normalizedStatus === 'blocking') return;
    const workerName = String(row?.parsed_display_value || row?.raw_cell_text || '').trim();
    if (workerName) aggregate.worker_names_list.push(workerName);
  });
  return Array.from(grouped.values())
    .map((aggregate) => {
      const summary = scopeSummaryMap.get(aggregate.scope_key);
      const shiftKind = String(aggregate.shift_kind || '').trim().toLowerCase();
      const nightReason = String(summary?.purpose_text || '').trim();
      const dayReason = String(aggregate.reason || '').trim();
      const blockingIssueCount = Number(summary?.blocking_issue_count ?? aggregate.blocking_issue_count ?? 0);
      const warningIssueCount = Number(summary?.warning_issue_count ?? aggregate.warning_issue_count ?? 0);
      const targetStatus = String(summary?.target_status || aggregate.target_status || '').trim() || null;
      const reviewStatus = String(aggregate.review_status || '').trim().toLowerCase();
      const displayStatus = blockingIssueCount > 0 || reviewStatus === 'blocking' || reviewStatus === 'over_capacity'
        ? 'upload_blocked'
        : targetStatus;
      return {
        ...aggregate,
        request_count: Number(summary?.request_count ?? aggregate.request_count ?? 0),
        entered_count: Number(summary?.valid_filled_count ?? aggregate.entered_count ?? 0),
        target_status: targetStatus,
        display_status: displayStatus,
        worker_names: aggregate.worker_names_list.join(', '),
        reason: shiftKind === 'night' ? nightReason : dayReason,
        blocking_issue_count: blockingIssueCount,
        warning_issue_count: warningIssueCount,
      };
    })
    .sort((left, right) => {
      const leftDate = String(left?.work_date || '');
      const rightDate = String(right?.work_date || '');
      if (leftDate !== rightDate) return leftDate.localeCompare(rightDate);
      const leftShift = String(left?.shift_kind || '').trim().toLowerCase() === 'night' ? 1 : 0;
      const rightShift = String(right?.shift_kind || '').trim().toLowerCase() === 'night' ? 1 : 0;
      if (leftShift !== rightShift) return leftShift - rightShift;
      const leftSite = `${String(left?.sheet_name || '')}|${String(left?.site_code || '')}|${String(left?.site_name || '')}`;
      const rightSite = `${String(right?.sheet_name || '')}|${String(right?.site_code || '')}|${String(right?.site_name || '')}`;
      return leftSite.localeCompare(rightSite);
    });
}

function buildScheduleSupportHqScopeAggregateKey(row) {
  const sheetName = String(row?.sheet_name || '').trim();
  const siteCode = String(row?.site_code || '').trim().toUpperCase();
  const siteName = String(row?.site_name || '').trim();
  const workDate = String(row?.work_date || '').trim();
  const shiftKind = String(row?.shift_kind || '').trim().toLowerCase();
  if (!sheetName || !workDate || !shiftKind) return '';
  return [sheetName, siteCode || siteName, workDate, shiftKind].join('|');
}

function renderScheduleSupportHqApplyDetails(scopeResults = []) {
  const list = $('#scheduleSupportHqApplyDetails');
  if (!(list instanceof HTMLElement)) return;
  list.innerHTML = '';
  const rows = Array.isArray(scopeResults) ? scopeResults : [];
  if (!rows.length) {
    list.classList.add('hidden');
    return;
  }
  const getHandoffStatusLabel = (status = '') => {
    const value = String(status || '').trim().toLowerCase();
    if (value === 'success') return 'Sentrix 전달 완료';
    if (value === 'partial') return '부분 전달';
    if (value === 'failed') return 'Sentrix 전달 실패';
    return '검토 필요';
  };
  const getHandoffStatusClass = (status = '') => {
    const value = String(status || '').trim().toLowerCase();
    if (value === 'success') return 'status-pill status-pill-success';
    if (value === 'partial') return 'status-pill status-pill-warn';
    if (value === 'failed') return 'status-pill status-pill-error';
    return 'status-pill status-pill-neutral';
  };
  rows.forEach((scope) => {
    const li = document.createElement('li');
    li.classList.add('content-fade-in');
    const container = document.createElement('div');
    container.className = 'list-row';
    const main = document.createElement('div');
    main.className = 'list-row-main';
    const title = document.createElement('div');
    title.className = 'list-row-title';
    title.textContent = [
      formatDateLabel(scope?.work_date || '', '-'),
      getSupportStatusShiftLabel(scope?.shift_kind || ''),
      getSupportStatusSiteLabel(scope?.site_code || '', scope?.site_name || ''),
    ].filter(Boolean).join(' · ');
    const sub = document.createElement('div');
    sub.className = 'list-row-sub';
    const targetStatus = String(scope?.target_status || '').trim();
    const previousStatus = String(scope?.previous_status || '').trim();
    const handoffStatus = String(scope?.handoff_status || '').trim();
    const sentrixTicketId = String(scope?.sentrix_ticket_id || '').trim();
    const handoffMessage = String(scope?.handoff_message || '').trim();
    sub.textContent = [
      `${Number(scope?.valid_filled_count || 0)} / ${Number(scope?.request_count || 0)}명`,
      previousStatus ? `이전 ${getSupportStatusRequestStatusLabel(previousStatus)}` : '',
      targetStatus ? `적용 ${getSupportStatusRequestStatusLabel(targetStatus)}` : '',
      handoffStatus ? getHandoffStatusLabel(handoffStatus) : '',
      sentrixTicketId ? `ticket ${sentrixTicketId}` : '',
      handoffMessage || '',
    ].filter(Boolean).join(' · ');
    main.appendChild(title);
    main.appendChild(sub);
    const pill = document.createElement('span');
    pill.className = getHandoffStatusClass(handoffStatus);
    pill.textContent = getHandoffStatusLabel(handoffStatus);
    container.appendChild(main);
    container.appendChild(pill);
    li.appendChild(container);
    list.appendChild(li);
  });
  list.classList.remove('hidden');
}

function renderScheduleSupportHqWorkspace() {
  const workspace = ensureScheduleSupportHqWorkspaceState();
  const contractHint = $('#scheduleSupportHqContractHint');
  const uploadMetaGrid = $('#scheduleSupportHqUploadMeta');
  const fileInput = $('#scheduleSupportHqUploadFile');
  const inspectBtn = $('#scheduleSupportHqInspectBtn');
  const reinspectBtn = $('#scheduleSupportHqReinspectBtn');
  const applyBtn = $('#scheduleSupportHqApplyBtn');
  const batchInfoEl = $('#scheduleSupportHqBatchInfo');
  const batchIssuesEl = $('#scheduleSupportHqBatchIssues');
  const applyResultEl = $('#scheduleSupportHqApplyResult');
  const reviewTitle = $('#scheduleSupportHqReviewStateTitle');
  const reviewText = $('#scheduleSupportHqReviewStateText');
  const openSentrixBtn = $('#scheduleSupportOpenSentrixBtn');
  const copyArtifactBtn = $('#scheduleSupportCopyArtifactBtn');
  if (
    !(uploadMetaGrid instanceof HTMLElement)
    || !(batchInfoEl instanceof HTMLElement)
    || !(applyResultEl instanceof HTMLElement)
    || !(reviewTitle instanceof HTMLElement)
    || !(reviewText instanceof HTMLElement)
  ) {
    return;
  }

  const allowed = canUseScheduleSupportRoundtripHq();
  const context = buildScheduleSupportHqContext();
  workspace.month = context.month;
  const selectedSite = getScheduleSupportHqSelectedSiteContext();
  const status = state.schedule.supportStatus && typeof state.schedule.supportStatus === 'object'
    ? state.schedule.supportStatus
    : null;
  const artifactContext = buildScheduleSupportArtifactContext(status, context.siteCode);
  const inspectResult = workspace.inspectResult && typeof workspace.inspectResult === 'object'
    ? workspace.inspectResult
    : null;
  const applyResult = workspace.applyResult && typeof workspace.applyResult === 'object'
    ? workspace.applyResult
    : null;
  const uploadMeta = inspectResult?.upload_meta && typeof inspectResult.upload_meta === 'object'
    ? inspectResult.upload_meta
    : null;
  const hasFile = fileInput instanceof HTMLInputElement && Boolean(fileInput.files?.length);
  const readyForUpload = allowed
    && Boolean(context.siteCode)
    && Boolean(artifactContext.artifact_id)
    && (
      context.siteCode === 'ALL'
        ? Number(status?.ready_site_count || 0) > 0
        : String(status?.source_state || '').trim() !== 'source_missing'
    );

  if (fileInput instanceof HTMLInputElement) {
    fileInput.disabled = !readyForUpload || workspace.inspectLoading || workspace.applyLoading;
  }
  if (inspectBtn instanceof HTMLButtonElement) {
    inspectBtn.disabled = !readyForUpload || !hasFile || workspace.inspectLoading || workspace.applyLoading;
    inspectBtn.textContent = workspace.inspectLoading ? '검토 중...' : '검토 시작';
  }
  if (reinspectBtn instanceof HTMLButtonElement) {
    reinspectBtn.disabled = !readyForUpload || !hasFile || workspace.inspectLoading || workspace.applyLoading;
  }
  if (applyBtn instanceof HTMLButtonElement) {
    applyBtn.disabled = !Boolean(inspectResult?.can_apply) || !inspectResult?.batch_id || workspace.inspectLoading || workspace.applyLoading || workspace.stale;
    applyBtn.textContent = workspace.applyLoading ? '적용 중...' : 'ARLS에서 적용';
  }
  if (openSentrixBtn instanceof HTMLButtonElement) {
    openSentrixBtn.disabled = !allowed || !artifactContext.artifact_id;
    openSentrixBtn.textContent = 'Sentrix 상태 보기';
  }
  if (copyArtifactBtn instanceof HTMLButtonElement) {
    copyArtifactBtn.disabled = !allowed || !artifactContext.artifact_id;
  }

  if (contractHint) {
    if (!allowed) {
      contractHint.textContent = 'HQ/Admin 권한이 있어야 HQ 작성본 workbook 검토와 적용을 시작할 수 있습니다.';
    } else if (!context.siteCode) {
      contractHint.textContent = '업로드 지점과 대상 월을 먼저 고정하면 HQ 작성본 workbook의 검토/적용을 여기서 시작할 수 있습니다.';
    } else if (workspace.loading) {
      contractHint.textContent = 'HQ 작성본 workbook 계약 정보를 불러오는 중입니다.';
    } else if (workspace.error) {
      contractHint.textContent = String(workspace.error || '').trim();
    } else if (!artifactContext.artifact_id) {
      contractHint.textContent = '현재 source artifact가 아직 없어 HQ 작성본 업로드를 시작할 수 없습니다. STEP 3에서 source export 상태를 먼저 확인하세요.';
    } else if (context.siteCode === 'ALL') {
      contractHint.textContent = '전체 지점 multi-sheet HQ 작성본을 업로드하면 ARLS가 검토/적용을 시작하고, 내부 state 엔진은 Sentrix가 이어받습니다.';
    } else {
      contractHint.textContent = `${getSupportStatusSiteLabel(context.siteCode, selectedSite?.siteName || '')} 기준 HQ 작성본을 ARLS에서 검토한 뒤 적용하면 Sentrix로 normalized snapshot을 handoff합니다. 업로드 workbook의 근무자 입력은 그대로 읽고, 요청 수는 기존 Sentrix ticket 기준으로 계산합니다.`;
    }
  }

  renderScheduleSupportArtifactMeta(artifactContext);
  const uploadMetaItems = [
    { label: '파일명', value: String(uploadMeta?.file_name || workspace.uploadFileName || '선택 전').trim() || '선택 전' },
    { label: '파일 크기', value: workspace.uploadFileSize > 0 ? `${Number(workspace.uploadFileSize).toLocaleString('ko-KR')} bytes` : '선택 전' },
    { label: '파일 수정시각', value: String(workspace.uploadFileLastModified || '선택 전').trim() || '선택 전' },
    { label: '대상월', value: formatScheduleMonthTitle(String(uploadMeta?.month || context.month || '')) },
    { label: '업로드 범위', value: context.siteCode === 'ALL' ? '전체 지점 workbook' : getSupportStatusSiteLabel(context.siteCode || '', selectedSite?.siteName || '') },
    { label: 'workbook family', value: String(uploadMeta?.workbook_family || workspace.contract?.workbook_family || SUPPORT_STATUS_HQ_WORKBOOK_FAMILY).trim() || SUPPORT_STATUS_HQ_WORKBOOK_FAMILY },
    { label: 'revision', value: String(uploadMeta?.revision || artifactContext.revision || workspace.contract?.template_version || SUPPORT_STATUS_HQ_TEMPLATE_VERSION).trim() || SUPPORT_STATUS_HQ_TEMPLATE_VERSION },
    { label: 'latest 상태', value: uploadMeta ? getSupportStatusHqLatestStatusLabel(uploadMeta.latest_status || '') : (artifactContext.artifact_id ? 'latest source 기준' : 'source 대기') },
    { label: 'artifact_id', value: String(artifactContext.artifact_id || '-').trim() || '-' },
  ];
  renderSupportStatusHqMetaGrid(uploadMetaGrid, uploadMetaItems);

  if (batchInfoEl) {
    if (!allowed) {
      batchInfoEl.textContent = '권한이 없어서 HQ 작성본 upload/apply 워크플로우를 시작할 수 없습니다.';
    } else if (workspace.stale) {
      batchInfoEl.textContent = `${formatScheduleSupportHqContextFields(workspace.staleFields)} 변경으로 이전 검토 결과가 stale 상태가 되었습니다. 다시 검토를 실행하세요.`;
    } else if (!context.siteCode) {
      batchInfoEl.textContent = '업로드 지점과 대상 월을 먼저 선택하세요.';
    } else if (!artifactContext.artifact_id) {
      batchInfoEl.textContent = '현재 source revision 기준 artifact lineage를 아직 만들지 못했습니다.';
    } else if (inspectResult?.batch_id) {
      batchInfoEl.textContent = [
        `artifact_id ${artifactContext.artifact_id}`,
        `batch ${String(inspectResult.batch_id).slice(0, 12)}`,
        context.month,
        `worker ${Number(inspectResult.summary?.worker_rows || 0)}건 parsed`,
        '요청 수는 기존 Sentrix ticket 기준',
      ].join(' · ');
    } else {
      batchInfoEl.textContent = `artifact_id ${artifactContext.artifact_id} 기준으로 HQ 작성본 workbook을 검토합니다. worker 입력은 업로드 파일에서 읽고, 요청 수는 기존 Sentrix ticket 기준으로 계산합니다.`;
    }
  }

  if (batchIssuesEl instanceof HTMLElement) {
    const blockedReasons = applyResult?.blocked && Array.isArray(applyResult.blocked_reasons)
      ? applyResult.blocked_reasons.filter(Boolean)
      : [];
    batchIssuesEl.innerHTML = '';
    if (!blockedReasons.length) {
      batchIssuesEl.classList.add('hidden');
    } else {
      batchIssuesEl.classList.remove('hidden');
      blockedReasons.forEach((reason) => {
        const li = document.createElement('li');
        li.textContent = String(reason || '').trim();
        batchIssuesEl.appendChild(li);
      });
    }
  }

  renderScheduleSupportHqReviewSummary();
  renderScheduleSupportHqIssueGroups();
  renderScheduleSupportHqReviewTable();
  renderScheduleSupportHqApplyDetails(applyResult?.scope_results || []);

  if (reviewTitle) {
    if (workspace.applyLoading) reviewTitle.textContent = '업로드 진행중...';
    else if (applyResult?.applied) reviewTitle.textContent = '업로드 완료';
    else if (applyResult?.partial_success) reviewTitle.textContent = '부분 적용';
    else if (applyResult?.blocked) reviewTitle.textContent = '적용 차단';
    else if (applyResult?.handoff_status === 'failed') reviewTitle.textContent = '전달 실패';
    else if (workspace.stale) reviewTitle.textContent = '재검토 필요';
    else if (inspectResult) reviewTitle.textContent = inspectResult.can_apply ? '적용 가능' : '검토 보완 필요';
    else reviewTitle.textContent = '적용 전 검토 영역';
  }
  if (reviewText) {
    if (workspace.applyLoading) {
      reviewText.textContent = 'normalized roster snapshot을 Sentrix로 전달하고 있습니다. 완료될 때까지 잠시 기다려 주세요.';
    } else if (applyResult?.applied) {
      reviewText.textContent = `scope ${Number(applyResult.applied_scope_count || 0)}건 handoff 완료 · ticket ${Number(applyResult.tickets_updated || 0)}건 갱신 · 자동승인 ${Number(applyResult.tickets_auto_approved || 0)}건 · 승인대기 ${Number(applyResult.tickets_pending || 0)}건`;
    } else if (applyResult?.partial_success) {
      reviewText.textContent = [
        `scope ${Number(applyResult.handoff_success_count || 0)}건 전달`,
        `실패 ${Number(applyResult.handoff_failed_count || 0)}건`,
        applyResult?.handoff_message ? String(applyResult.handoff_message).trim() : '',
        applyResult?.retry_token ? `retry ${String(applyResult.retry_token).slice(0, 12)}` : '',
      ].filter(Boolean).join(' · ');
    } else if (applyResult?.blocked && Array.isArray(applyResult.blocked_reasons) && applyResult.blocked_reasons.length) {
      reviewText.textContent = String(applyResult.blocked_reasons[0] || '').trim() || '차단 사유를 해결한 뒤 다시 검토하세요.';
    } else if (applyResult?.handoff_status === 'failed') {
      reviewText.textContent = [
        String(applyResult.handoff_message || 'Sentrix handoff에 실패했습니다.').trim(),
        applyResult?.retry_token ? `retry ${String(applyResult.retry_token).slice(0, 12)}` : '',
      ].filter(Boolean).join(' · ');
    } else if (workspace.applyError) {
      reviewText.textContent = String(workspace.applyError || '').trim();
    } else if (workspace.inspectError) {
      reviewText.textContent = String(workspace.inspectError || '').trim();
    } else if (workspace.stale) {
      reviewText.textContent = `${formatScheduleSupportHqContextFields(workspace.staleFields)} 변경으로 다시 검토해야 합니다.`;
    } else if (inspectResult) {
      reviewText.textContent = String(inspectResult.next_step_message || '검토 결과를 확인한 뒤 적용 여부를 결정하세요.').trim();
    } else {
      reviewText.textContent = 'HQ 작성본 workbook을 검토한 뒤 적용하면 ARLS가 Sentrix state engine으로 normalized snapshot을 handoff합니다.';
    }
  }

  if (applyResultEl) {
    if (workspace.applyLoading) {
      applyResultEl.textContent = '업로드 진행중... ARLS가 Sentrix state engine handoff를 실행하고 있습니다.';
    } else if (applyResult?.applied) {
      const partialBits = [];
      if (Number(applyResult.notifications_created || 0) > 0) partialBits.push(`알림 ${Number(applyResult.notifications_created || 0)}건`);
      if (Number(applyResult.bridge_actions_created || 0) > 0) partialBits.push(`ARLS bridge ${Number(applyResult.bridge_actions_created || 0)}건`);
      if (Number(applyResult.push_failed || 0) > 0 || Number(applyResult.bridge_failed || 0) > 0) {
        partialBits.push(`후처리 실패 push ${Number(applyResult.push_failed || 0)}건 / bridge ${Number(applyResult.bridge_failed || 0)}건`);
      }
      applyResultEl.textContent = `ARLS apply가 완료되었습니다. Sentrix state engine handoff 기준 batch ${String(applyResult.batch_id || '').slice(0, 12)} · ${partialBits.join(' · ') || '후처리 완료'}`;
    } else if (applyResult?.partial_success) {
      applyResultEl.textContent = [
        'ARLS 검토 결과는 유지됐지만 Sentrix handoff가 일부만 완료되었습니다.',
        `성공 ${Number(applyResult.handoff_success_count || 0)}건`,
        `실패 ${Number(applyResult.handoff_failed_count || 0)}건`,
        applyResult?.retry_token ? `retry ${String(applyResult.retry_token).slice(0, 12)}` : '',
      ].filter(Boolean).join(' · ');
    } else if (applyResult?.handoff_status === 'failed') {
      applyResultEl.textContent = [
        'ARLS local apply는 완료됐지만 Sentrix handoff에 실패했습니다.',
        String(applyResult.handoff_message || '').trim(),
        applyResult?.retry_token ? `retry ${String(applyResult.retry_token).slice(0, 12)}` : '',
      ].filter(Boolean).join(' · ');
    } else if (workspace.applyError) {
      applyResultEl.textContent = String(workspace.applyError || '').trim();
    } else if (workspace.stale) {
      applyResultEl.textContent = '현재 검토 결과는 더 이상 apply할 수 없습니다. 다시 검토한 뒤 적용하세요.';
    } else {
      applyResultEl.textContent = 'ARLS apply는 normalized roster snapshot을 Sentrix에 handoff하고, ticket 상태/알림/bridge 판단은 Sentrix가 이어받습니다.';
    }
  }
}

async function loadScheduleSupportHqWorkspaceContract({ force = false } = {}) {
  const workspace = ensureScheduleSupportHqWorkspaceState();
  if (!canUseScheduleSupportRoundtripHq()) {
    workspace.loading = false;
    workspace.error = '';
    workspace.contract = null;
    renderScheduleSupportHqWorkspace();
    return null;
  }
  workspace.loading = true;
  workspace.error = '';
  workspace.month = buildScheduleSupportHqContext().month;
  renderScheduleSupportHqWorkspace();
  const params = new URLSearchParams();
  params.set('month', workspace.month);
  params.set('tenant_code', getScheduleTenantValue());
  try {
    const payload = await apiRequest(`/schedules/support-roundtrip/hq-workspace?${params.toString()}`, { force });
    workspace.contract = payload && typeof payload === 'object' ? payload : null;
    workspace.loading = false;
    renderScheduleSupportHqWorkspace();
    return workspace.contract;
  } catch (error) {
    workspace.loading = false;
    workspace.error = normalizeActionError(error, 'HQ 작성본 workbook 계약 정보를 불러오지 못했습니다.');
    renderScheduleSupportHqWorkspace();
    throw error;
  }
}

async function onScheduleSupportHqInspect() {
  const workspace = ensureScheduleSupportHqWorkspaceState();
  const context = buildScheduleSupportHqContext();
  if (!canUseScheduleSupportRoundtripHq()) {
    showToast('HQ 작성본 upload 권한이 없습니다.', 'error');
    return;
  }
  if (!context.siteCode) {
    showToast('업로드 지점을 먼저 선택해 주세요.', 'error');
    return;
  }
  const status = state.schedule.supportStatus && typeof state.schedule.supportStatus === 'object'
    ? state.schedule.supportStatus
    : await loadScheduleSupportRoundtripStatus();
  const artifactContext = buildScheduleSupportArtifactContext(status, context.siteCode);
  if (!artifactContext.artifact_id) {
    showToast('현재 month/site 기준 source artifact가 아직 없습니다.', 'error');
    return;
  }
  const fileInput = $('#scheduleSupportHqUploadFile');
  if (!(fileInput instanceof HTMLInputElement) || !fileInput.files?.length) {
    showToast('검토할 HQ 작성본 workbook 파일을 먼저 선택해 주세요.', 'error');
    return;
  }
  const file = fileInput.files[0];
  workspace.inspectLoading = true;
  workspace.inspectError = '';
  workspace.applyError = '';
  workspace.applyResult = null;
  workspace.inspectResult = null;
  workspace.stale = false;
  workspace.staleFields = [];
  workspace.uploadFileName = String(file?.name || '').trim();
  workspace.uploadFileSize = Number(file?.size || 0);
  workspace.uploadFileLastModified = file?.lastModified
    ? new Date(file.lastModified).toLocaleString('ko-KR')
    : '';
  renderScheduleUploadWorkspace();
  const body = new FormData();
  body.append('file', file);
  body.append('month', context.month);
  body.append('tenant_code', getScheduleTenantValue());
  try {
    const result = await apiRequest('/schedules/support-roundtrip/hq-roster-upload/inspect', {
      method: 'POST',
      body,
    });
    if (fileInput instanceof HTMLInputElement) {
      // Allow re-selecting the same path/name after the workbook is edited locally.
      fileInput.value = '';
    }
    workspace.inspectResult = result && typeof result === 'object' ? result : null;
    workspace.inspectLoading = false;
    workspace.previewMode = 'actionable';
    setScheduleHqWizardStep(SCHEDULE_HQ_WIZARD_STEP_PREVIEW, { scroll: false });
    renderScheduleUploadWorkspace();
    const issueCount = Number(result?.issue_count || 0);
    if (issueCount > 0) {
      showToast(`HQ 작성본 검토 완료: ${issueCount}건 확인 필요`, 'error', 2800);
    } else {
      showToast('HQ 작성본 검토 완료', 'success', 2200);
    }
  } catch (error) {
    workspace.inspectLoading = false;
    workspace.inspectError = normalizeActionError(error, 'HQ 작성본 workbook 검토에 실패했습니다.');
    workspace.inspectResult = null;
    setScheduleHqWizardStep(SCHEDULE_HQ_WIZARD_STEP_UPLOAD, { scroll: false });
    renderScheduleUploadWorkspace();
    throw error;
  }
}

async function onScheduleSupportHqApply() {
  const workspace = ensureScheduleSupportHqWorkspaceState();
  const batchId = String(workspace.inspectResult?.batch_id || '').trim();
  if (!canUseScheduleSupportRoundtripHq()) {
    showToast('HQ 작성본 적용 권한이 없습니다.', 'error');
    return;
  }
  if (!batchId) {
    showToast('먼저 HQ 작성본 workbook 검토를 완료해 주세요.', 'error');
    return;
  }
  if (workspace.stale) {
    showToast('지점/월/파일 변경으로 검토 결과가 stale 상태입니다. 다시 검토해 주세요.', 'error');
    return;
  }
  if (!workspace.inspectResult?.can_apply) {
    showToast('차단 이슈를 해결한 뒤 다시 검토해 주세요.', 'error');
    return;
  }
  workspace.applyLoading = true;
  workspace.applyError = '';
  workspace.applyResult = null;
  setScheduleHqWizardStep(SCHEDULE_HQ_WIZARD_STEP_COMPLETE, { scroll: false });
  renderScheduleUploadWorkspace();
  const params = new URLSearchParams();
  params.set('tenant_code', getScheduleTenantValue());
  try {
    const result = await apiRequest(`/schedules/support-roundtrip/hq-roster-upload/${batchId}/apply?${params.toString()}`, {
      method: 'POST',
    });
    workspace.applyLoading = false;
    workspace.applyResult = result && typeof result === 'object' ? result : null;
    await Promise.allSettled([
      loadScheduleSupportRoundtripStatus(),
      loadScheduleSupportHqWorkspaceContract({ force: true }),
    ]);
    renderScheduleUploadWorkspace();
    if (result?.applied) {
      showToast('HQ 지원근무자 반영 apply를 완료했습니다.', 'success', 2600);
    } else if (result?.partial_success) {
      showToast(
        [
          'Sentrix handoff가 일부만 완료되었습니다.',
          `성공 ${Number(result.handoff_success_count || 0)}건`,
          `실패 ${Number(result.handoff_failed_count || 0)}건`,
        ].join(' · '),
        'error',
        3600,
      );
    } else if (result?.blocked && Array.isArray(result.blocked_reasons) && result.blocked_reasons.length) {
      showToast(String(result.blocked_reasons[0] || '').trim() || '차단 이슈가 남아 있습니다.', 'error', 3200);
    } else if (String(result?.handoff_status || '').trim().toLowerCase() === 'failed') {
      showToast(String(result?.handoff_message || 'Sentrix handoff에 실패했습니다.').trim(), 'error', 3600);
    } else {
      showToast('HQ 지원근무자 반영 apply 결과를 확인해 주세요.', 'info', 2400);
    }
  } catch (error) {
    workspace.applyLoading = false;
    workspace.applyError = normalizeActionError(error, 'HQ 작성본 apply에 실패했습니다.');
    workspace.applyResult = null;
    setScheduleHqWizardStep(SCHEDULE_HQ_WIZARD_STEP_COMPLETE, { scroll: false });
    renderScheduleUploadWorkspace();
    throw error;
  }
}

function getScheduleSupportRoundtripStateLabel(sourceState = '') {
  const value = String(sourceState || '').trim().toLowerCase();
  if (value === 'hq_merge_available') return 'Sentrix 전달됨';
  if (value === 'hq_merge_stale') return '재전달 필요';
  if (value === 'conflict_manual_review_required') return 'Sentrix 검토 필요';
  if (value === 'waiting_for_hq_merge') return 'Sentrix 제출 대기';
  if (value === 'source_missing') return '원본 대기';
  return value || '상태 미확인';
}

function getScheduleSupportRoundtripStateClass(sourceState = '', status = null) {
  const value = String(sourceState || '').trim().toLowerCase();
  if (value === 'hq_merge_available' && status?.final_download_enabled) return 'status-pill status-pill-success';
  if (value === 'conflict_manual_review_required') return 'status-pill status-pill-error';
  if (value === 'hq_merge_stale') return 'status-pill status-pill-warn';
  if (value === 'waiting_for_hq_merge') return 'status-pill status-pill-warn';
  return 'status-pill status-pill-neutral';
}

function resetScheduleSupportRoundtripPreview() {
  state.schedule.supportPreviewBatchId = '';
  state.schedule.supportPreview = null;
}

function renderScheduleSupportPreviewTable(previewRows = []) {
  const wrap = $('#scheduleSupportPreviewTableWrap');
  const body = $('#scheduleSupportPreviewTableBody');
  if (!wrap || !body) return;

  body.innerHTML = '';
  const rows = Array.isArray(previewRows) ? previewRows : [];
  if (!rows.length) {
    wrap.classList.add('hidden');
    return;
  }

  rows.forEach((row) => {
    const tr = document.createElement('tr');
    const diffCategory = String(row?.diff_category || '').trim().toLowerCase();
    const isConflict = Boolean(row?.is_blocking);
    const isProtected = Boolean(row?.is_protected) || diffCategory === 'ignored_protected';
    if (isConflict) tr.classList.add('schedule-preview-row-invalid');
    else if (isProtected) tr.classList.add('schedule-preview-row-protected');

    const periodLabel = (() => {
      const value = String(row?.support_period || '').trim().toLowerCase();
      if (value === 'night') return '야간';
      return '주간';
    })();
    const resolvedWorker = [row?.resolved_worker_name || '', row?.employee_name || '']
      .map((item) => String(item || '').trim())
      .filter(Boolean)
      .join(' / ') || '-';
    const actionLabel = (() => {
      const action = String(row?.apply_action || '').trim();
      if (action === 'upsert_support_assignment') return '지원 배정 반영';
      if (action === 'upsert_need_count') return '필요인원 반영';
      if (diffCategory === 'unchanged') return '변경 없음';
      if (diffCategory === 'ignored_blank') return '공란 무시';
      if (diffCategory === 'ignored_protected') return '보호로 무시';
      if (isConflict) return '충돌';
      return action || '-';
    })();
    const reasonLabel = String(
      row?.validation_error
      || row?.protected_reason
      || row?.validation_code
      || '-',
    ).trim();

    const cells = [
      row?.row_no ?? '',
      row?.schedule_date ?? '',
      periodLabel,
      row?.slot_index ?? '',
      String(row?.current_value || '-').trim() || '-',
      String(row?.workbook_value || '-').trim() || '-',
      resolvedWorker,
      actionLabel,
      reasonLabel,
    ];

    cells.forEach((cellValue, idx) => {
      const td = document.createElement('td');
      td.textContent = String(cellValue ?? '');
      if (idx === 7) {
        td.className = isConflict ? 'schedule-preview-cell-error' : 'schedule-preview-cell-ok';
      }
      tr.appendChild(td);
    });
    body.appendChild(tr);
  });

  wrap.classList.remove('hidden');
}

function renderScheduleSupportApplyDetails(appliedRows = [], skippedRows = []) {
  const list = $('#scheduleSupportApplyDetails');
  if (!list) return;
  list.innerHTML = '';
  const rows = [...(Array.isArray(appliedRows) ? appliedRows : []), ...(Array.isArray(skippedRows) ? skippedRows : [])];
  if (!rows.length) {
    list.classList.add('hidden');
    return;
  }

  rows.forEach((row) => {
    const li = document.createElement('li');
    li.classList.add('content-fade-in');
    const container = document.createElement('div');
    container.className = 'list-row';
    const main = document.createElement('div');
    main.className = 'list-row-main';
    const title = document.createElement('div');
    title.className = 'list-row-title';
    title.textContent = `${row?.schedule_date || '-'} · ${String(row?.support_period || 'day') === 'night' ? '야간' : '주간'} · 슬롯 ${row?.slot_index || 0}`;
    const sub = document.createElement('div');
    sub.className = 'list-row-sub';
    sub.textContent = [row?.worker_name || row?.employee_name || '-', row?.site_code || '-', row?.reason || '-']
      .map((item) => String(item || '').trim())
      .filter(Boolean)
      .join(' · ');
    main.appendChild(title);
    main.appendChild(sub);
    const pill = document.createElement('span');
    const statusText = String(row?.status || '').trim() || 'unknown';
    pill.className = scheduleApplyStatusClass(statusText);
    pill.textContent = getUiStatusLabel(statusText);
    container.appendChild(main);
    container.appendChild(pill);
    li.appendChild(container);
    list.appendChild(li);
  });
  list.classList.remove('hidden');
}

function setScheduleSupportRoundtripUI({
  batchInfo = '',
  issues = [],
  applyResult = '',
  canApply = false,
  previewRows = null,
  clearPreviewRows = false,
  applyRows = null,
  skippedRows = null,
  clearApplyDetails = false,
} = {}) {
  const infoEl = $('#scheduleSupportBatchInfo');
  const issuesEl = $('#scheduleSupportBatchIssues');
  const resultEl = $('#scheduleSupportApplyResult');
  const applyBtn = $('#scheduleSupportApplyBtn');

  if (infoEl) infoEl.textContent = batchInfo;
  if (resultEl) resultEl.textContent = applyResult;
  if (applyBtn) applyBtn.disabled = !canApply;

  if (issuesEl) {
    issuesEl.innerHTML = '';
    if (!issues.length) {
      issuesEl.classList.add('hidden');
    } else {
      issuesEl.classList.remove('hidden');
      issues.forEach((item) => {
        const li = document.createElement('li');
        li.textContent = String(item || '').trim();
        issuesEl.appendChild(li);
      });
    }
  }

  if (clearPreviewRows) {
    renderScheduleSupportPreviewTable([]);
  } else if (previewRows !== null) {
    renderScheduleSupportPreviewTable(previewRows);
  }

  if (clearApplyDetails) {
    renderScheduleSupportApplyDetails([], []);
  } else if (applyRows !== null || skippedRows !== null) {
    renderScheduleSupportApplyDetails(applyRows || [], skippedRows || []);
  }
}

function getScheduleSupportSelectedSiteCode() {
  const importSite = String($('#scheduleImportSite')?.value || '').trim().toUpperCase();
  const reportsSite = String($('#scheduleReportsSite')?.value || '').trim().toUpperCase();
  if (getScheduleActiveTopTab() === SCHEDULE_TAB_UPLOAD) {
    if (importSite) return importSite;
    if (reportsSite) return reportsSite;
  } else {
    if (reportsSite) return reportsSite;
    if (importSite) return importSite;
  }
  const boardSite = String($('#scheduleSiteFilter')?.value || '').trim().toUpperCase();
  if (boardSite && boardSite !== 'ALL') return boardSite;
  return '';
}

function buildScheduleSupportArtifactContext(status = null, siteCode = '') {
  const tenantCode = String(getTenantCodeForScopedAdminApi() || getScheduleTenantValue() || '').trim();
  const resolvedSiteCode = String(siteCode || status?.site_code || getScheduleSupportSelectedSiteCode() || '').trim().toUpperCase();
  const month = normalizeMonthKey(String(status?.month || getScheduleMonthValue() || '').trim());
  const revision = String(status?.artifact_revision || status?.source_revision || '').trim();
  const artifactId = String(status?.artifact_id || '').trim() || (
    tenantCode && resolvedSiteCode && month && revision
      ? `sentrix-hq:${tenantCode}:${month}:${resolvedSiteCode}:${revision}`
      : ''
  );
  return {
    artifact_id: artifactId,
    site_code: resolvedSiteCode,
    month,
    revision,
    generated_at: String(status?.artifact_generated_at || status?.source_uploaded_at || '').trim(),
  };
}

function renderScheduleSupportArtifactMeta(context = null) {
  const artifact = context && typeof context === 'object' ? context : {};
  setTextContentIfPresent('#scheduleSupportArtifactId', String(artifact.artifact_id || '').trim() || '-');
  setTextContentIfPresent('#scheduleSupportArtifactSite', String(artifact.site_code || '').trim() || '-');
  setTextContentIfPresent('#scheduleSupportArtifactMonth', String(artifact.month || '').trim() || '-');
  setTextContentIfPresent('#scheduleSupportArtifactRevision', String(artifact.revision || '').trim() || '-');
  setTextContentIfPresent(
    '#scheduleSupportArtifactGeneratedAt',
    artifact.generated_at ? formatOpsDateTime(artifact.generated_at) : '-',
    '-',
  );
}

function normalizeScheduleReportsTab(value = '') {
  const tab = String(value || '').trim().toLowerCase();
  return tab === SCHEDULE_REPORTS_TAB_FINANCE ? SCHEDULE_REPORTS_TAB_FINANCE : SCHEDULE_REPORTS_TAB_SUPPORT;
}

function renderScheduleSupportShortcutCard() {
  const panel = $('#scheduleSupportRoundtripPanel');
  if (!(panel instanceof HTMLElement)) return;

  const supportAllowed = canUseScheduleSupportRoundtripSource()
    || canUseScheduleSupportRoundtripHq()
    || canUseScheduleSupportRoundtripFinalDownload();
  panel.classList.toggle('hidden', !supportAllowed);
  if (!supportAllowed) return;

  const selectedSite = String($('#scheduleReportsSite')?.value || '').trim().toUpperCase();
  const status = state.schedule.supportStatus && typeof state.schedule.supportStatus === 'object'
    ? state.schedule.supportStatus
    : null;
  const pill = $('#scheduleReportsSupportShortcutPill');
  const text = $('#scheduleReportsSupportShortcutText');

  if (!selectedSite) {
    if (pill) {
      pill.className = 'status-pill status-pill-neutral';
      pill.textContent = '지점 선택';
    }
    if (text) {
      text.textContent = '보고 지점을 먼저 선택하면 Excel workflow 바로가기를 해당 지점/월 컨텍스트로 열 수 있습니다.';
    }
    return;
  }

  if (!status) {
    if (pill) {
      pill.className = 'status-pill status-pill-neutral';
      pill.textContent = '조회 중';
    }
    if (text) {
      text.textContent = '선택한 지점 기준 source artifact 상태를 확인하는 중입니다. 준비되면 Excel workflow에서 이어갈 수 있습니다.';
    }
    return;
  }

  const overallScope = selectedSite === 'ALL' || Boolean(status?.overall_scope);
  if (overallScope) {
    const readySiteCount = Number(status?.ready_site_count || 0);
    const totalSiteCount = Number(status?.total_site_count || 0);
    if (pill) {
      pill.className = readySiteCount > 0 ? 'status-pill status-pill-success' : 'status-pill status-pill-neutral';
      pill.textContent = readySiteCount > 0 ? '전체 준비' : '전체 대기';
    }
    if (text) {
      text.textContent = `${getScheduleMonthValue()} 기준 전체 ${readySiteCount}/${totalSiteCount || 0}개 지점이 준비되어 있습니다. 세부 추출/제출은 Excel workflow 탭에서 진행하세요.`;
    }
    return;
  }

  const sourceState = String(status?.source_state || '').trim();
  const artifactContext = buildScheduleSupportArtifactContext(status, selectedSite);
  if (pill) {
    pill.className = getScheduleSupportRoundtripStateClass(sourceState, status);
    pill.textContent = getScheduleSupportRoundtripStateLabel(sourceState);
  }
  if (text) {
    text.textContent = [
      `${selectedSite} · ${status?.month || getScheduleMonthValue()}`,
      artifactContext.revision ? `artifact ${artifactContext.revision.slice(0, 12)}` : 'artifact 준비 전',
      '실제 workflow는 Excel로 근무표 간편 제작 탭에서 진행',
    ].filter(Boolean).join(' · ');
  }
}

function renderScheduleReportsTabs() {
  const panel = $('#scheduleReportsPanel');
  if (!(panel instanceof HTMLElement)) return;

  const supportAllowed = canUseScheduleSupportRoundtripSource()
    || canUseScheduleSupportRoundtripHq()
    || canUseScheduleSupportRoundtripFinalDownload();
  const financeAllowed = canViewScheduleFinanceSubmission();
  const tabWrap = $('#scheduleReportsWorkspaceTabs');
  const supportPanel = $('#scheduleSupportRoundtripPanel');
  const financePanel = $('#scheduleFinanceSubmissionPanel');

  let activeTab = normalizeScheduleReportsTab(state.schedule.reportsTab || SCHEDULE_REPORTS_TAB_SUPPORT);
  if (activeTab === SCHEDULE_REPORTS_TAB_SUPPORT && !supportAllowed && financeAllowed) {
    activeTab = SCHEDULE_REPORTS_TAB_FINANCE;
  } else if (activeTab === SCHEDULE_REPORTS_TAB_FINANCE && !financeAllowed && supportAllowed) {
    activeTab = SCHEDULE_REPORTS_TAB_SUPPORT;
  }
  state.schedule.reportsTab = activeTab;

  if (tabWrap instanceof HTMLElement) {
    tabWrap.classList.toggle('hidden', !(supportAllowed && financeAllowed));
    tabWrap.querySelectorAll('[data-action="schedule-reports-tab"]').forEach((button) => {
      const tab = normalizeScheduleReportsTab(button?.dataset?.tab || '');
      const visible = (tab === SCHEDULE_REPORTS_TAB_SUPPORT && supportAllowed)
        || (tab === SCHEDULE_REPORTS_TAB_FINANCE && financeAllowed);
      const active = visible && tab === activeTab;
      button.classList.toggle('hidden', !visible);
      button.classList.toggle('active', active);
      button.setAttribute('aria-pressed', active ? 'true' : 'false');
    });
  }

  renderScheduleSupportShortcutCard();
  renderScheduleFinanceSubmissionStatus();

  if (supportPanel instanceof HTMLElement) {
    supportPanel.classList.toggle('hidden', !supportAllowed || activeTab !== SCHEDULE_REPORTS_TAB_SUPPORT);
  }
  if (financePanel instanceof HTMLElement) {
    financePanel.classList.toggle('hidden', !financeAllowed || activeTab !== SCHEDULE_REPORTS_TAB_FINANCE);
  }
}

function renderScheduleSupportRoundtripStatus() {
  const supportVisible = canUseScheduleSupportRoundtripSource()
    || canUseScheduleSupportRoundtripHq()
    || canUseScheduleSupportRoundtripFinalDownload();
  toggleVisibility('#scheduleExcelWorkflowExportSection', supportVisible);
  toggleVisibility('#scheduleExcelWorkflowHandoffSection', supportVisible);
  renderScheduleUploadWorkflowSections();
  if (!supportVisible) return;

  const status = state.schedule.supportStatus && typeof state.schedule.supportStatus === 'object'
    ? state.schedule.supportStatus
    : null;
  const selectedSite = getScheduleSupportSelectedSiteCode();
  const statePill = $('#scheduleSupportStatePill');
  const statusText = $('#scheduleSupportStatusText');
  const blockedList = $('#scheduleSupportBlockedReasons');
  const sourceRevision = $('#scheduleSupportSourceRevision');
  const sourceMeta = $('#scheduleSupportSourceMeta');
  const mergeState = $('#scheduleSupportMergeState');
  const mergeMeta = $('#scheduleSupportMergeMeta');
  const assignmentCount = $('#scheduleSupportAssignmentCount');
  const conflictMeta = $('#scheduleSupportConflictMeta');
  const finalState = $('#scheduleSupportFinalState');
  const finalMeta = $('#scheduleSupportFinalMeta');
  const hqDownloadBtn = $('#scheduleSupportHqDownloadBtn');
  const openSentrixBtn = $('#scheduleSupportOpenSentrixBtn');
  const copyArtifactBtn = $('#scheduleSupportCopyArtifactBtn');
  const downloadSection = $('#scheduleSupportHqDownloadSection');
  const uploadSection = $('#scheduleSupportUploadSection');
  const overallScope = selectedSite === 'ALL' || Boolean(status?.overall_scope);

  if (downloadSection instanceof HTMLElement) {
    downloadSection.classList.toggle('is-disabled', !canUseScheduleSupportRoundtripHq());
  }
  if (uploadSection instanceof HTMLElement) {
    uploadSection.classList.toggle('is-disabled', !canUseScheduleSupportRoundtripHq());
  }

  if (!selectedSite) {
    if (statePill) {
      statePill.className = 'status-pill status-pill-neutral';
      statePill.textContent = '지점 선택 필요';
    }
    if (statusText) statusText.textContent = '업로드 지점과 대상 월을 먼저 고정하면 source artifact와 Sentrix handoff 상태를 불러옵니다.';
    if (sourceRevision) sourceRevision.textContent = '없음';
    if (sourceMeta) sourceMeta.textContent = '지점 선택 후 확인';
    if (mergeState) mergeState.textContent = '대기';
    if (mergeMeta) mergeMeta.textContent = 'ARLS STEP 4 대기';
    if (assignmentCount) assignmentCount.textContent = '미생성';
    if (conflictMeta) conflictMeta.textContent = 'site/month 선택 후 확인';
    if (finalState) finalState.textContent = 'ARLS STEP 4';
    if (finalMeta) finalMeta.textContent = 'HQ 작성본 업로드와 검토/적용 시작은 ARLS에서 진행됩니다.';
    if (hqDownloadBtn) hqDownloadBtn.disabled = true;
    if (openSentrixBtn) openSentrixBtn.disabled = true;
    if (copyArtifactBtn) copyArtifactBtn.disabled = true;
    renderScheduleSupportArtifactMeta(null);
    if (blockedList) {
      blockedList.innerHTML = '';
      blockedList.classList.add('hidden');
    }
    renderScheduleSupportHqWorkspace();
    return;
  }

  if (!status) {
    if (statePill) {
      statePill.className = 'status-pill status-pill-neutral';
      statePill.textContent = '조회 중';
    }
    if (statusText) statusText.textContent = 'source artifact와 Sentrix handoff 상태를 조회하는 중입니다.';
    if (hqDownloadBtn) hqDownloadBtn.disabled = true;
    if (openSentrixBtn) openSentrixBtn.disabled = true;
    if (copyArtifactBtn) copyArtifactBtn.disabled = true;
    renderScheduleSupportArtifactMeta(null);
    renderScheduleSupportHqWorkspace();
    return;
  }

  if (overallScope) {
    const totalSiteCount = Number(status?.total_site_count || 0);
    const readySiteCount = Number(status?.ready_site_count || 0);
    const blockedReasons = Array.isArray(status?.blocked_reasons) ? status.blocked_reasons.filter(Boolean) : [];
    const artifactContext = buildScheduleSupportArtifactContext(status, 'ALL');
    if (statePill) {
      statePill.className = readySiteCount > 0 ? 'status-pill status-pill-success' : 'status-pill status-pill-neutral';
      statePill.textContent = '전체';
    }
    if (statusText) statusText.textContent = `${getScheduleMonthValue()} · 전체 ${readySiteCount}/${totalSiteCount || 0}개 지점 source workbook 준비`;
    if (sourceRevision) sourceRevision.textContent = `${readySiteCount}/${totalSiteCount || 0} ready`;
    if (sourceMeta) sourceMeta.textContent = '전체 지점 HQ 작성본 업로드를 위한 source 준비 현황';
    if (mergeState) mergeState.textContent = readySiteCount > 0 ? 'ARLS 검토 가능' : '대기';
    if (mergeMeta) mergeMeta.textContent = readySiteCount > 0 ? 'Excel workflow STEP 4에서 multi-sheet upload' : '준비된 지점 없음';
    if (assignmentCount) assignmentCount.textContent = artifactContext.artifact_id ? `${readySiteCount}개 ready` : '미생성';
    if (conflictMeta) conflictMeta.textContent = totalSiteCount > 0 ? `총 ${totalSiteCount}개 지점` : '지점 정보 없음';
    if (finalState) finalState.textContent = 'ARLS STEP 4';
    if (finalMeta) finalMeta.textContent = '전체 범위 HQ 작성본 업로드/검토는 ARLS에서 진행되고, 내부 state 엔진은 Sentrix가 처리합니다.';
    renderScheduleSupportArtifactMeta(artifactContext);

    if (blockedList) {
      blockedList.innerHTML = '';
      if (!blockedReasons.length) {
        blockedList.classList.add('hidden');
      } else {
        blockedList.classList.remove('hidden');
        blockedReasons.forEach((reason) => {
          const li = document.createElement('li');
          li.textContent = String(reason || '').trim();
          blockedList.appendChild(li);
        });
      }
    }

    if (hqDownloadBtn) hqDownloadBtn.disabled = !canUseScheduleSupportRoundtripHq() || readySiteCount <= 0;
    if (openSentrixBtn) openSentrixBtn.disabled = !canUseScheduleSupportRoundtripHq() || !artifactContext.artifact_id || readySiteCount <= 0;
    if (copyArtifactBtn) copyArtifactBtn.disabled = !canUseScheduleSupportRoundtripHq() || !artifactContext.artifact_id || readySiteCount <= 0;
    renderScheduleSupportHqWorkspace();
    return;
  }

  const sourceState = String(status.source_state || '').trim();
  const sourceLabel = getScheduleSupportRoundtripStateLabel(sourceState);
  const sourceMissing = sourceState === 'source_missing';
  const mergeAvailable = Boolean(status.hq_merge_available);
  const mergeStale = Boolean(status.hq_merge_stale);
  const blockedReasons = Array.isArray(status.blocked_reasons) ? status.blocked_reasons.filter(Boolean) : [];
  const artifactContext = buildScheduleSupportArtifactContext(status, selectedSite);

  if (statePill) {
    statePill.className = getScheduleSupportRoundtripStateClass(sourceState, status);
    statePill.textContent = sourceLabel;
  }
  if (statusText) {
    statusText.textContent = sourceMissing
      ? '현재 month/site 기준 Supervisor 원본 업로드가 아직 없습니다.'
      : [
        `${selectedSite} · ${status.month || getScheduleMonthValue()}`,
        artifactContext.revision ? `artifact ${artifactContext.revision.slice(0, 12)}` : 'artifact 준비',
        mergeStale ? 'ARLS STEP 4 재업로드 필요' : (mergeAvailable ? '최근 HQ 제출 이력 있음' : 'HQ 작성본 업로드 대기'),
      ].filter(Boolean).join(' · ');
  }
  if (sourceRevision) {
    sourceRevision.textContent = String(status.source_revision || '').trim().slice(0, 12) || '없음';
  }
  if (sourceMeta) {
    const metaBits = [];
    if (status.source_filename) metaBits.push(String(status.source_filename).trim());
    if (status.source_uploaded_by) metaBits.push(String(status.source_uploaded_by).trim());
    if (status.source_uploaded_at) metaBits.push(formatOpsDateTime(status.source_uploaded_at));
    sourceMeta.textContent = metaBits.filter(Boolean).join(' · ') || '원본 업로드 대기';
  }
  if (mergeState) {
    mergeState.textContent = mergeStale ? '재검토 필요' : (mergeAvailable ? '제출 이력 있음' : '대기');
  }
  if (mergeMeta) {
    const bits = [];
    if (status.latest_hq_revision) bits.push(`Sentrix ${String(status.latest_hq_revision).slice(0, 12)}`);
    if (status.latest_hq_uploaded_by) bits.push(String(status.latest_hq_uploaded_by).trim());
    if (status.latest_hq_uploaded_at) bits.push(formatOpsDateTime(status.latest_hq_uploaded_at));
    mergeMeta.textContent = bits.filter(Boolean).join(' · ') || (mergeAvailable ? '최근 HQ 작성본 제출 이력 확인됨' : 'HQ 작성본 제출 전');
  }
  if (assignmentCount) {
    assignmentCount.textContent = artifactContext.artifact_id ? '준비됨' : '미생성';
  }
  if (conflictMeta) {
    conflictMeta.textContent = artifactContext.artifact_id
      ? [artifactContext.revision ? `revision ${artifactContext.revision.slice(0, 12)}` : '', artifactContext.generated_at ? formatOpsDateTime(artifactContext.generated_at) : '']
        .filter(Boolean)
        .join(' · ') || '현재 source artifact 준비됨'
      : '현재 source artifact 없음';
  }
  if (finalState) {
    finalState.textContent = 'ARLS STEP 4';
  }
  if (finalMeta) {
    if (mergeStale) finalMeta.textContent = '최신 source artifact 기준으로 STEP 4에서 HQ 작성본을 다시 검토/적용해야 합니다.';
    else if (sourceMissing) finalMeta.textContent = '원본 업로드 후 source artifact가 생성됩니다.';
    else finalMeta.textContent = 'HQ 작성본 업로드/검토/적용 시작은 ARLS, 내부 roster/ticket state 엔진은 Sentrix가 처리합니다.';
  }
  renderScheduleSupportArtifactMeta(artifactContext);

  if (blockedList) {
    blockedList.innerHTML = '';
    if (!blockedReasons.length) {
      blockedList.classList.add('hidden');
    } else {
      blockedList.classList.remove('hidden');
      blockedReasons.forEach((reason) => {
        const li = document.createElement('li');
        li.textContent = String(reason || '').trim();
        blockedList.appendChild(li);
      });
    }
  }

  if (hqDownloadBtn) hqDownloadBtn.disabled = !canUseScheduleSupportRoundtripHq() || sourceMissing;
  if (openSentrixBtn) openSentrixBtn.disabled = !canUseScheduleSupportRoundtripHq() || sourceMissing || !artifactContext.artifact_id;
  if (copyArtifactBtn) copyArtifactBtn.disabled = !canUseScheduleSupportRoundtripHq() || !artifactContext.artifact_id;
  renderScheduleSupportHqWorkspace();
}

async function loadScheduleSupportRoundtripStatus() {
  if (!(canUseScheduleSupportRoundtripSource() || canUseScheduleSupportRoundtripHq() || canUseScheduleSupportRoundtripFinalDownload())) {
    state.schedule.supportStatus = null;
    renderScheduleSupportRoundtripStatus();
    renderScheduleSupportShortcutCard();
    return null;
  }
  const siteCode = getScheduleSupportSelectedSiteCode();
  if (!siteCode) {
    state.schedule.supportStatus = null;
    renderScheduleSupportRoundtripStatus();
    renderScheduleSupportShortcutCard();
    return null;
  }
  if (siteCode === 'ALL') {
    if (!canUseScheduleSupportRoundtripHq()) {
      state.schedule.supportStatus = {
        overall_scope: true,
        site_code: 'ALL',
        month: getScheduleMonthValue(),
        total_site_count: Array.isArray(state.siteCatalog) ? state.siteCatalog.length : 0,
        ready_site_count: 0,
        artifact_revision: 'latest',
        blocked_reasons: [],
      };
      renderScheduleSupportRoundtripStatus();
      renderScheduleSupportShortcutCard();
      return state.schedule.supportStatus;
    }
    state.schedule.supportStatus = null;
    renderScheduleSupportRoundtripStatus();
    renderScheduleSupportShortcutCard();
    const params = new URLSearchParams();
    params.set('month', getScheduleMonthValue());
    params.set('tenant_code', getScheduleTenantValue());
    const workspace = await apiRequest(`/schedules/support-roundtrip/hq-workspace?${params.toString()}`);
    const sites = Array.isArray(workspace?.sites) ? workspace.sites : [];
    const totalSiteCount = Number(workspace?.total_site_count || sites.length || 0);
    const readySiteCount = Number(
      workspace?.ready_site_count
      || sites.filter((site) => Boolean(site?.download_ready)).length
      || 0
    );
    state.schedule.supportStatus = {
      overall_scope: true,
      site_code: 'ALL',
      month: getScheduleMonthValue(),
      total_site_count: totalSiteCount,
      ready_site_count: readySiteCount,
      latest_status: String(workspace?.latest_status || 'latest').trim() || 'latest',
      artifact_revision: String(workspace?.latest_status || 'latest').trim() || 'latest',
      blocked_reasons: readySiteCount > 0 ? [] : ['선택한 월에 Sentrix로 넘길 수 있는 지원수요 source가 아직 없습니다.'],
    };
    renderScheduleSupportRoundtripStatus();
    renderScheduleSupportShortcutCard();
    return state.schedule.supportStatus;
  }
  state.schedule.supportStatus = null;
  renderScheduleSupportRoundtripStatus();
  renderScheduleSupportShortcutCard();
  const params = new URLSearchParams();
  params.set('month', getScheduleMonthValue());
  params.set('site_code', siteCode);
  params.set('tenant_code', getScheduleTenantValue());
  const status = await apiRequest(`/schedules/support-roundtrip/status?${params.toString()}`);
  state.schedule.supportStatus = status && typeof status === 'object' ? status : null;
  renderScheduleSupportRoundtripStatus();
  renderScheduleSupportShortcutCard();
  return state.schedule.supportStatus;
}

async function downloadScheduleWorkbookWithAuth(requestUrl, fallbackName) {
  const accessToken = getActiveAccessToken();
  if (!accessToken) {
    throw new Error('로그인 후 이용해 주세요.');
  }
  let response = await fetch(requestUrl, {
    headers: {
      Authorization: `Bearer ${accessToken}`,
    },
    mode: 'cors',
    credentials: 'omit',
  });
  if (response.status === 401) {
    const refreshed = await requestTokenRefresh();
    if (refreshed) {
      response = await fetch(requestUrl, {
        headers: {
          Authorization: `Bearer ${getActiveAccessToken()}`,
        },
        mode: 'cors',
        credentials: 'omit',
      });
    }
  }
  if (!response.ok) {
    const text = await response.text().catch(() => '');
    let detail = '';
    try {
      const payload = text ? JSON.parse(text) : null;
      detail = String(payload?.detail || payload?.message || '').trim();
    } catch {
      detail = '';
    }
    throw new Error(detail || `요청 실패 (${response.status})`);
  }
  const blob = await response.blob();
  const href = URL.createObjectURL(blob);
  const anchor = document.createElement('a');
  anchor.href = href;
  anchor.download = parseContentDispositionFilename(
    String(response.headers.get('Content-Disposition') || '').trim(),
    fallbackName,
  );
  document.body.appendChild(anchor);
  anchor.click();
  anchor.remove();
  URL.revokeObjectURL(href);
}

async function onScheduleSupportHqDownload() {
  if (!canUseScheduleSupportRoundtripHq()) {
    showToast('HQ 지원근무 추출 권한이 없습니다.', 'error');
    return;
  }
  const siteCode = getScheduleSupportSelectedSiteCode();
  if (!siteCode) {
    showToast('업로드 지점을 먼저 선택해 주세요.', 'error');
    return;
  }
  const month = getScheduleMonthValue();
  const params = new URLSearchParams();
  params.set('month', month);
  params.set('tenant_code', getScheduleTenantValue());
  const isAllSites = siteCode === 'ALL';
  params.set('scope', isAllSites ? 'all' : 'site');
  if (!isAllSites) {
    params.set('site_code', siteCode);
  }
  const fallbackGeneratedOn = (() => {
    const formatter = new Intl.DateTimeFormat('en-CA', {
      timeZone: 'Asia/Seoul',
      year: '2-digit',
      month: '2-digit',
      day: '2-digit',
    });
    const parts = Object.fromEntries(formatter.formatToParts(new Date()).map((part) => [part.type, part.value]));
    return `${parts.year || ''}${parts.month || ''}${parts.day || ''}`;
  })();
  await downloadScheduleWorkbookWithAuth(
    `${state.activeApiBase}/schedules/support-roundtrip/hq-roster-workbook?${params.toString()}`,
    `${month.slice(0, 4)}년 ${Number(month.slice(5, 7))}월 지원근무자용 스케쥴 제출_${siteCode}_${fallbackGeneratedOn}.xlsx`,
  );
  showToast(
    isAllSites ? '전체 지점 지원근무자용 workbook을 다운로드했습니다.' : 'HQ 지원근무자용 시트를 다운로드했습니다.',
    'success',
    2200,
  );
}

async function onScheduleSupportPreview() {
  await onScheduleSupportHqInspect();
}

async function onScheduleSupportApply() {
  await onScheduleSupportHqApply();
}

async function onScheduleSupportOpenSentrix() {
  if (!canUseScheduleSupportRoundtripHq()) {
    showToast('Sentrix handoff 열기 권한이 없습니다.', 'error');
    return;
  }
  const siteCode = getScheduleSupportSelectedSiteCode();
  if (!siteCode) {
    showToast('업로드 지점을 먼저 선택해 주세요.', 'error');
    return;
  }
  const status = (state.schedule.supportStatus && typeof state.schedule.supportStatus === 'object')
    ? state.schedule.supportStatus
    : await loadScheduleSupportRoundtripStatus();
  const artifactContext = buildScheduleSupportArtifactContext(status, siteCode);
  if (!artifactContext.artifact_id) {
    showToast('현재 month/site 기준 source artifact가 아직 없습니다.', 'error');
    return;
  }
  if (siteCode === 'ALL' && Number(status?.ready_site_count || 0) <= 0) {
    showToast('전체 범위에서 Sentrix로 넘길 준비가 된 지점이 아직 없습니다.', 'error');
    return;
  }
  const url = buildSentrixHqSupportSubmissionUrl({
    tenant_code: String(getTenantCodeForScopedAdminApi() || getScheduleTenantValue() || '').trim(),
    month: artifactContext.month || getScheduleMonthValue(),
    site_code: artifactContext.site_code === 'ALL' ? '' : (artifactContext.site_code || siteCode),
    artifact_id: artifactContext.artifact_id,
    revision: artifactContext.revision,
  });
  window.open(url, '_blank', 'noopener,noreferrer');
  showToast('Sentrix HQ submission workspace로 이동했습니다.', 'success', 2400);
}

async function onScheduleSupportCopyArtifact() {
  const siteCode = getScheduleSupportSelectedSiteCode();
  const status = state.schedule.supportStatus && typeof state.schedule.supportStatus === 'object'
    ? state.schedule.supportStatus
    : null;
  const artifactContext = buildScheduleSupportArtifactContext(status, siteCode);
  if (!artifactContext.artifact_id) {
    throw new Error('복사할 artifact_id가 없습니다.');
  }
  await copyTextToClipboard(artifactContext.artifact_id, 'artifact_id를 복사했습니다.');
}

