function showAuthError(msg) {
  setAuthMessage(msg, 'error');
}

function showAuthInfo(msg) {
  setAuthMessage(msg, 'info');
}

function normalizeAuthError(err) {
  const raw = String(err?.message || '').trim();
  const status = Number(err?.status || err?.httpStatus || 0);
  const code = String(err?.code || '').trim().toUpperCase();
  if (!raw) {
    return '로그인 중 알 수 없는 오류가 발생했습니다. 잠시 후 다시 시도해 주세요.';
  }

  const lowered = raw.toLowerCase();
  if (lowered.includes('invalid credentials')) {
    return state.tenantValid
      ? '아이디 또는 비밀번호가 올바르지 않습니다.'
      : '회사 번호, 아이디 또는 비밀번호가 올바르지 않습니다.';
  }
  if (lowered.includes('슈퍼 관리자 계정만') || lowered.includes('master')) {
    return '슈퍼 관리자 계정만 MASTER로 로그인할 수 있습니다.';
  }
  if (status === 400 || status === 422 || code === 'BAD_REQUEST' || code === 'INVALID_INPUT' || code === 'VALIDATION_ERROR') {
    return '입력값을 확인해주세요.';
  }
  if (status === 401 || code === 'UNAUTHORIZED' || lowered.includes('unauthorized')) {
    const hasActiveSession = Boolean(String(state.user?.id || '').trim());
    return hasActiveSession
      ? '로그인이 만료되었습니다. 다시 로그인해주세요.'
      : '아이디 또는 비밀번호를 다시 확인해 주세요.';
  }
  if (status === 403 || code === 'FORBIDDEN' || lowered.includes('forbidden')) {
    return '권한이 없습니다.';
  }
  if (
    code === 'COMPANY_EXISTS'
    || code === 'TENANT_EXISTS'
    || lowered.includes('already exists')
    || lowered.includes('duplicate')
    || lowered.includes('이미 존재')
  ) {
    return '이미 존재하는 회사 번호입니다.';
  }
  if (status >= 500 || code === 'SERVER_ERROR' || code === 'INTERNAL' || code === 'INTERNAL_SERVER_ERROR') {
    return '서버 오류입니다. 잠시 후 다시 시도해주세요.';
  }
  if (code === 'NETWORK_ERROR' || lowered.includes('failed to fetch') || lowered.includes('network') || lowered.includes('cors') || lowered.includes('timeout')) {
    return '네트워크 오류, 재시도';
  }
  return raw;
}

function normalizeActionError(err, fallbackMessage = '요청 처리 중 오류가 발생했습니다.') {
  const raw = String(err?.message || '').trim();
  const status = Number(err?.status || err?.httpStatus || 0);
  const code = String(err?.code || '').trim().toUpperCase();
  if (code === 'NETWORK_ERROR') return '네트워크 오류, 재시도';
  if (code === 'USER_NOT_FOUND') return '계정을 찾을 수 없습니다.';
  if (code === 'SELF_DELETE_FORBIDDEN') return '현재 로그인한 계정은 삭제할 수 없습니다.';
  if (code === 'LAST_MANAGER_DELETE_FORBIDDEN') return '마지막 지점관리자 계정은 삭제할 수 없습니다.';
  if (code === 'LAST_DEV_DELETE_FORBIDDEN') return '마지막 개발자 계정은 삭제할 수 없습니다.';
  if (code === 'TENANT_CONTEXT_REQUIRED') {
    return '작업회사를 먼저 선택해 주세요.';
  }
  if (code === 'TENANT_NOT_FOUND') {
    return '해당 회사(회사)를 찾을 수 없습니다. 마스터 콘솔에서 회사가 생성/활성화되어 있는지 확인하세요.';
  }
  if (code === 'TENANT_DISABLED') {
    return '비활성화된 회사입니다.';
  }
  if (code === 'SITE_NOT_FOUND') {
    return '현장을 먼저 생성하세요.';
  }
  if (code === 'EMPLOYEE_NOT_FOUND') {
    return '직원 정보를 찾을 수 없습니다.';
  }
  if (code === 'SITE_SCOPE_REQUIRED') {
    return '계정에 현장 권한이 설정되지 않아 작업할 수 없습니다.';
  }
  if (code === 'EMPLOYEE_HAS_REFERENCES') {
    return '근태/스케줄 참조 데이터가 있어 직원을 삭제할 수 없습니다.';
  }
  if (code === 'EMPLOYEE_CODE_CONFLICT') {
    return '직원 번호 생성 충돌이 발생했습니다. 다시 시도해 주세요.';
  }
  if (code === 'COMPANY_NOT_FOUND') {
    return '회사 번호를 확인해 주세요.';
  }
  if (!raw && !status) return fallbackMessage;
  const lowered = raw.toLowerCase();

  if (status === 400 || status === 422 || code === 'BAD_REQUEST' || code === 'INVALID_INPUT' || code === 'VALIDATION_ERROR') {
    return '입력값을 확인해주세요.';
  }
  if (status === 401 || code === 'UNAUTHORIZED' || lowered.includes('unauthorized')) {
    return '로그인이 만료되었습니다. 다시 로그인해주세요.';
  }
  if (status === 403 || code === 'FORBIDDEN' || lowered.includes('forbidden')) {
    return '권한이 없습니다.';
  }
  if (
    status === 409
    && (
      lowered.includes('employee mapping unavailable for monthly export')
      || lowered.includes('selected site workbook is not ready')
      || lowered.includes('support workbook source missing')
      || lowered.includes('support workbook generation failed')
      || lowered.includes('no support workbook source is ready')
      || lowered.includes('finance final workbook not available')
    )
  ) {
    return raw || fallbackMessage;
  }
  if (
    code === 'COMPANY_EXISTS'
    || code === 'TENANT_EXISTS'
    || code === 'SITE_EXISTS'
    || lowered.includes('already exists')
    || lowered.includes('duplicate')
    || lowered.includes('이미 존재')
  ) {
    if (code === 'SITE_EXISTS') return '이미 존재하는 현장 번호입니다.';
    if (code === 'TENANT_HAS_REFERENCES') return '참조 데이터가 남아 있어 하드 삭제할 수 없습니다.';
    if (code === 'MASTER_TENANT_PROTECTED') return 'MASTER 회사는 삭제/비활성화할 수 없습니다.';
    if (code === 'CURRENT_TENANT_PROTECTED') return '현재 로그인한 회사는 삭제/비활성화할 수 없습니다.';
    if (code === 'EMPLOYEE_HAS_REFERENCES') return '근태/스케줄 참조 데이터가 있어 직원을 삭제할 수 없습니다.';
    return '이미 존재하는 회사 번호입니다.';
  }
  if (status === 409) {
    return raw || fallbackMessage;
  }
  if (status >= 500 || code === 'SERVER_ERROR' || code === 'INTERNAL' || code === 'INTERNAL_SERVER_ERROR') {
    return '서버 오류입니다. 잠시 후 다시 시도해주세요.';
  }
  if (lowered.includes('failed to fetch') || lowered.includes('network') || lowered.includes('cors') || lowered.includes('timeout')) {
    return '네트워크 오류, 재시도';
  }
  if (lowered.includes('invalid current password')) {
    return '현재 비밀번호가 올바르지 않습니다.';
  }
  if (lowered.includes('new password must be different')) {
    return '새 비밀번호는 현재 비밀번호와 달라야 합니다.';
  }
  return raw;
}

function readLocalJSON(key, fallback) {
  try {
    const raw = localStorage.getItem(key);
    if (!raw) return fallback;
    return JSON.parse(raw);
  } catch {
    return fallback;
  }
}

function writeLocalJSON(key, value) {
  try {
    localStorage.setItem(key, JSON.stringify(value));
  } catch {
    // no-op
  }
}

function getMasterAuditLogStorageKey() {
  const tenant = String(state.user?.tenant_code || 'MASTER').trim().toUpperCase() || 'MASTER';
  const username = String(state.user?.username || 'dev').trim().toLowerCase() || 'dev';
  return `${MASTER_AUDIT_LOG_KEY}:${tenant}:${username}`;
}

function readMasterAuditLogs() {
  const logs = readLocalJSON(getMasterAuditLogStorageKey(), []);
  if (!Array.isArray(logs)) return [];
  return logs
    .filter((item) => item && typeof item === 'object')
    .sort((a, b) => String(b.timestamp || '').localeCompare(String(a.timestamp || '')));
}

function writeMasterAuditLogs(items = []) {
  const normalized = Array.isArray(items) ? items.slice(0, 400) : [];
  writeLocalJSON(getMasterAuditLogStorageKey(), normalized);
}

function appendMasterAuditLog({
  action = '',
  actionType = '',
  tenantId = '',
  tenantCode = '',
  targetType = '',
  targetId = '',
  targetLabel = '',
  before = null,
  after = null,
  note = '',
} = {}) {
  if (!state.user || getNavigationRole() !== 'DEV') return;
  const actor = `${state.user.full_name || state.user.username || 'DEV'} (${state.user.username || 'dev'})`;
  const entry = {
    id: (typeof crypto !== 'undefined' && typeof crypto.randomUUID === 'function')
      ? crypto.randomUUID()
      : `log_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`,
    timestamp: new Date().toISOString(),
    actor,
    action: String(action || '').trim() || 'unknown',
    action_type: String(actionType || '').trim() || 'other',
    tenant_id: String(tenantId || '').trim(),
    tenant_code: String(tenantCode || '').trim().toUpperCase(),
    target_type: String(targetType || '').trim(),
    target_id: String(targetId || '').trim(),
    target_label: String(targetLabel || '').trim(),
    before,
    after,
    note: String(note || '').trim(),
  };
  const next = [entry, ...readMasterAuditLogs()];
  writeMasterAuditLogs(next);
  debugAuditLog('master_audit', entry);
}

function getMasterPolicyStorageKey(tenantId = '') {
  const id = String(tenantId || '').trim();
  if (!id) return '';
  return `${MASTER_SECURITY_POLICY_KEY}:${id}`;
}

function readMasterSecurityPolicy(tenantId = '') {
  const key = getMasterPolicyStorageKey(tenantId);
  if (!key) return {
    defaultRole: 'officer',
    minPasswordLength: 8,
    strictGeofence: true,
    allowDevPromotion: false,
    allowBranchManagerUserManage: false,
  };
  const raw = readLocalJSON(key, {});
  return {
    defaultRole: ['officer', 'vice_supervisor', 'supervisor', 'hq_admin', 'developer'].includes(String(raw?.defaultRole || '').trim())
      ? String(raw.defaultRole).trim()
      : 'officer',
    minPasswordLength: Math.max(8, Math.min(64, Number(raw?.minPasswordLength) || 8)),
    strictGeofence: raw?.strictGeofence !== false,
    allowDevPromotion: raw?.allowDevPromotion === true,
    allowBranchManagerUserManage: raw?.allowBranchManagerUserManage === true,
  };
}

function writeMasterSecurityPolicy(tenantId = '', policy = {}) {
  const key = getMasterPolicyStorageKey(tenantId);
  if (!key) return;
  writeLocalJSON(key, policy);
}

function isCapacitorNativeRuntime() {
  const runtime = window.Capacitor;
  if (!runtime) return false;
  if (typeof runtime.isNativePlatform === 'function') {
    return runtime.isNativePlatform();
  }
  return Boolean(runtime.Plugins);
}

function getGeolocationPlugin() {
  const plugins = window.Capacitor?.Plugins || {};
  return plugins.Geolocation || null;
}

function getLocalNotificationsPlugin() {
  const plugins = window.Capacitor?.Plugins || {};
  return plugins.LocalNotifications || null;
}

function getPushNotificationsPlugin() {
  const plugins = window.Capacitor?.Plugins || {};
  return plugins.PushNotifications || null;
}

function hasGeolocationCapability() {
  if (isCapacitorNativeRuntime() && getGeolocationPlugin()) return true;
  return Boolean(navigator.geolocation);
}

function normalizePermissionState(raw) {
  const value = String(raw || '').trim().toLowerCase();
  if (value === 'granted') return 'granted';
  if (value === 'denied') return 'denied';
  if (value === 'prompt') return 'prompt';
  return 'unknown';
}

function isGeolocationDeniedError(error) {
  if (Number(error?.code) === 1) return true;
  const message = String(error?.message || '').trim().toLowerCase();
  if (!message) return false;
  return message.includes('denied') || message.includes('permission');
}

function isGeolocationTransientError(error) {
  const code = Number(error?.code || 0);
  if (code === 2 || code === 3) return true; // POSITION_UNAVAILABLE / TIMEOUT
  const message = String(error?.message || '').trim().toLowerCase();
  if (!message) return false;
  return (
    message.includes('position unavailable')
    || message.includes('locationunknown')
    || message.includes('kclerrorlocationunknown')
    || message.includes('timeout')
  );
}

async function getCurrentPositionFromRuntime(options = HOME_LOCATION_OPTIONS) {
  if (isCapacitorNativeRuntime()) {
    const plugin = getGeolocationPlugin();
    if (plugin && typeof plugin.getCurrentPosition === 'function') {
      const result = await plugin.getCurrentPosition(options);
      return {
        coords: {
          latitude: Number(result?.coords?.latitude),
          longitude: Number(result?.coords?.longitude),
          accuracy: Number(result?.coords?.accuracy),
        },
      };
    }
  }

  if (!navigator.geolocation) {
    const unsupportedError = new Error('Geolocation is not supported');
    unsupportedError.code = 0;
    throw unsupportedError;
  }

  return new Promise((resolve, reject) => {
    navigator.geolocation.getCurrentPosition(resolve, reject, options);
  });
}

async function getCurrentPositionWithRetry(primaryOptions = HOME_LOCATION_OPTIONS) {
  try {
    return await getCurrentPositionFromRuntime(primaryOptions);
  } catch (error) {
    if (isGeolocationDeniedError(error) || !isGeolocationTransientError(error)) {
      throw error;
    }
    debugAuditLog('location_request_retry', {
      reason: 'transient_location_error',
      error_code: Number(error?.code || 0),
      message: String(error?.message || '').slice(0, 140),
    });
    return getCurrentPositionFromRuntime(HOME_LOCATION_RETRY_OPTIONS);
  }
}

function clearHomeAttendanceCheckWatch() {
  const watchId = homeAttendanceCheckRuntime.watchId;
  const provider = homeAttendanceCheckRuntime.watchProvider;
  if (!watchId && watchId !== 0) {
    homeAttendanceCheckRuntime.watchId = null;
    homeAttendanceCheckRuntime.watchProvider = '';
    return;
  }

  try {
    if (provider === 'capacitor') {
      const plugin = getGeolocationPlugin();
      if (plugin && typeof plugin.clearWatch === 'function') {
        plugin.clearWatch({ id: String(watchId) }).catch(() => {
          // no-op
        });
      }
    } else if (navigator.geolocation && typeof navigator.geolocation.clearWatch === 'function') {
      navigator.geolocation.clearWatch(Number(watchId));
    }
  } catch {
    // no-op
  } finally {
    homeAttendanceCheckRuntime.watchId = null;
    homeAttendanceCheckRuntime.watchProvider = '';
  }
}

