function setSiteWifiSsid(siteCode, ssidRaw) {
  const code = String(siteCode || '').trim().toUpperCase();
  if (!code) return;
  const ssid = String(ssidRaw || '').trim();
  const cache = readSiteWifiSsidCache();
  if (!ssid) {
    delete cache[code];
  } else {
    cache[code] = ssid;
  }
  writeSiteWifiSsidCache(cache);
}

