function buildInAppNotificationId(seed = '') {
  const source = `${String(seed || '').trim()}:${Date.now()}:${Math.random().toString(36).slice(2, 10)}`;
  let hash = 0;
  for (let index = 0; index < source.length; index += 1) {
    hash = (hash * 33 + source.charCodeAt(index)) >>> 0;
  }
  return `n_${hash.toString(36)}_${Date.now().toString(36)}`;
}

function normalizeInAppNotificationMessage(item) {
  if (item && typeof item === 'object') {
    const value = item.message ?? item.text ?? item.title ?? '';
    return String(value || '').trim();
  }
  return String(item || '').trim();
}

function normalizeInAppNotificationItem(item, index = 0) {
  const message = normalizeInAppNotificationMessage(item);
  if (!message) return null;

  const objectLike = item && typeof item === 'object';
  const idRaw = objectLike ? String(item.id || '').trim() : '';
  const dedupeKeyRaw = objectLike ? String(item.dedupeKey || item.dedupe_key || '').trim() : '';
  const createdRaw = objectLike ? String(item.createdAt || item.created_at || item.at || '').trim() : '';
  const createdDate = createdRaw ? new Date(createdRaw) : null;
  const createdAt = createdDate && !Number.isNaN(createdDate.getTime())
    ? createdDate.toISOString()
    : new Date(Date.now() - (index * 1000)).toISOString();
  const payload = objectLike && item.payload && typeof item.payload === 'object'
    ? item.payload
    : {};

  return {
    id: idRaw || buildInAppNotificationId(`${message}:${index}`),
    dedupeKey: dedupeKeyRaw || null,
    message,
    read: objectLike ? Boolean(item.read) : false,
    createdAt,
    type: objectLike ? String(item.type || item.kind || 'info').trim().toLowerCase() : 'info',
    payload,
  };
}

function normalizeInAppNotificationItems(items = []) {
  const source = Array.isArray(items) ? items : [];
  const deduped = [];
  const dedupeByMessage = new Map();

  source.forEach((item, index) => {
    const parsed = normalizeInAppNotificationItem(item, index);
    if (!parsed) return;

    const key = String(parsed.dedupeKey || parsed.id || parsed.message || '').trim().toLowerCase();
    const existing = dedupeByMessage.get(key);
    if (!existing) {
      dedupeByMessage.set(key, parsed);
      deduped.push(parsed);
      return;
    }

    // Keep the newest item position, but merge unread state so new alerts stay visible.
    existing.read = existing.read && parsed.read;
    if (new Date(parsed.createdAt).getTime() > new Date(existing.createdAt).getTime()) {
      existing.createdAt = parsed.createdAt;
      existing.id = parsed.id;
      existing.type = parsed.type;
      existing.payload = parsed.payload;
      existing.dedupeKey = parsed.dedupeKey;
    }
  });

  return deduped.slice(0, IN_APP_NOTIFICATION_LIMIT);
}

function writeInAppNotificationItems(items = []) {
  const key = getInAppNotificationStorageKey();
  if (!key) return;
  writeLocalJSON(key, normalizeInAppNotificationItems(items));
}

function readInAppNotificationItems() {
  const key = getInAppNotificationStorageKey();
  if (!key) return [];
  const raw = readLocalJSON(key, []);
  return normalizeInAppNotificationItems(raw);
}

function hydrateInAppNotificationItems() {
  commitInAppNotificationItems(readInAppNotificationItems(), { persist: false });
}

function commitInAppNotificationItems(nextItems = [], { persist = true } = {}) {
  const normalized = normalizeInAppNotificationItems(nextItems);
  state.notificationItems = normalized;
  state.notificationCount = normalized.filter((item) => !item.read).length;
  if (persist) {
    writeInAppNotificationItems(normalized);
  }
  renderNotificationBadge();
  renderHomeManagerDashboard();
}

function pushInAppNotification(message, { type = 'info' } = {}) {
  const text = String(message || '').trim();
  if (!text) return;
  const current = Array.isArray(state.notificationItems) ? state.notificationItems : [];
  const next = [{
    id: buildInAppNotificationId(text),
    dedupeKey: null,
    message: text,
    read: false,
    createdAt: new Date().toISOString(),
    type: String(type || 'info').trim().toLowerCase() || 'info',
    payload: {},
  }, ...current];
  commitInAppNotificationItems(next);
}

function markInAppNotificationRead(notificationId = '') {
  const targetId = String(notificationId || '').trim();
  if (!targetId) return false;
  const current = Array.isArray(state.notificationItems) ? state.notificationItems : [];
  let changed = false;

  const next = current.map((item) => {
    if (String(item?.id || '') !== targetId || item.read) return item;
    changed = true;
    return { ...item, read: true };
  });

  if (changed) {
    commitInAppNotificationItems(next);
  }
  return changed;
}

function markAllInAppNotificationsRead() {
  const current = Array.isArray(state.notificationItems) ? state.notificationItems : [];
  const hasUnread = current.some((item) => !item?.read);
  if (!hasUnread) return false;

  const next = current.map((item) => {
    if (item.read) return item;
    return { ...item, read: true };
  });
  commitInAppNotificationItems(next);
  return true;
}

function normalizeNotificationToastLevel(type = '') {
  const normalized = String(type || '').trim().toLowerCase();
  if (normalized === 'error') return 'error';
  if (normalized === 'success') return 'success';
  return 'info';
}

async function syncServerInAppNotifications({ force = false, showToasts = false } = {}) {
  if (!state.token) return [];
  const lastFetchedAt = Number(state.notificationServerSyncAt || 0);
  if (!force && lastFetchedAt > 0 && (Date.now() - lastFetchedAt) < 15000) {
    return Array.isArray(state.notificationItems) ? state.notificationItems : [];
  }

  const previousUnreadIds = new Set(
    (Array.isArray(state.notificationItems) ? state.notificationItems : [])
      .filter((item) => !item?.read)
      .map((item) => String(item?.id || '').trim())
      .filter(Boolean),
  );
  const payload = await apiRequest('/notifications/in-app?limit=50', { suppressUnauthorizedRedirect: true });
  const nextItems = normalizeInAppNotificationItems(payload?.items || []);
  commitInAppNotificationItems(nextItems);
  state.notificationServerSyncAt = Date.now();

  if (showToasts) {
    nextItems
      .filter((item) => !item?.read)
      .filter((item) => {
        const id = String(item?.id || '').trim();
        return id && !previousUnreadIds.has(id) && !state.notificationToastSeenIds.has(id);
      })
      .slice(0, 3)
      .forEach((item) => {
        const id = String(item?.id || '').trim();
        if (id) {
          state.notificationToastSeenIds.add(id);
        }
        showToast(normalizeInAppNotificationMessage(item), normalizeNotificationToastLevel(item?.type), 2600);
      });
  }
  return nextItems;
}

async function markInAppNotificationReadRemote(notificationId = '') {
  const targetId = String(notificationId || '').trim();
  if (!targetId || !state.token) return false;
  await apiRequest(`/notifications/in-app/${encodeURIComponent(targetId)}/read`, {
    method: 'POST',
    suppressUnauthorizedRedirect: true,
  });
  return true;
}

async function markAllInAppNotificationsReadRemote() {
  if (!state.token) return false;
  await apiRequest('/notifications/in-app/read-all', {
    method: 'POST',
    suppressUnauthorizedRedirect: true,
  });
  return true;
}

function syncOutsideAttendanceNotification(outsideCountRaw) {
  const outsideCount = Number(outsideCountRaw) || 0;
  const current = Array.isArray(state.notificationItems) ? state.notificationItems : [];
  const kept = current.filter((item) => {
    const message = normalizeInAppNotificationMessage(item);
    return !message.startsWith('오늘 반경 밖 출퇴근');
  });
  if (outsideCount > 0) {
    kept.unshift({
      id: buildInAppNotificationId(`outside-attendance:${outsideCount}`),
      dedupeKey: `outside-attendance:${outsideCount}`,
      message: `오늘 반경 밖 출퇴근 ${outsideCount}건`,
      read: false,
      createdAt: new Date().toISOString(),
      type: 'warn',
      payload: {},
    });
  }
  commitInAppNotificationItems(kept);
}

function buildAttendanceRequestStatusNotificationText(status, siteLabel, reviewerLabel = '') {
  const site = String(siteLabel || '').trim() || '현장';
  const reviewer = String(reviewerLabel || '').trim();
  if (status === 'approved') {
    return reviewer ? `출근요청 승인: ${site} (${reviewer})` : `출근요청 승인: ${site}`;
  }
  if (status === 'rejected') {
    return reviewer ? `출근요청 반려: ${site} (${reviewer})` : `출근요청 반려: ${site}`;
  }
  if (status === 'cancelled') {
    return `출근요청 취소됨: ${site}`;
  }
  if (status === 'pending') {
    return `출근요청 대기중: ${site}`;
  }
  return `출근요청 상태 변경: ${site} (${getUiStatusLabel(status || 'unknown')})`;
}

function buildLocalNotificationStableId(seed = '') {
  const source = String(seed || '').trim();
  if (!source) return Math.max(1, Math.floor(Date.now() % 2147483000));
  let hash = 0;
  for (let idx = 0; idx < source.length; idx += 1) {
    hash = (hash * 33 + source.charCodeAt(idx)) % 2147483000;
  }
  return Math.max(1, hash);
}

function maybeSendAttendanceRequestStatusLocalNotification({
  status,
  requestId = '',
  siteLabel = '',
  reviewer = '',
} = {}) {
  const normalizedStatus = String(status || '').trim().toLowerCase();
  if (!['approved', 'rejected', 'cancelled'].includes(normalizedStatus)) return;
  if (!state.user || !state.token) return;
  if (!state.reminder.pushApprovalsEnabled) return;
  if (!isReminderPermissionGranted() || !isCapacitorNativeRuntime()) return;

  const plugin = getLocalNotificationsPlugin();
  if (!plugin || typeof plugin.schedule !== 'function') return;

  const title = normalizedStatus === 'approved'
    ? '출근요청 승인 완료'
    : (normalizedStatus === 'rejected' ? '출근요청 반려 안내' : '출근요청 상태 변경');
  const body = buildAttendanceRequestStatusNotificationText(normalizedStatus, siteLabel, reviewer);
  const idSeed = `attendance-status:${requestId || siteLabel}:${normalizedStatus}`;
  const payload = {
    id: buildLocalNotificationStableId(idSeed),
    title,
    body,
    schedule: { at: new Date(Date.now() + 1200) },
    extra: {
      request_status: normalizedStatus,
      request_id: String(requestId || '').trim(),
      site_name: String(siteLabel || '').trim(),
      reviewed_by_username: String(reviewer || '').trim(),
    },
  };

  plugin.schedule({ notifications: [payload] }).catch((err) => {
    console.error('[RG ARLS] approval local notification failed', err);
  });
}

function notifyAttendanceRequestStatusChange({
  status,
  requestId = '',
  siteLabel = '',
  reviewer = '',
} = {}) {
  pushInAppNotification(buildAttendanceRequestStatusNotificationText(status, siteLabel, reviewer));
  maybeSendAttendanceRequestStatusLocalNotification({
    status,
    requestId,
    siteLabel,
    reviewer,
  });
}

function formatLeaveHalfDaySlotLabel(slot) {
  const normalized = String(slot || '').trim().toLowerCase();
  return LEAVE_HALF_DAY_SLOT_LABELS[normalized] || '';
}

function formatLeavePeriodLabel(startAt, endAt, leaveType = '', halfDaySlot = '') {
  const start = String(startAt || '').trim();
  const end = String(endAt || '').trim();
  const leaveLabel = formatLeaveTypeLabel(leaveType);
  const slotLabel = formatLeaveHalfDaySlotLabel(halfDaySlot);
  if (String(leaveType || '').trim().toLowerCase() === 'half') {
    const dateLabel = start || end || '-';
    return slotLabel
      ? `${dateLabel} (${leaveLabel} · ${slotLabel})`
      : `${dateLabel} (${leaveLabel})`;
  }
  if (!start && !end) return leaveLabel;
  if (start === end || !end) return `${start} (${leaveLabel})`;
  return `${start} ~ ${end} (${leaveLabel})`;
}

function buildLeaveStatusNotificationText(status, leaveType, startAt, endAt, halfDaySlot, reviewerLabel = '') {
  const period = formatLeavePeriodLabel(startAt, endAt, leaveType, halfDaySlot);
  const reviewer = String(reviewerLabel || '').trim();
  if (status === 'approved') {
    return reviewer ? `휴가 승인: ${period} (${reviewer})` : `휴가 승인: ${period}`;
  }
  if (status === 'rejected') {
    return reviewer ? `휴가 반려: ${period} (${reviewer})` : `휴가 반려: ${period}`;
  }
  if (status === 'cancelled') {
    return `휴가 취소됨: ${period}`;
  }
  if (status === 'pending') {
    return `휴가 신청 대기중: ${period}`;
  }
  return `휴가 상태 변경: ${period} (${getUiStatusLabel(status || 'unknown')})`;
}

