function buildHomeSitePickerSheetNode() {
  const wrapper = document.createElement('div');
  wrapper.className = 'stack';

  const helper = document.createElement('p');
  helper.className = 'muted';
  helper.textContent = '선택한 현장를 기준으로 거리/반경을 계산합니다.';
  wrapper.appendChild(helper);

  const list = document.createElement('ul');
  list.className = 'home-site-sheet-list';
  wrapper.appendChild(list);

  const sites = Array.isArray(state.home.sites) ? state.home.sites : [];
  if (!sites.length) {
    renderEmptyState(list, '등록된 현장가 없습니다.');
    return wrapper;
  }

  const selectedCode = String(state.home.selectedSiteCode || '').trim();
  sites.forEach((site) => {
    const li = document.createElement('li');
    const btn = document.createElement('button');
    btn.type = 'button';
    btn.className = 'home-site-sheet-btn';
    if (String(site.site_code || '') === selectedCode) {
      btn.classList.add('active');
    }
    btn.dataset.action = 'home-select-site';
    btn.dataset.siteCode = String(site.site_code || '');

    const title = document.createElement('strong');
    title.textContent = getHomeSiteDisplayName(site);
    btn.appendChild(title);

    const radius = Number(site.radius_meters);
    const sub = document.createElement('span');
    sub.textContent = `반경 ${Number.isFinite(radius) ? Math.round(radius) : '-'}m`;
    btn.appendChild(sub);

    li.appendChild(btn);
    list.appendChild(li);
  });

  return wrapper;
}

function openHomeSitePickerSheet() {
  const sites = Array.isArray(state.home.sites) ? state.home.sites : [];
  if (!sites.length) {
    showToast('선택 가능한 현장가 없습니다.', 'error', 2200);
    return;
  }

  setHomeSitePickerExpanded(true);
  openSheet({
    title: '근무 현장 선택',
    contentNode: buildHomeSitePickerSheetNode(),
    actions: [
      { label: '닫기', variant: 'btn-secondary', action: 'sheet-close' },
    ],
  });
}

function buildHomeExternalMapUrl(site) {
  const siteLat = Number(site?.latitude);
  const siteLng = Number(site?.longitude);
  if (!isValidLatLng(siteLat, siteLng)) return '';
  const destination = `${siteLat},${siteLng}`;
  if (state.home.position && isValidLatLng(state.home.position.latitude, state.home.position.longitude)) {
    const origin = `${state.home.position.latitude},${state.home.position.longitude}`;
    return `https://www.google.com/maps/dir/?api=1&origin=${encodeURIComponent(origin)}&destination=${encodeURIComponent(destination)}&travelmode=walking`;
  }
  return `https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(destination)}`;
}

function openHomeExternalMap(siteCode = '') {
  const requestedCode = String(siteCode || '').trim();
  const site = requestedCode
    ? (state.home.sites.find((item) => String(item.site_code || '') === requestedCode) || null)
    : getSelectedHomeSite();
  if (!site) {
    showToast('근무 현장를 먼저 선택해 주세요.', 'error');
    return;
  }

  const url = buildHomeExternalMapUrl(site);
  if (!url) {
    showToast('현장 좌표 정보가 올바르지 않습니다.', 'error');
    return;
  }
  window.open(url, '_blank', 'noopener');
}

function buildHomeMapSheetNode(site) {
  const wrapper = document.createElement('div');
  wrapper.className = 'home-map-sheet';

  const siteLat = Number(site?.latitude);
  const siteLng = Number(site?.longitude);
  const radius = Number(site?.radius_meters);
  const distance = Number(state.home.geoDistance);
  const accuracy = Number(state.home.positionAccuracy);

  const mapCard = document.createElement('article');
  mapCard.className = 'map-card';
  wrapper.appendChild(mapCard);

  const iframe = document.createElement('iframe');
  iframe.title = 'home-site-map';
  iframe.loading = 'lazy';
  iframe.referrerPolicy = 'no-referrer-when-downgrade';
  iframe.src = buildGoogleMapsEmbedUrl(siteLat, siteLng, radius) || buildOpenStreetMapEmbedUrl(siteLat, siteLng, radius);
  mapCard.appendChild(iframe);

  const labels = document.createElement('div');
  labels.className = 'map-card-labels';
  mapCard.appendChild(labels);

  const sitePill = document.createElement('span');
  sitePill.className = 'status-pill status-pill-warn';
  sitePill.textContent = getHomeSiteDisplayName(site);
  labels.appendChild(sitePill);

  const geoPill = document.createElement('span');
  if (state.home.geoStatus === 'within') {
    geoPill.className = 'status-pill status-pill-success';
    geoPill.textContent = '반경 내';
  } else if (state.home.geoStatus === 'outside') {
    geoPill.className = 'status-pill status-pill-error';
    geoPill.textContent = '범위 밖';
  } else if (state.home.geoStatus === 'low_accuracy') {
    geoPill.className = 'status-pill status-pill-warn';
    geoPill.textContent = '정확도 낮음';
  } else {
    geoPill.className = 'status-pill status-pill-warn';
    geoPill.textContent = '확인 중';
  }
  labels.appendChild(geoPill);

  const metaGrid = document.createElement('div');
  metaGrid.className = 'home-map-meta-grid';
  wrapper.appendChild(metaGrid);

  const appendMeta = (label, value) => {
    const item = document.createElement('div');
    item.className = 'home-map-meta';
    const labelEl = document.createElement('span');
    labelEl.textContent = label;
    const valueEl = document.createElement('strong');
    valueEl.textContent = value;
    item.appendChild(labelEl);
    item.appendChild(valueEl);
    metaGrid.appendChild(item);
  };

  appendMeta('선택 현장', getHomeSiteDisplayName(site));
  appendMeta('현재 거리', formatDistanceMeters(distance));
  appendMeta('허용 반경', `${Number.isFinite(radius) ? Math.round(radius) : '-'}m`);
  appendMeta('GPS 정확도', `±${Number.isFinite(accuracy) ? Math.round(accuracy) : '-'}m`);

  const externalBtn = document.createElement('button');
  externalBtn.type = 'button';
  externalBtn.className = 'btn btn-secondary';
  externalBtn.dataset.action = 'home-map-open-external';
  externalBtn.dataset.siteCode = String(site.site_code || '');
  externalBtn.textContent = '외부 지도 열기';
  wrapper.appendChild(externalBtn);

  return wrapper;
}

function onHomeMap() {
  const site = getSelectedHomeSite();
  if (!site) {
    showToast('근무 현장를 먼저 선택해 주세요.', 'error');
    return;
  }
  const siteLat = Number(site.latitude);
  const siteLng = Number(site.longitude);
  if (!Number.isFinite(siteLat) || !Number.isFinite(siteLng)) {
    showToast('현장 좌표 정보가 올바르지 않습니다.', 'error');
    return;
  }
  openSheet({
    title: '지도에서 보기',
    contentNode: buildHomeMapSheetNode(site),
    actions: [
      { label: '닫기', variant: 'btn-secondary', action: 'sheet-close' },
    ],
  });
}

async function onHomeWeekOpenDate(dateKey) {
  const key = String(dateKey || '').trim();
  if (!/^\d{4}-\d{2}-\d{2}$/.test(key)) return;

  const month = key.slice(0, 7);
  const monthInput = $('#scheduleMonth');
  if (monthInput) monthInput.value = month;
  state.schedule.month = month;
  state.schedule.selectedDateKey = key;

  const moved = await navigateToRoute(ROUTE_SCHEDULE_CALENDAR);
  if (!moved) return;
  onScheduleSelectDate(key, { openSheetOnSelect: true });
}

async function onHomeRefreshLocation() {
  await requestHomeLocation({ forceToast: true });
}

async function onHomeOpenScheduleTools() {
  if (!can('scheduleWrite')) {
    showToast('스케줄 생성 권한이 없습니다.', 'error', 2600);
    return;
  }
  const moved = await navigateToRoute(ROUTE_ADMIN_SCHEDULE_TOOLS);
  if (!moved) return;
  showToast('스케줄 생성 화면으로 이동했습니다.', 'info', 1800);
}

async function onHomeRefreshWeek() {
  try {
    clearHeavyApiCache('home-sites:');
    clearHeavyApiCache('attendance-records:');
    invalidateScheduleCache();
    const result = await loadDashboard({ quiet: false, force: true });
    if (result && result.ok === false) {
      throw new Error(result.message || '근무현황 동기화 실패');
    }
    if (state.pollSuspended && state.token) {
      ensurePolling();
    }
    showToast('데이터를 새로고침했습니다.', 'success', 1800);
  } catch (err) {
    state.home.weekLoading = false;
    state.home.weekError = normalizeActionError(err, '이번 주 근무현황을 불러오지 못했습니다. 새로고침을 시도해 주세요.');
    state.home.weekEntries = [];
    renderHomeWeekStrip();
    showToast(state.home.weekError, 'error', 3200);
  }
}

async function onHomeOpenSettings() {
  const appPlugin = window.Capacitor?.Plugins?.App;
  if (appPlugin && typeof appPlugin.openSettings === 'function') {
    await appPlugin.openSettings();
    return;
  }
  showToast('설정 앱에서 RG ARLS 위치 권한을 허용해 주세요.', 'info', 3200);
}

function formatAttendanceRequestReason(reasonCode) {
  return ATTENDANCE_REQUEST_REASON_LABELS[String(reasonCode || '').trim()] || '기타';
}

function normalizeLeaveInternalReasonCode(leaveType = '', reason = '') {
  const type = String(leaveType || '').trim().toLowerCase();
  const reasonText = String(reason || '').trim().toLowerCase();
  if (type === 'sick' || reasonText.includes('병가')) return 'sick';
  if (type === 'early_leave' || type === 'early') return 'early_leave';
  if (type === 'other' && reasonText.includes('조퇴')) return 'early_leave';
  if (type === 'other' && reasonText.includes('병가')) return 'sick';
  if (type === 'other') return 'other';
  if (type === 'half') return 'half';
  return 'annual';
}

function resolveLeaveDisplayType(leaveType = '', reason = '') {
  const type = String(leaveType || '').trim().toLowerCase();
  if (type === 'half') return 'half';
  const internalCode = normalizeLeaveInternalReasonCode(type, reason);
  if (internalCode === 'half') return 'half';
  return 'annual';
}

function formatLeaveTypeLabel(leaveType, reason = '') {
  const displayType = resolveLeaveDisplayType(leaveType, reason);
  return LEAVE_TYPE_LABELS[displayType] || '연차';
}

function formatLeaveInternalReasonLabel(leaveType = '', reason = '') {
  const internalCode = normalizeLeaveInternalReasonCode(leaveType, reason);
  return LEAVE_INTERNAL_REASON_LABELS[internalCode] || '';
}

function setLeaveAttachmentHint(message = '선택된 첨부가 없습니다.') {
  const hintEl = $('#leaveAttachmentHint');
  if (!hintEl) return;
  hintEl.textContent = message;
}

function clearLeaveAttachmentSelection() {
  const fileInput = $('#leaveAttachments');
  if (fileInput instanceof HTMLInputElement) {
    fileInput.value = '';
  }
  setLeaveAttachmentHint('선택된 첨부가 없습니다.');
}

function getLeaveAttachmentNamesFromInput() {
  const fileInput = $('#leaveAttachments');
  const files = fileInput instanceof HTMLInputElement && fileInput.files
    ? Array.from(fileInput.files)
    : [];
  return files
    .map((file) => String(file?.name || '').trim())
    .filter(Boolean);
}

function updateLeaveFormState({ enforceHalfDayRange = true } = {}) {
  const leaveType = String($('#leaveType')?.value || '').trim().toLowerCase();
  const halfField = $('#leaveHalfSlotField');
  const halfSlot = $('#leaveHalfSlot');
  const startInput = $('#leaveStart');
  const endInput = $('#leaveEnd');
  const reasonInput = $('#leaveReason');

  const isHalf = leaveType === 'half';
  if (halfField) {
    halfField.classList.toggle('hidden', !isHalf);
  }
  if (halfSlot instanceof HTMLSelectElement) {
    halfSlot.disabled = !isHalf;
    if (!isHalf) {
      halfSlot.value = 'am';
    }
  }
  if (endInput instanceof HTMLInputElement) {
    endInput.disabled = isHalf;
  }

  if (
    enforceHalfDayRange
    && isHalf
    && startInput instanceof HTMLInputElement
    && endInput instanceof HTMLInputElement
    && startInput.value
  ) {
    endInput.value = startInput.value;
  }

  const reasonText = String(reasonInput instanceof HTMLInputElement ? reasonInput.value : '').trim();
  document.querySelectorAll('#leaveQuickTypeChips [data-leave-type]').forEach((button) => {
    const chipType = String(button?.dataset?.leaveType || '').trim().toLowerCase();
    const chipReason = String(button?.dataset?.reasonPreset || '').trim();
    let active = chipType === leaveType;
    if (active && chipReason) {
      active = reasonText === chipReason || !reasonText;
    }
    button.classList.toggle('active', active);
  });
}

function normalizeLeaveStatusFilter(value = '') {
  return normalizeLeaveHistoryFilter(value);
}

function resolveLeaveManagerScope() {
  if (!state.leaveView) {
    state.leaveView = createInitialLeaveViewState();
  }
  const managerMode = isManagerShellRole();
  const reviewCapable = Boolean(can('leaveReview'));
  if (!managerMode || !reviewCapable) return 'mine';
  const ownEmployeeCode = String(state.user?.employee_code || '').trim();
  const preferred = normalizeLeaveManagerScope(state.leaveView.managerScope);
  if (preferred === 'mine' && !ownEmployeeCode) return 'team';
  return preferred;
}

function setLeaveManagerScope(scope = 'mine') {
  if (!state.leaveView) {
    state.leaveView = createInitialLeaveViewState();
  }
  state.leaveView.managerScope = normalizeLeaveManagerScope(scope);
}

function setLeaveStatusFilter(filter = 'all') {
  if (!state.leaveView) {
    state.leaveView = createInitialLeaveViewState();
  }
  state.leaveView.statusFilter = normalizeLeaveStatusFilter(filter);
}

function formatLeaveUnits(value = 0, suffix = '일') {
  const num = Number(value || 0);
  if (!Number.isFinite(num)) return `0${suffix}`;
  const normalized = Math.abs(num - Math.round(num)) < 0.01
    ? String(Math.round(num))
    : num.toFixed(1);
  return `${normalized}${suffix}`;
}

function calculateLeaveUsageUnits(row = {}) {
  const status = String(row?.status || '').trim().toLowerCase();
  if (status !== 'approved') return { annual: 0, half: 0 };
  const displayType = resolveLeaveDisplayType(row?.leave_type, row?.reason);
  if (displayType === 'half') {
    return { annual: 0.5, half: 0.5 };
  }
  const dateKeys = buildLeaveDateKeys(row?.start_at, row?.end_at, row?.leave_type);
  const days = Math.max(1, dateKeys.length || 0);
  return { annual: days, half: 0 };
}

function buildLeaveSummary(rows = [], { scope = 'mine' } = {}) {
  const list = Array.isArray(rows) ? rows : [];
  const todayKey = toLocalDateKey(new Date());
  const weekKeys = new Set(getCurrentWeekDates(new Date()).map((date) => toLocalDateKey(date)));
  const activeStatuses = new Set(['approved', 'pending']);
  const todayEmployees = new Set();
  const weekEmployees = new Set();

  let annualUsed = 0;
  let halfUsed = 0;

  list.forEach((row) => {
    const usage = calculateLeaveUsageUnits(row);
    annualUsed += usage.annual;
    halfUsed += usage.half;

    const status = String(row?.status || '').trim().toLowerCase();
    if (!activeStatuses.has(status)) return;
    const employeeCode = String(row?.employee_code || '').trim() || String(row?.employee_name || '').trim();
    const keys = buildLeaveDateKeys(row?.start_at, row?.end_at, row?.leave_type);
    if (!employeeCode || !keys.length) return;
    if (keys.includes(todayKey)) {
      todayEmployees.add(employeeCode);
    }
    if (keys.some((key) => weekKeys.has(key))) {
      weekEmployees.add(employeeCode);
    }
  });

  const annualRemaining = Math.max(0, LEAVE_ANNUAL_DEFAULT_ALLOWANCE - annualUsed);
  return {
    scope,
    annualRemaining,
    annualUsed,
    halfUsed,
    todayLeaveCount: todayEmployees.size,
    weekLeaveCount: weekEmployees.size,
    pendingCount: list.filter((row) => String(row?.status || '').trim().toLowerCase() === 'pending').length,
    updatedAt: new Date().toISOString(),
  };
}

function setLeaveHint(message = '', level = 'info') {
  const hintEl = $('#leaveListHint');
  if (!hintEl) return;
  const text = String(message || '').trim();
  hintEl.textContent = text || '휴가 내역을 불러오는 중입니다.';
  hintEl.classList.remove('state-info', 'state-success', 'state-error');
  if (level === 'error') {
    hintEl.classList.add('state-error');
  } else if (level === 'success') {
    hintEl.classList.add('state-success');
  } else {
    hintEl.classList.add('state-info');
  }
}

