  right.appendChild(typePill);

  const statusPill = document.createElement('span');
  statusPill.className = requestStatusPillClass(row?.status || 'pending');
  statusPill.textContent = getUiStatusLabel(row?.status || 'pending');
  right.appendChild(statusPill);

  li.appendChild(right);
