function persistSession() {
  const token = String(state.token || '').trim();
  const refreshToken = String(state.refreshToken || '').trim();
  if (!token) return;
  const payload = { token, refreshToken, user: state.user || null };
  try {
    localStorage.setItem(SESSION_KEY, JSON.stringify(payload));
  } catch {
    // no-op
  }
  persistStoredAuthTokens(token, refreshToken);
  console.info('[RG ARLS][Auth] token stored', {
    hasAccessToken: Boolean(token),
    hasRefreshToken: Boolean(refreshToken),
  });
}

function clearSession() {
  if (state.reminder.syncTimer) {
    clearTimeout(state.reminder.syncTimer);
  }
  clearHomeAttendanceCheckWatch();
  clearHomeAttendanceCheckMapObjects();
  clearMasterSocBackfillCooldownTimer();
  cancelAllScheduledLocalReminders().catch(() => {
    // no-op
  });
  tokenRefreshPromise = null;
  state.token = '';
  state.refreshToken = '';
  state.user = null;
  state.notificationCount = 0;
  state.notificationItems = [];
  state.tenantValid = false;
  state.tenantChecking = false;
  state.loginTenantBeforeSuperAdmin = '';
  state.superAdminLoginMode = false;
  state.home = createInitialHomeState();
  state.attendanceRequest = createInitialAttendanceRequestState();
  state.attendanceView = createInitialAttendanceViewState();
  state.leaveView = createInitialLeaveViewState();
  if (!state.employeeAdmin || typeof state.employeeAdmin !== 'object') {
    state.employeeAdmin = createInitialEmployeeAdminState();
  } else {
    state.employeeAdmin.formLookupPending = 0;
    state.employeeAdmin.formLookupLoading = false;
    state.employeeAdmin.formTenantRequestSeq = 0;
    state.employeeAdmin.formSiteRequestSeq = 0;
  }
  state.correction = createInitialCorrectionState();
  state.schedule = createInitialScheduleState();
  state.ops = createInitialOpsState();
  state.supportStatus = createInitialSupportStatusState();
  state.reminder = createInitialReminderState();
  state.devAdmin = createInitialDevAdminState();
  state.integration = createInitialIntegrationState();
  state.uiContext = createInitialUiContextState();
  state.viewRuntime = createInitialViewRuntimeState();
  state.requestsTabView = 'requests';
  state.approvalTab = APPROVAL_TAB_CHECKIN;
  state.requestsMyFilter = REQUESTS_MY_FILTER_ALL;
  state.requestsManagerTab = REQUESTS_MANAGER_TAB_PENDING;
  state.requestsManagerProcessedType = 'all';
  state.requestsManagerProcessedDate = '';
  state.employeeRequestItemsById = new Map();
  state.managerRequestItemsById = new Map();
  state.approvalItemsById = new Map();
  state.leaveApprovalItemsById = new Map();
  state.approvalPullStartY = null;
  state.sites = [];
  state.siteCatalog = [];
  state.siteAddressResults = [];
  state.siteEditorLookupSeq = 0;
  state.siteEditorLookupPending = 0;
  state.siteEditorLookupLoading = false;
  setAuthStatus(AUTH_STATUS_UNAUTHENTICATED);
  state.currentRoute = ROUTE_LOGIN;
  state.lastAllowedRoute = DEFAULT_AUTH_ROUTE;
  state.pendingRouteAfterLogin = DEFAULT_AUTH_ROUTE;
  state.skipNextHashEvent = false;
  revokeRequestPhotoPreviewUrls();
  scheduleDataProvider = null;
  try {
    localStorage.removeItem(SESSION_KEY);
    localStorage.removeItem(UI_ACTIVE_TENANT_FILTER_KEY);
  } catch {
    // no-op
  }
  persistStoredAuthTokens('', '');
}

function loadSession() {
  let parsed = null;
  try {
    const raw = localStorage.getItem(SESSION_KEY);
    parsed = raw ? JSON.parse(raw) : null;
  } catch {
    parsed = null;
  }

  const sessionToken = normalizeStoredJwtToken(parsed?.token);
  const accessToken = sessionToken || normalizeStoredJwtToken(readStoredAuthTokenValue(ACCESS_TOKEN_KEY));
  const refreshToken = normalizeStoredJwtToken(parsed?.refreshToken || parsed?.refresh_token) || normalizeStoredJwtToken(readStoredAuthTokenValue(REFRESH_TOKEN_KEY));
  const user = parsed?.user && typeof parsed.user === 'object' ? parsed.user : null;
  if (!accessToken && !refreshToken) return null;
  return {
    token: accessToken,
    refreshToken,
    user,
  };
}

