async function fetchEmployeeLeaveRows() {
  if (!can('leave')) return [];
  const params = new URLSearchParams({ limit: '200' });
  const ownEmployeeCode = String(state.user?.employee_code || '').trim();
  if (ownEmployeeCode) params.set('employee_code', ownEmployeeCode);
  return apiRequest(`/leaves?${params.toString()}`);
}

async function fetchManagerAttendanceRequestRows() {
  if (!can('attendanceReview')) return [];
  return fetchManagerAttendanceRequests(['pending', 'approved', 'rejected', 'cancelled']);
}

async function fetchManagerLeaveRequestRows() {
  if (!can('leaveReview')) return [];
  return fetchManagerLeaveRequests(['pending', 'approved', 'rejected', 'cancelled']);
}

async function fetchRequestsDocumentRows() {
  if (isManagerShellRole()) {
    const statuses = ['requested', 'generating', 'issued', 'rejected'];
    const results = await Promise.all(statuses.map((status) => apiRequest(
      `/admin/hr/documents/employment-certificate/requests?${new URLSearchParams({
        status,
        page: '1',
        pageSize: '120',
      }).toString()}`,
    )));
    const merged = [];
    const seen = new Set();
    results.forEach((rows) => {
      (Array.isArray(rows) ? rows : []).forEach((row) => {
        const id = String(row?.id || '').trim();
        if (!id || seen.has(id)) return;
        seen.add(id);
        merged.push(row);
      });
    });
    return merged;
  }
  await loadHrEmploymentQuota({ force: false });
  return loadHrEmploymentMyRequests({ force: false });
}

function getRequestsActiveRawRowsForCurrentTab() {
  const segment = normalizeRequestsTabView(state.requestsTabView);
  const managerMode = isManagerShellRole();
  if (segment === 'leave') {
    const rows = Array.isArray(state.leaveView?.rows) ? state.leaveView.rows : [];
    return rows.map((row) => buildRequestsLeaveItem(row, { managerMode }));
  }
  if (segment === 'approvals') {
    if (state.requestsManagerTab === REQUESTS_MANAGER_TAB_SOC) {
      const rows = Array.isArray(state.requestsWorkspace?.socRows) ? state.requestsWorkspace.socRows : [];
      return rows.map((row) => buildRequestsSocItem(row));
    }
    const rows = Array.isArray(state.requestsWorkspace?.approvalRows) ? state.requestsWorkspace.approvalRows : [];
    return rows;
  }
  if (segment === 'correction') {
    const rows = Array.isArray(state.requestsWorkspace?.correctionRows)
      ? state.requestsWorkspace.correctionRows
      : (Array.isArray(state.correction?.items) ? state.correction.items : []);
    return rows.map((row) => buildRequestsCorrectionItem(row, { managerMode }));
  }
  if (segment === 'documents') {
    const rows = Array.isArray(state.requestsWorkspace?.documentRows) ? state.requestsWorkspace.documentRows : [];
    return rows.map((row) => buildRequestsDocumentItem(row, { adminMode: isManagerShellRole() }));
  }
  if (managerMode) {
    const rows = Array.isArray(state.requestsWorkspace?.attendanceRows) ? state.requestsWorkspace.attendanceRows : [];
    return rows.map((row) => buildRequestsAttendanceItem(row, { managerMode: true }));
  }
  const rows = Array.isArray(state.requestsWorkspace?.attendanceRows) ? state.requestsWorkspace.attendanceRows : [];
  return rows.map((row) => buildRequestsAttendanceItem(row, { managerMode: false }));
}

async function loadRequestsWorkspaceCurrentTab({ silent = false } = {}) {
  ensureRequestsWorkspaceFilters();
  const segment = normalizeRequestsTabView(state.requestsTabView);
  const managerMode = isManagerShellRole();
  if (segment === 'leave') {
    setRequestsWorkspaceHeading(segment);
    return loadLeaves();
  }
  renderRequestsWorkspaceLoading();
  try {
    if (segment === 'approvals') {
      if (state.requestsManagerTab === REQUESTS_MANAGER_TAB_SOC) {
        const params = new URLSearchParams();
        params.set('limit', '80');
        const tenantCode = getTenantCodeForScopedAdminApi();
        if (tenantCode) params.set('tenant_code', tenantCode);
        const socRows = await apiRequest(`/integrations/soc/events?${params.toString()}`);
        state.requestsWorkspace.socRows = (Array.isArray(socRows) ? socRows : []).map((row) => ({
          ...row,
          key: `soc-${row?.id || row?.received_at || Math.random().toString(36).slice(2, 8)}`,
          receivedAt: row?.received_at || '',
          eventType: row?.event_type || '',
          errorText: row?.error_text || '',
          appliedChanges: row?.applied_changes && typeof row.applied_changes === 'object' ? row.applied_changes : {},
        }));
      } else {
        const statuses = state.requestsManagerTab === REQUESTS_MANAGER_TAB_PROCESSED
          ? ['approved', 'rejected', 'cancelled']
          : ['pending'];
        const [attendanceRows, leaveRows, documentRows] = await Promise.all([
          can('attendanceReview') ? fetchManagerAttendanceRequests(statuses) : Promise.resolve([]),
          can('leaveReview') ? fetchManagerLeaveRequests(statuses) : Promise.resolve([]),
          fetchRequestsDocumentRows(),
        ]);
        const correctionStatuses = state.requestsManagerTab === REQUESTS_MANAGER_TAB_PROCESSED
          ? ['approved', 'rejected']
          : ['pending'];
        const correctionRows = can('attendanceReview') ? getCorrectionRowsByStatuses(correctionStatuses) : [];
        const approvalDocumentStatuses = new Set(
          state.requestsManagerTab === REQUESTS_MANAGER_TAB_PROCESSED
            ? ['issued', 'rejected']
            : ['requested', 'generating'],
        );
        state.requestsWorkspace.approvalRows = [
          ...(Array.isArray(attendanceRows) ? attendanceRows : []).map((row) => buildRequestsAttendanceItem(row, { managerMode: true })),
          ...(Array.isArray(leaveRows) ? leaveRows : []).map((row) => buildRequestsLeaveItem(row, { managerMode: true })),
          ...(Array.isArray(correctionRows) ? correctionRows : []).map((row) => buildRequestsCorrectionItem(row, { managerMode: true })),
          ...(Array.isArray(documentRows) ? documentRows : [])
            .filter((row) => approvalDocumentStatuses.has(normalizeHrRequestStatus(row?.status)))
            .map((row) => buildRequestsDocumentItem(row, { adminMode: true })),
        ];
      }
    } else if (segment === 'correction') {
      state.requestsWorkspace.correctionRows = Array.isArray(state.correction?.items) ? state.correction.items : [];
    } else if (segment === 'documents') {
      state.requestsWorkspace.documentRows = await fetchRequestsDocumentRows();
    } else {
      state.requestsWorkspace.attendanceRows = managerMode ? await fetchManagerAttendanceRequestRows() : await fetchEmployeeAttendanceRequestRows();
    }

    const rows = getRequestsActiveRawRowsForCurrentTab();
    setRequestsWorkspaceRows(rows);
    setRequestsWorkspaceHeading(segment);
    renderRequestsWorkspaceView();
    return rows;
  } catch (err) {
    setRequestsWorkspaceRows([]);
    setRequestsWorkspaceHeading(segment);
    renderRequestsWorkspaceView();
    if (!silent) {
      showToast(normalizeActionError(err, '요청 데이터를 불러오지 못했습니다.'), 'error', 4200);
    }
    return [];
  }
}

