async function loadRoadmapViewPresenter() {
  renderRoadmapView();
}

function renderMasterConsoleTenantList() {
  const list = $('#masterConsoleTenantList');
  if (!list) return;
  clearList(list);

  const routeMeta = getMasterRouteContext();
  const rows = [
    { tenant_code: 'MASTER', tenant_name: '마스터 콘솔', is_active: true },
    ...(Array.isArray(state.devAdmin.tenants) ? state.devAdmin.tenants : [])
      .filter((item) => !item?.is_deleted)
      .filter((item) => String(item?.tenant_code || '').trim().toUpperCase() !== 'MASTER'),
  ];

  if (!rows.length) {
    renderEmptyState(list, '회사가 없습니다.');
    return;
  }

  rows.forEach((row) => {
    const code = String(row?.tenant_code || '').trim().toUpperCase();
    const tenantId = String(row?.id || '').trim();
    if (!code) return;
    const name = String(row?.tenant_name || '').trim();
    const active = row?.is_active !== false || code === 'MASTER';
    const li = document.createElement('li');
    const btn = document.createElement('button');
    btn.type = 'button';
    const isActive = code === 'MASTER'
      ? !routeMeta.tenantId
      : Boolean(tenantId && String(routeMeta.tenantId || '').trim() === tenantId);
    btn.className = `drawer-item master-console-tenant-btn${isActive ? ' active' : ''}`;
    btn.dataset.action = 'master-route';
    btn.dataset.route = code === 'MASTER'
      ? ROUTE_MASTER_TENANTS
      : buildMasterTenantRoute(tenantId, 'overview');
    btn.disabled = !active;
    btn.innerHTML = `<strong>${code}</strong><span>${name || '-'}${active ? '' : ' · 비활성'}</span>`;
    li.appendChild(btn);
    list.appendChild(li);
  });
}

async function loadDevConsoleViewPresenter() {
  if (!can('tenantManage')) {
    renderEmptyState($('#masterTenantCardList'), '마스터 콘솔 접근 권한이 없습니다.');
    setInlineStatus('#masterConsoleStatus', '개발자 권한이 필요합니다.', 'error');
    return;
  }

  renderMasterRouteTabs();
  renderMasterRoutePanels();
  const currentDevConsoleRoute = normalizeRoutePath(state.currentRoute || '');
  const companyListRouteSet = new Set([ROUTE_MASTER_TENANTS, ROUTE_DEV_TENANTS]);
  if (companyListRouteSet.has(currentDevConsoleRoute)) {
    markViewPerfStage('critical_ui_ready', {
      routePath: currentDevConsoleRoute,
      viewName: 'dev-console',
    });
  }
  const devConsoleApiStartedAt = getPerfNowMs();

  setInlineStatus('#masterConsoleStatus', '회사 카탈로그 동기화 중...', 'info');
  await ensureDevTenantCatalog({ force: true });
  const routeMeta = syncMasterRouteContext();
  const tenantScopedRoutes = new Set(['tenant-overview', 'tenant-user-detail', 'tenant-security']);
  if (tenantScopedRoutes.has(routeMeta.name)) {
    const tenant = getMasterTenantByRouteOrContext();
    if (tenant) {
      await loadMasterTenantUsers(tenant, { force: true });
    }
  }
  if (routeMeta.name === 'tenant-users') {
    try {
      await loadMasterTenantProfile({ force: true });
    } catch (error) {
      setInlineStatus('#masterTenantProfileStatus', normalizeActionError(error, '회사 정보를 불러오지 못했습니다.'), 'error');
    }
  }
  renderMasterConsoleSummary();
  renderMasterAuditFilters();
  renderMasterRoutePanels();
  if (companyListRouteSet.has(normalizeRoutePath(state.currentRoute || ''))) {
    markViewPerfStage('critical_ui_ready', {
      routePath: normalizeRoutePath(state.currentRoute || ''),
      viewName: 'dev-console',
      metrics: {
        api_ms: getPerfNowMs() - devConsoleApiStartedAt,
      },
    });
  }
  setInlineStatus('#masterConsoleStatus', '동기화 완료', 'success');
}

async function loadEmployeesViewPresenter() {
  const isDevRole = getNavigationRole() === 'DEV';
  const includeInactiveToggle = $('#employeeIncludeInactive');
  const includeDeletedToggle = $('#employeeIncludeDeleted');
  const employeeSearchInput = $('#employeeSearchInput');
  if (includeInactiveToggle instanceof HTMLInputElement) includeInactiveToggle.checked = false;
  if (includeDeletedToggle instanceof HTMLInputElement) includeDeletedToggle.checked = false;
  if (employeeSearchInput instanceof HTMLInputElement) {
    employeeSearchInput.value = String(state.employeeAdmin?.searchQuery || '').trim();
  }
  const includeInactiveLabel = document.querySelector('label[for="employeeIncludeInactive"]');
  const includeDeletedLabel = document.querySelector('label[for="employeeIncludeDeleted"]');
  if (includeInactiveLabel instanceof HTMLElement) includeInactiveLabel.classList.toggle('hidden', !isDevRole);
  if (includeDeletedLabel instanceof HTMLElement) includeDeletedLabel.classList.toggle('hidden', !isDevRole);

  const route = normalizeRoutePath(state.currentRoute || '');
  const inCreateRoute = route === ROUTE_ADMIN_EMPLOYEES_NEW && can('employeeWrite');
  const inImportRoute = route === ROUTE_ADMIN_EMPLOYEES_IMPORT && can('employeeWrite');
  const inEditorRoute = inCreateRoute || inImportRoute;
  if (inCreateRoute) {
    const shellRenderStartedAt = getPerfNowMs();
    state.employeeAdmin.registrationMode = EMPLOYEE_REG_MODE_MANUAL;
    ensureEmployeeFormPresentation();
    markViewPerfStage('first_paintable_ui', {
      routePath: ROUTE_ADMIN_EMPLOYEES_NEW,
      viewName: 'employees',
      metrics: {
        api_ms: 0,
        render_ms: getPerfNowMs() - shellRenderStartedAt,
      },
    });
    markViewPerfStage('critical_ui_ready', {
      routePath: ROUTE_ADMIN_EMPLOYEES_NEW,
      viewName: 'employees',
    });
  } else if (inImportRoute) {
    state.employeeAdmin.registrationMode = EMPLOYEE_REG_MODE_IMPORT;
    ensureEmployeeFormPresentation();
    markViewPerfStage('critical_ui_ready', {
      routePath: ROUTE_ADMIN_EMPLOYEES_IMPORT,
      viewName: 'employees',
    });
  }
  const hasEmployeeCache = Array.isArray(state.employeeAdmin.rows) && state.employeeAdmin.rows.length > 0;
  const shouldRefresh = !hasEmployeeCache
    || (Date.now() - Number(employeesPresenterLastRefreshAt || 0)) > EMPLOYEES_VIEW_STALE_MS;
  const tenantFilterTask = syncEmployeeTenantFilterOptions({ force: shouldRefresh });
  if (hasEmployeeCache) {
    renderEmployeesFromCache();
  }

  if (!inEditorRoute) {
    runActionSafely(
      (async () => {
        await tenantFilterTask;
        await Promise.all([
          syncEmployeeSiteFilterOptions({ force: shouldRefresh }),
          loadEmployees({
            preferCache: true,
            skipNetworkWhenCached: hasEmployeeCache && !shouldRefresh,
          }),
        ]);
        employeesPresenterLastRefreshAt = Date.now();
      })(),
      '직원 목록 동기화에 실패했습니다.',
    );
    state.employeeAdmin.registrationMode = EMPLOYEE_REG_MODE_MANUAL;
    state.employeeAdmin.selectedEmployeeId = '';
    ensureEmployeeFormPresentation();
    return;
  }

  runActionSafely(
    (async () => {
      await tenantFilterTask;
      await Promise.all([
        syncEmployeeSiteFilterOptions({ force: false }),
        loadEmployees({ preferCache: true }),
      ]);
      if (inCreateRoute) {
        const selected = getEmployeeRowById(state.employeeAdmin.selectedEmployeeId || '');
        await syncEmployeeFormTenantOptions({ force: true, clearSelection: !selected });
        if (selected) {
          fillEmployeeFormForEdit(selected);
        } else {
          resetEmployeeForm();
        }
        state.employeeAdmin.registrationMode = EMPLOYEE_REG_MODE_MANUAL;
      } else if (inImportRoute) {
        state.employeeAdmin.registrationMode = EMPLOYEE_REG_MODE_IMPORT;
        state.employeeAdmin.selectedEmployeeId = '';
        await ensureEmployeeScopeSitesLoaded();
        renderEmployeeRosterImportRows();
      }
      ensureEmployeeFormPresentation();
    })(),
    '직원 등록/수정 참고 데이터를 불러오지 못했습니다.',
  );
}

function ensureHrDocsState() {
  if (!state.hrDocs || typeof state.hrDocs !== 'object') {
    state.hrDocs = createInitialHrDocumentsState();
  }
  return state.hrDocs;
}

function isHrAdminRole() {
  return getNavigationRole() === 'DEV' || getNavigationRole() === 'BRANCH_MANAGER';
}

function isHrTemplateManagerRole() {
  return getNavigationRole() === 'DEV';
}

function isHrEmployeeRole() {
  return !isHrAdminRole();
}

function normalizeHrPurposeCode(value = 'BANK') {
  const code = String(value || '').trim().toUpperCase();
  if (!HR_PURPOSE_CODES.has(code)) return 'BANK';
  return code;
}

function normalizeHrRequestStatus(value = '') {
  const status = String(value || '').trim().toLowerCase();
  if (!status) return 'requested';
  return status;
}

function normalizeHrAdminPanel(value = '') {
  const panel = String(value || '').trim().toLowerCase();
  return panel === 'templates' ? 'templates' : 'requests';
}

function getHrRequestStatusLabel(value = '') {
  const key = normalizeHrRequestStatus(value);
  return HR_REQUEST_STATUS_LABELS[key] || key;
}

function getHrRequestStatusPillClass(value = '') {
  const key = normalizeHrRequestStatus(value);
  if (key === 'issued') return 'status-pill status-pill-success';
  if (key === 'generating') return 'status-pill status-pill-warn';
  if (key === 'rejected' || key === 'failed') return 'status-pill status-pill-error';
  return 'status-pill status-pill-neutral';
}

function renderHrAdminPanelTabs() {
  const hrState = ensureHrDocsState();
  const templateManagerMode = isHrTemplateManagerRole();
  const activePanel = templateManagerMode
    ? normalizeHrAdminPanel(hrState.adminPanel || 'requests')
    : 'requests';
  hrState.adminPanel = activePanel;
  document.querySelectorAll('.hr-admin-panel-tabs [data-action="hr-admin-panel-tab"]').forEach((button) => {
    const panel = normalizeHrAdminPanel(button?.dataset?.panel || 'requests');
    const isTemplateTab = panel === 'templates';
    button.classList.toggle('hidden', isTemplateTab && !templateManagerMode);
    button.classList.toggle('active', panel === activePanel);
  });
  const requestsCard = $('#hrEmploymentAdminCard');
  const templateCard = $('#hrTemplateAdminCard');
  if (requestsCard) {
    requestsCard.classList.toggle('hidden', !isHrAdminRole() || activePanel !== 'requests');
  }
  if (templateCard) {
    templateCard.classList.toggle('hidden', !templateManagerMode || activePanel !== 'templates');
  }
}

function normalizeHrWorkspaceSegment(value = '') {
  const segment = String(value || '').trim().toLowerCase();
  if (segment === 'my-docs') return 'my-docs';
  if (segment === 'approvals') return 'approvals';
  if (segment === 'templates') return 'templates';
  return 'apply';
}

function resolveDefaultHrWorkspaceSegment() {
  if (isHrEmployeeRole()) return 'apply';
  return isHrTemplateManagerRole() ? 'approvals' : 'approvals';
}

function setHrWorkspaceSegment(value = '') {
  const hrState = ensureHrDocsState();
  hrState.workspaceSegment = normalizeHrWorkspaceSegment(value || hrState.workspaceSegment || resolveDefaultHrWorkspaceSegment());
  renderHrWorkspaceSegments();
}

function renderHrWorkspaceSegments() {
  const hrState = ensureHrDocsState();
  const employeeMode = isHrEmployeeRole();
  const adminMode = isHrAdminRole();
  const templateManagerMode = isHrTemplateManagerRole();
  let segment = normalizeHrWorkspaceSegment(hrState.workspaceSegment || resolveDefaultHrWorkspaceSegment());
  if (employeeMode && segment !== 'apply' && segment !== 'my-docs') {
    segment = 'apply';
  }
  if (adminMode && (segment === 'apply' || segment === 'my-docs')) {
    segment = 'approvals';
  }
  if (!templateManagerMode && segment === 'templates') {
    segment = 'approvals';
  }
  hrState.workspaceSegment = segment;

  const segmentWrap = $('#hrWorkspaceSegments');
  if (segmentWrap) {
    segmentWrap.querySelectorAll('[data-action="hr-workspace-segment"]').forEach((button) => {
      const buttonSegment = normalizeHrWorkspaceSegment(button?.dataset?.segment || 'apply');
      const isAdminTab = buttonSegment === 'approvals' || buttonSegment === 'templates';
      const isTemplateTab = buttonSegment === 'templates';
      const hidden = (employeeMode && isAdminTab) || (!employeeMode && (buttonSegment === 'apply' || buttonSegment === 'my-docs')) || (isTemplateTab && !templateManagerMode);
      button.classList.toggle('hidden', hidden);
      button.classList.toggle('active', !hidden && buttonSegment === segment);
      button.setAttribute('aria-pressed', !hidden && buttonSegment === segment ? 'true' : 'false');
    });
  }

  const showApply = segment === 'apply';
  const showMyDocs = segment === 'my-docs';
  const showApprovals = segment === 'approvals';
  const showTemplates = segment === 'templates';

  toggleVisibility('#hrDocumentHomeCard', true);
  toggleVisibility('#hrEmploymentEmployeeCard', employeeMode && showApply);
  toggleVisibility('#hrEmploymentMyRequestsCard', employeeMode && showMyDocs);

  if (showTemplates) {
    hrState.adminPanel = 'templates';
  } else if (showApprovals) {
    hrState.adminPanel = 'requests';
  }

  if (!adminMode) {
    toggleVisibility('#hrEmploymentAdminCard', false);
    toggleVisibility('#hrTemplateAdminCard', false);
  } else {
    renderHrAdminPanelTabs();
    if (showApprovals) {
      toggleVisibility('#hrEmploymentAdminCard', true);
      toggleVisibility('#hrTemplateAdminCard', false);
    } else if (showTemplates) {
      toggleVisibility('#hrEmploymentAdminCard', false);
      toggleVisibility('#hrTemplateAdminCard', templateManagerMode);
    }
  }
}

function formatHrPurposeLabel(code = '', text = '') {
  const normalizedCode = normalizeHrPurposeCode(code);
  if (normalizedCode === 'OTHER') {
    const detail = String(text || '').trim();
    return detail ? `기타 (${detail})` : '기타';
  }
  return HR_PURPOSE_LABELS[normalizedCode] || normalizedCode;
}

function renderHrDocCardSelection() {
  const hrState = ensureHrDocsState();
  let selected = String(hrState.selectedDocType || HR_DOC_TYPE_EMPLOYMENT_CERTIFICATE).trim();
  if (selected !== HR_DOC_TYPE_EMPLOYMENT_CERTIFICATE) {
    selected = HR_DOC_TYPE_EMPLOYMENT_CERTIFICATE;
    hrState.selectedDocType = selected;
  }
  document.querySelectorAll('#hrDocCardGrid .hr-doc-card').forEach((button) => {
    const docType = String(button?.dataset?.doc || '').trim();
    const isEmployment = docType === HR_DOC_TYPE_EMPLOYMENT_CERTIFICATE;
    const cardDisabled = !isEmployment;
    if (button instanceof HTMLButtonElement) {
      button.disabled = cardDisabled;
      button.setAttribute('aria-disabled', cardDisabled ? 'true' : 'false');
    }
    button.classList.toggle('hr-doc-card-disabled', cardDisabled);
    button.classList.toggle('active', !cardDisabled && docType === selected);
  });
}

function renderHrAdminStatusTabs() {
  const hrState = ensureHrDocsState();
  const selectedStatus = normalizeHrRequestStatus(hrState.adminStatus || 'requested');
  document.querySelectorAll('#hrEmploymentAdminStatusTabs [data-action="hr-admin-status-filter"]').forEach((button) => {
    const status = normalizeHrRequestStatus(button?.dataset?.status || 'requested');
    button.classList.toggle('active', status === selectedStatus);
  });
}

function updateHrRequestSubmitState() {
  const hrState = ensureHrDocsState();
  const submitBtn = $('#hrEmploymentRequestSubmitBtn');
  if (!(submitBtn instanceof HTMLButtonElement)) return;
  const purposeCode = normalizeHrPurposeCode(hrState.purposeCode || 'BANK');
  const purposeText = String(hrState.purposeText || '').trim();
  const canSubmit = !hrState.submitting && (
    purposeCode !== 'OTHER'
    || (purposeText.length >= 2 && purposeText.length <= 50)
  );
  submitBtn.disabled = !canSubmit;
}

function renderHrPurposeSelector() {
  const hrState = ensureHrDocsState();
  const selectedCode = normalizeHrPurposeCode(hrState.purposeCode || 'BANK');
  document.querySelectorAll('#hrPurposeCodeGroup [data-action="hr-purpose-select"]').forEach((button) => {
    const purposeCode = normalizeHrPurposeCode(button?.dataset?.purposeCode || 'BANK');
    button.classList.toggle('active', purposeCode === selectedCode);
  });
  const codeInput = $('#hrPurposeCode');
  if (codeInput instanceof HTMLInputElement) {
    codeInput.value = selectedCode;
  }
  const otherField = $('#hrPurposeOtherField');
  if (otherField) {
    otherField.classList.toggle('hidden', selectedCode !== 'OTHER');
  }
  const otherInput = $('#hrPurposeOtherText');
  if (otherInput instanceof HTMLInputElement) {
    otherInput.value = String(hrState.purposeText || '');
    otherInput.required = selectedCode === 'OTHER';
  }
  updateHrRequestSubmitState();
}

function renderHrQuota() {
  const hrState = ensureHrDocsState();
  const quotaPill = $('#hrEmploymentQuota');
  if (!quotaPill) return;
  const limit = Number(hrState.dailyLimit || HR_EMPLOYMENT_DAILY_LIMIT);
  const remaining = Math.max(0, Number(hrState.todayRemaining ?? limit));
  quotaPill.textContent = `오늘 남은 요청: ${remaining}/${limit}`;
}

function renderHrMyRequestRows() {
  const tbody = $('#hrEmploymentMyRequestTableBody');
  if (!(tbody instanceof HTMLElement)) return;
  const hrState = ensureHrDocsState();
  const rows = Array.isArray(hrState.myRows) ? hrState.myRows : [];
  if (!rows.length) {
    renderAdminTableEmptyState(tbody, 6, '요청 내역이 없습니다.');
    return;
  }

  tbody.innerHTML = '';
  rows.forEach((row) => {
    const tr = document.createElement('tr');

    const requestedAtTd = document.createElement('td');
    requestedAtTd.textContent = formatDateLabel(row?.requested_at, '-');
    tr.appendChild(requestedAtTd);

    const purposeTd = document.createElement('td');
    purposeTd.textContent = formatHrPurposeLabel(row?.purpose_code, row?.purpose_text);
    tr.appendChild(purposeTd);

    const statusTd = document.createElement('td');
    const statusPill = document.createElement('span');
    statusPill.className = getHrRequestStatusPillClass(row?.status);
    statusPill.textContent = getHrRequestStatusLabel(row?.status);
    statusTd.appendChild(statusPill);
    tr.appendChild(statusTd);

    const rejectionTd = document.createElement('td');
    rejectionTd.textContent = String(row?.rejection_reason || '').trim() || '-';
    tr.appendChild(rejectionTd);

    const issueTd = document.createElement('td');
    issueTd.textContent = String(row?.issue_number || '').trim() || '-';
    tr.appendChild(issueTd);

    const actionTd = document.createElement('td');
    const requestId = String(row?.id || '').trim();
    if (requestId && normalizeHrRequestStatus(row?.status) === 'issued' && row?.file_ready) {
      const downloadBtn = document.createElement('button');
      downloadBtn.type = 'button';
      downloadBtn.className = 'btn btn-secondary';
      downloadBtn.dataset.action = 'hr-employment-download';
      downloadBtn.dataset.requestId = requestId;
      downloadBtn.textContent = 'PDF 다운로드';
      actionTd.appendChild(downloadBtn);
    } else if (requestId && normalizeHrRequestStatus(row?.status) === 'rejected') {
      const reasonBtn = document.createElement('button');
      reasonBtn.type = 'button';
      reasonBtn.className = 'btn btn-ghost';
      reasonBtn.dataset.action = 'hr-employment-view-reason';
      reasonBtn.dataset.reason = String(row?.rejection_reason || '').trim();
      reasonBtn.textContent = '사유보기';
      actionTd.appendChild(reasonBtn);
    } else {
      actionTd.textContent = '-';
    }
    tr.appendChild(actionTd);

    tbody.appendChild(tr);
  });
}

function renderHrTemplateRows() {
  const tbody = $('#hrTemplateTableBody');
  if (!(tbody instanceof HTMLElement)) return;
  const hrState = ensureHrDocsState();
  const rows = Array.isArray(hrState.templatesRows) ? hrState.templatesRows : [];
  if (!rows.length) {
    renderAdminTableEmptyState(tbody, 6, '등록된 템플릿이 없습니다. 기본 템플릿을 사용합니다.');
    return;
  }
  tbody.innerHTML = '';
  rows.forEach((row) => {
    const tr = document.createElement('tr');
    const appendCell = (value = '-') => {
      const td = document.createElement('td');
      td.textContent = String(value || '-').trim() || '-';
      tr.appendChild(td);
    };
    appendCell(row?.document_type || '-');
    appendCell(`v${Number(row?.version || 0)}`);
    appendCell(row?.file_path || '-');
    appendCell(Boolean(row?.is_active) ? '활성' : '비활성');
    appendCell(formatDateLabel(row?.created_at, '-'));
    appendCell(row?.created_by || '-');
    tbody.appendChild(tr);
  });
}

function renderHrAdminRequestRows() {
  const tbody = $('#hrEmploymentAdminRequestTableBody');
  if (!(tbody instanceof HTMLElement)) return;
  const hrState = ensureHrDocsState();
  const rows = Array.isArray(hrState.adminRows) ? hrState.adminRows : [];
  if (!rows.length) {
    renderAdminTableEmptyState(tbody, 8, '해당 조건의 요청이 없습니다.');
    return;
  }

  tbody.innerHTML = '';
  rows.forEach((row) => {
    const tr = document.createElement('tr');

    const requestedAtTd = document.createElement('td');
    requestedAtTd.textContent = formatDateLabel(row?.requested_at, '-');
    tr.appendChild(requestedAtTd);

    const employeeTd = document.createElement('td');
    employeeTd.textContent = String(row?.employee_name || '-').trim() || '-';
    tr.appendChild(employeeTd);

    const companyTd = document.createElement('td');
    companyTd.textContent = String(row?.company_name || '-').trim() || '-';
    tr.appendChild(companyTd);

    const orgTd = document.createElement('td');
    orgTd.textContent = String(row?.org || '-').trim() || '-';
    tr.appendChild(orgTd);

    const purposeTd = document.createElement('td');
    purposeTd.textContent = formatHrPurposeLabel(row?.purpose_code, row?.purpose_text);
    tr.appendChild(purposeTd);

    const statusTd = document.createElement('td');
    const statusPill = document.createElement('span');
    statusPill.className = getHrRequestStatusPillClass(row?.status);
    statusPill.textContent = getHrRequestStatusLabel(row?.status);
    statusTd.appendChild(statusPill);
    tr.appendChild(statusTd);

    const mailTd = document.createElement('td');
    const companySent = Boolean(row?.mail_company_sent_at);
    const employeeSent = Boolean(row?.mail_employee_sent_at);
    mailTd.textContent = `회사:${companySent ? '성공' : '대기'} / 직원:${employeeSent ? '성공' : '대기'}`;
    tr.appendChild(mailTd);

    const actionTd = document.createElement('td');
    const requestId = String(row?.id || '').trim();
    if (requestId && normalizeHrRequestStatus(row?.status) === 'requested') {
      const actionsWrap = document.createElement('div');
      actionsWrap.className = 'inline-actions';
      const approveBtn = document.createElement('button');
      approveBtn.type = 'button';
      approveBtn.className = 'btn btn-primary';
      approveBtn.dataset.action = 'hr-admin-approve';
      approveBtn.dataset.requestId = requestId;
      approveBtn.textContent = '승인';
      const rejectBtn = document.createElement('button');
      rejectBtn.type = 'button';
      rejectBtn.className = 'btn btn-destructive';
      rejectBtn.dataset.action = 'hr-admin-reject';
      rejectBtn.dataset.requestId = requestId;
      rejectBtn.textContent = '반려';
      actionsWrap.append(approveBtn, rejectBtn);
      actionTd.appendChild(actionsWrap);
    } else if (normalizeHrRequestStatus(row?.status) === 'rejected') {
      const reasonBtn = document.createElement('button');
      reasonBtn.type = 'button';
      reasonBtn.className = 'btn btn-ghost';
      reasonBtn.dataset.action = 'hr-employment-view-reason';
      reasonBtn.dataset.reason = String(row?.rejection_reason || '').trim();
      reasonBtn.textContent = '사유보기';
      actionTd.appendChild(reasonBtn);
    } else {
      actionTd.textContent = '-';
    }
    tr.appendChild(actionTd);
    tbody.appendChild(tr);
  });
}

function renderHrScopeAndPanels() {
  const hrState = ensureHrDocsState();
  const navRole = getNavigationRole();
  const scopeHint = $('#hrScopeHint');
  const employeeCard = $('#hrEmploymentEmployeeCard');
  const myRowsCard = $('#hrEmploymentMyRequestsCard');
  const adminCard = $('#hrEmploymentAdminCard');
  const templateCard = $('#hrTemplateAdminCard');
  const statusEl = $('#hrEmploymentAdminStatus');
  const templateStatusEl = $('#hrTemplateStatus');
  const employeeStatusEl = $('#hrEmploymentRequestStatus');
  const adminMode = isHrAdminRole();
  const employeeMode = isHrEmployeeRole();
  const templateManagerMode = isHrTemplateManagerRole();

  if (scopeHint) {
    scopeHint.textContent = adminMode
      ? 'HQ/DEV는 재직증명서 요청을 승인/반려하고 발급 현황을 확인합니다.'
      : '재직증명서는 승인 후 발급됩니다. 오늘 최대 3회까지 요청할 수 있습니다.';
  }
  if (employeeCard) employeeCard.classList.toggle('hidden', !employeeMode);
  if (myRowsCard) myRowsCard.classList.toggle('hidden', !employeeMode);
  if (adminCard) adminCard.classList.toggle('hidden', !adminMode);
  if (templateCard) templateCard.classList.toggle('hidden', !templateManagerMode);
  if (statusEl && adminMode) {
    statusEl.textContent = '요청 목록을 불러오는 중입니다.';
  }
  if (templateStatusEl && adminMode) {
    templateStatusEl.textContent = '현재 템플릿 버전을 불러오는 중입니다.';
  }
  if (employeeStatusEl && employeeMode) {
    employeeStatusEl.textContent = '발급 용도를 선택하고 신청해 주세요.';
  }

  const tabButtons = document.querySelectorAll('#hrEmploymentAdminStatusTabs [data-action="hr-admin-status-filter"]');
  tabButtons.forEach((btn) => {
    btn.classList.toggle('hidden', !adminMode);
  });
  const adminSearch = $('#hrEmploymentAdminSearch');
  if (adminSearch instanceof HTMLInputElement) {
    adminSearch.disabled = !adminMode;
    adminSearch.value = String(hrState.adminQuery || '');
  }

  const uploadBtn = $('#hrTemplateUploadBtn');
  if (uploadBtn instanceof HTMLButtonElement) {
    uploadBtn.disabled = !templateManagerMode || Boolean(hrState.templateUploading);
  }

  const purposeCodeGroup = $('#hrPurposeCodeGroup');
  if (purposeCodeGroup) purposeCodeGroup.classList.toggle('hidden', !employeeMode);
  renderHrAdminPanelTabs();
  if (!hrState.workspaceSegment) {
    hrState.workspaceSegment = resolveDefaultHrWorkspaceSegment();
  }
  renderHrWorkspaceSegments();
}

async function loadHrEmploymentQuota({ force = false } = {}) {
  const hrState = ensureHrDocsState();
  if (!isHrEmployeeRole()) {
    hrState.dailyLimit = HR_EMPLOYMENT_DAILY_LIMIT;
    hrState.todayRequestedCount = 0;
    hrState.todayRemaining = HR_EMPLOYMENT_DAILY_LIMIT;
    renderHrQuota();
    return null;
  }
  const now = Date.now();
  const isFresh = !force
    && Number(hrState.myRowsFetchedAt || 0) > 0
    && (now - Number(hrState.myRowsFetchedAt || 0)) < HR_DATA_CACHE_TTL_MS;
  if (isFresh) {
    renderHrQuota();
    return {
      daily_limit: hrState.dailyLimit,
      today_requested_count: hrState.todayRequestedCount,
      today_remaining: hrState.todayRemaining,
    };
  }
  const payload = await apiRequest('/hr/documents/employment-certificate/quota');
  hrState.dailyLimit = Number(payload?.daily_limit || HR_EMPLOYMENT_DAILY_LIMIT) || HR_EMPLOYMENT_DAILY_LIMIT;
  hrState.todayRequestedCount = Number(payload?.today_requested_count || 0) || 0;
  hrState.todayRemaining = Number(payload?.today_remaining ?? Math.max(0, hrState.dailyLimit - hrState.todayRequestedCount)) || 0;
  renderHrQuota();
  return payload;
}

async function loadHrEmploymentMyRequests({ force = false } = {}) {
  const hrState = ensureHrDocsState();
  if (!isHrEmployeeRole()) {
    hrState.myRows = [];
    renderHrMyRequestRows();
    return [];
  }
  const now = Date.now();
  const isFresh = !force
    && Array.isArray(hrState.myRows)
    && Number(hrState.myRowsFetchedAt || 0) > 0
    && (now - Number(hrState.myRowsFetchedAt || 0)) < HR_DATA_CACHE_TTL_MS;
  if (isFresh) {
    renderHrMyRequestRows();
    return hrState.myRows;
  }
  hrState.loadingMyRows = true;
  const page = Math.max(1, Number(hrState.myRowsPage || 1));
  const pageSize = Math.max(1, Number(hrState.myRowsPageSize || 20));
  try {
    const rows = await apiRequest(`/hr/documents/employment-certificate/requests?me=1&page=${page}&pageSize=${pageSize}`);
    hrState.myRows = Array.isArray(rows) ? rows : [];
    hrState.myRowsFetchedAt = Date.now();
    renderHrMyRequestRows();
    return hrState.myRows;
  } finally {
    hrState.loadingMyRows = false;
  }
}

async function loadHrEmploymentAdminRequests({ force = false } = {}) {
  const hrState = ensureHrDocsState();
  if (!isHrAdminRole()) {
    hrState.adminRows = [];
    renderHrAdminRequestRows();
    return [];
  }
  const now = Date.now();
  const isFresh = !force
    && Array.isArray(hrState.adminRows)
    && Number(hrState.adminRowsFetchedAt || 0) > 0
    && (now - Number(hrState.adminRowsFetchedAt || 0)) < HR_DATA_CACHE_TTL_MS;
  if (isFresh) {
    renderHrAdminStatusTabs();
    renderHrAdminRequestRows();
    return hrState.adminRows;
  }
  hrState.loadingAdminRows = true;
  const statusFilter = normalizeHrRequestStatus(hrState.adminStatus || 'requested');
  const q = String(hrState.adminQuery || '').trim();
  const params = new URLSearchParams({
    status: statusFilter,
    page: String(Math.max(1, Number(hrState.adminRowsPage || 1))),
    pageSize: String(Math.max(1, Number(hrState.adminRowsPageSize || 30))),
  });
  if (q) params.set('q', q);
  try {
    const rows = await apiRequest(`/admin/hr/documents/employment-certificate/requests?${params.toString()}`);
    hrState.adminRows = Array.isArray(rows) ? rows : [];
    hrState.adminRowsFetchedAt = Date.now();
    renderHrAdminStatusTabs();
    renderHrAdminRequestRows();
    const statusEl = $('#hrEmploymentAdminStatus');
    if (statusEl) {
      statusEl.textContent = `${hrState.adminRows.length}건 조회됨`;
    }
    return hrState.adminRows;
  } finally {
    hrState.loadingAdminRows = false;
  }
}

async function loadHrDocumentTemplates({ force = false } = {}) {
  const hrState = ensureHrDocsState();
  if (!isHrTemplateManagerRole()) {
    hrState.templatesRows = [];
    renderHrTemplateRows();
    return [];
  }
  const now = Date.now();
  const isFresh = !force
    && Array.isArray(hrState.templatesRows)
    && Number(hrState.templatesFetchedAt || 0) > 0
    && (now - Number(hrState.templatesFetchedAt || 0)) < HR_DATA_CACHE_TTL_MS;
  if (isFresh) {
    renderHrTemplateRows();
    return hrState.templatesRows;
  }
  const rows = await apiRequest('/admin/hr/documents/templates?document_type=employment_certificate');
  hrState.templatesRows = Array.isArray(rows) ? rows : [];
  hrState.templatesFetchedAt = Date.now();
  renderHrTemplateRows();
  const statusEl = $('#hrTemplateStatus');
  if (statusEl) {
    statusEl.textContent = `${hrState.templatesRows.length}개 버전 조회됨`;
  }
  return hrState.templatesRows;
}

function renderHrViewFromCache() {
  renderHrScopeAndPanels();
  renderHrDocCardSelection();
  renderHrPurposeSelector();
  renderHrQuota();
  renderHrAdminPanelTabs();
  renderHrAdminStatusTabs();
  renderHrMyRequestRows();
  renderHrAdminRequestRows();
  renderHrTemplateRows();
}

async function loadHrViewPresenter() {
  const hrState = ensureHrDocsState();
  hrState.selectedDocType = HR_DOC_TYPE_EMPLOYMENT_CERTIFICATE;
  const parsed = parseRouteCandidate(getCurrentRouteWithQuery());
  const routeQuery = new URLSearchParams(parsed.query || '');
  if (isHrAdminRole()) {
    hrState.adminPanel = normalizeHrAdminPanel(routeQuery.get('panel') || hrState.adminPanel || 'requests');
    if (!isHrTemplateManagerRole() && hrState.adminPanel === 'templates') {
      hrState.adminPanel = 'requests';
    }
    hrState.workspaceSegment = hrState.adminPanel === 'templates' ? 'templates' : 'approvals';
  } else {
    hrState.workspaceSegment = normalizeHrWorkspaceSegment(hrState.workspaceSegment || 'apply');
  }
  renderHrViewFromCache();

  const tasks = [];
  if (isHrEmployeeRole()) {
    tasks.push(loadHrEmploymentQuota({ force: false }));
    tasks.push(loadHrEmploymentMyRequests({ force: false }));
  }
  if (isHrAdminRole()) {
    if (normalizeHrAdminPanel(hrState.adminPanel || 'requests') === 'templates') {
      tasks.push(loadHrDocumentTemplates({ force: false }));
    } else {
      tasks.push(loadHrEmploymentAdminRequests({ force: false }));
    }
  }
  if (tasks.length) {
    await Promise.all(tasks);
  }
}

async function submitHrEmploymentRequest() {
  const hrState = ensureHrDocsState();
  const purposeCode = normalizeHrPurposeCode(hrState.purposeCode || 'BANK');
  const purposeText = String(hrState.purposeText || '').trim();
  if (purposeCode === 'OTHER' && (purposeText.length < 2 || purposeText.length > 50)) {
    showToast('기타 용도는 2~50자로 입력해 주세요.', 'error', 2600);
    return;
  }
  hrState.submitting = true;
  updateHrRequestSubmitState();
  const statusEl = $('#hrEmploymentRequestStatus');
  if (statusEl) statusEl.textContent = '발급 요청을 등록하는 중입니다...';
  try {
    const payload = await apiRequest('/hr/documents/employment-certificate/requests', {
      method: 'POST',
      body: {
        purpose_code: purposeCode,
        purpose_text: purposeCode === 'OTHER' ? purposeText : null,
      },
    });
    hrState.todayRequestedCount = Number(payload?.today_requested_count || hrState.todayRequestedCount || 0);
    hrState.todayRemaining = Number(payload?.today_remaining ?? Math.max(0, HR_EMPLOYMENT_DAILY_LIMIT - hrState.todayRequestedCount));
    hrState.myRowsFetchedAt = 0;
    renderHrQuota();
    await loadHrEmploymentMyRequests({ force: true });
    if (statusEl) statusEl.textContent = '요청이 접수되었습니다. 승인 완료 후 PDF를 다운로드할 수 있습니다.';
    showToast('재직증명서 발급 요청이 접수되었습니다.', 'success', 2200);
  } finally {
    hrState.submitting = false;
    updateHrRequestSubmitState();
  }
}

async function downloadHrEmploymentRequestPdf(requestId = '') {
  const id = String(requestId || '').trim();
  if (!id) {
    throw new Error('다운로드할 요청 ID가 없습니다.');
  }
  const token = getActiveAccessToken();
  if (!token) {
    throw new Error('세션이 만료되었습니다. 다시 로그인해 주세요.');
  }
  const headers = { Authorization: `Bearer ${token}` };
  const tenantHeader = String(getActiveTenantHeaderValue() || '').trim();
  if (tenantHeader) {
    headers['X-Tenant-Id'] = tenantHeader;
  }
  const response = await fetch(
    `${state.activeApiBase}/hr/documents/requests/${encodeURIComponent(id)}/download`,
    {
      method: 'GET',
      headers,
      credentials: 'omit',
      mode: 'cors',
    },
  );
  if (!response.ok) {
    const body = await response.text();
    throw new Error(`다운로드 실패 (${response.status}): ${body || 'unknown error'}`);
  }
  const blob = await response.blob();
  const blobUrl = URL.createObjectURL(blob);
  const link = document.createElement('a');
  const fallbackName = `employment_certificate_${id}.pdf`;
  const disposition = String(response.headers.get('Content-Disposition') || '').trim();
  const match = disposition.match(/filename="?([^"]+)"?/i);
  link.href = blobUrl;
  link.download = String(match?.[1] || fallbackName).trim() || fallbackName;
  document.body.appendChild(link);
  link.click();
  link.remove();
  setTimeout(() => URL.revokeObjectURL(blobUrl), 8000);
}

async function approveHrEmploymentRequest(requestId = '') {
  const id = String(requestId || '').trim();
  if (!id) return;
  await apiRequest(`/admin/hr/documents/requests/${encodeURIComponent(id)}/approve`, {
    method: 'POST',
  });
}

async function rejectHrEmploymentRequest(requestId = '', reason = '') {
  const id = String(requestId || '').trim();
  const rejectionReason = String(reason || '').trim();
  if (!id) return;
  await apiRequest(`/admin/hr/documents/requests/${encodeURIComponent(id)}/reject`, {
    method: 'POST',
    body: { rejection_reason: rejectionReason },
  });
}

async function uploadHrDocumentTemplate() {
  const hrState = ensureHrDocsState();
  if (!isHrTemplateManagerRole()) {
    throw new Error('권한이 없습니다.');
  }
  const fileInput = $('#hrTemplateUploadFile');
  if (!(fileInput instanceof HTMLInputElement) || !fileInput.files || !fileInput.files.length) {
    throw new Error('업로드할 템플릿(.docx)을 선택해 주세요.');
  }
  const file = fileInput.files[0];
  const name = String(file?.name || '').trim().toLowerCase();
  if (!name.endsWith('.docx')) {
    throw new Error('템플릿은 .docx 파일만 업로드할 수 있습니다.');
  }
  if ((Number(file?.size || 0) || 0) > (2 * 1024 * 1024)) {
    throw new Error('템플릿 파일은 최대 2MB까지 업로드할 수 있습니다.');
  }
  hrState.templateUploading = true;
  renderHrScopeAndPanels();
  try {
    const formData = new FormData();
    formData.append('document_type', 'employment_certificate');
    formData.append('file', file);
    await apiRequest('/admin/hr/documents/templates/upload', {
      method: 'POST',
      body: formData,
    });
    fileInput.value = '';
    hrState.templatesFetchedAt = 0;
    await loadHrDocumentTemplates({ force: true });
    showToast('템플릿이 업로드되었습니다. 새 버전이 활성화되었습니다.', 'success', 2400);
  } finally {
    hrState.templateUploading = false;
    renderHrScopeAndPanels();
  }
}

async function loadOrgViewPresenter() {
  const isDevRole = getNavigationRole() === 'DEV';
  const includeInactiveToggle = $('#siteIncludeInactive');
  const includeDeletedToggle = $('#siteIncludeDeleted');
  if (includeInactiveToggle instanceof HTMLInputElement) includeInactiveToggle.checked = false;
  if (includeDeletedToggle instanceof HTMLInputElement) includeDeletedToggle.checked = false;
  const includeInactiveLabel = document.querySelector('label[for="siteIncludeInactive"]');
  const includeDeletedLabel = document.querySelector('label[for="siteIncludeDeleted"]');
  if (includeInactiveLabel instanceof HTMLElement) includeInactiveLabel.classList.toggle('hidden', !isDevRole);
  if (includeDeletedLabel instanceof HTMLElement) includeDeletedLabel.classList.toggle('hidden', !isDevRole);
  const activeSelect = $('#siteActiveFilter');
  if (activeSelect instanceof HTMLSelectElement) activeSelect.value = SITE_ACTIVE_ALL;
  ensureSiteRoutePresentation();

  const hasSiteCache = Array.isArray(state.sites) && state.sites.length > 0;
  const shouldRefresh = !hasSiteCache
    || (Date.now() - Number(orgPresenterLastRefreshAt || 0)) > ORG_VIEW_STALE_MS;
  const tenantFilterTask = syncSiteTenantFilterOptions({ force: shouldRefresh });
  if (hasSiteCache) {
    renderSiteCards(state.sites);
  }
  const route = normalizeRoutePath(state.currentRoute || '');
  const inSiteEditorRoute = route === ROUTE_ADMIN_SITES_NEW || route === ROUTE_ADMIN_SITES_EDIT;
  if (!inSiteEditorRoute) {
    markViewPerfStage('first_paintable_ui', {
      routePath: ROUTE_ADMIN_SITES,
      viewName: 'org',
      metrics: {
        api_ms: 0,
      },
    });
    markViewPerfStage('critical_ui_ready', {
      routePath: ROUTE_ADMIN_SITES,
      viewName: 'org',
    });
  }
  if (!inSiteEditorRoute) {
    runActionSafely(
      (async () => {
        await tenantFilterTask;
        await Promise.all([
          loadCompanies({ preferCache: true, force: shouldRefresh }),
          loadSites({
            preferCache: true,
            skipNetworkWhenCached: hasSiteCache && !shouldRefresh,
          }),
        ]);
        orgPresenterLastRefreshAt = Date.now();
      })(),
      '회사/지점 목록 동기화에 실패했습니다.',
    );
    ensureSiteRoutePresentation();
    return;
  }
  runActionSafely(
    (async () => {
      await tenantFilterTask;
      await Promise.all([
        loadCompanies({ preferCache: true, force: false }),
        loadSites({ preferCache: true }),
      ]);
    })(),
    '지점 등록/수정 참고 데이터를 불러오지 못했습니다.',
  );
  ensureSiteRoutePresentation();
}

