function getSortedSiteRows(rows = []) {
  const list = Array.isArray(rows) ? rows.slice() : [];
  const sortKey = String(state.siteTableSortKey || '').trim();
  const sortDirection = normalizeEmployeeSortDirection(state.siteTableSortDirection);
  if (!sortKey || !sortDirection) {
    return list.sort((left, right) => getSiteSourceIndex(left) - getSiteSourceIndex(right));
  }
  return list.sort((left, right) => compareSiteSortValues(left, right, sortKey, sortDirection));
}

function getTenantSourceIndex(item = {}, fallback = 0) {
  const raw = Number(item?.__sourceIndex);
  return Number.isFinite(raw) ? raw : fallback;
}

function getMasterTenantSortValue(item = {}, sortKey = '') {
  const isDeleted = Boolean(item?.is_deleted);
  const active = !isDeleted && item?.is_active !== false;
  switch (String(sortKey || '').trim()) {
    case 'tenantName':
      return String(item?.tenant_name || '').trim();
    case 'tenantCode':
      return String(item?.tenant_code || '').trim();
    case 'status':
      return isDeleted ? '삭제됨' : (active ? '활성' : '비활성');
    default:
      return '';
  }
}

function compareMasterTenantSortValues(leftItem, rightItem, sortKey, direction = 'asc') {
  const normalizedDirection = normalizeEmployeeSortDirection(direction) || 'asc';
  let result = compareAdminSortStrings(
    getMasterTenantSortValue(leftItem, sortKey),
    getMasterTenantSortValue(rightItem, sortKey),
  );
  if (result === 0) {
    result = getTenantSourceIndex(leftItem) - getTenantSourceIndex(rightItem);
  }
  return normalizedDirection === 'desc' ? -result : result;
}

