async function onMasterTenantsPurge({ mode = PURGE_MODE_SOFT } = {}) {
  if (!can('tenantManage')) {
    showToast('회사 정리 권한이 없습니다.', 'error');
    return;
  }

  const normalizedMode = String(mode || PURGE_MODE_SOFT).trim().toUpperCase();
  if (normalizedMode !== PURGE_MODE_SOFT && normalizedMode !== PURGE_MODE_HARD) {
    throw new Error('정리 모드는 SOFT 또는 HARD만 허용됩니다.');
  }

  const result = await apiRequest('/master/tenants/purge', {
    method: 'POST',
    body: {
      mode: normalizedMode,
      confirm: PURGE_CONFIRM_PHRASE,
    },
  });
  state.devAdmin.lastPurgeResult = {
    ...result,
    mode: normalizedMode,
    executed_at: new Date().toISOString(),
  };

  await ensureDevTenantCatalog({ force: true });
  renderMasterConsoleSummary();
  renderMasterConsoleTenantList();
  renderMasterTenantDashboard();
  renderMasterTenantOverview();

  const failedCount = Array.isArray(result?.failed) ? result.failed.length : 0;
  if (failedCount > 0) {
    showToast(`일괄 정리 완료(부분 실패 ${failedCount}건). 결과를 확인하세요.`, 'error', 3400);
    return;
  }
  showToast('일괄 정리 완료 · 결과가 기록되었습니다.', 'success', 2600);
}

async function refreshMasterTenantActionCaches() {
  clearListCaches({ clearStorage: true });
  await Promise.allSettled([
    refreshSiteCatalog({ force: true }),
    loadSites({ notifyOnError: false }),
    syncEmployeeSiteFilterOptions().then(() => loadEmployees()),
  ]);
}

function resolveTenantResetFailureStage(err) {
  const candidates = [
    err?.stage,
    err?.detail?.stage,
    err?.response?.stage,
    err?.response?.detail?.stage,
    err?.response?.error?.stage,
    err?.error?.stage,
    err?.error?.detail?.stage,
    err?.envelope?.error?.stage,
    err?.envelope?.error?.detail?.stage,
  ];
  for (const candidate of candidates) {
    const stage = String(candidate || '').trim();
    if (stage) return stage;
  }
  return '';
}

function resolveTenantResetFailureMessage(err, fallback = 'HR 테넌트 데이터 초기화에 실패했습니다.') {
  const base = normalizeActionError(err, fallback);
  const code = String(
    err?.code
    || err?.detail?.code
    || err?.detail?.error
    || err?.response?.code
    || err?.response?.error
    || err?.response?.error?.code
    || '',
  ).trim().toUpperCase();
  const stage = resolveTenantResetFailureStage(err);
  if ((code === 'TENANT_RESET_FAILED' || stage) && stage) {
    return `${base} (stage: ${stage})`;
  }
  return base;
}

