async function onMasterSocBackfill() {
  const tenantContext = getMasterTenantDangerContext();
  if (!tenantContext) {
    showToast('회사 목록의 작업 버튼에서 실행하세요.', 'info', 2200);
    return;
  }

  const now = Date.now();
  if (state.devAdmin.socBackfillRunning) return;
  if (Number(state.devAdmin.socBackfillCooldownUntil || 0) > now) {
    showToast('잠시 후 다시 시도해 주세요.', 'info', 1800);
    return;
  }

  openConfirmDialog({
    title: 'SOC 재동기화',
    message: `${tenantContext.tenantName} (${tenantContext.tenantCodeUpper}) 회사 데이터를 SOC로 재동기화하시겠습니까?`,
    acceptLabel: '재동기화 실행',
    acceptVariant: 'btn-primary',
    mobileSheet: true,
    onAccept: async () => {
      state.devAdmin.socBackfillRunning = true;
      updateMasterSocBackfillButtonState();
      setInlineStatus('#masterSocDangerStatus', 'SOC 재동기화 실행 중...', 'info');

      try {
        const result = await apiRequest('/admin/soc/backfill-sites', {
          method: 'POST',
          headers: {
            'X-Tenant-Id': tenantContext.tenantCodeLower,
          },
        });
        clearListCaches({ clearStorage: true });
        await Promise.allSettled([
          refreshSiteCatalog({ force: true }),
          loadSites({ notifyOnError: false }),
          syncEmployeeSiteFilterOptions().then(() => loadEmployees()),
        ]);
        const sent = Number(result?.sent || 0);
        const failedRows = Array.isArray(result?.failed) ? result.failed : [];
        const failedCount = failedRows.length;
        if (failedCount > 0) {
          setInlineStatus('#masterSocDangerStatus', `SOC 재동기화 완료(부분 실패 ${failedCount}건)`, 'error');
          showToast(`SOC 재동기화 완료 · 성공 ${sent}건 / 실패 ${failedCount}건`, 'error', 3600);
        } else {
          setInlineStatus('#masterSocDangerStatus', `SOC 재동기화 완료 · 성공 ${sent}건`, 'success');
          showToast(`SOC 재동기화 완료 · 성공 ${sent}건`, 'success', 2600);
        }
      } catch (err) {
        const message = normalizeActionError(err, 'SOC 재동기화에 실패했습니다.');
        setInlineStatus('#masterSocDangerStatus', message, 'error');
        showToast(message, 'error', 3600);
      } finally {
        state.devAdmin.socBackfillRunning = false;
        setMasterSocBackfillCooldown(3000);
        updateMasterSocFullResetButtonState();
      }
    },
  });
}

