function normalizeScheduleHqTab(value = '') {
  const tab = String(value || '').trim().toLowerCase();
  if (tab === SCHEDULE_TAB_TEMPLATES) return SCHEDULE_TAB_TEMPLATES;
  if (tab === SCHEDULE_TAB_REPORTS || tab === 'report' || tab === 'reports') return SCHEDULE_TAB_REPORTS;
  if (tab === SCHEDULE_TAB_UPLOAD || tab === 'excel') return SCHEDULE_TAB_UPLOAD;
  if (tab === SCHEDULE_TAB_LIST) return SCHEDULE_TAB_LIST;
  if (tab === SCHEDULE_TAB_CALENDAR || tab === 'monthly') return SCHEDULE_TAB_CALENDAR;
  return SCHEDULE_TAB_CALENDAR;
}

function normalizeScheduleUploadWorkflowSection(value = '') {
  const section = String(value || '').trim().toLowerCase();
  if (section === SCHEDULE_UPLOAD_WORKFLOW_BASE) return SCHEDULE_UPLOAD_WORKFLOW_BASE;
  if (section === SCHEDULE_UPLOAD_WORKFLOW_EXPORT) return SCHEDULE_UPLOAD_WORKFLOW_EXPORT;
  if (section === SCHEDULE_UPLOAD_WORKFLOW_HANDOFF) return SCHEDULE_UPLOAD_WORKFLOW_HANDOFF;
  return SCHEDULE_UPLOAD_WORKFLOW_MAPPING;
}

function normalizeScheduleUploadWorkspaceMode(value = '') {
  return String(value || '').trim().toLowerCase() === SCHEDULE_UPLOAD_MODE_HQ
    ? SCHEDULE_UPLOAD_MODE_HQ
    : SCHEDULE_UPLOAD_MODE_BASE;
}

function normalizeScheduleBaseWizardStep(value = '') {
  const step = String(value || '').trim().toLowerCase();
  if (step === SCHEDULE_BASE_WIZARD_STEP_CONTEXT) return SCHEDULE_BASE_WIZARD_STEP_CONTEXT;
  if (step === SCHEDULE_BASE_WIZARD_STEP_FILE) return SCHEDULE_BASE_WIZARD_STEP_FILE;
  if (step === SCHEDULE_BASE_WIZARD_STEP_REVIEW) return SCHEDULE_BASE_WIZARD_STEP_REVIEW;
  if (step === SCHEDULE_BASE_WIZARD_STEP_APPLY) return SCHEDULE_BASE_WIZARD_STEP_APPLY;
  return SCHEDULE_BASE_WIZARD_STEP_MAPPING;
}

function normalizeScheduleHqWizardStep(value = '') {
  const step = String(value || '').trim().toLowerCase();
  if (step === SCHEDULE_HQ_WIZARD_STEP_UPLOAD) return SCHEDULE_HQ_WIZARD_STEP_UPLOAD;
  if (step === SCHEDULE_HQ_WIZARD_STEP_PREVIEW) return SCHEDULE_HQ_WIZARD_STEP_PREVIEW;
  if (step === SCHEDULE_HQ_WIZARD_STEP_COMPLETE) return SCHEDULE_HQ_WIZARD_STEP_COMPLETE;
  return SCHEDULE_HQ_WIZARD_STEP_EXPORT;
}

function canUseScheduleUploadHqWizard() {
  return canUseScheduleSupportRoundtripHq() || isMasterDeveloperAccount();
}

function isScheduleTemplateTabVisible() {
  return can('scheduleWrite');
}

function isScheduleBoardTab(tab = '') {
  const normalized = normalizeScheduleHqTab(tab);
  return normalized === SCHEDULE_TAB_CALENDAR || normalized === SCHEDULE_TAB_LIST;
}

function closeScheduleActionDropdowns({ keepMenuId = '' } = {}) {
  const keep = String(keepMenuId || '').trim();
  document.querySelectorAll('[data-schedule-action-dropdown]').forEach((menuEl) => {
    if (!(menuEl instanceof HTMLElement)) return;
    const menuId = String(menuEl.dataset.scheduleActionDropdown || '').trim();
    const open = Boolean(keep) && menuId === keep;
    menuEl.classList.toggle('hidden', !open);
    const trigger = document.querySelector(`[data-action="schedule-toggle-action-dropdown"][data-menu-id="${menuId}"]`);
    if (trigger instanceof HTMLElement) {
      trigger.setAttribute('aria-expanded', open ? 'true' : 'false');
      trigger.classList.toggle('active', open);
    }
  });
}

function toggleScheduleActionDropdown(menuId = '') {
  const key = String(menuId || '').trim();
  if (!key) return;
  const menuEl = document.querySelector(`[data-schedule-action-dropdown="${key}"]`);
  if (!(menuEl instanceof HTMLElement)) return;
  const isOpen = !menuEl.classList.contains('hidden');
  if (isOpen) {
    closeScheduleActionDropdowns();
    return;
  }
  closeScheduleActionDropdowns({ keepMenuId: key });
}

function getScheduleActiveTopTab() {
  const current = normalizeScheduleHqTab(state.schedule?.hqTab || SCHEDULE_TAB_CALENDAR);
  if (current === SCHEDULE_TAB_UPLOAD && !canOpenScheduleUploadWorkspace()) {
    return SCHEDULE_TAB_CALENDAR;
  }
  if (current === SCHEDULE_TAB_REPORTS && !canViewScheduleReportsWorkspace()) {
    return SCHEDULE_TAB_CALENDAR;
  }
  if (current === SCHEDULE_TAB_TEMPLATES && !isScheduleTemplateTabVisible()) {
    return SCHEDULE_TAB_CALENDAR;
  }
  return current;
}

function syncScheduleRouteTabQuery(tab = '') {
  const route = normalizeRoutePath(state.currentRoute || '');
  if (!isScheduleRoutePath(route)) return;
  const normalized = normalizeScheduleHqTab(tab || state.schedule?.hqTab || SCHEDULE_TAB_CALENDAR);
  const nextRoute = getScheduleTabRoute(normalized);
  if (!nextRoute) return;
  state.currentRoute = nextRoute;
  state.lastAllowedRoute = nextRoute;
  updateRouteHash(nextRoute, { replace: true });
  applyDesktopRouteLayout(nextRoute);
}

function formatScheduleTemplateDutyTypeLabel(value = '') {
  const duty = String(value || '').trim().toLowerCase();
  if (duty === 'day') return '주간근무';
  if (duty === 'overtime') return '초과근무';
  if (duty === 'night') return '야간근무';
  return duty || '-';
}

const SCHEDULE_CREATE_TEMPLATE_DUTY_ORDER = ['day', 'overtime', 'night'];

function getScheduleCreateTemplateDutyOrder(value = '') {
  const duty = normalizeShiftType(value);
  const index = SCHEDULE_CREATE_TEMPLATE_DUTY_ORDER.indexOf(duty);
  return index >= 0 ? index : SCHEDULE_CREATE_TEMPLATE_DUTY_ORDER.length;
}

function getScheduleCreateSelectedTemplateRows(ctx = {}) {
  const selectedIds = ctx?.selectedTemplateIds instanceof Set
    ? Array.from(ctx.selectedTemplateIds)
    : [];
  const options = Array.isArray(ctx?.templateOptions) ? ctx.templateOptions : [];
  const optionMap = new Map(options.map((item) => [String(item?.id || '').trim(), item]));
  const seenDuties = new Set();
  return selectedIds
    .map((id) => optionMap.get(String(id || '').trim()) || null)
    .filter(Boolean)
    .sort((left, right) => {
      const dutyCompare = getScheduleCreateTemplateDutyOrder(left?.duty_type)
        - getScheduleCreateTemplateDutyOrder(right?.duty_type);
      if (dutyCompare !== 0) return dutyCompare;
      return String(left?.template_name || left?.label || '').localeCompare(String(right?.template_name || right?.label || ''));
    })
    .filter((item) => {
      const duty = normalizeShiftType(item?.duty_type || '');
      if (!duty || seenDuties.has(duty)) return false;
      seenDuties.add(duty);
      return true;
    });
}

function getScheduleCreateSelectedTemplateRowByDuty(ctx = {}, dutyType = '') {
  const normalizedDuty = normalizeShiftType(dutyType);
  return getScheduleCreateSelectedTemplateRows(ctx)
    .find((item) => normalizeShiftType(item?.duty_type || '') === normalizedDuty) || null;
}

function formatScheduleCreateTemplateTriggerLabel(ctx = {}) {
  const selectedRows = getScheduleCreateSelectedTemplateRows(ctx);
  if (!selectedRows.length) return '선택안됨';
  return selectedRows
    .map((item) => `${formatScheduleTemplateDutyTypeLabel(item?.duty_type)} · ${String(item?.template_name || item?.label || '').trim()}`)
    .join(' / ');
}

function getScheduleCreateTemplateCombinationConflict(rows = []) {
  const selectedRows = (Array.isArray(rows) ? rows : []).filter(Boolean);
  if (selectedRows.length <= 1) return null;
  const normalizedRows = [];
  const seenDutyMap = new Map();
  for (let index = 0; index < selectedRows.length; index += 1) {
    const row = selectedRows[index];
    const duty = normalizeShiftType(row?.duty_type || '');
    if (duty && seenDutyMap.has(duty)) {
      return {
        type: 'duplicate-duty',
        left: seenDutyMap.get(duty),
        right: row,
        message: `${formatScheduleTemplateDutyTypeLabel(duty)} 템플릿은 하나만 선택할 수 있습니다.`,
      };
    }
    if (duty) {
      seenDutyMap.set(duty, row);
    }
    const range = buildScheduleTimeRangeForOverlap(
      row?.start_time || '',
      row?.end_time || '',
    );
    if (!range) {
      return {
        type: 'invalid-time',
        left: row,
        right: null,
        message: '시간 정보가 올바르지 않아 선택할 수 없습니다.',
      };
    }
    normalizedRows.push({
      row,
      duty,
      startMinutes: range.startMinutes,
      endMinutes: range.endMinutes,
    });
  }

  normalizedRows.sort((left, right) => {
    if (left.startMinutes !== right.startMinutes) return left.startMinutes - right.startMinutes;
    if (left.endMinutes !== right.endMinutes) return left.endMinutes - right.endMinutes;
    return getScheduleCreateTemplateDutyOrder(left.duty) - getScheduleCreateTemplateDutyOrder(right.duty);
  });

  for (let index = 0; index < normalizedRows.length - 1; index += 1) {
    const left = normalizedRows[index];
    const right = normalizedRows[index + 1];
    if (left.startMinutes < right.endMinutes && right.startMinutes < left.endMinutes) {
      return {
        type: 'overlap',
        left: left.row,
        right: right.row,
        message: '시간이 겹치는 근무구분 템플릿은 함께 선택할 수 없습니다.',
      };
    }
    if (left.endMinutes !== right.startMinutes) {
      return {
        type: 'discontinuous',
        left: left.row,
        right: right.row,
        message: '시간이 이어져있지않아 선택할수 없습니다.',
      };
    }
  }
  return null;
}

function renderScheduleHqTabs() {
  const tabWrap = $('#scheduleHqTabs');
  bootstrapScheduleTabPanelRefs();

  const canOpenTemplateTab = isScheduleTemplateTabVisible();
  const canOpenUploadTab = canOpenScheduleUploadWorkspace();
  const canOpenReportsTab = canViewScheduleReportsWorkspace();
  const activeTab = getScheduleActiveTopTab();
  state.schedule.hqTab = activeTab;
  if (activeTab === SCHEDULE_TAB_LIST) {
    state.schedule.viewMode = SCHEDULE_VIEW_MODE_LIST;
  } else if (activeTab === SCHEDULE_TAB_CALENDAR) {
    state.schedule.viewMode = SCHEDULE_VIEW_MODE_CALENDAR;
  }

  if (tabWrap instanceof HTMLElement) {
    tabWrap.classList.remove('hidden');
    const uiActiveTab = activeTab === SCHEDULE_TAB_LIST ? SCHEDULE_TAB_CALENDAR : activeTab;
    tabWrap.querySelectorAll('[data-action="schedule-hq-tab"]').forEach((button) => {
      const tab = normalizeScheduleHqTab(button?.dataset?.tab || '');
      const isTemplateTab = tab === SCHEDULE_TAB_TEMPLATES;
      const isUploadTab = tab === SCHEDULE_TAB_UPLOAD;
      const isReportsTab = tab === SCHEDULE_TAB_REPORTS;
      button.classList.toggle(
        'hidden',
        (isTemplateTab && !canOpenTemplateTab)
          || (isUploadTab && !canOpenUploadTab)
          || (isReportsTab && !canOpenReportsTab),
      );
      const active = tab === uiActiveTab;
      button.classList.toggle('active', active);
      button.setAttribute('aria-pressed', active ? 'true' : 'false');
    });
  }

  const boardFiltersVisible = isScheduleBoardTab(activeTab);
  toggleVisibility('#scheduleCalendarFilterRow', boardFiltersVisible);
  toggleVisibility('#scheduleCalendarToggleRow', boardFiltersVisible);
  toggleVisibility('#scheduleOpsToolbar', boardFiltersVisible);

  const host = scheduleTabPanelRefs.host;
  const boardPanel = scheduleTabPanelRefs.board;
  const uploadPanel = scheduleTabPanelRefs.upload;
  const reportsPanel = scheduleTabPanelRefs.reports;
  const templatePanel = scheduleTabPanelRefs.templates;
  const allPanels = [boardPanel, uploadPanel, reportsPanel, templatePanel].filter((panel) => panel instanceof HTMLElement);
  const activePanel = getScheduleTabPanelRoot(activeTab);

  if (host instanceof HTMLElement) {
    allPanels.forEach((panel) => {
      if (panel.parentElement) {
        panel.parentElement.removeChild(panel);
      }
      panel.classList.add('hidden');
    });
    if (activePanel instanceof HTMLElement) {
      activePanel.classList.remove('hidden');
      host.appendChild(activePanel);
    }
    ensureScheduleDetachedNodeCache();
  } else {
    if (boardPanel) boardPanel.classList.toggle('hidden', activePanel !== boardPanel);
    if (uploadPanel) uploadPanel.classList.toggle('hidden', activePanel !== uploadPanel);
    if (reportsPanel) reportsPanel.classList.toggle('hidden', activePanel !== reportsPanel);
    if (templatePanel) templatePanel.classList.toggle('hidden', activePanel !== templatePanel);
  }

  if (activeTab === SCHEDULE_TAB_REPORTS) {
    renderScheduleReportsTabs();
  }
}

function onScheduleHqTabChange(tab = SCHEDULE_TAB_CALENDAR) {
  closeScheduleActionDropdowns();
  state.schedule.hqTab = normalizeScheduleHqTab(tab);
  state.schedule.desktopDrawerOpen = false;
  if (state.schedule.hqTab === SCHEDULE_TAB_UPLOAD && !canOpenScheduleUploadWorkspace()) {
    state.schedule.hqTab = SCHEDULE_TAB_CALENDAR;
  }
  if (state.schedule.hqTab === SCHEDULE_TAB_REPORTS && !canViewScheduleReportsWorkspace()) {
    state.schedule.hqTab = SCHEDULE_TAB_CALENDAR;
  }
  if (state.schedule.hqTab === SCHEDULE_TAB_TEMPLATES && !isScheduleTemplateTabVisible()) {
    state.schedule.hqTab = SCHEDULE_TAB_CALENDAR;
  }
  if (state.schedule.hqTab === SCHEDULE_TAB_LIST) {
    state.schedule.viewMode = SCHEDULE_VIEW_MODE_LIST;
  } else if (state.schedule.hqTab === SCHEDULE_TAB_CALENDAR) {
    state.schedule.viewMode = SCHEDULE_VIEW_MODE_CALENDAR;
  }
  renderScheduleHqTabs();
  syncScheduleRouteTabQuery(state.schedule.hqTab);
  if (state.schedule.hqTab === SCHEDULE_TAB_TEMPLATES) {
    runActionSafely(
      Promise.allSettled([
        loadScheduleTemplateRows({ force: false }),
        loadScheduleImportMappingProfile({ force: false }),
      ]),
      '근무 템플릿 목록을 불러오지 못했습니다.',
    );
    renderScheduleDesktopDrawer();
    return;
  }
  if (state.schedule.hqTab === SCHEDULE_TAB_UPLOAD) {
    runActionSafely(
      bootstrapScheduleUploadWorkspace({ force: false }),
      '업로드 지점 목록을 동기화하지 못했습니다.',
    );
    renderScheduleDesktopDrawer();
    return;
  }
  if (state.schedule.hqTab === SCHEDULE_TAB_REPORTS) {
    runActionSafely(
      (async () => {
        await refreshScheduleImportSiteOptions({ force: false });
        await Promise.allSettled([
          loadScheduleSupportRoundtripStatus(),
          loadScheduleFinanceSubmissionStatus(),
        ]);
        renderScheduleReportsTabs();
      })(),
      '보고 지점 목록/제출 상태를 동기화하지 못했습니다.',
    );
    renderScheduleDesktopDrawer();
    return;
  }
  const hasRows = Array.isArray(state.schedule?.rows) && state.schedule.rows.length > 0;
  if (!hasRows) {
    runActionSafely(
      loadSchedule({ force: false }),
      '스케줄 월 조회 중 오류가 발생했습니다.',
    );
    return;
  }
  renderScheduleAll();
}

function formatScheduleTemplateTimeRange(row = {}) {
  const start = String(row?.start_time || '').trim();
  const end = String(row?.end_time || '').trim();
  if (!start || !end) return '-';
  return `${start.slice(0, 5)}-${end.slice(0, 5)}`;
}

function formatScheduleImportMappingRequirementLabel(value = '') {
  const [rowTypeRaw, hoursRaw] = String(value || '').trim().split(':');
  const dutyLabel = formatScheduleTemplateDutyTypeLabel(rowTypeRaw || '').trim() || '-';
  const hoursNumber = Number(hoursRaw || '');
  if (Number.isFinite(hoursNumber)) {
    return `${dutyLabel} ${Number.isInteger(hoursNumber) ? hoursNumber : hoursNumber}시간`.trim();
  }
  return [dutyLabel, String(hoursRaw || '').trim()].filter(Boolean).join(' ').trim() || String(value || '').trim() || '-';
}

function formatScheduleImportMappingRequirementLabels(values = []) {
  return (Array.isArray(values) ? values : [])
    .map((item) => formatScheduleImportMappingRequirementLabel(item))
    .filter(Boolean);
}

function buildScheduleImportMappingTemplateOptions() {
  return (Array.isArray(state.schedule?.templateRows) ? state.schedule.templateRows : [])
    .filter((row) => String(row?.id || '').trim() && row?.is_active !== false)
    .slice()
    .sort((left, right) => {
      const dutyCompare = getScheduleCreateTemplateDutyOrder(left?.duty_type) - getScheduleCreateTemplateDutyOrder(right?.duty_type);
      if (dutyCompare !== 0) return dutyCompare;
      return String(left?.template_name || '').localeCompare(String(right?.template_name || ''));
    });
}

function buildScheduleImportMappingTemplateOptionLabel(row = {}) {
  const dutyLabel = formatScheduleTemplateDutyTypeLabel(row?.duty_type);
  const timeRange = formatScheduleTemplateTimeRange(row);
  const paidHours = row?.paid_hours == null ? '' : `${row.paid_hours}h`;
  const siteLabel = String(row?.site_name || row?.site_code || '공통').trim() || '공통';
  const templateName = String(row?.template_name || '').trim() || '템플릿';
  return [templateName, dutyLabel, timeRange !== '-' ? timeRange : '', paidHours, siteLabel]
    .filter(Boolean)
    .join(' · ');
}

function renderScheduleImportMappingProfileSummary() {
  const badgeEl = $('#scheduleTemplateMappingBadge');
  const textEl = $('#scheduleTemplateMappingText');
  const missingEl = $('#scheduleTemplateMappingMissing');
  if (!(badgeEl instanceof HTMLElement) || !(textEl instanceof HTMLElement) || !(missingEl instanceof HTMLElement)) return;

  const profile = state.schedule?.importMappingProfile && typeof state.schedule.importMappingProfile === 'object'
    ? state.schedule.importMappingProfile
    : null;
  const previewMapping = state.preview?.metadata?.mapping_profile && typeof state.preview.metadata.mapping_profile === 'object'
    ? state.preview.metadata.mapping_profile
    : null;
  const missingLabels = Array.isArray(previewMapping?.missing_required_entry_labels) && previewMapping.missing_required_entry_labels.length
    ? previewMapping.missing_required_entry_labels
    : formatScheduleImportMappingRequirementLabels(previewMapping?.missing_required_entries || []);

  badgeEl.className = 'status-pill status-pill-warn';
  badgeEl.textContent = '미설정';
  textEl.textContent = '엑셀 숫자값을 ARLS 근무 템플릿 시간 범위와 연결해야 업로드 분석이 가능합니다.';

  if (profile && Number(profile.entry_count || 0) > 0) {
    badgeEl.className = missingLabels.length ? 'status-pill status-pill-warn' : 'status-pill status-pill-success';
    badgeEl.textContent = missingLabels.length
      ? `${Number(profile.entry_count || 0)}개 매핑 · 추가 필요`
      : `${Number(profile.entry_count || 0)}개 매핑`;
    const entryLines = (Array.isArray(profile.entries) ? profile.entries : [])
      .slice(0, 3)
      .map((entry) => {
        const requirement = formatScheduleImportMappingRequirementLabel(`${entry?.row_type || ''}:${entry?.numeric_hours ?? ''}`);
        const templateName = String(entry?.template_name || '').trim() || '템플릿 미지정';
        return `${requirement} -> ${templateName}`;
      })
      .filter(Boolean);
    textEl.textContent = entryLines.length
      ? `${String(profile.profile_name || '기본 월간 업로드 매핑').trim() || '기본 월간 업로드 매핑'} · ${entryLines.join(' / ')}`
      : `${String(profile.profile_name || '기본 월간 업로드 매핑').trim() || '기본 월간 업로드 매핑'} · 매핑 항목을 확인하세요.`;
  }

  if (missingLabels.length) {
    missingEl.classList.remove('hidden');
    missingEl.textContent = `현재 업로드 기준 필요한 매핑: ${missingLabels.join(', ')}`;
  } else {
    missingEl.classList.add('hidden');
    missingEl.textContent = '';
  }
}

function renderScheduleTemplateTable() {
  const tableBody = $('#scheduleTemplateTableBody');
  const statusEl = $('#scheduleTemplateStatus');
  if (!(tableBody instanceof HTMLElement)) return;
  tableBody.innerHTML = '';
  renderScheduleImportMappingProfileSummary();

  const rows = Array.isArray(state.schedule?.templateRows) ? state.schedule.templateRows : [];
  if (!rows.length) {
    const tr = document.createElement('tr');
    tr.className = 'admin-table-empty-row';
    const td = document.createElement('td');
    td.colSpan = 8;
    td.textContent = '등록된 근무 템플릿이 없습니다.';
    tr.appendChild(td);
    tableBody.appendChild(tr);
    if (statusEl) statusEl.textContent = '등록된 템플릿이 없습니다.';
    return;
  }

  rows.forEach((row) => {
    const tr = document.createElement('tr');
    const isActive = row?.is_active !== false;
    const rowCells = [
      String(row?.template_name || '').trim() || '-',
      formatScheduleTemplateDutyTypeLabel(row?.duty_type),
      formatScheduleTemplateTimeRange(row),
      (row?.paid_hours ?? row?.paidHours ?? '') === '' ? '-' : String(row?.paid_hours ?? row?.paidHours),
      String(row?.site_name || row?.site_code || '공통').trim() || '공통',
      row?.is_default ? '기본' : '-',
      isActive ? '활성' : '비활성',
    ];
    rowCells.forEach((value) => {
      const td = document.createElement('td');
      td.textContent = String(value || '-');
      tr.appendChild(td);
    });

    const actionTd = document.createElement('td');
    actionTd.className = 'actions-cell';
    const actionsWrap = document.createElement('div');
    actionsWrap.className = 'table-actions';

    const editBtn = document.createElement('button');
    editBtn.type = 'button';
    editBtn.className = 'btn btn-secondary';
    editBtn.dataset.action = 'schedule-template-edit';
    editBtn.dataset.templateId = String(row?.id || '').trim();
    editBtn.textContent = '수정';
    actionsWrap.appendChild(editBtn);

    const toggleBtn = document.createElement('button');
    toggleBtn.type = 'button';
    toggleBtn.className = isActive ? 'btn btn-destructive' : 'btn btn-secondary';
    toggleBtn.dataset.action = 'schedule-template-toggle-active';
    toggleBtn.dataset.templateId = String(row?.id || '').trim();
    toggleBtn.dataset.nextActive = isActive ? '0' : '1';
    toggleBtn.textContent = isActive ? '비활성화' : '활성화';
    actionsWrap.appendChild(toggleBtn);

    actionTd.appendChild(actionsWrap);
    tr.appendChild(actionTd);
    tableBody.appendChild(tr);
  });

  if (statusEl) {
    statusEl.textContent = `${rows.length}개 템플릿`;
  }
}

async function loadScheduleTemplateRows({ force = false } = {}) {
  if (!canMutateScheduleData()) return [];
  const statusEl = $('#scheduleTemplateStatus');
  const now = Date.now();
  const isFresh = Array.isArray(state.schedule.templateRows)
    && state.schedule.templateRows.length > 0
    && Number(state.schedule.templatesFetchedAt || 0) > 0
    && (now - Number(state.schedule.templatesFetchedAt || 0)) < SCHEDULE_TEMPLATE_ROWS_CACHE_TTL_MS;
  if (!force && isFresh) {
    renderScheduleTemplateTable();
    return state.schedule.templateRows;
  }

  if (statusEl) statusEl.textContent = '근무 템플릿을 불러오는 중입니다...';
  const params = new URLSearchParams();
  params.set('tenant_code', getScheduleTenantValue());
  params.set('include_inactive', 'true');
  const siteFilterCode = String($('#scheduleSiteFilter')?.value || '').trim();
  if (siteFilterCode && siteFilterCode.toLowerCase() !== 'all') {
    params.set('site_code', siteFilterCode);
  }
  const rows = await apiRequest(`/schedules/work-templates?${params.toString()}`);
  state.schedule.templateRows = Array.isArray(rows) ? rows : [];
  state.schedule.templatesFetchedAt = Date.now();
  renderScheduleTemplateTable();
  return state.schedule.templateRows;
}

async function loadScheduleImportMappingProfile({ force = false } = {}) {
  if (!canMutateScheduleData()) return null;
  const now = Date.now();
  const cached = state.schedule?.importMappingProfile;
  const fetchedAt = Number(state.schedule?.importMappingProfileFetchedAt || 0);
  const isFresh = cached && fetchedAt > 0 && (now - fetchedAt) < SCHEDULE_TEMPLATE_ROWS_CACHE_TTL_MS;
  if (!force && isFresh) {
    renderScheduleImportMappingProfileSummary();
    return cached;
  }
  const profile = await apiRequest(`/schedules/import-mapping-profile?tenant_code=${encodeURIComponent(getScheduleTenantValue())}`);
  state.schedule.importMappingProfile = profile && typeof profile === 'object' ? profile : null;
  state.schedule.importMappingProfileFetchedAt = Date.now();
  renderScheduleImportMappingProfileSummary();
  return state.schedule.importMappingProfile;
}

async function bootstrapScheduleUploadWorkspace({ force = false } = {}) {
  if (!canOpenScheduleUploadWorkspace()) return null;
  const currentPromise = state.schedule?.uploadWorkspaceBootPromise;
  if (currentPromise && !force) {
    return currentPromise;
  }
  const bootPromise = (async () => {
    state.schedule.uploadWorkspaceBooting = true;
    renderScheduleUploadWorkspace();
    try {
      syncScheduleImportMonthInput({ force: true });
      await refreshScheduleImportSiteOptions({ force });
      await Promise.allSettled([
        loadScheduleImportMappingProfile({ force }),
        loadScheduleSupportRoundtripStatus(),
        loadScheduleSupportHqWorkspaceContract({ force }),
      ]);
      renderScheduleUploadWorkspace();
      return true;
    } finally {
      state.schedule.uploadWorkspaceBooting = false;
      state.schedule.uploadWorkspaceBootPromise = null;
      renderScheduleUploadWorkspace();
    }
  })();
  state.schedule.uploadWorkspaceBootPromise = bootPromise;
  return bootPromise;
}

function createScheduleImportMappingEntryEditorRow(entry = {}, templateOptions = []) {
  const row = document.createElement('div');
  row.className = 'schedule-mapping-entry-row';

  const rowTypeField = document.createElement('label');
  rowTypeField.className = 'input-field';
  rowTypeField.textContent = '행 유형';
  const rowTypeSelect = document.createElement('select');
  rowTypeSelect.dataset.mappingField = 'row_type';
  [
    { value: 'day', label: '주간근무' },
    { value: 'overtime', label: '초과근무' },
    { value: 'night', label: '야간근무' },
  ].forEach((item) => {
    const option = document.createElement('option');
    option.value = item.value;
    option.textContent = item.label;
    rowTypeSelect.appendChild(option);
  });
  rowTypeSelect.value = String(entry?.row_type || 'day').trim().toLowerCase() || 'day';
  rowTypeField.appendChild(rowTypeSelect);

  const hoursField = document.createElement('label');
  hoursField.className = 'input-field';
  hoursField.textContent = '시간';
  const hoursInput = document.createElement('input');
  hoursInput.type = 'number';
  hoursInput.step = '0.5';
  hoursInput.min = '0.5';
  hoursInput.max = '24';
  hoursInput.dataset.mappingField = 'numeric_hours';
  hoursInput.value = entry?.numeric_hours == null ? '' : String(entry.numeric_hours);
  hoursField.appendChild(hoursInput);

  const templateField = document.createElement('label');
  templateField.className = 'input-field';
  templateField.textContent = '연결 템플릿';
  const templateSelect = document.createElement('select');
  templateSelect.dataset.mappingField = 'template_id';
  const syncTemplateOptions = () => {
    const selectedTemplateId = String(templateSelect.value || entry?.template_id || '').trim();
    const dutyType = String(rowTypeSelect.value || '').trim().toLowerCase();
    templateSelect.innerHTML = '<option value="">템플릿 선택</option>';
    templateOptions
      .filter((item) => String(item?.duty_type || '').trim().toLowerCase() === dutyType)
      .forEach((item) => {
        const option = document.createElement('option');
        option.value = String(item?.id || '').trim();
        option.textContent = buildScheduleImportMappingTemplateOptionLabel(item);
        templateSelect.appendChild(option);
      });
    if (selectedTemplateId && Array.from(templateSelect.options).some((item) => String(item.value || '').trim() === selectedTemplateId)) {
      templateSelect.value = selectedTemplateId;
    }
  };
  rowTypeSelect.addEventListener('change', syncTemplateOptions);
  syncTemplateOptions();
  templateField.appendChild(templateSelect);

  const removeBtn = document.createElement('button');
  removeBtn.type = 'button';
  removeBtn.className = 'btn btn-secondary';
  removeBtn.textContent = '삭제';
  removeBtn.addEventListener('click', () => row.remove());

  row.appendChild(rowTypeField);
  row.appendChild(hoursField);
  row.appendChild(templateField);
  row.appendChild(removeBtn);
  return row;
}

async function openScheduleImportMappingEditor() {
  if (!canMutateScheduleData()) {
    showToast('매핑 프로필 권한이 없습니다.', 'error');
    return;
  }
  await Promise.allSettled([
    loadScheduleTemplateRows({ force: false }),
    loadScheduleImportMappingProfile({ force: false }),
  ]);
  const templateOptions = buildScheduleImportMappingTemplateOptions();
  if (!templateOptions.length) {
    showToast('먼저 활성 근무 템플릿을 준비해 주세요.', 'error');
    return;
  }

  const profile = state.schedule?.importMappingProfile && typeof state.schedule.importMappingProfile === 'object'
    ? state.schedule.importMappingProfile
    : null;
  const previewMapping = state.preview?.metadata?.mapping_profile && typeof state.preview.metadata.mapping_profile === 'object'
    ? state.preview.metadata.mapping_profile
    : null;
  const missingEntries = Array.isArray(previewMapping?.missing_required_entries) ? previewMapping.missing_required_entries : [];

  const content = document.createElement('div');
  content.className = 'stack';

  const intro = document.createElement('p');
  intro.className = 'muted';
  intro.textContent = '엑셀 숫자값(예: 주간 10, 주간 12)을 ARLS 근무 템플릿 시간 범위와 연결합니다.';
  content.appendChild(intro);

  if (missingEntries.length) {
    const required = document.createElement('p');
    required.className = 'muted';
    required.textContent = `현재 업로드 기준 필요한 매핑: ${formatScheduleImportMappingRequirementLabels(missingEntries).join(', ')}`;
    content.appendChild(required);
  }

  const profileNameField = document.createElement('label');
  profileNameField.className = 'input-field';
  profileNameField.textContent = '프로필명';
  const profileNameInput = document.createElement('input');
  profileNameInput.id = 'scheduleImportMappingProfileName';
  profileNameInput.value = String(profile?.profile_name || '기본 월간 업로드 매핑').trim() || '기본 월간 업로드 매핑';
  profileNameField.appendChild(profileNameInput);
  content.appendChild(profileNameField);

  const rowList = document.createElement('div');
  rowList.id = 'scheduleImportMappingEntryList';
  rowList.className = 'schedule-mapping-entry-list';
  content.appendChild(rowList);

  const currentEntries = Array.isArray(profile?.entries) ? profile.entries : [];
  const existingKeys = new Set(
    currentEntries.map((entry) => {
      const rowType = String(entry?.row_type || '').trim().toLowerCase();
      const hours = Number(entry?.numeric_hours ?? '');
      return rowType && Number.isFinite(hours) ? `${rowType}:${hours.toFixed(2)}` : '';
    }).filter(Boolean),
  );
  const seedEntries = [
    ...currentEntries,
    ...missingEntries
      .map((item) => {
        const [rowType, hoursText] = String(item || '').split(':');
        const hours = Number(hoursText || '');
        const key = rowType && Number.isFinite(hours) ? `${rowType}:${hours.toFixed(2)}` : '';
        if (!key || existingKeys.has(key)) return null;
        existingKeys.add(key);
        return {
          row_type: rowType,
          numeric_hours: hours,
          template_id: '',
        };
      })
      .filter(Boolean),
  ];

  const appendRow = (entry = {}) => {
    rowList.appendChild(createScheduleImportMappingEntryEditorRow(entry, templateOptions));
  };

  if (seedEntries.length) {
    seedEntries.forEach((entry) => appendRow(entry));
  } else {
    appendRow({});
  }

  const addBtn = document.createElement('button');
  addBtn.type = 'button';
  addBtn.className = 'btn btn-secondary';
  addBtn.textContent = '매핑 행 추가';
  addBtn.addEventListener('click', () => appendRow({}));
  content.appendChild(addBtn);

  openSheet({
    title: '월간 업로드 매핑 프로필',
    contentNode: content,
    actions: [
      { label: '취소', variant: 'btn-secondary', action: 'sheet-close' },
      { label: '저장', variant: 'btn-primary', action: 'schedule-import-mapping-save' },
    ],
  });
  state.sheetContext = { type: 'schedule-import-mapping-editor' };
}

async function onScheduleImportMappingSave() {
  if (!canMutateScheduleData()) {
    showToast('매핑 프로필 권한이 없습니다.', 'error');
    return;
  }
  const profileName = String($('#scheduleImportMappingProfileName')?.value || '').trim() || '기본 월간 업로드 매핑';
  const rows = Array.from(document.querySelectorAll('#scheduleImportMappingEntryList .schedule-mapping-entry-row'));
  const entries = [];
  const seen = new Set();
  for (const row of rows) {
    const rowType = String(row.querySelector('[data-mapping-field="row_type"]')?.value || '').trim().toLowerCase();
    const hoursRaw = String(row.querySelector('[data-mapping-field="numeric_hours"]')?.value || '').trim();
    const templateId = String(row.querySelector('[data-mapping-field="template_id"]')?.value || '').trim();
    if (!rowType && !hoursRaw && !templateId) continue;
    const hours = Number(hoursRaw);
    if (!rowType || !Number.isFinite(hours) || hours <= 0 || !templateId) {
      showToast('행 유형, 시간, 연결 템플릿을 모두 입력해 주세요.', 'error');
      return;
    }
    const key = `${rowType}:${hours.toFixed(2)}`;
    if (seen.has(key)) {
      showToast(`중복 매핑이 있습니다: ${formatScheduleImportMappingRequirementLabel(key)}`, 'error');
      return;
    }
    seen.add(key);
    entries.push({
      row_type: rowType,
      numeric_hours: hours,
      template_id: templateId,
    });
  }
  if (!entries.length) {
    showToast('최소 한 개 이상의 매핑 항목을 입력해 주세요.', 'error');
    return;
  }

  const profile = await apiRequest(`/schedules/import-mapping-profile?tenant_code=${encodeURIComponent(getScheduleTenantValue())}`, {
    method: 'PUT',
    body: {
      profile_name: profileName,
      entries,
    },
  });
  state.schedule.importMappingProfile = profile && typeof profile === 'object' ? profile : null;
  state.schedule.importMappingProfileFetchedAt = Date.now();
  renderScheduleImportMappingProfileSummary();
  invalidateScheduleImportAnalysis(['mapping_profile']);
  closeSheet();
  showToast('월간 업로드 매핑 프로필을 저장했습니다.', 'success', 2600);
}

async function refreshScheduleImportSiteOptions({ force = false } = {}) {
  const importSelect = $('#scheduleImportSite');
  const reportsSelect = $('#scheduleReportsSite');
  const selects = [importSelect, reportsSelect].filter((select) => select instanceof HTMLSelectElement);
  if (!selects.length) return;
  state.schedule.importSiteOptionsLoading = true;
  selects.forEach((select) => {
    const current = String(select.value || '').trim().toUpperCase();
    select.innerHTML = '<option value="">지점 불러오는 중...</option>';
    if (current) {
      select.dataset.pendingValue = current;
    } else {
      delete select.dataset.pendingValue;
    }
    select.disabled = true;
  });
  renderScheduleUploadWorkspace();
  try {
    let rows = [];
    try {
      rows = await refreshSiteCatalog({ force });
    } catch {
      rows = Array.isArray(state.siteCatalog) ? state.siteCatalog : [];
    }
    const optionRows = Array.isArray(rows) ? rows : [];
    const normalizedOptions = optionRows
      .map((item) => ({
        site_code: String(item?.site_code || '').trim().toUpperCase(),
        site_name: String(item?.site_name || '').trim(),
      }))
      .filter((item) => item.site_code)
      .sort((a, b) => String(a.site_code).localeCompare(String(b.site_code)));
    const boardSite = String($('#scheduleSiteFilter')?.value || '').trim().toUpperCase();

    selects.forEach((select) => {
      const isReportsSelect = select.id === 'scheduleReportsSite';
      const current = String(select.dataset.pendingValue || select.value || '').trim().toUpperCase();
      select.innerHTML = '<option value="">지점 선택</option>';
      if (isReportsSelect && isScheduleUploadTenantWideUser()) {
        const allOption = document.createElement('option');
        allOption.value = 'ALL';
        allOption.textContent = '전체';
        select.appendChild(allOption);
      }
      normalizedOptions.forEach((item) => {
        const option = document.createElement('option');
        option.value = item.site_code;
        option.textContent = item.site_name ? `${item.site_code} · ${item.site_name}` : item.site_code;
        select.appendChild(option);
      });
      const fallbackValue = current
        || (boardSite && boardSite !== 'ALL' ? boardSite : '')
        || (!isScheduleUploadTenantWideUser() && select.options.length > 1
          ? String(select.options[1].value || '').trim().toUpperCase()
          : '');
      if (fallbackValue && Array.from(select.options).some((item) => String(item.value || '').trim().toUpperCase() === fallbackValue)) {
        select.value = fallbackValue;
      }
      delete select.dataset.pendingValue;
      select.disabled = false;
    });
    applyPendingScheduleHqWizardResume();
  } finally {
    selects.forEach((select) => {
      if (!select.options.length || /지점 불러오는 중/.test(String(select.options[0]?.textContent || ''))) {
        select.innerHTML = '<option value="">지점 선택</option>';
        delete select.dataset.pendingValue;
      }
      select.disabled = false;
    });
    state.schedule.importSiteOptionsLoading = false;
    applyPendingScheduleHqWizardResume();
    renderScheduleUploadWorkspace();
  }
}

function openScheduleDownloadSheet() {
  if (!canMutateScheduleData()) {
    showToast('다운로드 권한이 없습니다.', 'error');
    return;
  }
  const content = document.createElement('div');
  content.className = 'stack';
  const monthField = document.createElement('label');
  monthField.className = 'input-field';
  monthField.textContent = '기간(월)';
  const monthInput = document.createElement('input');
  monthInput.type = 'month';
  monthInput.id = 'scheduleMonthlyExportMonth';
  monthInput.value = getScheduleMonthValue();
  monthField.appendChild(monthInput);
  content.appendChild(monthField);

  const siteField = document.createElement('label');
  siteField.className = 'input-field';
  siteField.textContent = '지점';
  const siteInput = document.createElement('select');
  siteInput.id = 'scheduleMonthlyExportSite';
  siteField.appendChild(siteInput);
  content.appendChild(siteField);

  const populateSites = async () => {
    const rows = await refreshSiteCatalog({ force: false });
    const list = Array.isArray(rows) ? rows : [];
    const options = list
      .map((item) => ({
        code: String(item?.site_code || '').trim().toUpperCase(),
        name: String(item?.site_name || '').trim(),
      }))
      .filter((item) => item.code)
      .sort((a, b) => String(a.code).localeCompare(String(b.code)));
    siteInput.innerHTML = '';

    const allOption = document.createElement('option');
    allOption.value = 'ALL';
    allOption.textContent = '전체 지점';
    siteInput.appendChild(allOption);

    options.forEach((item) => {
      const option = document.createElement('option');
      option.value = item.code;
      option.textContent = item.name ? `${item.code} · ${item.name}` : item.code;
      siteInput.appendChild(option);
    });

    const importSite = String($('#scheduleImportSite')?.value || '').trim().toUpperCase();
    if (importSite && options.some((item) => item.code === importSite)) {
      siteInput.value = importSite;
      return;
    }
    siteInput.value = 'ALL';
  };

  openSheet({
    title: '월간 근무표 (Excel)',
    contentNode: content,
    actions: [
      { label: '취소', variant: 'btn-secondary', action: 'sheet-close' },
      { label: '다운로드', variant: 'btn-primary', action: 'schedule-download-monthly-excel' },
    ],
  });
  state.sheetContext = {
    type: 'schedule-download',
    monthInputId: 'scheduleMonthlyExportMonth',
    siteInputId: 'scheduleMonthlyExportSite',
  };
  populateSites().catch(() => {
    showToast('지점 목록을 불러오지 못했습니다.', 'error', 2400);
  });
}

async function onScheduleDownloadMonthlyExcel() {
  if (!canMutateScheduleData()) {
    showToast('다운로드 권한이 없습니다.', 'error');
    return;
  }
  const month = normalizeMonthKey($(`#${state.sheetContext?.monthInputId || ''}`)?.value || getScheduleMonthValue());
  const rawSiteCode = String($(`#${state.sheetContext?.siteInputId || ''}`)?.value || '').trim().toUpperCase();
  const siteCode = rawSiteCode || 'ALL';
  if (!month) {
    showToast('월을 선택해 주세요.', 'error');
    return;
  }
  const accessToken = getActiveAccessToken();
  if (!accessToken) {
    showToast('로그인 후 이용해 주세요.', 'error');
    return;
  }
  const params = new URLSearchParams();
  params.set('month', month);
  params.set('tenant_code', getScheduleTenantValue());
  params.set('site_code', siteCode === 'ALL' ? 'all' : siteCode);
  const requestUrl = `${state.activeApiBase}/schedules/export/monthly-excel?${params.toString()}`;
  let response = await fetch(requestUrl, {
    headers: {
      Authorization: `Bearer ${accessToken}`,
    },
    mode: 'cors',
    credentials: 'omit',
  });
  if (response.status === 401) {
    const refreshed = await requestTokenRefresh();
    if (refreshed) {
      response = await fetch(requestUrl, {
        headers: {
          Authorization: `Bearer ${getActiveAccessToken()}`,
        },
        mode: 'cors',
        credentials: 'omit',
      });
    }
  }
  if (!response.ok) {
    throw new Error(`다운로드 요청 실패 (${response.status})`);
  }
  const blob = await response.blob();
  const href = URL.createObjectURL(blob);
  const anchor = document.createElement('a');
  const fallbackGeneratedOn = (() => {
    const formatter = new Intl.DateTimeFormat('en-CA', {
      timeZone: 'Asia/Seoul',
      year: '2-digit',
      month: '2-digit',
      day: '2-digit',
    });
    const parts = Object.fromEntries(
      formatter.formatToParts(new Date()).map((part) => [part.type, part.value]),
    );
    return `${parts.year || ''}${parts.month || ''}${parts.day || ''}`;
  })();
  const siteNameForFile = siteCode === 'ALL'
    ? `HQ_${getCurrentTenantDisplayName()}_월간 근무표_${`20${fallbackGeneratedOn}`}`
    : `${month.slice(0, 4)}년 ${Number(month.slice(5, 7))}월 근무표_${siteCode}_${fallbackGeneratedOn}`;
  const fallbackName = `${siteNameForFile}.xlsx`;
  const disposition = String(response.headers.get('Content-Disposition') || '').trim();
  const utf8Match = disposition.match(/filename\*\s*=\s*UTF-8''([^;]+)/i);
  const basicMatch = disposition.match(/filename="?([^"]+)"?/i);
  let resolvedName = fallbackName;
  if (utf8Match?.[1]) {
    try {
      resolvedName = decodeURIComponent(String(utf8Match[1]).trim());
    } catch (_) {
      resolvedName = fallbackName;
    }
  } else if (basicMatch?.[1]) {
    resolvedName = String(basicMatch[1]).trim() || fallbackName;
  }
  anchor.href = href;
  anchor.download = resolvedName;
  document.body.appendChild(anchor);
  anchor.click();
  anchor.remove();
  URL.revokeObjectURL(href);
  closeSheet();
  showToast('월간 근무표를 다운로드했습니다.', 'success', 2200);
}

function formatScheduleCreateTemplateOptionLabel(row = {}) {
  const templateName = String(row?.template_name || '템플릿').trim() || '템플릿';
  const start = String(row?.start_time || '').trim().slice(0, 5) || '--:--';
  const end = String(row?.end_time || '').trim().slice(0, 5) || '--:--';
  const paidHoursRaw = row?.paid_hours;
  const paidHours = Number.isFinite(Number(paidHoursRaw)) ? Number(paidHoursRaw) : 0;
  const breakMinutesRaw = row?.break_minutes;
  const breakMinutes = Number.isFinite(Number(breakMinutesRaw)) ? Number(breakMinutesRaw) : 0;
  return `${templateName} ${start}-${end} (${paidHours}h, 휴게:${breakMinutes}m)`;
}

function buildScheduleTemplateSelectOptions(siteCode = '') {
  const normalizedSiteCode = String(siteCode || '').trim().toUpperCase();
  const rows = Array.isArray(state.schedule?.templateRows) ? state.schedule.templateRows : [];
  return rows
    .filter((row) => {
      const code = String(row?.site_code || '').trim().toUpperCase();
      if (!normalizedSiteCode) return true;
      return !code || code === normalizedSiteCode;
    })
    .filter((row) => row?.is_active !== false)
    .map((row) => ({
      id: String(row?.id || '').trim(),
      template_name: String(row?.template_name || '').trim(),
      duty_type: normalizeShiftType(row?.duty_type || ''),
      start_time: String(row?.start_time || '').trim(),
      end_time: String(row?.end_time || '').trim(),
      paid_hours: row?.paid_hours ?? null,
      break_minutes: row?.break_minutes ?? null,
      site_code: String(row?.site_code || '').trim().toUpperCase(),
      label: formatScheduleCreateTemplateOptionLabel(row),
    }))
    .filter((row) => row.id)
    .sort((left, right) => {
      const dutyCompare = getScheduleCreateTemplateDutyOrder(left?.duty_type)
        - getScheduleCreateTemplateDutyOrder(right?.duty_type);
      if (dutyCompare !== 0) return dutyCompare;
      return String(left?.template_name || '').localeCompare(String(right?.template_name || ''));
    });
}

function buildScheduleTimeRangeForOverlap(startTime = '', endTime = '') {
  const startMinutes = getAttendanceComparableMinutes(startTime);
  const endMinutes = getAttendanceComparableMinutes(endTime);
  if (!Number.isFinite(startMinutes) || !Number.isFinite(endMinutes)) return null;
  let normalizedEndMinutes = endMinutes;
  if (normalizedEndMinutes <= startMinutes) {
    normalizedEndMinutes += 1440;
  }
  return {
    startMinutes,
    endMinutes: normalizedEndMinutes,
  };
}

function hasScheduleTimeOverlap(
  leftStart = '',
  leftEnd = '',
  rightStart = '',
  rightEnd = '',
) {
  const leftRange = buildScheduleTimeRangeForOverlap(leftStart, leftEnd);
  const rightRange = buildScheduleTimeRangeForOverlap(rightStart, rightEnd);
  if (!leftRange || !rightRange) return true;
  return leftRange.startMinutes < rightRange.endMinutes
    && rightRange.startMinutes < leftRange.endMinutes;
}

function getScheduleCreateModalContext() {
  const ctx = state.sheetContext;
  if (!ctx || typeof ctx !== 'object') return null;
  if (ctx.type !== 'schedule-create-modal') return null;
  return ctx;
}

function getScheduleCreateEmployeesCacheKey(siteCode = '') {
  return `schedule-create-employees:${ensureScheduleTenantCode(getScheduleTenantValue())}:${String(siteCode || '').trim().toUpperCase() || 'ALL'}`;
}

async function listScheduleCreateEmployees(siteCode = '', { force = false } = {}) {
  const normalizedSiteCode = String(siteCode || '').trim().toUpperCase();
  const cacheKey = getScheduleCreateEmployeesCacheKey(normalizedSiteCode);
  if (!force) {
    const cached = getCachedHeavyApiValue(cacheKey);
    if (Array.isArray(cached)) {
      return cached;
    }
  }
  const params = new URLSearchParams();
  params.set('limit', '500');
  const tenantCode = getScheduleTenantValue();
  if (tenantCode) {
    params.set('tenant_code', tenantCode);
  }
  if (normalizedSiteCode) {
    params.set('site_code', normalizedSiteCode);
  }
  const rows = await fetchPagedApiRows(`/employees?${params.toString()}`, {
    pageLimit: 500,
    maxPages: 20,
  });
  const normalizedRows = (Array.isArray(rows) ? rows : [])
    .map((item) => ({
      employee_id: String(item?.id || '').trim(),
      employee_code: String(item?.employee_code || '').trim(),
      full_name: String(item?.full_name || item?.employee_name || '').trim(),
      site_code: String(item?.site_code || '').trim().toUpperCase(),
      site_name: String(item?.site_name || '').trim(),
    }))
    .filter((item) => item.employee_code)
    .sort((a, b) => String(a.employee_code).localeCompare(String(b.employee_code)));
  setCachedHeavyApiValue(cacheKey, normalizedRows, SCHEDULE_CREATE_EMPLOYEE_CACHE_TTL_MS);
  return normalizedRows;
}

function getScheduleCreateEmployeeSeedRows(siteCode = '') {
  const normalizedSiteCode = String(siteCode || '').trim().toUpperCase();
  if (!normalizedSiteCode) return [];
  const deduped = new Map();
  const seedSources = [
    ...(Array.isArray(state.employeeAdmin?.rows) ? state.employeeAdmin.rows : []),
    ...(Array.isArray(state.schedule?.employees) ? state.schedule.employees : []),
  ];
  seedSources.forEach((item) => {
    const employeeCode = String(item?.employee_code || '').trim();
    const rowSiteCode = String(item?.site_code || '').trim().toUpperCase();
    if (!employeeCode || rowSiteCode !== normalizedSiteCode || deduped.has(employeeCode)) return;
    deduped.set(employeeCode, {
      employee_id: String(item?.employee_id || item?.id || '').trim(),
      employee_code: employeeCode,
      full_name: String(item?.full_name || item?.employee_name || '').trim(),
      site_code: rowSiteCode,
      site_name: String(item?.site_name || '').trim(),
    });
  });
  return Array.from(deduped.values()).sort((a, b) => {
    const nameCompare = String(a.full_name || '').localeCompare(String(b.full_name || ''));
    if (nameCompare !== 0) return nameCompare;
    return String(a.employee_code || '').localeCompare(String(b.employee_code || ''));
  });
}

function populateScheduleCreateEmployeeOptions(
  employeeSelect,
  rows = [],
  {
    defaultLabel = '선택안됨',
    emptyLabel = '등록된 직원이 없습니다.',
    selectedEmployeeCode = '',
    preferredEmployeeId = '',
    preferredEmployeeCode = '',
  } = {},
) {
  if (!(employeeSelect instanceof HTMLSelectElement)) return '';
  const normalizedRows = Array.isArray(rows) ? rows : [];
  employeeSelect.innerHTML = '';
  const defaultOption = document.createElement('option');
  defaultOption.value = '';
  defaultOption.textContent = defaultLabel;
  employeeSelect.appendChild(defaultOption);
  normalizedRows.forEach((item) => {
    const option = document.createElement('option');
    option.value = String(item?.employee_code || '').trim();
    option.dataset.employeeId = String(item?.employee_id || '').trim();
    option.textContent = item?.full_name
      ? `${String(item.employee_code || '').trim()} · ${String(item.full_name || '').trim()}`
      : String(item?.employee_code || '').trim();
    employeeSelect.appendChild(option);
  });
  if (!normalizedRows.length) {
    defaultOption.textContent = emptyLabel;
    employeeSelect.value = '';
    return '';
  }
  if (preferredEmployeeId) {
    const optionById = Array.from(employeeSelect.options).find((option) => String(option.dataset.employeeId || '').trim() === preferredEmployeeId);
    if (optionById) {
      employeeSelect.value = optionById.value;
    }
  } else if (preferredEmployeeCode && normalizedRows.some((item) => String(item?.employee_code || '').trim() === preferredEmployeeCode)) {
    employeeSelect.value = preferredEmployeeCode;
  } else if (selectedEmployeeCode && normalizedRows.some((item) => String(item?.employee_code || '').trim() === selectedEmployeeCode)) {
    employeeSelect.value = selectedEmployeeCode;
  }
  return String(employeeSelect.value || '').trim();
}

function getScheduleSingleCreateDefaultDateKey(explicitDate = '') {
  const requested = String(explicitDate || '').trim();
  if (/^\d{4}-\d{2}-\d{2}$/.test(requested)) return requested;
  const lastInteracted = String(state.schedule?.lastInteractedDateKey || '').trim();
  if (/^\d{4}-\d{2}-\d{2}$/.test(lastInteracted)) return lastInteracted;
  return toLocalDateKey(new Date());
}

function formatScheduleSingleCreateTitle(dateKey = '') {
  const normalized = String(dateKey || '').trim();
  if (!/^\d{4}-\d{2}-\d{2}$/.test(normalized)) return '근무일정 추가하기';
  const date = new Date(`${normalized}T00:00:00`);
  if (Number.isNaN(date.getTime())) return '근무일정 추가하기';
  const weekday = SCHEDULE_MONTH_WEEKDAY_LABELS[date.getDay()] || '';
  return `근무일정 추가하기 (${weekday}, ${date.getMonth() + 1}월 ${date.getDate()}일)`;
}

function normalizeScheduleSingleTimePart(value = '', { min = 0, max = 59 } = {}) {
  const text = String(value ?? '').trim();
  if (!/^\d{1,2}$/.test(text)) return '';
  const num = Number(text);
  if (!Number.isFinite(num) || num < min || num > max) return '';
  return String(num).padStart(2, '0');
}

function buildScheduleSingleTimeText(hourValue = '', minuteValue = '') {
  const hour = normalizeScheduleSingleTimePart(hourValue, { min: 0, max: 23 });
  const minute = normalizeScheduleSingleTimePart(minuteValue, { min: 0, max: 59 });
  if (!hour || !minute) return '';
  return `${hour}:${minute}`;
}

function parseScheduleSingleTimeMinutes(timeText = '') {
  const value = String(timeText || '').trim();
  if (!/^\d{2}:\d{2}$/.test(value)) return null;
  const [hourPart, minutePart] = value.split(':').map((item) => Number(item));
  if (!Number.isFinite(hourPart) || !Number.isFinite(minutePart)) return null;
  if (hourPart < 0 || hourPart > 23 || minutePart < 0 || minutePart > 59) return null;
  return (hourPart * 60) + minutePart;
}

function isScheduleSingleTimeRangeValid(startText = '', endText = '') {
  const startMinutes = parseScheduleSingleTimeMinutes(startText);
  const endMinutes = parseScheduleSingleTimeMinutes(endText);
  if (startMinutes == null || endMinutes == null) return false;
  return startMinutes !== endMinutes;
}

async function onScheduleCreateSingle(modalCtx = null) {
  if (!canMutateScheduleData()) {
    showToast('근무일정 생성 권한이 없습니다.', 'error');
    return;
  }
  const ctx = modalCtx && typeof modalCtx === 'object' ? modalCtx : state.sheetContext;
  if (!ctx || ctx.type !== 'schedule-single-create-modal') {
    showToast('단일 생성 컨텍스트를 찾지 못했습니다.', 'error');
    return;
  }

  const dateInput = ctx.refs?.dateInput;
  const siteSelect = ctx.refs?.siteSelect;
  const employeeSelect = ctx.refs?.employeeSelect;
  const dutySelect = ctx.refs?.dutySelect;
  const startHourInput = ctx.refs?.startHourInput;
  const startMinuteInput = ctx.refs?.startMinuteInput;
  const endHourInput = ctx.refs?.endHourInput;
  const endMinuteInput = ctx.refs?.endMinuteInput;
  const noteInput = ctx.refs?.noteInput;

  const selectedDate = normalizeYmdDateValue(dateInput?.value || '');
  const selectedSiteCode = String(siteSelect?.value || '').trim().toUpperCase();
  const selectedEmployeeCode = String(employeeSelect?.value || '').trim();
  const selectedShiftType = normalizeShiftType(dutySelect?.value || '') || 'day';
  const selectedSiteOption = siteSelect instanceof HTMLSelectElement
    ? siteSelect.options[siteSelect.selectedIndex] || null
    : null;
  const selectedEmployeeOption = employeeSelect instanceof HTMLSelectElement
    ? employeeSelect.options[employeeSelect.selectedIndex] || null
    : null;
  const selectedSiteId = String(selectedSiteOption?.dataset?.siteId || '').trim();
  const selectedEmployeeId = String(selectedEmployeeOption?.dataset?.employeeId || '').trim();
  const shiftStartTime = buildScheduleSingleTimeText(startHourInput?.value || '', startMinuteInput?.value || '');
  const shiftEndTime = buildScheduleSingleTimeText(endHourInput?.value || '', endMinuteInput?.value || '');
  const scheduleNote = String(noteInput?.value || '').trim();

  if (
    !selectedDate
    || !selectedSiteCode
    || !selectedEmployeeCode
    || !isScheduleSingleTimeRangeValid(shiftStartTime, shiftEndTime)
  ) {
    showToast('날짜, 직원, 지점, 시작/종료 시간을 확인해 주세요.', 'error');
    return;
  }

  const result = await apiRequest('/schedules/bulk', {
    method: 'POST',
    body: {
      tenant_code: getScheduleTenantValue(),
      site_id: selectedSiteId || null,
      employee_id: selectedEmployeeId || null,
      site_code: selectedSiteCode,
      employee_code: selectedEmployeeCode,
      shift_type: selectedShiftType,
      shift_start_time: shiftStartTime,
      shift_end_time: shiftEndTime,
      schedule_note: scheduleNote || null,
      dates: [selectedDate],
    },
  });

  const createdCount = Number(result?.created_count || 0);
  const skippedDuplicates = Number(result?.skipped_duplicates || 0);
  const errors = Array.isArray(result?.errors) ? result.errors.filter(Boolean) : [];
  closeSheet();
  state.schedule.lastInteractedDateKey = selectedDate;

  if (errors.length) {
    showToast(`일부 항목이 실패했습니다. (${errors.length}건)`, 'error', 3200);
  } else if (createdCount > 0) {
    showToast('근무일정이 추가되었습니다.', 'success', 2400);
  } else if (skippedDuplicates > 0) {
    showToast('중복 일정으로 추가된 항목이 없습니다.', 'info', 2400);
  } else {
    showToast('근무일정이 추가되었습니다.', 'success', 2400);
  }

  invalidateScheduleCache();
  applyCreatedScheduleRowsToCurrentView(Array.isArray(result?.created_rows) ? result.created_rows : [], {
    month: getMonthFromDateKey(selectedDate),
    tenantCode: getScheduleTenantValue(),
  });
}

async function openSingleScheduleModal({
  date = '',
  prefillSiteId = '',
  prefillEmployeeId = '',
  prefillSiteCode = '',
  prefillEmployeeCode = '',
} = {}) {
  if (!canMutateScheduleData()) {
    showToast('근무일정 생성 권한이 없습니다.', 'error');
    return;
  }

  const requestedDateKey = getScheduleSingleCreateDefaultDateKey(date);
  const selectedDateFromMonthFilter = String($('#scheduleSiteFilter')?.value || '').trim().toUpperCase();
  const selectedDate = normalizeYmdDateValue(requestedDateKey) || toLocalDateKey(new Date());
  const buildSiteOptions = () => (Array.isArray(state.siteCatalog) ? state.siteCatalog : [])
    .map((row) => ({
      id: String(row?.id || '').trim(),
      code: String(row?.site_code || '').trim().toUpperCase(),
      name: String(row?.site_name || '').trim(),
    }))
    .filter((row) => row.code)
    .sort((a, b) => String(a.code).localeCompare(String(b.code)));
  const siteOptions = buildSiteOptions();

  const preferredSiteCode = String(prefillSiteCode || '').trim().toUpperCase()
    || (selectedDateFromMonthFilter !== 'ALL' ? selectedDateFromMonthFilter : '')
    || '';
  const fallbackSite = siteOptions.find((item) => item.code === preferredSiteCode)
    || (String(prefillSiteId || '').trim()
      ? siteOptions.find((item) => item.id === String(prefillSiteId || '').trim())
      : null)
    || siteOptions[0]
    || null;

  const ctx = {
    type: 'schedule-single-create-modal',
    selectedDateKey: selectedDate,
    selectedSiteCode: fallbackSite?.code || '',
    selectedEmployeeCode: String(prefillEmployeeCode || '').trim(),
    selectedShiftType: 'day',
    refs: {},
    employeeRows: [],
    employeeLoadToken: 0,
    cleanup: null,
  };

  const content = document.createElement('div');
  content.className = 'schedule-single-create-modal';

  const header = document.createElement('div');
  header.className = 'schedule-single-create-header';
  const titleEl = document.createElement('h3');
  titleEl.className = 'schedule-single-create-title';
  titleEl.textContent = formatScheduleSingleCreateTitle(selectedDate);
  header.appendChild(titleEl);
  content.appendChild(header);

  const body = document.createElement('div');
  body.className = 'schedule-single-create-body';
  const left = document.createElement('div');
  left.className = 'schedule-single-create-left';
  const right = document.createElement('aside');
  right.className = 'schedule-single-create-right';

  const createFieldRow = (labelText, controlNode) => {
    const row = document.createElement('div');
    row.className = 'schedule-single-create-field-row';
    const label = document.createElement('label');
    label.className = 'schedule-single-create-field-label';
    label.textContent = labelText;
    row.appendChild(label);
    const controlWrap = document.createElement('div');
    controlWrap.className = 'schedule-single-create-field-control';
    controlWrap.appendChild(controlNode);
    row.appendChild(controlWrap);
    return row;
  };

  const dateWrap = document.createElement('div');
  dateWrap.className = 'schedule-single-create-date-wrap';
  const dateInput = document.createElement('input');
  dateInput.type = 'date';
  dateInput.className = 'schedule-single-create-date-input';
  dateInput.value = selectedDate;
  const dateHint = document.createElement('span');
  dateHint.className = 'schedule-single-create-date-hint';
  dateWrap.appendChild(dateInput);
  dateWrap.appendChild(dateHint);
  left.appendChild(createFieldRow('날짜', dateWrap));

  const employeeSelect = document.createElement('select');
  employeeSelect.className = 'schedule-single-create-select';
  employeeSelect.innerHTML = '<option value="">선택안됨</option>';
  left.appendChild(createFieldRow('직원', employeeSelect));

  const siteSelect = document.createElement('select');
  siteSelect.className = 'schedule-single-create-select';
  siteSelect.innerHTML = '<option value="">선택안됨</option>';
  left.appendChild(createFieldRow('지점', siteSelect));

  const dutySelect = document.createElement('select');
  dutySelect.className = 'schedule-single-create-select';
  [
    { value: 'day', label: '주간근무' },
    { value: 'night', label: '야간근무' },
    { value: 'off', label: '휴무' },
    { value: 'holiday', label: '공휴일' },
  ].forEach((item) => {
    const option = document.createElement('option');
    option.value = item.value;
    option.textContent = item.label;
    dutySelect.appendChild(option);
  });
  dutySelect.value = 'day';
  left.appendChild(createFieldRow('직무', dutySelect));

  const timeControls = document.createElement('div');
  timeControls.className = 'schedule-single-create-time-controls';
  const startHourInput = document.createElement('input');
  startHourInput.type = 'text';
  startHourInput.inputMode = 'numeric';
  startHourInput.maxLength = 2;
  startHourInput.className = 'schedule-single-create-time-input';
  startHourInput.value = '09';
  const startMinuteInput = document.createElement('input');
  startMinuteInput.type = 'text';
  startMinuteInput.inputMode = 'numeric';
  startMinuteInput.maxLength = 2;
  startMinuteInput.className = 'schedule-single-create-time-input';
  startMinuteInput.value = '00';
  const endHourInput = document.createElement('input');
  endHourInput.type = 'text';
  endHourInput.inputMode = 'numeric';
  endHourInput.maxLength = 2;
  endHourInput.className = 'schedule-single-create-time-input';
  endHourInput.value = '18';
  const endMinuteInput = document.createElement('input');
  endMinuteInput.type = 'text';
  endMinuteInput.inputMode = 'numeric';
  endMinuteInput.maxLength = 2;
  endMinuteInput.className = 'schedule-single-create-time-input';
  endMinuteInput.value = '00';
  const colonA = document.createElement('span');
  colonA.className = 'schedule-single-create-time-separator';
  colonA.textContent = ':';
  const colonB = document.createElement('span');
  colonB.className = 'schedule-single-create-time-separator';
  colonB.textContent = ':';
  const rangeSep = document.createElement('span');
  rangeSep.className = 'schedule-single-create-time-separator';
  rangeSep.textContent = '~';
  timeControls.appendChild(startHourInput);
  timeControls.appendChild(colonA);
  timeControls.appendChild(startMinuteInput);
  timeControls.appendChild(rangeSep);
  timeControls.appendChild(endHourInput);
  timeControls.appendChild(colonB);
  timeControls.appendChild(endMinuteInput);
  left.appendChild(createFieldRow('시간', timeControls));

  const noteInput = document.createElement('textarea');
  noteInput.className = 'schedule-single-create-note';
  noteInput.rows = 4;
  left.appendChild(createFieldRow('일정노트', noteInput));

  const breakHead = document.createElement('div');
  breakHead.className = 'schedule-single-create-break-head';
  breakHead.textContent = '근무일정 휴게시간';
  right.appendChild(breakHead);
  const breakToggleLabel = document.createElement('label');
  breakToggleLabel.className = 'schedule-single-create-break-toggle';
  const autoBreakInput = document.createElement('input');
  autoBreakInput.type = 'checkbox';
  autoBreakInput.checked = true;
  const autoBreakText = document.createElement('span');
  autoBreakText.textContent = '자동 휴게시간 사용';
  breakToggleLabel.appendChild(autoBreakInput);
  breakToggleLabel.appendChild(autoBreakText);
  right.appendChild(breakToggleLabel);
  const breakSummary = document.createElement('p');
  breakSummary.className = 'schedule-single-create-break-summary';
  right.appendChild(breakSummary);

  body.appendChild(left);
  body.appendChild(right);
  content.appendChild(body);

  const footer = document.createElement('div');
  footer.className = 'schedule-single-create-footer';
  const closeBtn = document.createElement('button');
  closeBtn.type = 'button';
  closeBtn.className = 'btn btn-secondary';
  closeBtn.textContent = '닫기';
  const submitBtn = document.createElement('button');
  submitBtn.type = 'button';
  submitBtn.className = 'btn btn-primary';
  submitBtn.textContent = '추가하기';
  submitBtn.disabled = true;
  footer.appendChild(closeBtn);
  footer.appendChild(submitBtn);
  content.appendChild(footer);

  ctx.refs = {
    titleEl,
    dateInput,
    dateHint,
    siteSelect,
    employeeSelect,
    dutySelect,
    startHourInput,
    startMinuteInput,
    endHourInput,
    endMinuteInput,
    noteInput,
    autoBreakInput,
    breakSummary,
    submitBtn,
  };

  const updateDateLabel = () => {
    const normalizedDate = normalizeYmdDateValue(dateInput.value) || selectedDate;
    ctx.selectedDateKey = normalizedDate;
    dateInput.value = normalizedDate;
    titleEl.textContent = formatScheduleSingleCreateTitle(normalizedDate);
    const date = new Date(`${normalizedDate}T00:00:00`);
    if (Number.isNaN(date.getTime())) {
      dateHint.textContent = '';
      return;
    }
    const weekday = SCHEDULE_MONTH_WEEKDAY_LABELS[date.getDay()] || '';
    dateHint.textContent = `${date.getFullYear()}.${String(date.getMonth() + 1).padStart(2, '0')}.${String(date.getDate()).padStart(2, '0')} (${weekday})`;
  };

  const updateBreakSummary = () => {
    if (!autoBreakInput.checked) {
      breakSummary.textContent = '자동 휴게시간: 0분';
      return;
    }
    breakSummary.textContent = '자동 휴게시간: 0분';
  };

  const updateSubmitState = () => {
    const selectedDateKey = normalizeYmdDateValue(dateInput.value);
    const selectedSiteCode = String(siteSelect.value || '').trim().toUpperCase();
    const selectedEmployeeCode = String(employeeSelect.value || '').trim();
    const shiftStartTime = buildScheduleSingleTimeText(startHourInput.value, startMinuteInput.value);
    const shiftEndTime = buildScheduleSingleTimeText(endHourInput.value, endMinuteInput.value);
    const canSubmit = Boolean(
      selectedDateKey
      && selectedSiteCode
      && selectedEmployeeCode
      && isScheduleSingleTimeRangeValid(shiftStartTime, shiftEndTime),
    );
    submitBtn.disabled = !canSubmit;
  };

  const normalizeTimeInput = (input, max) => {
    if (!(input instanceof HTMLInputElement)) return;
    const digitsOnly = String(input.value || '').replace(/[^\d]/g, '').slice(0, 2);
    input.value = digitsOnly;
    if (!digitsOnly) return;
    const num = Number(digitsOnly);
    if (!Number.isFinite(num)) {
      input.value = '';
      return;
    }
    if (num > max) {
      input.value = String(max);
    }
  };

  const commitTimeInput = (input, max) => {
    if (!(input instanceof HTMLInputElement)) return;
    const normalized = normalizeScheduleSingleTimePart(input.value, { min: 0, max });
    input.value = normalized || '';
  };

  const renderEmployeeOptions = async () => {
    ctx.employeeLoadToken += 1;
    const token = ctx.employeeLoadToken;
    const selectedEmployeeCode = String(employeeSelect.value || '').trim();
    const preferredEmployeeId = String(prefillEmployeeId || '').trim();
    const preferredEmployeeCode = String(prefillEmployeeCode || '').trim();
    const scopedSiteCode = String(siteSelect.value || '').trim().toUpperCase();
    if (!scopedSiteCode) {
      employeeSelect.disabled = true;
      employeeSelect.innerHTML = '<option value="">지점을 먼저 선택해 주세요.</option>';
      ctx.selectedEmployeeCode = '';
      updateSubmitState();
      return;
    }
    const seedRows = getScheduleCreateEmployeeSeedRows(scopedSiteCode);
    if (seedRows.length) {
      ctx.employeeRows = seedRows;
      populateScheduleCreateEmployeeOptions(employeeSelect, seedRows, {
        defaultLabel: '선택안됨',
        emptyLabel: '등록된 직원이 없습니다.',
        selectedEmployeeCode,
        preferredEmployeeId,
        preferredEmployeeCode,
      });
      employeeSelect.disabled = false;
      ctx.selectedEmployeeCode = String(employeeSelect.value || '').trim();
      updateSubmitState();
    } else {
      employeeSelect.disabled = true;
      employeeSelect.innerHTML = '<option value="">직원 불러오는 중...</option>';
    }
    try {
      const rows = await listScheduleCreateEmployees(scopedSiteCode);
      if (token !== ctx.employeeLoadToken) return;
      ctx.employeeRows = rows;
      populateScheduleCreateEmployeeOptions(employeeSelect, rows, {
        defaultLabel: '선택안됨',
        emptyLabel: '등록된 직원이 없습니다.',
        selectedEmployeeCode,
        preferredEmployeeId,
        preferredEmployeeCode,
      });
    } catch (error) {
      if (token !== ctx.employeeLoadToken) return;
      employeeSelect.innerHTML = '<option value="">직원 목록 조회 실패</option>';
      showToast(normalizeActionError(error, '직원 목록을 불러오지 못했습니다.'), 'error', 2600);
    } finally {
      if (token === ctx.employeeLoadToken) {
        employeeSelect.disabled = false;
        ctx.selectedEmployeeCode = String(employeeSelect.value || '').trim();
        updateSubmitState();
      }
    }
  };

  const populateSiteOptions = () => {
    const options = buildSiteOptions();
    const currentValue = String(siteSelect.value || ctx.selectedSiteCode || '').trim().toUpperCase();
    siteSelect.innerHTML = '';
    if (!options.length) {
      const option = document.createElement('option');
      option.value = '';
      option.textContent = '지점 불러오는 중...';
      siteSelect.appendChild(option);
      siteSelect.disabled = true;
      ctx.selectedSiteCode = '';
      return;
    }
    options.forEach((item) => {
      const option = document.createElement('option');
      option.value = item.code;
      option.dataset.siteId = item.id;
      option.textContent = item.name ? `${item.code} · ${item.name}` : item.code;
      siteSelect.appendChild(option);
    });
    siteSelect.disabled = false;
    if (currentValue && options.some((item) => item.code === currentValue)) {
      siteSelect.value = currentValue;
    } else if (fallbackSite?.code && options.some((item) => item.code === fallbackSite.code)) {
      siteSelect.value = fallbackSite.code;
    } else {
      siteSelect.value = options[0]?.code || '';
    }
    ctx.selectedSiteCode = String(siteSelect.value || '').trim().toUpperCase();
  };
  populateSiteOptions();

  openSheet({
    title: '',
    contentNode: content,
    actions: [],
  });
  const sheet = $('#appSheet');
  if (sheet) {
    sheet.classList.add('sheet-layout-schedule-single-create');
  }
  state.sheetContext = ctx;

  dateInput.addEventListener('change', () => {
    updateDateLabel();
    updateSubmitState();
  });
  siteSelect.addEventListener('change', () => {
    ctx.selectedSiteCode = String(siteSelect.value || '').trim().toUpperCase();
    ctx.selectedEmployeeCode = '';
    employeeSelect.value = '';
    renderEmployeeOptions().catch(() => {});
    updateSubmitState();
  });
  employeeSelect.addEventListener('change', () => {
    ctx.selectedEmployeeCode = String(employeeSelect.value || '').trim();
    updateSubmitState();
  });
  dutySelect.addEventListener('change', () => {
    ctx.selectedShiftType = normalizeShiftType(dutySelect.value) || 'day';
  });
  [startHourInput, startMinuteInput, endHourInput, endMinuteInput].forEach((input) => {
    const max = input === startHourInput || input === endHourInput ? 23 : 59;
    input.addEventListener('input', () => {
      normalizeTimeInput(input, max);
      updateBreakSummary();
      updateSubmitState();
    });
    input.addEventListener('blur', () => {
      commitTimeInput(input, max);
      updateBreakSummary();
      updateSubmitState();
    });
  });
  autoBreakInput.addEventListener('change', () => {
    updateBreakSummary();
  });
  closeBtn.addEventListener('click', () => closeSheet());
  submitBtn.addEventListener('click', () => {
    if (submitBtn.disabled) return;
    setButtonsBusy(submitBtn, true, '추가 중...');
    runActionSafely(
      onScheduleCreateSingle(ctx),
      '근무일정을 추가하지 못했습니다.',
    ).finally(() => {
      setButtonsBusy(submitBtn, false);
    });
  });

  updateDateLabel();
  updateBreakSummary();
  renderEmployeeOptions().catch(() => {});
  updateSubmitState();
  refreshSiteCatalog({ force: false })
    .then(() => {
      if (state.sheetContext !== ctx) return;
      populateSiteOptions();
      renderEmployeeOptions().catch(() => {});
    })
    .catch(() => {});
}

async function openScheduleCreateSheet({ bulk = false } = {}) {
  if (!canMutateScheduleData()) {
    showToast('근무일정 생성 권한이 없습니다.', 'error');
    return;
  }
  const buildSiteOptions = () => (Array.isArray(state.siteCatalog) ? state.siteCatalog : [])
    .map((row) => ({
      id: String(row?.id || '').trim(),
      code: String(row?.site_code || '').trim().toUpperCase(),
      name: String(row?.site_name || '').trim(),
    }))
    .filter((row) => row.code)
    .sort((a, b) => String(a.code).localeCompare(String(b.code)));
  const siteOptions = buildSiteOptions();
  const initialMonth = normalizeMonthKey(state.schedule?.month || getScheduleMonthValue()) || toMonthKey(new Date());
  const initialSiteFromImport = String($('#scheduleImportSite')?.value || '').trim().toUpperCase();
  const initialSiteCode = initialSiteFromImport && siteOptions.some((item) => item.code === initialSiteFromImport)
    ? initialSiteFromImport
    : (siteOptions[0]?.code || '');
  const initialDates = new Set();
  if (!bulk) {
    initialDates.add(toLocalDateKey(new Date()));
  }

  const ctx = {
    type: 'schedule-create-modal',
    mode: bulk ? 'bulk' : 'single',
    calendarMonth: initialMonth,
    selectedSiteCode: initialSiteCode,
    selectedEmployeeCode: '',
    selectedTemplateIds: new Set(),
    selectedDates: initialDates,
    selectedLeaveType: '',
    templateSearch: '',
    templateDropdownOpen: false,
    templateOptions: [],
    employeeRows: [],
    employeeLoadToken: 0,
    monthRowsCache: new Map(),
    monthRowsLoading: new Set(),
    refs: {},
    cleanup: null,
  };

  const content = document.createElement('div');
  content.className = 'schedule-create-modal';

  const header = document.createElement('div');
  header.className = 'schedule-create-header';
  const headerTitleWrap = document.createElement('div');
  headerTitleWrap.className = 'schedule-create-header-title';
  const titleEl = document.createElement('h3');
  titleEl.textContent = '근무일정 추가하기';
  headerTitleWrap.appendChild(titleEl);
  header.appendChild(headerTitleWrap);
  const headerActions = document.createElement('div');
  headerActions.className = 'schedule-create-header-actions';
  const helpBtn = document.createElement('button');
  helpBtn.type = 'button';
  helpBtn.className = 'btn btn-icon btn-secondary';
  helpBtn.setAttribute('aria-label', '근무일정 추가 도움말');
  helpBtn.textContent = '?';
  const closeBtn = document.createElement('button');
  closeBtn.type = 'button';
  closeBtn.className = 'btn btn-icon btn-secondary';
  closeBtn.setAttribute('aria-label', '닫기');
  closeBtn.textContent = '×';
  headerActions.appendChild(helpBtn);
  headerActions.appendChild(closeBtn);
  header.appendChild(headerActions);
  content.appendChild(header);

  const tabRow = document.createElement('div');
  tabRow.className = 'schedule-create-tab-row';
  [
    { key: 'template', label: '템플릿 기준', enabled: false },
    { key: 'site', label: '지점 기준', enabled: false },
    { key: 'duty', label: '직무 기준', enabled: false },
    { key: 'employee', label: '직원 기준', enabled: true },
  ].forEach((tab) => {
    const btn = document.createElement('button');
    btn.type = 'button';
    btn.className = `schedule-create-tab${tab.enabled ? ' active' : ''}`;
    btn.textContent = tab.label;
    if (!tab.enabled) {
      btn.disabled = true;
      btn.setAttribute('aria-disabled', 'true');
    } else {
      btn.setAttribute('aria-current', 'page');
    }
    tabRow.appendChild(btn);
  });
  content.appendChild(tabRow);

  const fieldsWrap = document.createElement('div');
  fieldsWrap.className = 'schedule-create-fields';

  const row1 = document.createElement('div');
  row1.className = 'schedule-create-field-row';
  const siteField = document.createElement('label');
  siteField.className = 'input-field';
  siteField.innerHTML = '<span>지점</span>';
  const siteSelect = document.createElement('select');
  siteField.appendChild(siteSelect);
  row1.appendChild(siteField);

  const employeeField = document.createElement('label');
  employeeField.className = 'input-field';
  employeeField.innerHTML = '<span>직원</span>';
  const employeeSelect = document.createElement('select');
  employeeSelect.innerHTML = '<option value="">직원 선택</option>';
  employeeField.appendChild(employeeSelect);
  row1.appendChild(employeeField);
  fieldsWrap.appendChild(row1);

  const row2 = document.createElement('div');
  row2.className = 'schedule-create-field-row';

  const templateField = document.createElement('div');
  templateField.className = 'input-field schedule-create-template-field';
  const templateLabel = document.createElement('span');
  templateLabel.textContent = '근무일정 템플릿';
  templateField.appendChild(templateLabel);
  const templateTrigger = document.createElement('button');
  templateTrigger.type = 'button';
  templateTrigger.className = 'schedule-create-template-trigger';
  templateTrigger.setAttribute('aria-haspopup', 'listbox');
  templateTrigger.setAttribute('aria-expanded', 'false');
  templateTrigger.textContent = '선택안됨';
  templateField.appendChild(templateTrigger);

  const templateDropdown = document.createElement('div');
  templateDropdown.className = 'schedule-create-template-dropdown hidden';
  const templateSearch = document.createElement('input');
  templateSearch.type = 'search';
  templateSearch.className = 'schedule-create-template-search';
  templateSearch.placeholder = '검색';
  templateDropdown.appendChild(templateSearch);
  const templateList = document.createElement('div');
  templateList.className = 'schedule-create-template-list';
  templateDropdown.appendChild(templateList);
  templateField.appendChild(templateDropdown);
  row2.appendChild(templateField);

  const leaveField = document.createElement('label');
  leaveField.className = 'input-field';
  leaveField.innerHTML = '<span>휴가 유형들</span>';
  const leaveSelect = document.createElement('select');
  [
    { value: '', label: '선택안됨' },
    { value: 'annual', label: '연차' },
    { value: 'half_am', label: '반차(오전)' },
    { value: 'half_pm', label: '반차(오후)' },
    { value: 'off', label: '휴무' },
  ].forEach((item) => {
    const option = document.createElement('option');
    option.value = item.value;
    option.textContent = item.label;
    leaveSelect.appendChild(option);
  });
  leaveField.appendChild(leaveSelect);
  row2.appendChild(leaveField);
  fieldsWrap.appendChild(row2);
  content.appendChild(fieldsWrap);

  const guide = document.createElement('p');
  guide.className = 'schedule-create-guide';
  guide.textContent = '근무구분별로 템플릿을 하나씩 선택할 수 있습니다. 서로 시간이 겹치지 않으면 주간·초과·야간을 함께 배정할 수 있습니다.';
  content.appendChild(guide);

  const calendarWrap = document.createElement('div');
  calendarWrap.className = 'schedule-create-calendar-wrap';
  const calendarHead = document.createElement('div');
  calendarHead.className = 'schedule-create-calendar-head';
  const prevBtn = document.createElement('button');
  prevBtn.type = 'button';
  prevBtn.className = 'btn btn-secondary btn-icon';
  prevBtn.textContent = '‹';
  prevBtn.setAttribute('aria-label', '이전 달');
  const monthTitle = document.createElement('strong');
  monthTitle.className = 'schedule-create-calendar-month';
  monthTitle.textContent = formatScheduleMonthTitle(ctx.calendarMonth);
  const nextBtn = document.createElement('button');
  nextBtn.type = 'button';
  nextBtn.className = 'btn btn-secondary btn-icon';
  nextBtn.textContent = '›';
  nextBtn.setAttribute('aria-label', '다음 달');
  calendarHead.appendChild(prevBtn);
  calendarHead.appendChild(monthTitle);
  calendarHead.appendChild(nextBtn);
  calendarWrap.appendChild(calendarHead);

  const calendarGrid = document.createElement('div');
  calendarGrid.className = 'schedule-create-calendar-grid';
  calendarWrap.appendChild(calendarGrid);

  const selectedDatesHint = document.createElement('p');
  selectedDatesHint.className = 'schedule-create-selected-dates';
  calendarWrap.appendChild(selectedDatesHint);
  const calendarLockedHint = document.createElement('div');
  calendarLockedHint.className = 'schedule-create-calendar-locked-hint hidden';
  calendarLockedHint.textContent = '근무일정 템플릿을 선택하면 날짜를 고를 수 있습니다.';
  calendarWrap.appendChild(calendarLockedHint);
  content.appendChild(calendarWrap);

  const footer = document.createElement('div');
  footer.className = 'schedule-create-footer';
  const footerCloseBtn = document.createElement('button');
  footerCloseBtn.type = 'button';
  footerCloseBtn.className = 'btn btn-secondary';
  footerCloseBtn.textContent = '닫기';
  const submitBtn = document.createElement('button');
  submitBtn.type = 'button';
  submitBtn.className = 'btn btn-primary';
  submitBtn.textContent = '추가하기';
  submitBtn.disabled = true;
  footer.appendChild(footerCloseBtn);
  footer.appendChild(submitBtn);
  content.appendChild(footer);

  ctx.refs = {
    siteSelect,
    employeeSelect,
    templateTrigger,
    templateDropdown,
    templateSearch,
    templateList,
    leaveSelect,
    calendarGrid,
    calendarWrap,
    calendarLockedHint,
    prevBtn,
    nextBtn,
    monthTitle,
    selectedDatesHint,
    submitBtn,
  };

  const setTemplateDropdownOpen = (open) => {
    const nextOpen = Boolean(open);
    ctx.templateDropdownOpen = nextOpen;
    templateDropdown.classList.toggle('hidden', !nextOpen);
    templateTrigger.setAttribute('aria-expanded', nextOpen ? 'true' : 'false');
  };

  const updateSubmitState = () => {
    const selectedTemplateRows = getScheduleCreateSelectedTemplateRows(ctx);
    const dateCount = ctx.selectedDates.size;
    const canSubmit = Boolean(
      ctx.selectedSiteCode
      && ctx.selectedEmployeeCode
      && selectedTemplateRows.length
      && dateCount > 0,
    );
    submitBtn.disabled = !canSubmit;
    const monthLoading = ctx.monthRowsLoading instanceof Set && ctx.monthRowsLoading.has(ctx.calendarMonth);
    const combinationConflict = getScheduleCreateTemplateCombinationConflict(selectedTemplateRows);
    const hasTemplateSelected = selectedTemplateRows.length > 0;
    const conflictGuide = hasTemplateSelected && ctx.selectedEmployeeCode
      ? '회색 날짜는 기존 일정과 시간이 겹쳐 선택할 수 없습니다.'
      : '직원과 템플릿을 선택하면 겹치는 일정 날짜가 회색으로 비활성화됩니다.';
    if (combinationConflict) {
      selectedDatesHint.textContent = combinationConflict.message;
    } else if (!hasTemplateSelected) {
      selectedDatesHint.textContent = '근무일정 템플릿을 먼저 선택해 주세요.';
    } else if (monthLoading) {
      selectedDatesHint.textContent = '기존 일정 확인 중...';
    } else if (dateCount > 0) {
      selectedDatesHint.textContent = `선택된 날짜 ${dateCount}일 · ${conflictGuide}`;
    } else {
      selectedDatesHint.textContent = `선택된 날짜가 없습니다. · ${conflictGuide}`;
    }
  };

  const getSelectedTemplateRows = () => getScheduleCreateSelectedTemplateRows(ctx);

  const shouldCheckScheduleConflict = () => {
    const templateRows = getSelectedTemplateRows();
    return Boolean(
      String(ctx.selectedEmployeeCode || '').trim()
      && templateRows.length
      && !getScheduleCreateTemplateCombinationConflict(templateRows)
      && templateRows.every((row) => String(row?.start_time || '').trim() && String(row?.end_time || '').trim()),
    );
  };

  const isScheduleCreateCalendarEnabled = () => getSelectedTemplateRows().length > 0;

  const syncCalendarLockState = () => {
    const enabled = isScheduleCreateCalendarEnabled();
    calendarWrap.classList.toggle('is-disabled', !enabled);
    calendarLockedHint.classList.toggle('hidden', enabled);
    prevBtn.disabled = !enabled;
    nextBtn.disabled = !enabled;
    prevBtn.setAttribute('aria-disabled', enabled ? 'false' : 'true');
    nextBtn.setAttribute('aria-disabled', enabled ? 'false' : 'true');
  };

  const getCachedScheduleRowsForMonth = (monthKey = '') => {
    const cache = ctx.monthRowsCache instanceof Map ? ctx.monthRowsCache : new Map();
    return Array.isArray(cache.get(monthKey)) ? cache.get(monthKey) : [];
  };

  const getScheduleCreateDateConflict = (dateKey = '') => {
    if (!shouldCheckScheduleConflict()) return null;
    const templateRows = getSelectedTemplateRows();
    const rows = getCachedScheduleRowsForMonth(getMonthFromDateKey(dateKey))
      .filter((row) => String(row?.employee_code || '').trim() === String(ctx.selectedEmployeeCode || '').trim())
      .filter((row) => String(row?.schedule_date || '').trim() === String(dateKey || '').trim());
    const conflictRowMap = new Map();
    templateRows.forEach((templateRow) => {
      const candidateStart = String(templateRow?.start_time || '').trim();
      const candidateEnd = String(templateRow?.end_time || '').trim();
      rows.forEach((row) => {
        if (!hasScheduleTimeOverlap(
          candidateStart,
          candidateEnd,
          row?.start_time || row?.shift_start_time || '',
          row?.end_time || row?.shift_end_time || '',
        )) {
          return;
        }
        const key = String(row?.schedule_id || row?.id || `${row?.schedule_date || ''}:${row?.shift_type || ''}`);
        if (!conflictRowMap.has(key)) {
          conflictRowMap.set(key, row);
        }
      });
    });
    const conflictRows = Array.from(conflictRowMap.values());
    if (!conflictRows.length) return null;
    const firstConflict = conflictRows[0];
    const reason = formatScheduleBoardItemTimeLabel(firstConflict);
    return {
      count: conflictRows.length,
      reason,
    };
  };

  const syncSelectedDatesAgainstConflicts = () => {
    if (!shouldCheckScheduleConflict()) return;
    Array.from(ctx.selectedDates || []).forEach((dateKey) => {
      if (getScheduleCreateDateConflict(dateKey)) {
        ctx.selectedDates.delete(dateKey);
      }
    });
  };

  const ensureMonthRowsForConflictCheck = async (monthKey = '') => {
    const normalizedMonth = normalizeMonthKey(monthKey);
    if (!normalizedMonth || !shouldCheckScheduleConflict()) return [];
    if (!(ctx.monthRowsCache instanceof Map)) ctx.monthRowsCache = new Map();
    if (!(ctx.monthRowsLoading instanceof Set)) ctx.monthRowsLoading = new Set();
    if (ctx.monthRowsCache.has(normalizedMonth)) {
      return getCachedScheduleRowsForMonth(normalizedMonth);
    }
    if (ctx.monthRowsLoading.has(normalizedMonth)) return [];
    ctx.monthRowsLoading.add(normalizedMonth);
    updateSubmitState();
    try {
      const liteBundle = await loadMonthlyScheduleLiteWithCache({
        month: normalizedMonth,
        tenantCode: getScheduleTenantValue(),
        force: false,
      });
      const normalizedRows = (Array.isArray(liteBundle?.days) ? liteBundle.days : [])
        .flatMap((day) => {
          const dateKey = String(day?.date || '').trim();
          if (getMonthFromDateKey(dateKey) !== normalizedMonth) return [];
          return (Array.isArray(day?.items) ? day.items : [])
            .map((item) => {
              const normalized = normalizeScheduleBoardItem(item);
              return {
                id: normalized.schedule_id || '',
                schedule_id: normalized.schedule_id || '',
                schedule_date: dateKey,
                employee_code: normalized.employee_code,
                shift_type: normalized.shift_type,
                start_time: normalized.start_time,
                end_time: normalized.end_time,
              };
            })
            .filter((row) => row.employee_code && row.shift_type);
        });
      ctx.monthRowsCache.set(normalizedMonth, normalizedRows);
      return normalizedRows;
    } finally {
      ctx.monthRowsLoading.delete(normalizedMonth);
      updateSubmitState();
    }
  };

  const refreshCalendarAvailability = async ({ ensureConflictRows = false } = {}) => {
    if (ensureConflictRows) {
      await ensureMonthRowsForConflictCheck(ctx.calendarMonth);
    }
    syncSelectedDatesAgainstConflicts();
    renderCalendar();
    updateSubmitState();
  };

  const renderTemplateOptions = () => {
    const selectedSiteCode = String(siteSelect.value || '').trim().toUpperCase();
    ctx.selectedSiteCode = selectedSiteCode;
    ctx.templateOptions = buildScheduleTemplateSelectOptions(selectedSiteCode);
    const nextSelectedIds = new Set(
      Array.from(ctx.selectedTemplateIds || [])
        .map((id) => String(id || '').trim())
        .filter((id) => ctx.templateOptions.some((item) => item.id === id)),
    );
    ctx.selectedTemplateIds = nextSelectedIds;
    if (!ctx.selectedTemplateIds.size) {
      ctx.selectedDates.clear();
    }
    const selectedRows = getSelectedTemplateRows();
    templateTrigger.textContent = formatScheduleCreateTemplateTriggerLabel(ctx);

    const query = String(ctx.templateSearch || '').trim().toLowerCase();
    const visibleRows = ctx.templateOptions.filter((item) => {
      if (!query) return true;
      return (
        String(item.label || '').toLowerCase().includes(query)
        || formatScheduleTemplateDutyTypeLabel(item?.duty_type).toLowerCase().includes(query)
      );
    });

    templateList.innerHTML = '';
    if (!visibleRows.length) {
      const empty = document.createElement('p');
      empty.className = 'muted';
      empty.textContent = '표시할 템플릿이 없습니다.';
      templateList.appendChild(empty);
      syncCalendarLockState();
      updateSubmitState();
      return;
    }
    const groupedRows = new Map();
    visibleRows.forEach((item) => {
      const duty = normalizeShiftType(item?.duty_type || '') || 'other';
      if (!groupedRows.has(duty)) groupedRows.set(duty, []);
      groupedRows.get(duty).push(item);
    });
    SCHEDULE_CREATE_TEMPLATE_DUTY_ORDER.forEach((duty) => {
      const rows = groupedRows.get(duty) || [];
      if (!rows.length) return;
      const section = document.createElement('section');
      section.className = 'schedule-create-template-group';
      section.dataset.duty = duty;
      const heading = document.createElement('h4');
      heading.className = 'schedule-create-template-group-title';
      heading.textContent = formatScheduleTemplateDutyTypeLabel(duty);
      section.appendChild(heading);
      rows.forEach((item) => {
        const row = document.createElement('label');
        row.className = 'schedule-create-template-item';
        const checkbox = document.createElement('input');
        checkbox.type = 'checkbox';
        checkbox.className = 'schedule-create-template-check';
        checkbox.checked = ctx.selectedTemplateIds.has(item.id);
        row.classList.toggle('is-selected', checkbox.checked);
        checkbox.addEventListener('change', () => {
          const currentSelection = getSelectedTemplateRows()
            .filter((selected) => normalizeShiftType(selected?.duty_type || '') !== duty);
          if (checkbox.checked) {
            const conflict = getScheduleCreateTemplateCombinationConflict([...currentSelection, item]);
            if (conflict) {
              checkbox.checked = false;
              showToast(conflict.message, 'error', 2400);
              return;
            }
            const nextIds = new Set(
              Array.from(ctx.selectedTemplateIds || [])
                .filter((id) => {
                  const existing = ctx.templateOptions.find((option) => option.id === id);
                  return normalizeShiftType(existing?.duty_type || '') !== duty;
                }),
            );
            nextIds.add(item.id);
            ctx.selectedTemplateIds = nextIds;
          } else {
            ctx.selectedTemplateIds.delete(item.id);
          }
          renderTemplateOptions();
          refreshCalendarAvailability({ ensureConflictRows: true }).catch(() => {});
        });
        const indicator = document.createElement('span');
        indicator.className = 'schedule-create-template-indicator';
        const textWrap = document.createElement('span');
        textWrap.className = 'schedule-create-template-copy';
        const titleRow = document.createElement('span');
        titleRow.className = 'schedule-create-template-title-row';
        const title = document.createElement('strong');
        title.textContent = String(item.template_name || item.label || '').trim();
        const time = document.createElement('span');
        time.className = 'schedule-create-template-time';
        time.textContent = `${String(item.start_time || '').slice(0, 5)}-${String(item.end_time || '').slice(0, 5)}`;
        titleRow.appendChild(title);
        titleRow.appendChild(time);
        const metaRow = document.createElement('span');
        metaRow.className = 'schedule-create-template-meta-row';
        const meta = document.createElement('small');
        meta.textContent = `${Number(item.paid_hours || 0)}h`;
        const breakTag = document.createElement('small');
        breakTag.textContent = `휴게 ${Number(item.break_minutes || 0)}m`;
        metaRow.appendChild(meta);
        metaRow.appendChild(breakTag);
        textWrap.appendChild(titleRow);
        textWrap.appendChild(metaRow);
        row.appendChild(checkbox);
        row.appendChild(indicator);
        row.appendChild(textWrap);
        section.appendChild(row);
      });
      templateList.appendChild(section);
    });
    syncCalendarLockState();
    updateSubmitState();
  };

  const renderCalendar = () => {
    const month = normalizeMonthKey(ctx.calendarMonth) || toMonthKey(new Date());
    ctx.calendarMonth = month;
    const monthMeta = getMonthMeta(month);
    if (!monthMeta) return;
    monthTitle.textContent = formatScheduleMonthTitle(month);
    calendarGrid.innerHTML = '';
    syncCalendarLockState();

    const weekdayRow = document.createElement('div');
    weekdayRow.className = 'schedule-create-calendar-weekdays';
    SCHEDULE_MONTH_WEEKDAY_LABELS.forEach((weekday) => {
      const el = document.createElement('div');
      el.className = 'schedule-create-weekday';
      el.textContent = weekday;
      weekdayRow.appendChild(el);
    });
    calendarGrid.appendChild(weekdayRow);

    const daysGrid = document.createElement('div');
    daysGrid.className = 'schedule-create-calendar-days';
    calendarGrid.appendChild(daysGrid);

    const slots = [];
    for (let i = 0; i < monthMeta.firstDate.getDay(); i += 1) {
      slots.push('');
    }
    for (let day = 1; day <= monthMeta.daysInMonth; day += 1) {
      slots.push(`${month}-${String(day).padStart(2, '0')}`);
    }
    while (slots.length < 42) {
      slots.push('');
    }

    const todayKey = toLocalDateKey(new Date());
    slots.forEach((dateKey) => {
      const btn = document.createElement('button');
      btn.type = 'button';
      btn.className = 'schedule-create-day-btn';
      if (!dateKey) {
        btn.classList.add('is-empty');
        btn.disabled = true;
        daysGrid.appendChild(btn);
        return;
      }
      btn.dataset.date = dateKey;
      btn.textContent = String(Number(dateKey.slice(-2)));
      if (dateKey === todayKey) btn.classList.add('is-today');
      if (!isScheduleCreateCalendarEnabled()) {
        btn.disabled = true;
        btn.setAttribute('aria-disabled', 'true');
      }
      const conflict = getScheduleCreateDateConflict(dateKey);
      if (conflict) {
        btn.classList.add('is-conflict');
        btn.disabled = true;
        btn.setAttribute('aria-disabled', 'true');
        btn.title = conflict.count > 1
          ? `겹치는 일정 ${conflict.count}건이 있어 선택할 수 없습니다.`
          : `기존 일정(${conflict.reason})과 시간이 겹쳐 선택할 수 없습니다.`;
      }
      if (ctx.selectedDates.has(dateKey)) btn.classList.add('is-selected');
      btn.addEventListener('click', () => {
        if (btn.disabled) return;
        if (ctx.mode === 'single') {
          if (ctx.selectedDates.has(dateKey)) {
            ctx.selectedDates.clear();
          } else {
            ctx.selectedDates.clear();
            ctx.selectedDates.add(dateKey);
          }
        } else if (ctx.selectedDates.has(dateKey)) {
          ctx.selectedDates.delete(dateKey);
        } else {
          ctx.selectedDates.add(dateKey);
        }
        renderCalendar();
        updateSubmitState();
      });
      daysGrid.appendChild(btn);
    });
    updateSubmitState();
  };

  const renderEmployeeOptions = async () => {
    ctx.employeeLoadToken += 1;
    const token = ctx.employeeLoadToken;
    const selectedEmployeeCode = String(employeeSelect.value || '').trim();
    const scopedSiteCode = String(siteSelect.value || '').trim().toUpperCase();
    if (!scopedSiteCode) {
      employeeSelect.disabled = true;
      employeeSelect.innerHTML = '<option value="">지점을 먼저 선택해 주세요.</option>';
      ctx.selectedEmployeeCode = '';
      refreshCalendarAvailability({ ensureConflictRows: false }).catch(() => {});
      return;
    }
    const seedRows = getScheduleCreateEmployeeSeedRows(scopedSiteCode);
    if (seedRows.length) {
      ctx.employeeRows = seedRows;
      populateScheduleCreateEmployeeOptions(employeeSelect, seedRows, {
        defaultLabel: '직원 선택',
        emptyLabel: '등록된 직원이 없습니다.',
        selectedEmployeeCode,
      });
      employeeSelect.disabled = false;
      ctx.selectedEmployeeCode = String(employeeSelect.value || '').trim();
      refreshCalendarAvailability({ ensureConflictRows: true }).catch(() => {});
    } else {
      employeeSelect.disabled = true;
      employeeSelect.innerHTML = '<option value="">직원 불러오는 중...</option>';
    }
    try {
      const rows = await listScheduleCreateEmployees(scopedSiteCode);
      if (token !== ctx.employeeLoadToken) return;
      ctx.employeeRows = rows;
      populateScheduleCreateEmployeeOptions(employeeSelect, rows, {
        defaultLabel: '직원 선택',
        emptyLabel: '등록된 직원이 없습니다.',
        selectedEmployeeCode,
      });
    } catch (error) {
      if (token !== ctx.employeeLoadToken) return;
      employeeSelect.innerHTML = '<option value="">직원 목록 조회 실패</option>';
      showToast(normalizeActionError(error, '직원 목록을 불러오지 못했습니다.'), 'error', 2600);
    } finally {
      if (token === ctx.employeeLoadToken) {
        employeeSelect.disabled = false;
        ctx.selectedEmployeeCode = String(employeeSelect.value || '').trim();
        refreshCalendarAvailability({ ensureConflictRows: true }).catch(() => {});
      }
    }
  };

  const populateSiteOptions = () => {
    const options = buildSiteOptions();
    const currentValue = String(siteSelect.value || ctx.selectedSiteCode || '').trim().toUpperCase();
    siteSelect.innerHTML = '';
    if (!options.length) {
      const option = document.createElement('option');
      option.value = '';
      option.textContent = '지점 불러오는 중...';
      siteSelect.appendChild(option);
      siteSelect.disabled = true;
      ctx.selectedSiteCode = '';
      return;
    }
    options.forEach((item) => {
      const option = document.createElement('option');
      option.value = item.code;
      option.dataset.siteId = item.id;
      option.textContent = item.name ? `${item.code} · ${item.name}` : item.code;
      siteSelect.appendChild(option);
    });
    siteSelect.disabled = false;
    if (currentValue && options.some((item) => item.code === currentValue)) {
      siteSelect.value = currentValue;
    } else if (ctx.selectedSiteCode && options.some((item) => item.code === ctx.selectedSiteCode)) {
      siteSelect.value = ctx.selectedSiteCode;
    } else {
      siteSelect.value = options[0]?.code || '';
    }
    ctx.selectedSiteCode = String(siteSelect.value || '').trim().toUpperCase();
  };
  populateSiteOptions();

  openSheet({
    title: '',
    contentNode: content,
    actions: [],
  });
  const sheet = $('#appSheet');
  if (sheet) {
    sheet.classList.add('sheet-layout-schedule-create');
  }

  const outsideClickHandler = (event) => {
    if (getScheduleCreateModalContext() !== ctx) return;
    const target = event.target instanceof Node ? event.target : null;
    if (target && !templateField.contains(target)) {
      setTemplateDropdownOpen(false);
    }
  };
  document.addEventListener('click', outsideClickHandler, true);
  ctx.cleanup = () => {
    document.removeEventListener('click', outsideClickHandler, true);
  };

  state.sheetContext = ctx;

  helpBtn.addEventListener('click', () => {
    showToast('지점 그리고 직원을 선택한 후, 템플릿 혹은 휴가 유형들을 선택해 주세요', 'info', 2600);
  });
  closeBtn.addEventListener('click', () => closeSheet());
  footerCloseBtn.addEventListener('click', () => closeSheet());

  templateTrigger.addEventListener('click', () => {
    setTemplateDropdownOpen(!ctx.templateDropdownOpen);
  });
  templateSearch.addEventListener('input', () => {
    ctx.templateSearch = String(templateSearch.value || '').trim();
    renderTemplateOptions();
  });

  siteSelect.addEventListener('change', () => {
    ctx.selectedSiteCode = String(siteSelect.value || '').trim().toUpperCase();
    ctx.selectedEmployeeCode = '';
    employeeSelect.value = '';
    renderTemplateOptions();
    refreshCalendarAvailability({ ensureConflictRows: false }).catch(() => {});
    renderEmployeeOptions().catch(() => {});
  });
  employeeSelect.addEventListener('change', () => {
    ctx.selectedEmployeeCode = String(employeeSelect.value || '').trim();
    refreshCalendarAvailability({ ensureConflictRows: true }).catch(() => {});
  });
  leaveSelect.addEventListener('change', () => {
    ctx.selectedLeaveType = String(leaveSelect.value || '').trim();
  });
  prevBtn.addEventListener('click', () => {
    ctx.calendarMonth = shiftMonthKey(ctx.calendarMonth, -1);
    refreshCalendarAvailability({ ensureConflictRows: true }).catch(() => {});
  });
  nextBtn.addEventListener('click', () => {
    ctx.calendarMonth = shiftMonthKey(ctx.calendarMonth, 1);
    refreshCalendarAvailability({ ensureConflictRows: true }).catch(() => {});
  });
  submitBtn.addEventListener('click', () => {
    if (submitBtn.disabled) return;
    setButtonsBusy(submitBtn, true, '추가 중...');
    runActionSafely(
      onScheduleCreateByTemplate({ bulk }),
      '근무일정을 추가하지 못했습니다.',
    ).finally(() => {
      setButtonsBusy(submitBtn, false);
    });
  });

  renderTemplateOptions();
  renderCalendar();
  renderEmployeeOptions().catch(() => {});
  updateSubmitState();
  refreshSiteCatalog({ force: false })
    .then(() => {
      if (state.sheetContext !== ctx) return;
      populateSiteOptions();
      renderTemplateOptions();
      renderEmployeeOptions().catch(() => {});
    })
    .catch(() => {});
  loadScheduleTemplateRows({ force: false })
    .then(() => {
      if (state.sheetContext !== ctx) return;
      renderTemplateOptions();
      refreshCalendarAvailability({ ensureConflictRows: false }).catch(() => {});
    })
    .catch(() => {});
}

async function onScheduleCreateByTemplate({ bulk = false } = {}) {
  if (!canMutateScheduleData()) {
    showToast('근무일정 생성 권한이 없습니다.', 'error');
    return;
  }
  const modalCtx = getScheduleCreateModalContext();
  if (modalCtx) {
    const siteSelect = modalCtx.refs?.siteSelect;
    const employeeSelect = modalCtx.refs?.employeeSelect;
    const selectedSiteCode = String(siteSelect?.value || '').trim().toUpperCase();
    const selectedSiteOption = siteSelect instanceof HTMLSelectElement
      ? siteSelect.options[siteSelect.selectedIndex] || null
      : null;
    const selectedSiteId = String(selectedSiteOption?.dataset?.siteId || '').trim();
    const selectedEmployeeCode = String(employeeSelect?.value || '').trim();
    const selectedEmployeeOption = employeeSelect instanceof HTMLSelectElement
      ? employeeSelect.options[employeeSelect.selectedIndex] || null
      : null;
    const selectedEmployeeId = String(selectedEmployeeOption?.dataset?.employeeId || '').trim();
    const selectedTemplateRows = getScheduleCreateSelectedTemplateRows(modalCtx);
    let selectedDates = Array.from(modalCtx.selectedDates || [])
      .map((item) => String(item || '').trim())
      .filter((item) => /^\d{4}-\d{2}-\d{2}$/.test(item))
      .sort((a, b) => String(a).localeCompare(String(b)));

    if (modalCtx.mode === 'single' && selectedDates.length > 1) {
      selectedDates = selectedDates.slice(0, 1);
    }
    if (!selectedSiteCode || !selectedEmployeeCode || !selectedTemplateRows.length || !selectedDates.length) {
      showToast('지점, 직원, 템플릿, 날짜를 선택해 주세요.', 'error');
      return;
    }
    const combinationConflict = getScheduleCreateTemplateCombinationConflict(selectedTemplateRows);
    if (combinationConflict) {
      showToast(combinationConflict.message, 'error');
      return;
    }

    const aggregated = {
      created_count: 0,
      skipped_duplicates: 0,
      errors: [],
      created_rows: [],
    };
    for (const templateRow of selectedTemplateRows) {
      const result = await apiRequest('/schedules/bulk', {
        method: 'POST',
        body: {
          tenant_code: getScheduleTenantValue(),
          site_id: selectedSiteId || null,
          employee_id: selectedEmployeeId || null,
          site_code: selectedSiteCode,
          employee_code: selectedEmployeeCode,
          template_id: templateRow.id,
          dates: selectedDates,
        },
      });
      aggregated.created_count += Number(result?.created_count || 0);
      aggregated.skipped_duplicates += Number(result?.skipped_duplicates || 0);
      if (Array.isArray(result?.errors)) {
        aggregated.errors.push(...result.errors.filter(Boolean));
      }
      if (Array.isArray(result?.created_rows)) {
        aggregated.created_rows.push(...result.created_rows);
      }
    }

    const createdCount = Number(aggregated.created_count || 0);
    const skippedDuplicates = Number(aggregated.skipped_duplicates || 0);
    const errors = Array.isArray(aggregated.errors) ? aggregated.errors.filter(Boolean) : [];
    closeSheet();
    if (errors.length) {
      showToast(`일부 항목이 실패했습니다. (${errors.length}건)`, 'error', 3200);
    } else if (createdCount > 0) {
      showToast('근무일정이 추가되었습니다', 'success', 2400);
    } else if (skippedDuplicates > 0) {
      showToast('중복 일정으로 추가된 항목이 없습니다.', 'info', 2400);
    } else {
      showToast('근무일정이 추가되었습니다', 'success', 2400);
    }
    invalidateScheduleCache();
    applyCreatedScheduleRowsToCurrentView(Array.isArray(aggregated.created_rows) ? aggregated.created_rows : [], {
      month: selectedDates[0] ? getMonthFromDateKey(selectedDates[0]) : state.schedule.month,
      tenantCode: getScheduleTenantValue(),
    });
    return;
  }

  const siteCode = String($(`#${state.sheetContext?.siteInputId || ''}`)?.value || '').trim().toUpperCase();
  const employeeCode = String($(`#${state.sheetContext?.employeeInputId || ''}`)?.value || '').trim();
  const templateId = String($(`#${state.sheetContext?.templateInputId || ''}`)?.value || '').trim();
  const dateValue = String($(`#${state.sheetContext?.dateInputId || ''}`)?.value || '').trim();
  if (!siteCode || !employeeCode || !templateId || !dateValue) {
    showToast('지점, 직원, 템플릿, 날짜를 입력해 주세요.', 'error');
    return;
  }
  const dates = bulk
    ? dateValue
      .split(',')
      .map((item) => String(item || '').trim())
      .filter((item) => /^\d{4}-\d{2}-\d{2}$/.test(item))
    : [dateValue];
  if (!dates.length) {
    showToast('날짜 형식을 확인해 주세요.', 'error');
    return;
  }
  await apiRequest('/schedules/bulk', {
    method: 'POST',
    body: {
      tenant_code: getScheduleTenantValue(),
      site_code: siteCode,
      employee_code: employeeCode,
      template_id: templateId,
      dates,
    },
  });
  closeSheet();
  showToast('근무일정이 추가되었습니다', 'success', 2400);
  loadSchedule({ force: false, deferDetailHydration: true, background: true }).catch((error) => {
    console.error('[RG ARLS] schedule fallback refresh failed after legacy create path', error);
  });
}

async function openScheduleTemplateEditor(templateId = '') {
  if (!canMutateScheduleData()) {
    showToast('근무 템플릿 권한이 없습니다.', 'error');
    return;
  }
  await Promise.allSettled([
    refreshSiteCatalog({ force: false }),
    loadScheduleTemplateRows({ force: false }),
  ]);
  const rows = Array.isArray(state.schedule.templateRows) ? state.schedule.templateRows : [];
  const current = rows.find((item) => String(item?.id || '').trim() === String(templateId || '').trim()) || null;

  const content = document.createElement('div');
  content.className = 'stack';
  const createField = (label, input) => {
    const field = document.createElement('label');
    field.className = 'input-field';
    field.textContent = label;
    field.appendChild(input);
    return field;
  };

  const nameInput = document.createElement('input');
  nameInput.type = 'text';
  nameInput.id = 'scheduleTemplateNameInput';
  nameInput.value = String(current?.template_name || '').trim();
  content.appendChild(createField('템플릿명', nameInput));

  const dutySelect = document.createElement('select');
  dutySelect.id = 'scheduleTemplateDutyInput';
  [
    { value: 'day', label: '주간근무' },
    { value: 'overtime', label: '초과근무' },
    { value: 'night', label: '야간근무' },
  ].forEach((item) => {
    const option = document.createElement('option');
    option.value = item.value;
    option.textContent = item.label;
    dutySelect.appendChild(option);
  });
  dutySelect.value = String(current?.duty_type || 'day').trim().toLowerCase() || 'day';
  content.appendChild(createField('근무구분', dutySelect));

  const startInput = document.createElement('input');
  startInput.type = 'time';
  startInput.id = 'scheduleTemplateStartInput';
  startInput.value = String(current?.start_time || '').trim().slice(0, 5);
  content.appendChild(createField('시작시간', startInput));

  const endInput = document.createElement('input');
  endInput.type = 'time';
  endInput.id = 'scheduleTemplateEndInput';
  endInput.value = String(current?.end_time || '').trim().slice(0, 5);
  content.appendChild(createField('종료시간', endInput));

  const paidInput = document.createElement('input');
  paidInput.type = 'number';
  paidInput.step = '0.5';
  paidInput.min = '0';
  paidInput.max = '24';
  paidInput.id = 'scheduleTemplatePaidInput';
  paidInput.value = current?.paid_hours == null ? '' : String(current.paid_hours);
  content.appendChild(createField('유급시간', paidInput));

  const breakInput = document.createElement('input');
  breakInput.type = 'number';
  breakInput.step = '1';
  breakInput.min = '0';
  breakInput.max = '1440';
  breakInput.id = 'scheduleTemplateBreakInput';
  breakInput.value = current?.break_minutes == null ? '' : String(current.break_minutes);
  content.appendChild(createField('휴게시간(분)', breakInput));

  const siteSelect = document.createElement('select');
  siteSelect.id = 'scheduleTemplateSiteInput';
  const commonOption = document.createElement('option');
  commonOption.value = '';
  commonOption.textContent = '공통(전체 지점)';
  siteSelect.appendChild(commonOption);
  (Array.isArray(state.siteCatalog) ? state.siteCatalog : [])
    .map((row) => ({
      code: String(row?.site_code || '').trim().toUpperCase(),
      name: String(row?.site_name || '').trim(),
      id: String(row?.id || '').trim(),
    }))
    .filter((row) => row.id && row.code)
    .sort((a, b) => String(a.code).localeCompare(String(b.code)))
    .forEach((row) => {
      const option = document.createElement('option');
      option.value = row.id;
      option.textContent = `${row.code} · ${row.name || '-'}`;
      siteSelect.appendChild(option);
    });
  siteSelect.value = String(current?.site_id || '').trim();
  content.appendChild(createField('적용 지점', siteSelect));

  const defaultWrap = document.createElement('label');
  defaultWrap.className = 'choice-row';
  const defaultInput = document.createElement('input');
  defaultInput.type = 'checkbox';
  defaultInput.id = 'scheduleTemplateDefaultInput';
  defaultInput.checked = Boolean(current?.is_default);
  defaultWrap.appendChild(defaultInput);
  defaultWrap.appendChild(document.createTextNode('기본 템플릿'));
  content.appendChild(defaultWrap);

  const activeWrap = document.createElement('label');
  activeWrap.className = 'choice-row';
  const activeInput = document.createElement('input');
  activeInput.type = 'checkbox';
  activeInput.id = 'scheduleTemplateActiveInput';
  activeInput.checked = current ? current?.is_active !== false : true;
  activeWrap.appendChild(activeInput);
  activeWrap.appendChild(document.createTextNode('활성'));
  content.appendChild(activeWrap);

  openSheet({
    title: current ? '근무 템플릿 수정' : '근무 템플릿 생성',
    contentNode: content,
    actions: [
      { label: '취소', variant: 'btn-secondary', action: 'sheet-close' },
      { label: current ? '저장' : '생성', variant: 'btn-primary', action: 'schedule-template-save' },
    ],
  });
  state.sheetContext = {
    type: 'schedule-template-editor',
    templateId: current ? String(current.id || '').trim() : '',
  };
}

async function onScheduleTemplateSave() {
  if (!canMutateScheduleData()) {
    showToast('근무 템플릿 권한이 없습니다.', 'error');
    return;
  }
  const templateName = String($('#scheduleTemplateNameInput')?.value || '').trim();
  const dutyType = String($('#scheduleTemplateDutyInput')?.value || '').trim().toLowerCase();
  const startTime = String($('#scheduleTemplateStartInput')?.value || '').trim();
  const endTime = String($('#scheduleTemplateEndInput')?.value || '').trim();
  const paidHoursRaw = String($('#scheduleTemplatePaidInput')?.value || '').trim();
  const breakMinutesRaw = String($('#scheduleTemplateBreakInput')?.value || '').trim();
  const siteId = String($('#scheduleTemplateSiteInput')?.value || '').trim();
  const isDefault = Boolean($('#scheduleTemplateDefaultInput')?.checked);
  const isActive = Boolean($('#scheduleTemplateActiveInput')?.checked);
  if (!templateName || !dutyType) {
    showToast('템플릿명과 근무구분을 입력해 주세요.', 'error');
    return;
  }
  const payload = {
    template_name: templateName,
    duty_type: dutyType,
    start_time: startTime || null,
    end_time: endTime || null,
    paid_hours: paidHoursRaw ? Number(paidHoursRaw) : null,
    break_minutes: breakMinutesRaw ? Number(breakMinutesRaw) : null,
    site_id: siteId || null,
    is_default: isDefault,
    is_active: isActive,
  };
  const templateId = String(state.sheetContext?.templateId || '').trim();
  if (templateId) {
    await apiRequest(`/schedules/work-templates/${encodeURIComponent(templateId)}?tenant_code=${encodeURIComponent(getScheduleTenantValue())}`, {
      method: 'PUT',
      body: payload,
    });
  } else {
    await apiRequest(`/schedules/work-templates?tenant_code=${encodeURIComponent(getScheduleTenantValue())}`, {
      method: 'POST',
      body: payload,
    });
  }
  closeSheet();
  showToast(templateId ? '근무 템플릿을 수정했습니다.' : '근무 템플릿을 생성했습니다.', 'success', 2200);
  await loadScheduleTemplateRows({ force: true });
  await loadScheduleImportMappingProfile({ force: true });
}

async function onScheduleTemplateToggleActive(templateId = '', nextActive = true) {
  const id = String(templateId || '').trim();
  if (!id) return;
  const rows = Array.isArray(state.schedule?.templateRows) ? state.schedule.templateRows : [];
  const current = rows.find((item) => String(item?.id || '').trim() === id);
  if (!current) {
    await loadScheduleTemplateRows({ force: true });
    return;
  }
  const payload = {
    template_name: String(current?.template_name || '').trim(),
    duty_type: String(current?.duty_type || '').trim().toLowerCase(),
    start_time: String(current?.start_time || '').trim() || null,
    end_time: String(current?.end_time || '').trim() || null,
    paid_hours: current?.paid_hours ?? null,
    break_minutes: current?.break_minutes ?? null,
    site_id: current?.site_id || null,
    is_default: Boolean(current?.is_default),
    is_active: Boolean(nextActive),
  };
  await apiRequest(`/schedules/work-templates/${encodeURIComponent(id)}?tenant_code=${encodeURIComponent(getScheduleTenantValue())}`, {
    method: 'PUT',
    body: payload,
  });
  showToast(nextActive ? '템플릿을 활성화했습니다.' : '템플릿을 비활성화했습니다.', 'success', 1800);
  await loadScheduleTemplateRows({ force: true });
  await loadScheduleImportMappingProfile({ force: true });
}

function normalizeScheduleViewMode(value = '') {
  const mode = String(value || '').trim().toLowerCase();
  if (mode === SCHEDULE_VIEW_MODE_LIST) return SCHEDULE_VIEW_MODE_LIST;
  return SCHEDULE_VIEW_MODE_CALENDAR;
}

function getScheduleMonthValue() {
  const inputMonth = normalizeMonthKey($('#scheduleMonth')?.value || '');
  return inputMonth || toMonthKey(new Date());
}

function getScheduleViewModeValue() {
  return normalizeScheduleViewMode(state.schedule?.viewMode || SCHEDULE_VIEW_MODE_CALENDAR);
}

function getScheduleTenantValue() {
  const navRole = getNavigationRole();
  if (navRole !== 'DEV') {
    return ensureScheduleTenantCode(state.user?.tenant_code || '');
  }
  return ensureScheduleTenantCode(
    $('#scheduleTenant')?.value
    || getWorkingTenantDisplayCode()
    || getActiveTenantContext().code
    || state.user?.tenant_code
    || '',
  );
}

function getScheduleSiteFilterValue() {
  const raw = String($('#scheduleSiteFilter')?.value || state.schedule?.siteFilter || 'all').trim().toUpperCase();
  if (!raw || raw === 'ALL') return 'all';
  return raw;
}

function getScheduleShiftFilterValue() {
  const raw = String($('#scheduleShiftFilter')?.value || state.schedule?.shiftFilter || 'all').trim().toLowerCase();
  if (!raw || raw === 'all') return 'all';
  return normalizeShiftType(raw);
}

function getScheduleShowLeaveRowsValue() {
  const input = $('#scheduleShowLeaves');
  if (input instanceof HTMLInputElement) {
    return Boolean(input.checked);
  }
  return state.schedule?.showLeaveRows !== false;
}

function formatScheduleMonthTitle(month = '') {
  const normalized = normalizeMonthKey(month);
  if (!normalized) return '월간 일정';
  const [yearPart, monthPart] = normalized.split('-').map((value) => Number(value));
  if (!Number.isFinite(yearPart) || !Number.isFinite(monthPart)) return normalized;
  return `${yearPart}년 ${monthPart}월`;
}

function renderScheduleMonthToolbar() {
  const month = normalizeMonthKey(state.schedule?.month || getScheduleMonthValue());
  state.schedule.month = month;
  state.schedule.monthTitle = formatScheduleMonthTitle(month);

  const monthTitle = $('#scheduleMonthTitle');
  if (monthTitle) {
    monthTitle.textContent = state.schedule.monthTitle;
  }

  const mode = getScheduleViewModeValue();
  state.schedule.viewMode = mode;
  document.querySelectorAll('[data-action="schedule-set-view"]').forEach((button) => {
    const targetMode = normalizeScheduleViewMode(button?.getAttribute('data-view') || button?.dataset?.view || '');
    button.classList.toggle('active', targetMode === mode);
    button.setAttribute('aria-pressed', targetMode === mode ? 'true' : 'false');
  });

  const siteFilterInput = $('#scheduleSiteFilter');
  if (siteFilterInput instanceof HTMLSelectElement) {
    siteFilterInput.value = String(state.schedule.siteFilter || 'all').toUpperCase() === 'ALL'
      ? 'all'
      : String(state.schedule.siteFilter || 'all');
  }
  const shiftFilterInput = $('#scheduleShiftFilter');
  if (shiftFilterInput instanceof HTMLSelectElement) {
    shiftFilterInput.value = String(state.schedule.shiftFilter || 'all');
  }
  const showLeaveInput = $('#scheduleShowLeaves');
  if (showLeaveInput instanceof HTMLInputElement) {
    showLeaveInput.checked = state.schedule.showLeaveRows !== false;
  }
  const leaveManageToggle = $('#scheduleLeaveManageToggle');
  if (leaveManageToggle instanceof HTMLInputElement) {
    leaveManageToggle.checked = state.schedule.showLeaveRows !== false;
  }
  renderScheduleHqTabs();
}

function buildScheduleToolbarMetaText() {
  const parts = [state.schedule.monthTitle || formatScheduleMonthTitle(state.schedule.month)];
  const siteFilter = getScheduleSiteFilterValue();
  const shiftFilter = getScheduleShiftFilterValue();
  const employeeFilter = getScheduleEmployeeFilterValue();
  const showLeaveRows = getScheduleShowLeaveRowsValue();
  if (siteFilter === 'all') {
    parts.push('전체 지점');
  } else {
    const siteSelect = $('#scheduleSiteFilter');
    const label = siteSelect instanceof HTMLSelectElement
      ? String(siteSelect.options[siteSelect.selectedIndex]?.textContent || siteFilter).trim()
      : siteFilter;
    parts.push(label || siteFilter);
  }
  parts.push(shiftFilter === 'all' ? '전체 근무' : `${getScheduleShiftMeta(shiftFilter).label}`);
  parts.push(employeeFilter ? `직원 검색: ${employeeFilter}` : '전체 직원');
  parts.push(showLeaveRows ? '휴가 표시' : '휴가 숨김');
  return parts.join(' · ');
}

function buildScheduleToolbarSummary(month = '') {
  const normalizedMonth = normalizeMonthKey(month || state.schedule.month);
  const monthMeta = getMonthMeta(normalizedMonth);
  const rows = Array.isArray(state.schedule.filteredRows) ? state.schedule.filteredRows : [];
  const assignedCount = rows.filter((row) => !isLeaveScheduleRow(row)).length;
  const leaveCount = rows.filter((row) => isLeaveScheduleRow(row)).length;
  let emptyDays = 0;
  if (monthMeta) {
    const dayMap = getScheduleBoardDayMap(normalizedMonth);
    for (let day = 1; day <= monthMeta.daysInMonth; day += 1) {
      const dateKey = `${normalizedMonth}-${String(day).padStart(2, '0')}`;
      const bucket = dayMap.get(dateKey);
      if (!bucket || !Array.isArray(bucket.items) || bucket.items.length === 0) {
        emptyDays += 1;
      }
    }
  }
  return [
    { label: '배정', value: String(assignedCount) },
    { label: '휴가', value: String(leaveCount) },
    { label: '미배정 일자', value: String(emptyDays) },
  ];
}

function renderScheduleOpsToolbar() {
  const activeTab = getScheduleActiveTopTab();
  const isBoardTab = isScheduleBoardTab(activeTab);
  toggleVisibility('#scheduleOpsToolbar', isBoardTab);

  const metaEl = $('#scheduleToolbarMeta');
  if (metaEl instanceof HTMLElement) {
    metaEl.textContent = buildScheduleToolbarMetaText();
  }

  const summaryWrap = $('#scheduleToolbarSummaryStrip');
  if (summaryWrap instanceof HTMLElement) {
    summaryWrap.innerHTML = '';
    buildScheduleToolbarSummary(state.schedule.month).forEach((item) => {
      const block = document.createElement('div');
      block.className = 'schedule-summary-item';
      block.innerHTML = `
        <span class="schedule-summary-label">${item.label}</span>
        <strong class="schedule-summary-value">${item.value}</strong>
      `;
      summaryWrap.appendChild(block);
    });
  }

  const canWrite = canMutateScheduleData();
  document.querySelectorAll('#scheduleActionMenuRow .shell-manager-only').forEach((node) => {
    node.classList.toggle('hidden', !canWrite);
  });
}

function renderScheduleFilterOptions() {
  const siteSelect = $('#scheduleSiteFilter');
  const shiftSelect = $('#scheduleShiftFilter');
  const rows = Array.isArray(getScheduleCombinedRows()) ? getScheduleCombinedRows() : [];

  if (siteSelect instanceof HTMLSelectElement) {
    const previous = String(state.schedule.siteFilter || siteSelect.value || 'all').trim();
    const siteMap = new Map();
    rows.forEach((row) => {
      const siteCode = String(row?.site_code || '').trim().toUpperCase();
      if (!siteCode || siteMap.has(siteCode)) return;
      const siteName = String(row?.site_name || '').trim();
      siteMap.set(siteCode, siteName);
    });
    siteSelect.innerHTML = '<option value="all">전체 지점</option>';
    Array.from(siteMap.entries())
      .sort((a, b) => String(a[0]).localeCompare(String(b[0])))
      .forEach(([siteCode, siteName]) => {
        const option = document.createElement('option');
        option.value = siteCode;
        option.textContent = siteName ? `${siteCode} · ${siteName}` : siteCode;
        siteSelect.appendChild(option);
      });
    siteSelect.value = siteMap.has(previous) ? previous : 'all';
    state.schedule.siteFilter = siteSelect.value;
  }

  if (shiftSelect instanceof HTMLSelectElement) {
    const previous = String(state.schedule.shiftFilter || shiftSelect.value || 'all').trim().toLowerCase();
    const shiftValues = new Set();
    rows.forEach((row) => {
      const shiftType = normalizeShiftType(row?.shift_type || '');
      if (!shiftType) return;
      shiftValues.add(shiftType);
    });
    shiftSelect.innerHTML = '<option value="all">전체 근무</option>';
    Array.from(shiftValues)
      .sort((a, b) => String(a).localeCompare(String(b)))
      .forEach((shiftType) => {
        const option = document.createElement('option');
        option.value = shiftType;
        option.textContent = getScheduleShiftMeta(shiftType).label;
        shiftSelect.appendChild(option);
      });
    shiftSelect.value = shiftValues.has(previous) ? previous : 'all';
    state.schedule.shiftFilter = shiftSelect.value;
  }
}

function normalizeYmdDateValue(value = '') {
  const raw = String(value || '').trim();
  if (!/^\d{4}-\d{2}-\d{2}$/.test(raw)) return '';
  return raw;
}

function getScheduleExportFilterValues() {
  const start = normalizeYmdDateValue($('#scheduleExportStart')?.value || '');
  const end = normalizeYmdDateValue($('#scheduleExportEnd')?.value || '');
  return {
    startDate: start,
    endDate: end,
    companyCode: String($('#scheduleExportCompany')?.value || '').trim(),
    siteCode: String($('#scheduleExportSite')?.value || '').trim(),
  };
}

function applyScheduleExportDateFromMonth(monthValue = '') {
  const month = normalizeMonthKey(monthValue || getScheduleMonthValue());
  if (!month) return;
  const [yearPart, monthPart] = month.split('-').map((item) => Number(item));
  if (!Number.isInteger(yearPart) || !Number.isInteger(monthPart)) return;
  const start = new Date(yearPart, monthPart - 1, 1);
  const end = new Date(yearPart, monthPart, 0);
  const startKey = toLocalDateKey(start);
  const endKey = toLocalDateKey(end);

  const startInput = $('#scheduleExportStart');
  const endInput = $('#scheduleExportEnd');
  if (startInput instanceof HTMLInputElement && !normalizeYmdDateValue(startInput.value)) {
    startInput.value = startKey;
  }
  if (endInput instanceof HTMLInputElement && !normalizeYmdDateValue(endInput.value)) {
    endInput.value = endKey;
  }
}

function buildScheduleExportHref() {
  const tenantCode = getScheduleTenantValue();
  const month = getScheduleMonthValue();
  const { startDate, endDate, companyCode, siteCode } = getScheduleExportFilterValues();
  const params = new URLSearchParams();
  params.set('format', 'xlsx');
  params.set('tenant_code', tenantCode);

  if (startDate && endDate) {
    params.set('start_date', startDate);
    params.set('end_date', endDate);
  } else {
    params.set('month', month);
  }

  if (companyCode) params.set('company_code', companyCode);
  if (siteCode) params.set('site_code', siteCode);

  return `${state.activeApiBase}/schedules/export?${params.toString()}`;
}

function refreshScheduleExportLink() {
  const exportBtn = $('#scheduleExportBtn');
  if (!exportBtn) return;
  exportBtn.href = buildScheduleExportHref();
}

function getScheduleEmployeeFilterValue() {
  return String($('#scheduleEmployeeFilter')?.value || '').trim().toLowerCase();
}

function getScheduleManagerSearchValue() {
  return String($('#scheduleManagerEmployeeSearch')?.value || '').trim().toLowerCase();
}

function getScheduleShiftMeta(shiftType = '') {
  return SCHEDULE_SHIFT_META[normalizeShiftType(shiftType)] || {
    label: shiftType ? String(shiftType).toUpperCase() : '미정',
    time: '-',
    pill: 'pending',
  };
}

function getScheduleDisplayMeta(row = {}) {
  const displayType = resolveScheduleDisplayType(row);
  const fallback = SCHEDULE_DISPLAY_META[displayType] || getScheduleShiftMeta(row?.shift_type || '');
  const explicitLabel = String(row?.schedule_display_label || '').trim();
  const explicitTime = String(row?.schedule_display_time || row?.shift_label || '').trim();
  return {
    type: displayType,
    label: explicitLabel || fallback.label,
    time: explicitTime || fallback.time,
    pill: fallback.pill,
  };
}

function normalizeScheduleEmployees(rows = []) {
  const list = Array.isArray(rows) ? rows : [];
  const map = new Map();
  list.forEach((item) => {
    const employeeCode = String(item?.employee_code || '').trim();
    if (!employeeCode) return;
    if (map.has(employeeCode)) return;
    map.set(employeeCode, {
      employee_code: employeeCode,
      full_name: String(item?.full_name || item?.employee_name || '').trim(),
      company_code: String(item?.company_code || '').trim(),
      site_code: String(item?.site_code || '').trim(),
      site_name: String(item?.site_name || '').trim(),
    });
  });
  return Array.from(map.values()).sort((a, b) => String(a.employee_code).localeCompare(String(b.employee_code)));
}

function buildScheduleEmployeesFromRows(rows = []) {
  return normalizeScheduleEmployees(
    (Array.isArray(rows) ? rows : []).map((row) => ({
      employee_code: row.employee_code,
      full_name: row.employee_name || row.full_name || '',
      company_code: row.company_code || '',
      site_code: row.site_code || '',
      site_name: row.site_name || '',
    })),
  );
}

function isLeaveScheduleRow(row) {
  return String(row?.source_type || '').trim() === 'leave';
}

function getScheduleRowDisplayMeta(row) {
  if (isLeaveScheduleRow(row)) {
    const leaveLabel = formatLeaveTypeLabel(row?.leave_type || '');
    const halfDayLabel = formatLeaveHalfDaySlotLabel(row?.leave_half_slot || row?.half_day_slot || '');
    return {
      label: halfDayLabel ? `${leaveLabel} (${halfDayLabel})` : leaveLabel,
      time: '휴가',
      pill: 'holiday',
    };
  }
  return getScheduleDisplayMeta(row || {});
}

function buildLeaveDateKeys(startAt, endAt, leaveType = '') {
  const start = String(startAt || '').trim();
  const end = String(endAt || '').trim();
  if (!/^\d{4}-\d{2}-\d{2}$/.test(start)) return [];
  const normalizedType = String(leaveType || '').trim().toLowerCase();
  if (normalizedType === 'half') return [start];

  const endKey = /^\d{4}-\d{2}-\d{2}$/.test(end) ? end : start;
  const startDate = new Date(`${start}T00:00:00`);
  const endDate = new Date(`${endKey}T00:00:00`);
  if (Number.isNaN(startDate.getTime()) || Number.isNaN(endDate.getTime()) || startDate > endDate) {
    return [start];
  }

  const dates = [];
  const cursor = new Date(startDate);
  while (cursor <= endDate && dates.length < 370) {
    dates.push(toLocalDateKey(cursor));
    cursor.setDate(cursor.getDate() + 1);
  }
  return dates;
}

function normalizeApprovedLeaveRows(leaves = [], months = []) {
  const monthSet = new Set((Array.isArray(months) ? months : []).map((month) => normalizeMonthKey(month)).filter(Boolean));
  const rows = [];

  (Array.isArray(leaves) ? leaves : []).forEach((leave) => {
    const status = String(leave?.status || '').trim().toLowerCase();
    if (status !== 'approved') return;
    const employeeCode = String(leave?.employee_code || '').trim();
    if (!employeeCode) return;

    const dateKeys = buildLeaveDateKeys(leave?.start_at, leave?.end_at, leave?.leave_type);
    dateKeys.forEach((dateKey) => {
      if (!/^\d{4}-\d{2}-\d{2}$/.test(dateKey)) return;
      if (monthSet.size > 0 && !monthSet.has(dateKey.slice(0, 7))) return;
      rows.push({
        id: `leave-${leave.id}-${dateKey}`,
        source_type: 'leave',
        source_id: String(leave.id || ''),
        tenant_code: leave.tenant_code || '',
        company_code: leave.company_code || '',
        site_code: leave.site_code || '',
        site_name: leave.site_name || '',
        employee_code: employeeCode,
        employee_name: leave.employee_name || '',
        schedule_date: dateKey,
        shift_type: 'holiday',
        leave_type: leave.leave_type || 'other',
        leave_half_slot: leave.half_day_slot || '',
        leave_status: status,
        leave_reason: leave.reason || '',
        attachment_names: Array.isArray(leave.attachment_names) ? leave.attachment_names : [],
        memo: leave.reason || '',
      });
    });
  });

  return normalizeScheduleRows(rows);
}

function mergeScheduleRowsWithLeaveRows(scheduleRows = [], leaveRows = []) {
  const baseRows = normalizeScheduleRows(scheduleRows);
  const normalizedLeaves = normalizeScheduleRows(leaveRows);
  if (!normalizedLeaves.length) return baseRows;

  const leaveKeySet = new Set(
    normalizedLeaves.map((row) => `${String(row.employee_code || '').trim()}|${String(row.schedule_date || '').trim()}`),
  );
  const merged = baseRows.filter((row) => {
    const key = `${String(row.employee_code || '').trim()}|${String(row.schedule_date || '').trim()}`;
    return !leaveKeySet.has(key);
  });
  merged.push(...normalizedLeaves);
  return normalizeScheduleRows(merged);
}

function getScheduleCombinedRows() {
  return mergeScheduleRowsWithLeaveRows(state.schedule.rows, state.schedule.leaveRows);
}

function isSocScheduleRow(row) {
  return String(row?.source || '').trim().toUpperCase() === 'SOC';
}

function getScheduleDateOvertimeRows(dateKey = '') {
  const key = String(dateKey || '').trim();
  if (!/^\d{4}-\d{2}-\d{2}$/.test(key)) return [];
  if (!(state.schedule.overtimeByDate instanceof Map)) {
    state.schedule.overtimeByDate = new Map();
    return [];
  }
  const rows = state.schedule.overtimeByDate.get(key);
  return Array.isArray(rows) ? rows : [];
}

function getScheduleOvertimeSummaryByEmployee(dateKey = '', employeeCode = '') {
  const code = String(employeeCode || '').trim();
  const rows = getScheduleDateOvertimeRows(dateKey)
    .filter((item) => String(item?.employee_code || '').trim() === code);
  if (!rows.length) {
    return {
      soc: null,
      closing: null,
      rows: [],
    };
  }
  const soc = rows.find((item) => String(item?.overtime_source || '').trim().toUpperCase() === 'SOC_TICKET') || null;
  const closing = rows.find((item) => String(item?.overtime_source || '').trim().toUpperCase() === 'ATTENDANCE_CLOSE') || null;
  return { soc, closing, rows };
}

function formatOvertimeHoursLabel(value) {
  const num = Number(value);
  if (!Number.isFinite(num) || num <= 0) return '0h';
  if (Math.abs(num - Math.round(num)) < 0.0001) return `${Math.round(num)}h`;
  return `${num.toFixed(1)}h`;
}

async function loadScheduleOvertimeForDate(dateKey, { force = false } = {}) {
  const key = String(dateKey || '').trim();
  if (!/^\d{4}-\d{2}-\d{2}$/.test(key)) return [];

  if (!(state.schedule.overtimeByDate instanceof Map)) {
    state.schedule.overtimeByDate = new Map();
  }
  if (!(state.schedule.overtimeLoadingByDate instanceof Set)) {
    state.schedule.overtimeLoadingByDate = new Set();
  }

  if (!force && state.schedule.overtimeByDate.has(key)) {
    return state.schedule.overtimeByDate.get(key) || [];
  }
  if (state.schedule.overtimeLoadingByDate.has(key)) {
    return state.schedule.overtimeByDate.get(key) || [];
  }

  state.schedule.overtimeLoadingByDate.add(key);
  try {
    const params = new URLSearchParams();
    params.set('date', key);
    const tenantCode = getScheduleTenantValue();
    if (tenantCode) params.set('tenant_code', tenantCode);
    if (!isScheduleManagerMode()) {
      const ownEmployeeCode = String(state.user?.employee_code || '').trim();
      if (ownEmployeeCode) params.set('employee_code', ownEmployeeCode);
    }
    const rows = await apiRequest(`/schedules/overtime-daily?${params.toString()}`);
    const normalized = Array.isArray(rows) ? rows : [];
    state.schedule.overtimeByDate.set(key, normalized);
    return normalized;
  } catch (error) {
    state.schedule.overtimeByDate.set(key, []);
    showToast(normalizeActionError(error, '일자 OT 정보를 불러오지 못했습니다.'), 'info', 2800);
    return [];
  } finally {
    state.schedule.overtimeLoadingByDate.delete(key);
  }
}

function refreshScheduleDateSheetIfOpen(dateKey = '') {
  const key = String(dateKey || '').trim();
  if (!key) return;
  if (state.sheetContext?.mode !== 'schedule-date-detail') return;
  if (String(state.sheetContext?.dateKey || '') !== key) return;
  openScheduleDateSheet(key, { preserveContext: true });
}

function queueScheduleOvertimeLoad(dateKey, { force = false } = {}) {
  const key = String(dateKey || '').trim();
  if (!/^\d{4}-\d{2}-\d{2}$/.test(key)) return;
  loadScheduleOvertimeForDate(key, { force })
    .then(() => {
      if (String(state.schedule.selectedDateKey || '') === key) {
        renderScheduleDetail();
      }
      refreshScheduleDateSheetIfOpen(key);
    })
    .catch(() => {});
}

function getScheduleP1DetailCacheKey(dateKey = '', siteCode = '') {
  const datePart = String(dateKey || '').trim();
  const sitePart = String(siteCode || '').trim().toUpperCase();
  const tenantPart = String(getScheduleTenantValue() || '').trim().toUpperCase();
  return `${tenantPart}|${datePart}|${sitePart}`;
}

function getScheduleDateDetailFromCache(dateKey = '', siteCode = '') {
  const key = getScheduleP1DetailCacheKey(dateKey, siteCode);
  if (!(state.schedule.p1DateDetailsByKey instanceof Map)) {
    state.schedule.p1DateDetailsByKey = new Map();
  }
  return state.schedule.p1DateDetailsByKey.get(key) || null;
}

async function loadScheduleDateDetail(dateKey, siteCode, { force = false } = {}) {
  const workDate = String(dateKey || '').trim();
  const scopedSiteCode = String(siteCode || '').trim().toUpperCase();
  if (!/^\d{4}-\d{2}-\d{2}$/.test(workDate) || !scopedSiteCode) return null;

  if (!(state.schedule.p1DateDetailsByKey instanceof Map)) {
    state.schedule.p1DateDetailsByKey = new Map();
  }
  if (!(state.schedule.p1DateDetailsLoadingByKey instanceof Set)) {
    state.schedule.p1DateDetailsLoadingByKey = new Set();
  }

  const cacheKey = getScheduleP1DetailCacheKey(workDate, scopedSiteCode);
  if (!force && state.schedule.p1DateDetailsByKey.has(cacheKey)) {
    return state.schedule.p1DateDetailsByKey.get(cacheKey) || null;
  }
  if (state.schedule.p1DateDetailsLoadingByKey.has(cacheKey)) {
    return state.schedule.p1DateDetailsByKey.get(cacheKey) || null;
  }

  state.schedule.p1DateDetailsLoadingByKey.add(cacheKey);
  try {
    const params = new URLSearchParams();
    params.set('date', workDate);
    params.set('site_code', scopedSiteCode);
    const tenantCode = getScheduleTenantValue();
    if (tenantCode) params.set('tenant_code', tenantCode);
    const payload = await apiRequest(`/schedules/date-details?${params.toString()}`);
    const normalized = (payload && typeof payload === 'object') ? payload : null;
    state.schedule.p1DateDetailsByKey.set(cacheKey, normalized);
    return normalized;
  } catch (error) {
    state.schedule.p1DateDetailsByKey.delete(cacheKey);
    showToast(normalizeActionError(error, 'P1 상세 데이터를 불러오지 못했습니다.'), 'info', 2600);
    return null;
  } finally {
    state.schedule.p1DateDetailsLoadingByKey.delete(cacheKey);
  }
}

async function ensureScheduleDateDetails(dateKey, siteCodes = [], { force = false } = {}) {
  const workDate = String(dateKey || '').trim();
  if (!/^\d{4}-\d{2}-\d{2}$/.test(workDate)) return [];
  const uniqueSiteCodes = Array.from(
    new Set(
      (Array.isArray(siteCodes) ? siteCodes : [])
        .map((item) => String(item || '').trim().toUpperCase())
        .filter(Boolean),
    ),
  );
  if (!uniqueSiteCodes.length) return [];
  return Promise.all(uniqueSiteCodes.map((siteCode) => loadScheduleDateDetail(workDate, siteCode, { force })));
}

async function loadApprovedLeaveRowsForMonths(months = [], { tenantCode = '', limit = 300 } = {}) {
  if (!can('leave')) return [];
  const normalizedMonths = Array.from(
    new Set(
      (Array.isArray(months) ? months : [])
        .map((item) => normalizeMonthKey(item))
        .filter(Boolean),
    ),
  );
  if (!normalizedMonths.length) return [];

  const params = new URLSearchParams();
  params.set('status', 'approved');
  params.set('limit', String(Math.min(Math.max(Number(limit) || 100, 1), 300)));
  const tenant = ensureScheduleTenantCode(tenantCode);
  if (tenant) {
    params.set('tenant_code', tenant);
  }

  if (!isScheduleManagerMode()) {
    const employeeCode = String(state.user?.employee_code || '').trim();
    if (employeeCode) {
      params.set('employee_code', employeeCode);
    }
  }

  const queryString = params.toString();
  const rows = await apiRequest(`/leaves${queryString ? `?${queryString}` : ''}`);
  return normalizeApprovedLeaveRows(rows, normalizedMonths);
}

function getScheduleEmployeeByCode(employeeCode) {
  const code = String(employeeCode || '').trim();
  if (!code) return null;
  const list = Array.isArray(state.schedule.employees) ? state.schedule.employees : [];
  return list.find((item) => String(item.employee_code || '').trim() === code) || null;
}

function getScheduleScopedRows() {
  const rows = getScheduleCombinedRows();
  const employeeFilter = getScheduleEmployeeFilterValue();
  const siteFilter = getScheduleSiteFilterValue();
  const shiftFilter = getScheduleShiftFilterValue();
  const showLeaveRows = getScheduleShowLeaveRowsValue();
  const isManager = isScheduleManagerMode();
  const myEmployeeCode = String(state.user?.employee_code || '').trim();

  state.schedule.employeeFilter = employeeFilter;
  state.schedule.siteFilter = siteFilter;
  state.schedule.shiftFilter = shiftFilter;
  state.schedule.showLeaveRows = showLeaveRows;

  let scopedRows = rows;
  if (!isManager) {
    if (!myEmployeeCode) {
      return [];
    }
    scopedRows = scopedRows.filter((row) => String(row.employee_code || '').trim() === myEmployeeCode);
  }
  if (employeeFilter) {
    scopedRows = scopedRows.filter((row) => {
      const employeeCode = String(row.employee_code || '').toLowerCase();
      const employeeName = String(row.employee_name || row.full_name || '').toLowerCase();
      return employeeCode.includes(employeeFilter) || employeeName.includes(employeeFilter);
    });
  }

  if (siteFilter !== 'all') {
    scopedRows = scopedRows.filter((row) => String(row?.site_code || '').trim().toUpperCase() === siteFilter);
  }

  if (shiftFilter !== 'all') {
    scopedRows = scopedRows.filter((row) => normalizeShiftType(row?.shift_type || '') === shiftFilter);
  }

  if (!showLeaveRows) {
    scopedRows = scopedRows.filter((row) => !isLeaveScheduleRow(row));
  }

  return normalizeScheduleRows(scopedRows);
}

function ensureScheduleSelectedEmployee() {
  if (!isScheduleManagerMode()) {
    state.schedule.selectedEmployeeCode = String(state.user?.employee_code || '').trim();
    return state.schedule.selectedEmployeeCode;
  }
  state.schedule.selectedEmployeeCode = '';
  return '';
}

function getRowsByDate(rows = []) {
  const map = new Map();
  (Array.isArray(rows) ? rows : []).forEach((row) => {
    const dateKey = String(row?.schedule_date || '').trim();
    if (!dateKey) return;
    if (!map.has(dateKey)) {
      map.set(dateKey, []);
    }
    map.get(dateKey).push(row);
  });
  return map;
}

function buildScheduleDetailSubtitle(row) {
  const meta = getScheduleRowDisplayMeta(row);
  if (isLeaveScheduleRow(row)) {
    const reason = String(row?.leave_reason || row?.reason || '').trim();
    const parts = ['휴가 승인', meta.label];
    if (reason) parts.push(`사유 ${reason}`);
    return parts.join(' · ');
  }
  const siteLabel = row?.site_name || row?.site_code || '-';
  const memo = String(row?.memo || row?.note || row?.description || '').trim();
  const supportWorker = String(
    row?.support_worker
    || row?.support_employee_code
    || row?.support_employee
    || row?.support_staff
    || '',
  ).trim();
  const displayType = resolveScheduleDisplayType(row);
  const parts = [`${siteLabel}`];
  if (isScheduleNonWorkingDisplayType(displayType)) {
    parts.push(`근무유형 ${meta.label}`);
  } else {
    parts.push(`시간 ${meta.time}`);
  }
  if (memo) parts.push(`메모 ${memo}`);
  if (supportWorker) parts.push(`지원 ${supportWorker}`);
  const leaderName = String(
    row?.leader_full_name
    || row?.leader_username
    || row?.leader_name
    || row?.leader_code
    || '',
  ).trim();
  if (leaderName) parts.push(`리더 ${leaderName}`);
  const closerName = String(
    row?.closer_full_name
    || row?.closer_username
    || row?.closer_employee_code
    || '',
  ).trim();
  if (closerName) parts.push(`마감자 ${closerName}`);
  const otSummary = getScheduleOvertimeSummaryByEmployee(row?.schedule_date, row?.employee_code);
  if (otSummary.soc) {
    parts.push(`SOC OT ${formatOvertimeHoursLabel(otSummary.soc.overtime_hours_step)}`);
  }
  if (otSummary.closing) {
    parts.push(`마감 OT ${formatOvertimeHoursLabel(otSummary.closing.overtime_hours_step)}`);
  }
  return parts.join(' · ');
}

function buildScheduleListSheetNote(row) {
  if (isLeaveScheduleRow(row)) {
    const reason = String(row?.leave_reason || row?.reason || '').trim();
    return reason ? `사유 ${reason}` : '휴가 승인';
  }
  const leaderName = String(
    row?.leader_full_name
    || row?.leader_username
    || row?.leader_name
    || row?.leader_code
    || '',
  ).trim();
  const supportWorker = String(
    row?.support_worker
    || row?.support_employee_code
    || row?.support_employee
    || row?.support_staff
    || '',
  ).trim();
  if (supportWorker) return `지원 ${supportWorker}`;
  if (leaderName) return `리더 ${leaderName}`;
  const memo = String(row?.memo || row?.note || row?.description || '').trim();
  return memo || '';
}

