function cancelScheduleEmployeeListChunkRender({ invalidateGeneration = true } = {}) {
  if (invalidateGeneration) {
    state.schedule.employeeListChunkGeneration = Number(state.schedule.employeeListChunkGeneration || 0) + 1;
  }
  state.schedule.employeeListChunkCancelled = true;
  const cancelFn = state.schedule.employeeListChunkCancel;
  state.schedule.employeeListChunkCancel = null;
  if (typeof cancelFn === 'function') {
    try {
      cancelFn();
    } catch {
      // no-op
    }
  }
  const listEl = $('#scheduleEmployeeList');
  if (listEl instanceof HTMLElement) {
    delete listEl.dataset.renderToken;
  }
}

function beginScheduleEmployeeListChunkRender() {
  const nextGeneration = Number(state.schedule.employeeListChunkGeneration || 0) + 1;
  state.schedule.employeeListChunkGeneration = nextGeneration;
  state.schedule.employeeListChunkCancelled = false;
  const prevCancel = state.schedule.employeeListChunkCancel;
  state.schedule.employeeListChunkCancel = null;
  if (typeof prevCancel === 'function') {
    try {
      prevCancel();
    } catch {
      // no-op
    }
  }
  return nextGeneration;
}

function isScheduleEmployeeListChunkCurrent(generation) {
  const route = normalizeRoutePath(state.currentRoute || '');
  return isScheduleRoutePath(route)
    && !Boolean(state.schedule.employeeListChunkCancelled)
    && Number(state.schedule.employeeListChunkGeneration || 0) === Number(generation || 0);
}

function renderScheduleEmployeeList() {
  const listEl = $('#scheduleEmployeeList');
  if (!listEl) return;
  const renderStartedAt = getPerfNowMs();
  const generation = beginScheduleEmployeeListChunkRender();

  clearList(listEl);
  if (!isScheduleManagerMode()) {
    state.schedule.lastPerf.employeeListRenderMs = 0;
    state.schedule.employeeListChunkCancel = null;
    return;
  }

  const search = getScheduleManagerSearchValue();
  state.schedule.managerSearch = search;
  const rows = (Array.isArray(state.schedule.employees) ? state.schedule.employees : [])
    .filter((item) => {
      if (!search) return true;
      const employeeCode = String(item.employee_code || '').toLowerCase();
      const employeeName = String(item.full_name || '').toLowerCase();
      return employeeCode.includes(search) || employeeName.includes(search);
    });

  if (!rows.length) {
    renderEmptyState(listEl, '검색 결과가 없습니다.');
    state.schedule.lastPerf.employeeListRenderMs = getPerfNowMs() - renderStartedAt;
    state.schedule.employeeListChunkCancel = null;
    return;
  }

  const buildEmployeeNode = (item) => {
    const li = document.createElement('li');
    const btn = document.createElement('button');
    btn.type = 'button';
    btn.className = 'schedule-employee-btn';
    const employeeCode = String(item.employee_code || '').trim();
    if (employeeCode && employeeCode === state.schedule.selectedEmployeeCode) {
      btn.classList.add('active');
    }
    btn.dataset.action = 'schedule-select-employee';
    btn.dataset.employeeCode = employeeCode;
    btn.innerHTML = `<strong>${employeeCode}</strong><span>${item.full_name || '이름 없음'}</span>`;
    li.appendChild(btn);
    return li;
  };

  if (rows.length > 180) {
    const chunkRuntime = renderChunkedNodes(listEl, rows, buildEmployeeNode, {
      chunkSize: 60,
      shouldContinue: () => isScheduleEmployeeListChunkCurrent(generation),
      onCancel: () => {
        if (Number(state.schedule.employeeListChunkGeneration || 0) === generation) {
          state.schedule.employeeListChunkCancel = null;
        }
      },
      onComplete: () => {
        if (!isScheduleEmployeeListChunkCurrent(generation)) return;
        state.schedule.lastPerf.employeeListRenderMs = getPerfNowMs() - renderStartedAt;
        state.schedule.employeeListChunkCancel = null;
      },
    });
    state.schedule.employeeListChunkCancel = typeof chunkRuntime?.cancel === 'function'
      ? chunkRuntime.cancel
      : null;
    return;
  }

  const frag = document.createDocumentFragment();
  rows.forEach((item) => {
    frag.appendChild(buildEmployeeNode(item));
  });
  listEl.appendChild(frag);
  state.schedule.lastPerf.employeeListRenderMs = getPerfNowMs() - renderStartedAt;
  state.schedule.employeeListChunkCancel = null;
}

function renderScheduleManagerHints() {
  const panel = $('#scheduleManagerPanel');
  const managerHint = $('#scheduleManagerHint');
  const selectedHint = $('#scheduleSelectedEmployeeHint');
  if (!panel || !managerHint || !selectedHint) return;

  const managerMode = isScheduleManagerMode();
  panel.classList.toggle('hidden', !managerMode);
  if (!managerMode) return;

  const selectedEmployee = getScheduleEmployeeByCode(state.schedule.selectedEmployeeCode);
  if (selectedEmployee) {
    selectedHint.textContent = `선택됨: ${selectedEmployee.employee_code} · ${selectedEmployee.full_name || '이름 없음'}`;
  } else {
    selectedHint.textContent = '직원을 선택하면 월간 캘린더가 해당 직원 기준으로 조회됩니다.';
  }

  managerHint.textContent = state.schedule.usingMockProvider
    ? 'Mock 데이터 모드입니다. 실제 API 연결 전 UI 검증용으로 동작합니다.'
    : '직원 선택 후 월간 일정을 조회할 수 있습니다.';
}

