async function onSiteUseCurrentLocation() {
  if (!hasGeolocationCapability()) {
    showToast('이 기기에서는 현재 위치 기능을 지원하지 않습니다.', 'error');
    return;
  }
  try {
    const pos = await getCurrentPositionFromRuntime({ enableHighAccuracy: true, maximumAge: 10000, timeout: 8000 });
    $('#siteLatitude').value = Number(pos.coords.latitude).toFixed(6);
    $('#siteLongitude').value = Number(pos.coords.longitude).toFixed(6);
    const placeIdInput = $('#sitePlaceId');
    if (placeIdInput) placeIdInput.value = '';
    if (!$('#siteAddress').value.trim()) {
      $('#siteAddress').value = '현재 위치';
    }
    refreshSiteEditorPreview();
    showToast('현재 위치를 현장 좌표로 설정했습니다.', 'success', 2200);
  } catch {
    showToast('현재 위치를 가져오지 못했습니다. 위치 권한을 확인해 주세요.', 'error', 3000);
  }
}

async function onSiteSubmit(event) {
  if (event?.preventDefault) event.preventDefault();
  if (!can('siteWrite')) {
    showToast('현장 등록은 개발자 또는 지점관리자 권한이 필요합니다.', 'error');
    return;
  }
  const siteForm = $('#siteForm');
  if (!(siteForm instanceof HTMLFormElement) || !isSiteEditorOpen()) {
    showToast('현장 저장은 현장 편집기에서만 가능합니다.', 'error', 3200);
    return;
  }
  if (state.submitSiteBusy) return;
  if (state.siteEditorLookupLoading) {
    showToast('회사/참고 데이터를 불러오는 중입니다. 잠시 후 다시 시도해 주세요.', 'info', 2400);
    return;
  }

  state.submitSiteBusy = true;
  clearSiteFormFieldErrors();
  refreshSiteFormSubmitAvailability();
  setInlineStatus('#siteSubmitStatus', '처리 중...', 'info');

  const siteId = ($('#siteId')?.value || '').trim();
  const selectedTenantId = getSiteEditorSelectedTenantCode();
  const siteCodeRaw = ($('#siteCode')?.value || '').trim();
  const siteCode = siteCodeRaw;
  const siteName = ($('#siteName')?.value || '').trim();
  const address = ($('#siteAddress')?.value || '').trim();
  const placeId = String($('#sitePlaceId')?.value || '').trim();
  const wifiSsid = String($('#siteWifiSsid')?.value || '').trim();
  let saveSucceeded = false;

  try {
    if (!selectedTenantId) {
      setSiteFormFieldError('tenant_id', '회사 선택 필요');
      throw new Error('현장을 등록할 회사를 먼저 선택해 주세요.');
    }
    if (!siteName) {
      if (!siteName) setSiteFormFieldError('name', '현장명을 입력해 주세요.');
      throw new Error('현장명을 입력해 주세요.');
    }
    if (!siteCode) {
      setSiteFormFieldError('site_id', 'required');
      throw new Error('현장 번호를 입력해 주세요.');
    }

    const latitude = parseNumberInput($('#siteLatitude')?.value);
    const longitude = parseNumberInput($('#siteLongitude')?.value);
    const radius_meters = parseNumberInput($('#siteRadius')?.value);
    const activeInput = $('#siteIsActive');
    const is_active = activeInput instanceof HTMLInputElement ? Boolean(activeInput.checked) : true;

    if (!isValidLatLng(latitude, longitude)) {
      setSiteFormFieldError('latitude', '위치/반경을 설정해주세요');
      throw new Error('위도/경도를 올바르게 입력해 주세요.');
    }
    if (!Number.isFinite(radius_meters) || radius_meters <= 0) {
      setSiteFormFieldError('radius_meters', '위치/반경을 설정해주세요');
      throw new Error('반경은 0보다 큰 숫자여야 합니다.');
    }
    if (radius_meters < SITE_RADIUS_MIN_RECOMMENDED || radius_meters > SITE_RADIUS_MAX_RECOMMENDED) {
      showToast(`반경 권장 범위는 ${SITE_RADIUS_MIN_RECOMMENDED}m~${SITE_RADIUS_MAX_RECOMMENDED}m 입니다.`, 'info', 2600);
    }

    const payload = {
      tenant_id: selectedTenantId,
      site_id: siteCode || null,
      site_name: siteName,
      address: address || null,
      place_id: placeId || null,
      lat: latitude,
      lng: longitude,
      radius_m: radius_meters,
      is_active,
    };

    let savedSite = null;
    const saveRequestOptions = {
      method: siteId ? 'PUT' : 'POST',
      body: payload,
      // Site editor tenant selection must override global DEV tenant context.
      ctxTenantId: selectedTenantId,
    };
    if (siteId) {
      savedSite = await apiRequest(`/sites/${siteId}`, saveRequestOptions);
    } else {
      savedSite = await apiRequest('/sites', saveRequestOptions);
    }
    saveSucceeded = true;

    const savedSiteCode = String(savedSite?.site_code || siteCode || '').trim().toUpperCase();
    if (getNavigationRole() === 'DEV') {
      await syncSiteTenantFilterOptions({ force: true });
      const siteTenantFilter = $('#siteTenantFilter');
      if (siteTenantFilter instanceof HTMLSelectElement) {
        const hasSelectedTenantOption = Array.from(siteTenantFilter.options)
          .some((option) => String(option?.value || '').trim() === String(selectedTenantId || '').trim());
        if (hasSelectedTenantOption) {
          siteTenantFilter.value = selectedTenantId;
          state.siteTenantFilterValue = selectedTenantId;
        } else {
          siteTenantFilter.value = 'all';
          state.siteTenantFilterValue = 'all';
        }
      } else {
        state.siteTenantFilterValue = selectedTenantId;
      }
    }
    await loadSites({ notifyOnError: false, throwOnError: true });
    await refreshSiteCatalog({ force: true });
    const refreshedRows = Array.isArray(state.sites) ? state.sites : [];
    const matchedSavedSite = refreshedRows.find((item) => {
      if (!siteId) {
        return String(item?.site_name || '').trim() === siteName
          && String(item?.tenant_id || '').trim() === String(selectedTenantId || '').trim();
      }
      return String(item?.id || '').trim() === String(siteId || '').trim();
    });
    const resolvedSiteCode = String(matchedSavedSite?.site_code || savedSiteCode || '').trim().toUpperCase();
    if (resolvedSiteCode) {
      const siteCodeInput = $('#siteCode');
      if (siteCodeInput) siteCodeInput.value = resolvedSiteCode;
      setSiteWifiSsid(resolvedSiteCode, wifiSsid);
    }
    renderHomePolicySkeleton();
    await refreshHomeGeofenceSitesAfterMutation({
      preferredSiteCode: payload.is_active ? resolvedSiteCode : '',
    });
    applyEmployeeFormScopeDefaults();
    const actionLabel = siteId ? '수정' : '등록';
    const successMessage = `현장 ${actionLabel}이 완료되었습니다.${resolvedSiteCode ? ` (${resolvedSiteCode})` : ''}`;
    renderSiteCards(refreshedRows);
    closeSiteEditor();
    await navigateToRoute(ROUTE_ADMIN_SITES, { replace: true, silentDeniedModal: true });
    showToast(`✓ ${successMessage}`, 'success', 2800);
    setInlineStatus('#siteSubmitStatus', `✓ ${successMessage}`, 'success');
    triggerHaptic('success');
  } catch (err) {
    const code = String(err?.code || '').trim().toUpperCase();
    const status = Number(err?.status || 0);
    if (saveSucceeded) {
      if (code === 'TENANT_CONTEXT_REQUIRED') {
        const message = '저장은 완료됐지만 조회 테넌트가 선택되지 않아 목록을 불러오지 못했습니다. 상단에서 회사를 선택해 주세요.';
        showToast(message, 'info', 4200);
        setInlineStatus('#siteSubmitStatus', message, 'error');
        return;
      }
      if (code === 'TENANT_DISABLED') {
        const message = '저장은 완료됐지만 비활성화된 회사라 목록을 불러오지 못했습니다.';
        showToast(message, 'error', 4200);
        setInlineStatus('#siteSubmitStatus', message, 'error');
        return;
      }
      if (code === 'FORBIDDEN' || status === 403) {
        const message = '저장은 완료됐지만 목록 조회 권한이 없습니다.';
        showToast(message, 'error', 4200);
        setInlineStatus('#siteSubmitStatus', message, 'error');
        return;
      }
      const message = '저장은 완료됐지만 목록을 불러오지 못했습니다. 새로고침 후 확인해 주세요.';
      showToast(message, 'error', 4200);
      setInlineStatus('#siteSubmitStatus', message, 'error');
      return;
    }

    const fieldErrors = extractValidationFields(err);
    let fieldSummary = '';
    if (fieldErrors) {
      Object.entries(fieldErrors).forEach(([fieldKey, fieldMessage]) => {
        setSiteFormFieldError(fieldKey, String(fieldMessage || '').trim());
      });
      const firstEntry = Object.entries(fieldErrors).find(([, fieldMessage]) => {
        return Boolean(String(fieldMessage || '').trim());
      });
      if (firstEntry) {
        fieldSummary = getSiteFormFieldErrorText(firstEntry[0], firstEntry[1]);
      }
    }
    if (Number(err?.status || 0) === 404 && String(err?.code || '').trim().toUpperCase() === 'TENANT_NOT_FOUND') {
      setSiteFormFieldError('tenant_id', '선택한 회사를 찾을 수 없습니다.');
    }
    const message = fieldSummary || normalizeActionError(err, '현장 저장 처리 중 오류가 발생했습니다.');
    showToast(message, 'error', 5000);
    setInlineStatus('#siteSubmitStatus', message, 'error');
  } finally {
    state.submitSiteBusy = false;
    refreshSiteFormSubmitAvailability();
  }
}

async function onLeaveSubmit(event) {
  event.preventDefault();
  if (!can('leaveWrite')) {
    showToast('휴가 처리 권한이 없습니다.', 'error');
    return;
  }
  const submitBtn = $('#leaveSubmitBtn');
  setButtonsBusy(submitBtn, true, '신청 중...');
  try {
    const leaveType = String($('#leaveType')?.value || '').trim().toLowerCase();
    const halfDaySlot = String($('#leaveHalfSlot')?.value || '').trim().toLowerCase();
    const startAt = String($('#leaveStart')?.value || '').trim();
    const endAtRaw = String($('#leaveEnd')?.value || '').trim();
    const endAt = leaveType === 'half' ? startAt : endAtRaw;
    const attachmentNames = getLeaveAttachmentNamesFromInput();

    const reasonText = String($('#leaveReason')?.value || '').trim();
    const payload = {
      tenant_code: $('#leaveTenant')?.value.trim(),
      employee_code: $('#leaveEmp')?.value.trim(),
      leave_type: leaveType,
      half_day_slot: leaveType === 'half' ? halfDaySlot : null,
      start_at: startAt,
      end_at: endAt,
      reason: reasonText,
      attachment_names: attachmentNames,
    };

    if (!payload.tenant_code || !payload.employee_code || !payload.leave_type || !payload.start_at || !payload.end_at) {
      throw new Error('회사 번호, 직원 번호, 휴가 유형, 시작일, 종료일을 입력해 주세요.');
    }
    if (payload.leave_type === 'half' && !payload.half_day_slot) {
      throw new Error('반차 신청 시 오전/오후를 선택해 주세요.');
    }
    if (payload.start_at > payload.end_at) {
      throw new Error('휴가 기간을 다시 확인해 주세요. 시작일이 종료일보다 늦을 수 없습니다.');
    }
    if (attachmentNames.length > 3) {
      throw new Error('첨부는 최대 3개까지 가능합니다.');
    }
    if ((payload.leave_type === 'sick' || payload.leave_type === 'other') && !payload.reason) {
      payload.reason = payload.leave_type === 'sick' ? '병가' : '조퇴';
    }

    await apiRequest('/leaves', { method: 'POST', body: payload });
    setLeaveStatusFilter('all');
    renderLeaveStatusFilterTabs();
    await loadLeaves();
    if (state.currentView === 'requests' && !isManagerShellRole()) {
      await loadEmployeeRequestsView({ silent: true });
    }
    if (state.currentView === 'schedule') {
      await loadSchedule({ force: true });
    }
    const reasonInput = $('#leaveReason');
    if (reasonInput instanceof HTMLInputElement) {
      reasonInput.value = '';
    }
    applyLeaveQuickType('annual', '');
    clearLeaveAttachmentSelection();
    setLeaveHint('신청 완료: 내역 상단에서 대기 상태를 확인할 수 있습니다.', 'success');
    showToast('휴가 신청이 등록되었습니다. 승인 전까지 대기 상태로 표시됩니다.', 'success', 2800);
  } catch (err) {
    showToast(mapLeaveErrorMessage(err, '휴가 신청에 실패했습니다.'), 'error', 4500);
  } finally {
    setButtonsBusy(submitBtn, false);
  }
}

function resetLeaveWorkspaceComposer() {
  const typeInput = $('#leaveWorkspaceType');
  const halfSlotInput = $('#leaveWorkspaceHalfSlot');
  const startInput = $('#leaveWorkspaceStart');
  const endInput = $('#leaveWorkspaceEnd');
  const reasonInput = $('#leaveWorkspaceReason');
  if (typeInput instanceof HTMLSelectElement) typeInput.value = 'annual';
  if (halfSlotInput instanceof HTMLSelectElement) halfSlotInput.value = 'am';
  if (startInput instanceof HTMLInputElement) startInput.value = '';
  if (endInput instanceof HTMLInputElement) endInput.value = '';
  if (reasonInput instanceof HTMLInputElement) reasonInput.value = '';
  clearLeaveWorkspaceAttachmentSelection();
  updateLeaveWorkspaceComposerState({ enforceHalfDayRange: false });
}

