function buildScheduleDeleteScopeLocalPreview({
  scheduleId = '',
  scheduleDate = '',
  employeeCode = '',
  siteCode = '',
} = {}) {
  const targetScheduleId = String(scheduleId || '').trim();
  const rows = Array.isArray(state.schedule.rows) ? state.schedule.rows : [];
  const current = rows.find((row) => String(row?.id || '').trim() === targetScheduleId) || null;
  const resolvedDate = String(current?.schedule_date || scheduleDate || '').trim();
  const resolvedEmployeeCode = String(current?.employee_code || employeeCode || '').trim();
  const resolvedEmployeeName = String(current?.employee_name || current?.full_name || '').trim();
  const resolvedSiteCode = String(current?.site_code || siteCode || '').trim();
  const futureRows = rows.filter((row) => {
    const rowEmployeeCode = String(row?.employee_code || '').trim();
    const rowDate = String(row?.schedule_date || '').trim();
    return Boolean(
      resolvedEmployeeCode
      && resolvedDate
      && rowEmployeeCode
      && rowEmployeeCode === resolvedEmployeeCode
      && rowDate
      && rowDate >= resolvedDate
    );
  });
  const hasCurrent = futureRows.some((row) => String(row?.id || '').trim() === targetScheduleId);
  const totalFutureCount = futureRows.length + (hasCurrent || !targetScheduleId ? 0 : 1);
  return {
    schedule_id: targetScheduleId || null,
    schedule_date: resolvedDate || null,
    employee_code: resolvedEmployeeCode || null,
    employee_name: resolvedEmployeeName || null,
    site_code: resolvedSiteCode || null,
    additional_future_count: Math.max(totalFutureCount - 1, 0),
    total_future_count: totalFutureCount,
    scope_rule: 'same_employee_from_selected_date',
  };
}

function openScheduleDeleteSheet({ scheduleId, scheduleDate, employeeCode, siteCode }) {
  if (!scheduleId) return Promise.resolve();
  return fetchScheduleDeleteScopePreview(scheduleId)
    .catch((error) => {
      console.error('[RG ARLS] schedule delete scope preview failed', error);
      return buildScheduleDeleteScopeLocalPreview({
        scheduleId,
        scheduleDate,
        employeeCode,
        siteCode,
      });
    })
    .then((preview) => {
    const additionalFutureCount = Number.isFinite(Number(preview?.additional_future_count))
      ? Math.max(Number(preview.additional_future_count), 0)
      : 0;
    const summaryParts = [
      String(preview?.schedule_date || scheduleDate || '').trim(),
      String(preview?.employee_name || employeeCode || '').trim(),
      String(preview?.site_code || siteCode || '').trim(),
    ].filter(Boolean);
    const extraNode = summaryParts.length
      ? (() => {
          const node = document.createElement('div');
          node.className = 'input-helper';
          node.textContent = summaryParts.join(' · ');
          return node;
        })()
      : null;
    openConfirmDialog({
      title: '근무일정 삭제',
      message: `이 근무일정만 지우시겠습니까? 혹은 함께 생성된 ${additionalFutureCount}개의 근무일정까지 함께 지우시겠습니까?`,
      cancelLabel: '취소',
      secondaryLabel: '이 근무일정만',
      acceptLabel: '향후 모든 근무일정',
      secondaryVariant: 'btn-secondary',
      acceptVariant: 'btn-destructive',
      mobileSheet: true,
      extraNode,
      onSecondaryAccept: async () => {
        await onScheduleDeleteConfirm(scheduleId, { scope: 'single' });
      },
      onAccept: async () => {
        await onScheduleDeleteConfirm(scheduleId, { scope: 'future' });
      },
    });
    });
}

async function onScheduleEdit(scheduleId, currentShift, meta = {}) {
  if (!canMutateScheduleData()) {
    showToast('스케줄 수정은 개발자/지점관리자 권한과 실제 API 연결이 필요합니다.', 'error');
    return;
  }
  if (!scheduleId) {
    showToast('수정할 스케줄 ID가 없습니다.', 'error');
    return;
  }
  let leaderBundle = null;
  try {
    leaderBundle = await fetchScheduleLeaderCandidates(scheduleId);
  } catch (error) {
    console.error('[RG ARLS] leader candidate load failed', error);
  }
  openScheduleEditSheet({
    scheduleId,
    currentShift,
    scheduleDate: meta.scheduleDate,
    employeeCode: meta.employeeCode,
    siteCode: meta.siteCode,
    currentLeaderUserId: meta.currentLeaderUserId,
    currentLeaderName: meta.currentLeaderName,
    leaderBundle,
    row: meta.row,
  });
}

function resolveScheduleRowsForBoardSelection({
  dateKey = '',
  scheduleId = '',
  combinedScheduleIds = '',
  employeeCode = '',
  employeeId = '',
  employeeName = '',
  siteCode = '',
  startTime = '',
  endTime = '',
  shiftType = '',
} = {}) {
  const targetDate = String(dateKey || '').trim();
  const targetScheduleId = String(scheduleId || '').trim();
  const targetEmployeeCode = String(employeeCode || '').trim();
  const targetEmployeeId = String(employeeId || '').trim();
  const targetEmployeeName = String(employeeName || '').trim();
  const targetSiteCode = String(siteCode || '').trim().toUpperCase();
  const targetStartTime = String(startTime || '').trim().slice(0, 5);
  const targetEndTime = String(endTime || '').trim().slice(0, 5);
  const targetShiftType = normalizeShiftType(shiftType);
  const combinedIds = String(combinedScheduleIds || '')
    .split(',')
    .map((value) => String(value || '').trim())
    .filter(Boolean);
  const filteredRows = Array.isArray(state.schedule.filteredRows) ? state.schedule.filteredRows : [];
  const allRows = Array.isArray(state.schedule.rows) ? state.schedule.rows : [];
  const dateRows = filteredRows.filter((row) => String(row?.schedule_date || '').trim() === targetDate);
  const allDateRows = allRows.filter((row) => String(row?.schedule_date || '').trim() === targetDate);
  if (targetScheduleId) {
    const matched = dateRows.filter((row) => String(row?.id || '').trim() === targetScheduleId);
    if (matched.length) return matched;
    const matchedFromAllRows = allDateRows.filter((row) => String(row?.id || '').trim() === targetScheduleId);
    if (matchedFromAllRows.length) return matchedFromAllRows;
    return [];
  }
  if (combinedIds.length) {
    const matched = dateRows.filter((row) => combinedIds.includes(String(row?.id || '').trim()));
    if (matched.length) return matched;
    const matchedFromAllRows = allDateRows.filter((row) => combinedIds.includes(String(row?.id || '').trim()));
    if (matchedFromAllRows.length) return matchedFromAllRows;
    return [];
  }
  const fallbackRows = dateRows.length ? dateRows : allDateRows;
  return fallbackRows.filter((row) => {
    const rowEmployeeCode = String(row?.employee_code || '').trim();
    const rowEmployeeId = String(row?.employee_id || '').trim();
    const rowEmployeeName = String(row?.employee_name || row?.full_name || '').trim();
    const rowSiteCode = String(row?.site_code || '').trim().toUpperCase();
    const rowStartTime = String(row?.shift_start_time || row?.start_time || '').trim().slice(0, 5);
    const rowEndTime = String(row?.shift_end_time || row?.end_time || '').trim().slice(0, 5);
    const rowShiftType = normalizeShiftType(row?.shift_type || '');
    if (targetEmployeeId && rowEmployeeId && rowEmployeeId !== targetEmployeeId) return false;
    if (targetEmployeeCode && rowEmployeeCode && rowEmployeeCode !== targetEmployeeCode) return false;
    if (targetEmployeeName && rowEmployeeName && rowEmployeeName !== targetEmployeeName) return false;
    if (targetSiteCode && rowSiteCode && rowSiteCode !== targetSiteCode) return false;
    if (targetShiftType && rowShiftType && rowShiftType !== targetShiftType) return false;
    if (targetStartTime && rowStartTime && rowStartTime !== targetStartTime) return false;
    if (targetEndTime && rowEndTime && rowEndTime !== targetEndTime) return false;
    return true;
  });
}

