    if (action === 'requests-sort') {
      const workspace = ensureRequestsWorkspaceFilters();
      const sortKey = normalizeRequestsWorkspaceSortKey(actionEl.dataset.sortKey || '');
      if (!sortKey) return;
      const currentKey = normalizeRequestsWorkspaceSortKey(workspace.sortKey || 'submitted_at');
      const currentDirection = normalizeRequestsWorkspaceSortDirection(workspace.sortDirection || 'desc');
      if (currentKey !== sortKey) {
        workspace.sortKey = sortKey;
        workspace.sortDirection = sortKey === 'submitted_at' ? 'desc' : 'asc';
      } else if (currentDirection === 'asc') {
        workspace.sortDirection = 'desc';
      } else {
        workspace.sortKey = 'submitted_at';
        workspace.sortDirection = 'desc';
      }
      setRequestsWorkspaceRows(getRequestsActiveRawRowsForCurrentTab());
      renderRequestsWorkspaceView();
      return;
    }

